window.KJV1769_STRONG_BOOKS["Ezek"] = {"osis":"Ezek","book":"에스겔","verses":{"1:1":{"text":"Now it came to pass in the thirtieth year, in the fourth month, in the fifth day of the month, as I was among the captives by the river of Chebar, that the heavens were opened, and I saw visions of God.","words":[["H7970","Now it came to pass in the thirtieth",0,36],["H8141","year",37,41],["H7243","in the fourth",43,56],["H2568","month, in the fifth",57,76],["H2320","day of the month",77,93],["H8432","as I was among",95,109],["H1473","the captives",110,122],["H5104","by the river",123,135],["H3529","of Chebar",136,145],["H8064","that the heavens",147,163],["H6605","were opened",164,175],["H7200","and I saw",177,186],["H4759","visions",187,194],["H0430","of God",195,201]]},"1:2":{"text":"In the fifth day of the month, which was the fifth year of king Jehoiachin's captivity,","words":[["H2568","In the fifth",0,12],["H2320","day of the month",13,29],["H2549","which was the fifth",31,50],["H8141","year",51,55],["H4428","of king",56,63],["H3112","Jehoiachin's",64,76],["H1546","captivity",77,86]]},"1:3":{"text":"The word of the LORD came expressly unto Ezekiel the priest, the son of Buzi, in the land of the Chaldeans by the river Chebar; and the hand of the LORD was there upon him.","words":[["H1697","The word",0,8],["H3068","of the LORD",9,20],["H3168","came expressly unto Ezekiel",21,48],["H3548","the priest",49,59],["H1121","the son",61,68],["H0941","of Buzi",69,76],["H0776","in the land",78,89],["H3778","of the Chaldeans",90,106],["H5104","by the river",107,119],["H3529","Chebar",120,126],["H3027","and the hand",128,140],["H3068","of the LORD",141,152]]},"1:4":{"text":"And I looked, and, behold, a whirlwind came out of the north, a great cloud, and a fire infolding itself, and a brightness was about it, and out of the midst thereof as the colour of amber, out of the midst of the fire.","words":[["H7200","And I looked",0,12],["H7307","and, behold, a whirlwind",14,38],["H5591","and, behold, a whirlwind",14,38],["H0935","came",39,43],["H6828","out of the north",44,60],["H1419","a great",62,69],["H6051","cloud",70,75],["H0784","and a fire",77,87],["H3947","infolding",88,97],["H5051","itself, and a brightness",98,122],["H5439","was about",123,132],["H8432","it, and out of the midst",133,157],["H5869","thereof as the colour",158,179],["H2830","of amber",180,188],["H8432","out of the midst",190,206],["H0784","of the fire",207,218]]},"1:5":{"text":"Also out of the midst thereof came the likeness of four living creatures. And this was their appearance; they had the likeness of a man.","words":[["H8432","Also out of the midst",0,21],["H1823","thereof came the likeness",22,47],["H0702","of four",48,55],["H2416","living creatures",56,72],["H4758","And this was their appearance",74,103],["H2007","they",105,109],["H1823","had the likeness",110,126],["H0120","of a man",127,135]]},"1:6":{"text":"And every one had four faces, and every one had four wings.","words":[["H0259","And every one",0,13],["H0702","had four",14,22],["H6440","faces",23,28],["H0259","and every one",30,43],["H0702","had four",44,52],["H3671","wings",53,58]]},"1:7":{"text":"And their feet were straight feet; and the sole of their feet was like the sole of a calf's foot: and they sparkled like the colour of burnished brass.","words":[["H7272","And their feet",0,14],["H3477","were straight",15,28],["H7272","feet",29,33],["H3709","and the sole",35,47],["H7272","of their feet",48,61],["H3709","was like the sole",62,79],["H5695","of a calf's",80,91],["H7272","foot",92,96],["H5340","and they sparkled",98,115],["H5869","like the colour",116,131],["H7044","of burnished",132,144],["H5178","brass",145,150]]},"1:8":{"text":"And they had the hands of a man under their wings on their four sides; and they four had their faces and their wings.","words":[["H3027","And they had the hands",0,22],["H0120","of a man",23,31],["H3671","under their wings",32,49],["H0702","on their four",50,63],["H7253","sides",64,69],["H0702","and they four",71,84],["H6440","had their faces",85,100],["H3671","and their wings",101,116]]},"1:9":{"text":"Their wings were joined one to another; they turned not when they went; they went every one straight forward.","words":[["H3671","Their wings",0,11],["H2266","were joined",12,23],["H0802","one",24,27],["H0269","to another",28,38],["H5437","they turned",40,51],["H3212","not when they went",52,70],["H3212","they went",72,81],["H0376","every one",82,91],["H5676","straight",92,100],["H6440","forward",101,108]]},"1:10":{"text":"As for the likeness of their faces, they four had the face of a man, and the face of a lion, on the right side: and they four had the face of an ox on the left side; they four also had the face of an eagle.","words":[["H1823","As for the likeness",0,19],["H6440","of their faces",20,34],["H0702","they four",36,45],["H6440","had the face",46,58],["H0120","of a man",59,67],["H6440","and the face",69,81],["H0738","of a lion",82,91],["H3225","on the right side",93,110],["H0702","and they four",112,125],["H6440","had the face",126,138],["H7794","of an ox",139,147],["H8040","on the left side",148,164],["H0702","they four",166,175],["H6440","also had the face",176,193],["H5404","of an eagle",194,205]]},"1:11":{"text":"Thus were their faces: and their wings were stretched upward; two wings of every one were joined one to another, and two covered their bodies.","words":[["H6440","Thus were their faces",0,21],["H3671","and their wings",23,38],["H6504","were stretched",39,53],["H4605","upward",54,60],["H8147","two",62,65],["H0376","wings of every one",66,84],["H2266","were joined",85,96],["H0376","one",97,100],["H0376","to another",101,111],["H8147","and two",113,120],["H3680","covered",121,128],["H1472","their bodies",129,141]]},"1:12":{"text":"And they went every one straight forward: whither the spirit was to go, they went; and they turned not when they went.","words":[["H3212","And they went",0,13],["H0376","every one",14,23],["H5676","straight",24,32],["H6440","forward",33,40],["H7307","whither the spirit",42,60],["H3212","was to go",61,70],["H3212","they went",72,81],["H5437","and they turned",83,98],["H3212","not when they went",99,117]]},"1:13":{"text":"As for the likeness of the living creatures, their appearance was like burning coals of fire, and like the appearance of lamps: it went up and down among the living creatures; and the fire was bright, and out of the fire went forth lightning.","words":[["H1823","As for the likeness",0,19],["H2416","of the living creatures",20,43],["H4758","their appearance",45,61],["H1197","was like burning",62,78],["H1513","coals",79,84],["H0784","of fire",85,92],["H4758","and like the appearance",94,117],["H3940","of lamps",118,126],["H1980","it went up and down",128,147],["H2416","among the living creatures",148,174],["H0784","and the fire",176,188],["H5051","was bright",189,199],["H0784","and out of the fire",201,220],["H3318","went forth",221,231],["H1300","lightning",232,241]]},"1:14":{"text":"And the living creatures ran and returned as the appearance of a flash of lightning.","words":[["H2416","And the living creatures",0,24],["H7519","ran",25,28],["H7725","and returned",29,41],["H4758","as the appearance",42,59],["H0965","of a flash of lightning",60,83]]},"1:15":{"text":"Now as I beheld the living creatures, behold one wheel upon the earth by the living creatures, with his four faces.","words":[["H7200","Now as I beheld",0,15],["H2416","the living creatures",16,36],["H0259","behold one",38,48],["H0212","wheel",49,54],["H0776","upon the earth",55,69],["H0681","by",70,72],["H2416","the living creatures",73,93],["H0702","with his four",95,108],["H6440","faces",109,114]]},"1:16":{"text":"The appearance of the wheels and their work was like unto the colour of a beryl: and they four had one likeness: and their appearance and their work was as it were a wheel in the middle of a wheel.","words":[["H4758","The appearance",0,14],["H0212","of the wheels",15,28],["H4639","and their work",29,43],["H5869","was like unto the colour",44,68],["H8658","of a beryl",69,79],["H0702","and they four",81,94],["H0259","had one",95,102],["H1823","likeness",103,111],["H4758","and their appearance",113,133],["H4639","and their work",134,148],["H0212","was as it were a wheel",149,171],["H8432","in the middle",172,185],["H0212","of a wheel",186,196]]},"1:17":{"text":"When they went, they went upon their four sides: and they turned not when they went.","words":[["H3212","When they went",0,14],["H3212","they went",16,25],["H0702","upon their four",26,41],["H7253","sides",42,47],["H5437","and they turned",49,64],["H3212","not when they went",65,83]]},"1:18":{"text":"As for their rings, they were so high that they were dreadful; and their rings were full of eyes round about them four.","words":[["H1354","As for their rings",0,18],["H1363","they were so high",20,37],["H3374","that they were dreadful",38,61],["H1354","and their rings",63,78],["H4392","were full",79,88],["H5869","of eyes",89,96],["H5439","round about",97,108],["H0702","them four",109,118]]},"1:19":{"text":"And when the living creatures went, the wheels went by them: and when the living creatures were lifted up from the earth, the wheels were lifted up.","words":[["H2416","And when the living creatures",0,29],["H3212","went",30,34],["H0212","the wheels",36,46],["H3212","went",47,51],["H0681","by them",52,59],["H2416","and when the living creatures",61,90],["H5375","were lifted up",91,105],["H0776","from the earth",106,120],["H0212","the wheels",122,132],["H5375","were lifted up",133,147]]},"1:20":{"text":"Whithersoever the spirit was to go, they went, thither was their spirit to go; and the wheels were lifted up over against them: for the spirit of the living creature was in the wheels.","words":[["H7307","Whithersoever the spirit",0,24],["H3212","was to go",25,34],["H3212","they went",36,45],["H7307","thither was their spirit",47,71],["H3212","to go",72,77],["H0212","and the wheels",79,93],["H5375","were lifted up",94,108],["H5980","over against",109,121],["H7307","them: for the spirit",122,142],["H2416","of the living creature",143,165],["H0212","was in the wheels",166,183]]},"1:21":{"text":"When those went, these went; and when those stood, these stood; and when those were lifted up from the earth, the wheels were lifted up over against them: for the spirit of the living creature was in the wheels.","words":[["H3212","When those went",0,15],["H3212","these went",17,27],["H5975","and when those stood",29,49],["H5975","these stood",51,62],["H5375","and when those were lifted up",64,93],["H0776","from the earth",94,108],["H0212","the wheels",110,120],["H5375","were lifted up",121,135],["H5980","over against",136,148],["H7307","them: for the spirit",149,169],["H2416","of the living creature",170,192],["H0212","was in the wheels",193,210]]},"1:22":{"text":"And the likeness of the firmament upon the heads of the living creature was as the colour of the terrible crystal, stretched forth over their heads above.","words":[["H1823","And the likeness",0,16],["H7549","of the firmament",17,33],["H7218","upon the heads",34,48],["H2416","of the living creature",49,71],["H5869","was as the colour",72,89],["H3372","of the terrible",90,105],["H7140","crystal",106,113],["H5186","stretched forth",115,130],["H7218","over their heads",131,147],["H4605","above",148,153]]},"1:23":{"text":"And under the firmament were their wings straight, the one toward the other: every one had two, which covered on this side, and every one had two, which covered on that side, their bodies.","words":[["H7549","And under the firmament",0,23],["H3671","were their wings",24,40],["H3477","straight",41,49],["H0802","the one",51,58],["H0269","toward the other",59,75],["H0376","every one",77,86],["H8147","had two",87,94],["H3680","which covered",96,109],["H2007","on this side",110,122],["H0376","and every one",124,137],["H8147","had two",138,145],["H3680","which covered",147,160],["H2007","on that side",161,173],["H1472","their bodies",175,187]]},"1:24":{"text":"And when they went, I heard the noise of their wings, like the noise of great waters, as the voice of the Almighty, the voice of speech, as the noise of an host: when they stood, they let down their wings.","words":[["H3212","And when they went",0,18],["H8085","I heard",20,27],["H6963","the noise",28,37],["H3671","of their wings",38,52],["H6963","like the noise",54,68],["H7227","of great",69,77],["H4325","waters",78,84],["H6963","as the voice",86,98],["H7706","of the Almighty",99,114],["H6963","the voice",116,125],["H1999","of speech",126,135],["H6963","as the noise",137,149],["H4264","of an host",150,160],["H5975","when they stood",162,177],["H7503","they let down",179,192],["H3671","their wings",193,204]]},"1:25":{"text":"And there was a voice from the firmament that was over their heads, when they stood, and had let down their wings.","words":[["H6963","And there was a voice",0,21],["H7549","from the firmament",22,40],["H7218","that was over their heads",41,66],["H5975","when they stood",68,83],["H7503","and had let down",85,101],["H3671","their wings",102,113]]},"1:26":{"text":"And above the firmament that was over their heads was the likeness of a throne, as the appearance of a sapphire stone: and upon the likeness of the throne was the likeness as the appearance of a man above upon it.","words":[["H4605","And above",0,9],["H7549","the firmament",10,23],["H7218","that was over their heads",24,49],["H1823","was the likeness",50,66],["H3678","of a throne",67,78],["H4758","as the appearance",80,97],["H5601","of a sapphire",98,111],["H0068","stone",112,117],["H1823","and upon the likeness",119,140],["H3678","of the throne",141,154],["H1823","was the likeness",155,171],["H4758","as the appearance",172,189],["H0120","of a man",190,198],["H4605","above",199,204]]},"1:27":{"text":"And I saw as the colour of amber, as the appearance of fire round about within it, from the appearance of his loins even upward, and from the appearance of his loins even downward, I saw as it were the appearance of fire, and it had brightness round about.","words":[["H7200","And I saw",0,9],["H5869","as the colour",10,23],["H2830","of amber",24,32],["H4758","as the appearance",34,51],["H0784","of fire",52,59],["H5439","round about",60,71],["H1004","within",72,78],["H4758","it, from the appearance",79,102],["H4975","of his loins",103,115],["H4605","even upward",116,127],["H4758","and from the appearance",129,152],["H4975","of his loins",153,165],["H4295","even downward",166,179],["H7200","I saw",181,186],["H4758","as it were the appearance",187,212],["H0784","of fire",213,220],["H5051","and it had brightness",222,243],["H5439","round about",244,255]]},"1:28":{"text":"As the appearance of the bow that is in the cloud in the day of rain, so was the appearance of the brightness round about. This was the appearance of the likeness of the glory of the LORD. And when I saw it, I fell upon my face, and I heard a voice of one that spake.","words":[["H4758","As the appearance",0,17],["H7198","of the bow",18,28],["H6051","that is in the cloud",29,49],["H3117","in the day",50,60],["H1653","of rain",61,68],["H4758","so was the appearance",70,91],["H5051","of the brightness",92,109],["H5439","round about",110,121],["H4758","This was the appearance",123,146],["H1823","of the likeness",147,162],["H3519","of the glory",163,175],["H3068","of the LORD",176,187],["H7200","And when I saw",189,203],["H5307","it, I fell",204,214],["H6440","upon my face",215,227],["H8085","and I heard",229,240],["H6963","a voice",241,248],["H1696","of one that spake",249,266]]},"2:1":{"text":"And he said unto me, Son of man, stand upon thy feet, and I will speak unto thee.","words":[["H0559","And he said",0,11],["H1121","unto me, Son",12,24],["H0120","of man",25,31],["H5975","stand",33,38],["H7272","upon thy feet",39,52],["H1696","and I will speak",54,70]]},"2:2":{"text":"And the spirit entered into me when he spake unto me, and set me upon my feet, that I heard him that spake unto me.","words":[["H7307","And the spirit",0,14],["H0935","entered",15,22],["H1696","into me when he spake",23,44],["H5975","unto me, and set",45,61],["H7272","me upon my feet",62,77],["H8085","that I heard",79,91],["H1696","him that spake",92,106]]},"2:3":{"text":"And he said unto me, Son of man, I send thee to the children of Israel, to a rebellious nation that hath rebelled against me: they and their fathers have transgressed against me, even unto this very day.","words":[["H0559","And he said",0,11],["H1121","unto me, Son",12,24],["H0120","of man",25,31],["H7971","I send",33,39],["H1121","thee to the children",40,60],["H3478","of Israel",61,70],["H4775","to a rebellious",72,87],["H1471","nation",88,94],["H4775","that hath rebelled",95,113],["H0001","against me: they and their fathers",114,148],["H6586","have transgressed",149,166],["H6106","against me, even unto this very",167,198],["H3117","day",199,202]]},"2:4":{"text":"For they are impudent children and stiffhearted. I do send thee unto them; and thou shalt say unto them, Thus saith the Lord GOD.","words":[["H7186","For they are impudent",0,21],["H6440","For they are impudent",0,21],["H1121","children",22,30],["H2389","and stiffhearted",31,47],["H3820","and stiffhearted",31,47],["H7971","I do send",49,58],["H0559","thee unto them; and thou shalt say",59,93],["H0559","unto them, Thus saith",94,115],["H0136","the Lord",116,124],["H3069","GOD",125,128]]},"2:5":{"text":"And they, whether they will hear, or whether they will forbear, (for they are a rebellious house,) yet shall know that there hath been a prophet among them.","words":[["H8085","And they, whether they will hear",0,32],["H2308","or whether they will forbear",34,62],["H4805","(for they are a rebellious",64,90],["H1004","house",91,96],["H3045",") yet shall know",97,113],["H5030","that there hath been a prophet",114,144],["H8432","among",145,150]]},"2:6":{"text":"And thou, son of man, be not afraid of them, neither be afraid of their words, though briers and thorns be with thee, and thou dost dwell among scorpions: be not afraid of their words, nor be dismayed at their looks, though they be a rebellious house.","words":[["H1121","And thou, son",0,13],["H0120","of man",14,20],["H3372","be not afraid",22,35],["H3372","of them, neither be afraid",36,62],["H1697","of their words",63,77],["H5621","though briers",79,92],["H5544","and thorns",93,103],["H3427","be with thee, and thou dost dwell",104,137],["H6137","among scorpions",138,153],["H3372","be not afraid",155,168],["H1697","of their words",169,183],["H2865","nor be dismayed",185,200],["H6440","at their looks",201,215],["H4805","though they be a rebellious",217,244],["H1004","house",245,250]]},"2:7":{"text":"And thou shalt speak my words unto them, whether they will hear, or whether they will forbear: for they are most rebellious.","words":[["H1696","And thou shalt speak",0,20],["H1697","my words",21,29],["H8085","unto them, whether they will hear",30,63],["H2308","or whether they will forbear",65,93],["H4805","for they are most rebellious",95,123]]},"2:8":{"text":"But thou, son of man, hear what I say unto thee; Be not thou rebellious like that rebellious house: open thy mouth, and eat that I give thee.","words":[["H1121","But thou, son",0,13],["H0120","of man",14,20],["H8085","hear",22,26],["H1696","what I say",27,37],["H1961","unto thee; Be not",38,55],["H4805","thou rebellious",56,71],["H4805","like that rebellious",72,92],["H1004","house",93,98],["H6475","open",100,104],["H6310","thy mouth",105,114],["H0398","and eat",116,123],["H5414","that I give",124,135]]},"2:9":{"text":"And when I looked, behold, an hand was sent unto me; and, lo, a roll of a book was therein;","words":[["H7200","And when I looked",0,17],["H3027","behold, an hand",19,34],["H7971","was sent",35,43],["H4039","unto me; and, lo, a roll",44,68],["H5612","of a book",69,78]]},"2:10":{"text":"And he spread it before me; and it was written within and without: and there was written therein lamentations, and mourning, and woe.","words":[["H6566","And he spread",0,13],["H6440","it before",14,23],["H3789","me; and it was written",24,46],["H6440","within",47,53],["H0268","and without",54,65],["H3789","and there was written",67,88],["H7015","therein lamentations",89,109],["H1899","and mourning",111,123],["H1958","and woe",125,132]]},"3:1":{"text":"Moreover he said unto me, Son of man, eat that thou findest; eat this roll, and go speak unto the house of Israel.","words":[["H0559","Moreover he said",0,16],["H1121","unto me, Son",17,29],["H0120","of man",30,36],["H0398","eat",38,41],["H4672","that thou findest",42,59],["H0398","eat",61,64],["H4039","this roll",65,74],["H3212","and go",76,82],["H1696","speak",83,88],["H1004","unto the house",89,103],["H3478","of Israel",104,113]]},"3:2":{"text":"So I opened my mouth, and he caused me to eat that roll.","words":[["H6605","So I opened",0,11],["H6310","my mouth",12,20],["H0398","and he caused me to eat",22,45],["H4039","that roll",46,55]]},"3:3":{"text":"And he said unto me, Son of man, cause thy belly to eat, and fill thy bowels with this roll that I give thee. Then did I eat it; and it was in my mouth as honey for sweetness.","words":[["H0559","And he said",0,11],["H1121","unto me, Son",12,24],["H0120","of man",25,31],["H0990","cause thy belly",33,48],["H0398","to eat",49,55],["H4390","and fill",57,65],["H4578","thy bowels",66,76],["H4039","with this roll",77,91],["H5414","that I give",92,103],["H0398","thee. Then did I eat",104,124],["H6310","it; and it was in my mouth",125,151],["H1706","as honey",152,160],["H4966","for sweetness",161,174]]},"3:4":{"text":"And he said unto me, Son of man, go, get thee unto the house of Israel, and speak with my words unto them.","words":[["H0559","And he said",0,11],["H1121","unto me, Son",12,24],["H0120","of man",25,31],["H3212","go",33,35],["H0935","get",37,40],["H1004","thee unto the house",41,60],["H3478","of Israel",61,70],["H1696","and speak",72,81],["H1697","with my words",82,95]]},"3:5":{"text":"For thou art not sent to a people of a strange speech and of an hard language, but to the house of Israel;","words":[["H7971","For thou art not sent",0,21],["H5971","to a people",22,33],["H6012","of a strange",34,46],["H8193","speech",47,53],["H3515","and of an hard",54,68],["H3956","language",69,77],["H1004","but to the house",79,95],["H3478","of Israel",96,105]]},"3:6":{"text":"Not to many people of a strange speech and of an hard language, whose words thou canst not understand. Surely, had I sent thee to them, they would have hearkened unto thee.","words":[["H7227","Not to many",0,11],["H5971","people",12,18],["H6012","of a strange",19,31],["H8193","speech",32,38],["H3515","and of an hard",39,53],["H3956","language",54,62],["H1697","whose words",64,75],["H8085","thou canst not understand",76,101],["H7971","Surely, had I sent",103,121],["H8085","thee to them, they would have hearkened",122,161]]},"3:7":{"text":"But the house of Israel will not hearken unto thee; for they will not hearken unto me: for all the house of Israel are impudent and hardhearted.","words":[["H1004","But the house",0,13],["H3478","of Israel",14,23],["H0014","will",24,28],["H8085","not hearken",29,40],["H0014","unto thee; for they will",41,65],["H8085","not hearken",66,77],["H1004","unto me: for all the house",78,104],["H3478","of Israel",105,114],["H2389","are impudent",115,127],["H4696","are impudent",115,127],["H7186","and hardhearted",128,143],["H3820","and hardhearted",128,143]]},"3:8":{"text":"Behold, I have made thy face strong against their faces, and thy forehead strong against their foreheads.","words":[["H5414","Behold, I have made",0,19],["H6440","thy face",20,28],["H2389","strong",29,35],["H5980","against",36,43],["H6440","their faces",44,55],["H4696","and thy forehead",57,73],["H2389","strong",74,80],["H5980","against",81,88],["H4696","their foreheads",89,104]]},"3:9":{"text":"As an adamant harder than flint have I made thy forehead: fear them not, neither be dismayed at their looks, though they be a rebellious house.","words":[["H8068","As an adamant",0,13],["H2389","harder",14,20],["H6864","than flint",21,31],["H5414","have I made",32,43],["H4696","thy forehead",44,56],["H3372","fear",58,62],["H2865","them not, neither be dismayed",63,92],["H6440","at their looks",93,107],["H4805","though they be a rebellious",109,136],["H1004","house",137,142]]},"3:10":{"text":"Moreover he said unto me, Son of man, all my words that I shall speak unto thee receive in thine heart, and hear with thine ears.","words":[["H0559","Moreover he said",0,16],["H1121","unto me, Son",17,29],["H0120","of man",30,36],["H1697","all my words",38,50],["H1696","that I shall speak",51,69],["H3947","unto thee receive",70,87],["H3824","in thine heart",88,102],["H8085","and hear",104,112],["H0241","with thine ears",113,128]]},"3:11":{"text":"And go, get thee to them of the captivity, unto the children of thy people, and speak unto them, and tell them, Thus saith the Lord GOD; whether they will hear, or whether they will forbear.","words":[["H3212","And go",0,6],["H0935","get",8,11],["H1473","thee to them of the captivity",12,41],["H1121","unto the children",43,60],["H5971","of thy people",61,74],["H1696","and speak",76,85],["H0559","unto them, and tell",86,105],["H0559","them, Thus saith",106,122],["H0136","the Lord",123,131],["H3069","GOD",132,135],["H8085","whether they will hear",137,159],["H2308","or whether they will forbear",161,189]]},"3:12":{"text":"Then the spirit took me up, and I heard behind me a voice of a great rushing, saying, Blessed be the glory of the LORD from his place.","words":[["H7307","Then the spirit",0,15],["H5375","took me up",16,26],["H8085","and I heard",28,39],["H0310","behind",40,46],["H6963","me a voice",47,57],["H1419","of a great",58,68],["H7494","rushing",69,76],["H1288","saying, Blessed",78,93],["H3519","be the glory",94,106],["H3068","of the LORD",107,118],["H4725","from his place",119,133]]},"3:13":{"text":"I heard also the noise of the wings of the living creatures that touched one another, and the noise of the wheels over against them, and a noise of a great rushing.","words":[["H6963","I heard also the noise",0,22],["H3671","of the wings",23,35],["H2416","of the living creatures",36,59],["H5401","that touched",60,72],["H0802","one",73,76],["H0269","another",77,84],["H6963","and the noise",86,99],["H0212","of the wheels",100,113],["H5980","over against",114,126],["H6963","them, and a noise",127,144],["H1419","of a great",145,155],["H7494","rushing",156,163]]},"3:14":{"text":"So the spirit lifted me up, and took me away, and I went in bitterness, in the heat of my spirit; but the hand of the LORD was strong upon me.","words":[["H7307","So the spirit",0,13],["H5375","lifted me up",14,26],["H3947","and took me away",28,44],["H3212","and I went",46,56],["H4751","in bitterness",57,70],["H2534","in the heat",72,83],["H7307","of my spirit",84,96],["H3027","but the hand",98,110],["H3068","of the LORD",111,122],["H2388","was strong",123,133]]},"3:15":{"text":"Then I came to them of the captivity at Telabib, that dwelt by the river of Chebar, and I sat where they sat, and remained there astonished among them seven days.","words":[["H0935","Then I came",0,11],["H1473","to them of the captivity",12,36],["H8512","at Telabib",37,47],["H3427","that dwelt",49,59],["H5104","by the river",60,72],["H3529","of Chebar",73,82],["H3427","and I sat",84,93],["H3427","where they sat",94,108],["H3427","and remained",110,122],["H8074","there astonished",123,139],["H8432","among",140,145],["H7651","them seven",146,156],["H3117","days",157,161]]},"3:16":{"text":"And it came to pass at the end of seven days, that the word of the LORD came unto me, saying,","words":[["H7097","And it came to pass at the end",0,30],["H7651","of seven",31,39],["H3117","days",40,44],["H1697","that the word",46,59],["H3068","of the LORD",60,71],["H0559","came unto me, saying",72,92]]},"3:17":{"text":"Son of man, I have made thee a watchman unto the house of Israel: therefore hear the word at my mouth, and give them warning from me.","words":[["H1121","Son",0,3],["H0120","of man",4,10],["H5414","I have made",12,23],["H6822","thee a watchman",24,39],["H1004","unto the house",40,54],["H3478","of Israel",55,64],["H8085","therefore hear",66,80],["H1697","the word",81,89],["H6310","at my mouth",90,101],["H2094","and give them warning",103,124]]},"3:18":{"text":"When I say unto the wicked, Thou shalt surely die; and thou givest him not warning, nor speakest to warn the wicked from his wicked way, to save his life; the same wicked man shall die in his iniquity; but his blood will I require at thine hand.","words":[["H0559","When I say",0,10],["H7563","unto the wicked",11,26],["H4191","Thou shalt surely",28,45],["H4191","die",46,49],["H2094","and thou givest him not warning",51,82],["H1696","nor speakest",84,96],["H2094","to warn",97,104],["H7563","the wicked",105,115],["H7563","from his wicked",116,131],["H1870","way",132,135],["H2421","to save his life",137,153],["H7563","the same wicked",155,170],["H4191","man shall die",171,184],["H5771","in his iniquity",185,200],["H1818","but his blood",202,215],["H1245","will I require",216,230],["H3027","at thine hand",231,244]]},"3:19":{"text":"Yet if thou warn the wicked, and he turn not from his wickedness, nor from his wicked way, he shall die in his iniquity; but thou hast delivered thy soul.","words":[["H2094","Yet if thou warn",0,16],["H7563","the wicked",17,27],["H7725","and he turn",29,40],["H7562","not from his wickedness",41,64],["H7563","nor from his wicked",66,85],["H1870","way",86,89],["H4191","he shall die",91,103],["H5771","in his iniquity",104,119],["H5337","but thou hast delivered",121,144],["H5315","thy soul",145,153]]},"3:20":{"text":"Again, When a righteous man doth turn from his righteousness, and commit iniquity, and I lay a stumblingblock before him, he shall die: because thou hast not given him warning, he shall die in his sin, and his righteousness which he hath done shall not be remembered; but his blood will I require at thine hand.","words":[["H7725","Again",0,5],["H6662","When a righteous",7,23],["H7725","man doth turn",24,37],["H6664","from his righteousness",38,60],["H6213","and commit",62,72],["H5766","iniquity",73,81],["H5414","and I lay",83,92],["H4383","a stumblingblock",93,109],["H6440","before",110,116],["H4191","him, he shall die",117,134],["H2094","because thou hast not given him warning",136,175],["H4191","he shall die",177,189],["H2403","in his sin",190,200],["H6666","and his righteousness",202,223],["H6213","which he hath done",224,242],["H2142","shall not be remembered",243,266],["H1818","but his blood",268,281],["H1245","will I require",282,296],["H3027","at thine hand",297,310]]},"3:21":{"text":"Nevertheless if thou warn the righteous man, that the righteous sin not, and he doth not sin, he shall surely live, because he is warned; also thou hast delivered thy soul.","words":[["H2094","Nevertheless if thou warn",0,25],["H6662","the righteous",26,39],["H6662","man, that the righteous",40,63],["H2398","sin",64,67],["H2398","not, and he doth not sin",68,92],["H2421","he shall surely",94,109],["H2421","live",110,114],["H2094","because he is warned",116,136],["H5337","also thou hast delivered",138,162],["H5315","thy soul",163,171]]},"3:22":{"text":"And the hand of the LORD was there upon me; and he said unto me, Arise, go forth into the plain, and I will there talk with thee.","words":[["H3027","And the hand",0,12],["H3068","of the LORD",13,24],["H0559","was there upon me; and he said",25,55],["H6965","unto me, Arise",56,70],["H3318","go forth",72,80],["H1237","into the plain",81,95],["H1696","and I will there talk",97,118]]},"3:23":{"text":"Then I arose, and went forth into the plain: and, behold, the glory of the LORD stood there, as the glory which I saw by the river of Chebar: and I fell on my face.","words":[["H6965","Then I arose",0,12],["H3318","and went forth",14,28],["H1237","into the plain",29,43],["H3519","and, behold, the glory",45,67],["H3068","of the LORD",68,79],["H5975","stood",80,85],["H3519","there, as the glory",86,105],["H7200","which I saw",106,117],["H5104","by the river",118,130],["H3529","of Chebar",131,140],["H5307","and I fell",142,152],["H6440","on my face",153,163]]},"3:24":{"text":"Then the spirit entered into me, and set me upon my feet, and spake with me, and said unto me, Go, shut thyself within thine house.","words":[["H7307","Then the spirit",0,15],["H0935","entered",16,23],["H5975","into me, and set",24,40],["H7272","me upon my feet",41,56],["H1696","and spake",58,67],["H0559","with me, and said",68,85],["H0935","unto me, Go",86,97],["H5462","shut",99,103],["H8432","thyself within",104,118],["H1004","thine house",119,130]]},"3:25":{"text":"But thou, O son of man, behold, they shall put bands upon thee, and shall bind thee with them, and thou shalt not go out among them:","words":[["H1121","But thou, O son",0,15],["H0120","of man",16,22],["H5414","behold, they shall put",24,46],["H5688","bands",47,52],["H0631","upon thee, and shall bind",53,78],["H3318","thee with them, and thou shalt not go out",79,120],["H8432","among",121,126]]},"3:26":{"text":"And I will make thy tongue cleave to the roof of thy mouth, that thou shalt be dumb, and shalt not be to them a reprover: for they are a rebellious house.","words":[["H3956","And I will make thy tongue",0,26],["H1692","cleave",27,33],["H2441","to the roof of thy mouth",34,58],["H0481","that thou shalt be dumb",60,83],["H0376","and shalt not be to them a reprover",85,120],["H3198","and shalt not be to them a reprover",85,120],["H4805","for they are a rebellious",122,147],["H1004","house",148,153]]},"3:27":{"text":"But when I speak with thee, I will open thy mouth, and thou shalt say unto them, Thus saith the Lord GOD; He that heareth, let him hear; and he that forbeareth, let him forbear: for they are a rebellious house.","words":[["H1696","But when I speak",0,16],["H0854","with",17,21],["H6605","thee, I will open",22,39],["H6310","thy mouth",40,49],["H0559","and thou shalt say",51,69],["H0559","unto them, Thus saith",70,91],["H0136","the Lord",92,100],["H3069","GOD",101,104],["H8085","He that heareth",106,121],["H8085","let him hear",123,135],["H2310","and he that forbeareth",137,159],["H2308","let him forbear",161,176],["H4805","for they are a rebellious",178,203],["H1004","house",204,209]]},"4:1":{"text":"Thou also, son of man, take thee a tile, and lay it before thee, and pourtray upon it the city, even Jerusalem:","words":[["H1121","Thou also, son",0,14],["H0120","of man",15,21],["H3947","take",23,27],["H3843","thee a tile",28,39],["H5414","and lay",41,48],["H6440","it before",49,58],["H2710","thee, and pourtray",59,77],["H5892","upon it the city",78,94],["H3389","even Jerusalem",96,110]]},"4:2":{"text":"And lay siege against it, and build a fort against it, and cast a mount against it; set the camp also against it, and set battering rams against it round about.","words":[["H5414","And lay",0,7],["H4692","siege",8,13],["H1129","against it, and build",14,35],["H1785","a fort",36,42],["H8210","against it, and cast",43,63],["H5550","a mount",64,71],["H5414","against it; set",72,87],["H4264","the camp",88,96],["H7760","also against it, and set",97,121],["H3733","battering rams",122,136],["H5439","against it round about",137,159]]},"4:3":{"text":"Moreover take thou unto thee an iron pan, and set it for a wall of iron between thee and the city: and set thy face against it, and it shall be besieged, and thou shalt lay siege against it. This shall be a sign to the house of Israel.","words":[["H3947","Moreover take",0,13],["H1270","thou unto thee an iron",14,36],["H4227","pan",37,40],["H5414","and set",42,49],["H7023","it for a wall",50,63],["H1270","of iron",64,71],["H5892","between thee and the city",72,97],["H3559","and set",99,106],["H6440","thy face",107,115],["H4692","against it, and it shall be besieged",116,152],["H6696","and thou shalt lay siege",154,178],["H0226","against it. This shall be a sign",179,211],["H1004","to the house",212,224],["H3478","of Israel",225,234]]},"4:4":{"text":"Lie thou also upon thy left side, and lay the iniquity of the house of Israel upon it: according to the number of the days that thou shalt lie upon it thou shalt bear their iniquity.","words":[["H7901","Lie",0,3],["H8042","thou also upon thy left",4,27],["H6654","side",28,32],["H7760","and lay",34,41],["H5771","the iniquity",42,54],["H1004","of the house",55,67],["H3478","of Israel",68,77],["H4557","upon it: according to the number",78,110],["H3117","of the days",111,122],["H7901","that thou shalt lie",123,142],["H5375","upon it thou shalt bear",143,166],["H5771","their iniquity",167,181]]},"4:5":{"text":"For I have laid upon thee the years of their iniquity, according to the number of the days, three hundred and ninety days: so shalt thou bear the iniquity of the house of Israel.","words":[["H5414","For I have laid",0,15],["H8141","upon thee the years",16,35],["H5771","of their iniquity",36,53],["H4557","according to the number",55,78],["H3117","of the days",79,90],["H7969","three",92,97],["H3967","hundred",98,105],["H8673","and ninety",106,116],["H3117","days",117,121],["H5375","so shalt thou bear",123,141],["H5771","the iniquity",142,154],["H1004","of the house",155,167],["H3478","of Israel",168,177]]},"4:6":{"text":"And when thou hast accomplished them, lie again on thy right side, and thou shalt bear the iniquity of the house of Judah forty days: I have appointed thee each day for a year.","words":[["H3615","And when thou hast accomplished",0,31],["H0428","them",32,36],["H7901","lie",38,41],["H8145","again",42,47],["H3233","on thy right",48,60],["H3227","on thy right",48,60],["H6654","side",61,65],["H5375","and thou shalt bear",67,86],["H5771","the iniquity",87,99],["H1004","of the house",100,112],["H3063","of Judah",113,121],["H0705","forty",122,127],["H3117","days",128,132],["H5414","I have appointed",134,150],["H3117","thee each day",151,164],["H3117","thee each day",151,164],["H8141","for a year",165,175],["H8141","for a year",165,175]]},"4:7":{"text":"Therefore thou shalt set thy face toward the siege of Jerusalem, and thine arm shall be uncovered, and thou shalt prophesy against it.","words":[["H3559","Therefore thou shalt set",0,24],["H6440","thy face",25,33],["H4692","toward the siege",34,50],["H3389","of Jerusalem",51,63],["H2220","and thine arm",65,78],["H2834","shall be uncovered",79,97],["H5012","and thou shalt prophesy",99,122]]},"4:8":{"text":"And, behold, I will lay bands upon thee, and thou shalt not turn thee from one side to another, till thou hast ended the days of thy siege.","words":[["H5414","And, behold, I will lay",0,23],["H5688","bands",24,29],["H2015","upon thee, and thou shalt not turn",30,64],["H6654","thee from one side",65,83],["H6654","to another",84,94],["H3615","till thou hast ended",96,116],["H3117","the days",117,125],["H4692","of thy siege",126,138]]},"4:9":{"text":"Take thou also unto thee wheat, and barley, and beans, and lentiles, and millet, and fitches, and put them in one vessel, and make thee bread thereof, according to the number of the days that thou shalt lie upon thy side, three hundred and ninety days shalt thou eat thereof.","words":[["H3947","Take",0,4],["H2406","thou also unto thee wheat",5,30],["H8184","and barley",32,42],["H6321","and beans",44,53],["H5742","and lentiles",55,67],["H1764","and millet",69,79],["H3698","and fitches",81,92],["H5414","and put",94,101],["H0259","them in one",102,113],["H3627","vessel",114,120],["H6213","and make",122,130],["H3899","thee bread",131,141],["H4557","thereof, according to the number",142,174],["H3117","of the days",175,186],["H7901","that thou shalt lie",187,206],["H6654","upon thy side",207,220],["H7969","three",222,227],["H3967","hundred",228,235],["H8673","and ninety",236,246],["H3117","days",247,251],["H0398","shalt thou eat",252,266]]},"4:10":{"text":"And thy meat which thou shalt eat shall be by weight, twenty shekels a day: from time to time shalt thou eat it.","words":[["H3978","And thy meat",0,12],["H0398","which thou shalt eat",13,33],["H4946","shall be by weight",34,52],["H6242","twenty",54,60],["H8255","shekels",61,68],["H3117","a day",69,74],["H6256","from time",76,85],["H6256","to time",86,93],["H0398","shalt thou eat",94,108]]},"4:11":{"text":"Thou shalt drink also water by measure, the sixth part of an hin: from time to time shalt thou drink.","words":[["H8354","Thou shalt drink",0,16],["H4325","also water",17,27],["H4884","by measure",28,38],["H8345","the sixth part",40,54],["H1969","of an hin",55,64],["H6256","from time",66,75],["H6256","to time",76,83],["H8354","shalt thou drink",84,100]]},"4:12":{"text":"And thou shalt eat it as barley cakes, and thou shalt bake it with dung that cometh out of man, in their sight.","words":[["H0398","And thou shalt eat",0,18],["H8184","it as barley",19,31],["H5692","cakes",32,37],["H5746","and thou shalt bake",39,58],["H1561","it with dung",59,71],["H6627","that cometh out",72,87],["H0120","of man",88,94],["H5869","in their sight",96,110]]},"4:13":{"text":"And the LORD said, Even thus shall the children of Israel eat their defiled bread among the Gentiles, whither I will drive them.","words":[["H3068","And the LORD",0,12],["H0559","said",13,17],["H1121","Even thus shall the children",19,47],["H3478","of Israel",48,57],["H0398","eat",58,61],["H2931","their defiled",62,75],["H3899","bread",76,81],["H1471","among the Gentiles",82,100],["H5080","whither I will drive",102,122]]},"4:14":{"text":"Then said I, Ah Lord GOD! behold, my soul hath not been polluted: for from my youth up even till now have I not eaten of that which dieth of itself, or is torn in pieces; neither came there abominable flesh into my mouth.","words":[["H0559","Then said",0,9],["H0162","I, Ah",10,15],["H0136","Lord",16,20],["H3069","GOD",21,24],["H5315","behold, my soul",26,41],["H2930","hath not been polluted",42,64],["H5271","for from my youth",66,83],["H0398","up even till now have I not eaten",84,117],["H5038","of that which dieth of itself",118,147],["H2966","or is torn in pieces",149,169],["H0935","neither came",171,183],["H6292","there abominable",184,200],["H1320","flesh",201,206],["H6310","into my mouth",207,220]]},"4:15":{"text":"Then he said unto me, Lo, I have given thee cow's dung for man's dung, and thou shalt prepare thy bread therewith.","words":[["H0559","Then he said",0,12],["H7200","unto me, Lo",13,24],["H5414","I have given",26,38],["H1241","thee cow's",39,49],["H6832","dung",50,54],["H6832","dung",50,54],["H0120","for man's",55,64],["H1561","dung",65,69],["H6213","and thou shalt prepare",71,93],["H3899","thy bread",94,103]]},"4:16":{"text":"Moreover he said unto me, Son of man, behold, I will break the staff of bread in Jerusalem: and they shall eat bread by weight, and with care; and they shall drink water by measure, and with astonishment:","words":[["H0559","Moreover he said",0,16],["H1121","unto me, Son",17,29],["H0120","of man",30,36],["H7665","behold, I will break",38,58],["H4294","the staff",59,68],["H3899","of bread",69,77],["H3389","in Jerusalem",78,90],["H0398","and they shall eat",92,110],["H3899","bread",111,116],["H4948","by weight",117,126],["H1674","and with care",128,141],["H8354","and they shall drink",143,163],["H4325","water",164,169],["H4884","by measure",170,180],["H8078","and with astonishment",182,203]]},"4:17":{"text":"That they may want bread and water, and be astonied one with another, and consume away for their iniquity.","words":[["H2637","That they may want",0,18],["H3899","bread",19,24],["H4325","and water",25,34],["H8074","and be astonied",36,51],["H0376","one",52,55],["H0251","with another",56,68],["H4743","and consume away",70,86],["H5771","for their iniquity",87,105]]},"5:1":{"text":"And thou, son of man, take thee a sharp knife, take thee a barber's razor, and cause it to pass upon thine head and upon thy beard: then take thee balances to weigh, and divide the hair.","words":[["H1121","And thou, son",0,13],["H0120","of man",14,20],["H3947","take",22,26],["H2299","thee a sharp",27,39],["H2719","knife",40,45],["H3947","take",47,51],["H1532","thee a barber's",52,67],["H8593","razor",68,73],["H5674","and cause it to pass",75,95],["H7218","upon thine head",96,111],["H2206","and upon thy beard",112,130],["H3947","then take",132,141],["H3976","thee balances",142,155],["H4948","to weigh",156,164],["H2505","and divide",166,176]]},"5:2":{"text":"Thou shalt burn with fire a third part in the midst of the city, when the days of the siege are fulfilled: and thou shalt take a third part, and smite about it with a knife: and a third part thou shalt scatter in the wind; and I will draw out a sword after them.","words":[["H1197","Thou shalt burn",0,15],["H0217","with fire",16,25],["H7992","a third part",26,38],["H8432","in the midst",39,51],["H5892","of the city",52,63],["H3117","when the days",65,78],["H4692","of the siege",79,91],["H4390","are fulfilled",92,105],["H3947","and thou shalt take",107,126],["H7992","a third part",127,139],["H5221","and smite",141,150],["H5439","about",151,156],["H2719","it with a knife",157,172],["H7992","and a third part",174,190],["H2219","thou shalt scatter",191,209],["H7307","in the wind",210,221],["H7324","and I will draw out",223,242],["H2719","a sword",243,250],["H0310","after",251,256]]},"5:3":{"text":"Thou shalt also take thereof a few in number, and bind them in thy skirts.","words":[["H3947","Thou shalt also take",0,20],["H4592","thereof a few",21,34],["H4557","in number",35,44],["H6696","and bind",46,54],["H3671","them in thy skirts",55,73]]},"5:4":{"text":"Then take of them again, and cast them into the midst of the fire, and burn them in the fire; for thereof shall a fire come forth into all the house of Israel.","words":[["H3947","Then take of them again",0,23],["H7993","and cast",25,33],["H8432","them into the midst",34,53],["H0784","of the fire",54,65],["H8313","and burn",67,75],["H0784","them in the fire",76,92],["H0784","for thereof shall a fire",94,118],["H3318","come forth",119,129],["H1004","into all the house",130,148],["H3478","of Israel",149,158]]},"5:5":{"text":"Thus saith the Lord GOD; This is Jerusalem: I have set it in the midst of the nations and countries that are round about her.","words":[["H0559","Thus saith",0,10],["H0136","the Lord",11,19],["H3069","GOD",20,23],["H3389","This is Jerusalem",25,42],["H7760","I have set",44,54],["H8432","it in the midst",55,70],["H1471","of the nations",71,85],["H0776","and countries",86,99],["H5439","that are round about",100,120]]},"5:6":{"text":"And she hath changed my judgments into wickedness more than the nations, and my statutes more than the countries that are round about her: for they have refused my judgments and my statutes, they have not walked in them.","words":[["H4784","And she hath changed",0,20],["H4941","my judgments",21,33],["H7564","into wickedness",34,49],["H1471","more than the nations",50,71],["H2708","and my statutes",73,88],["H0776","more than the countries",89,112],["H5439","that are round about",113,133],["H3988","her: for they have refused",134,160],["H4941","my judgments",161,173],["H2708","and my statutes",174,189],["H1980","they have not walked",191,211]]},"5:7":{"text":"Therefore thus saith the Lord GOD; Because ye multiplied more than the nations that are round about you, and have not walked in my statutes, neither have kept my judgments, neither have done according to the judgments of the nations that are round about you;","words":[["H0559","Therefore thus saith",0,20],["H0136","the Lord",21,29],["H3069","GOD",30,33],["H1995","Because ye multiplied",35,56],["H1471","more than the nations",57,78],["H5439","that are round about",79,99],["H1980","you, and have not walked",100,124],["H2708","in my statutes",125,139],["H6213","neither have kept",141,158],["H4941","my judgments",159,171],["H6213","neither have done",173,190],["H4941","according to the judgments",191,217],["H1471","of the nations",218,232],["H5439","that are round about",233,253]]},"5:8":{"text":"Therefore thus saith the Lord GOD; Behold, I, even I, am against thee, and will execute judgments in the midst of thee in the sight of the nations.","words":[["H0559","Therefore thus saith",0,20],["H0136","the Lord",21,29],["H3069","GOD",30,33],["H6213","Behold, I, even I, am against thee, and will execute",35,87],["H4941","judgments",88,97],["H8432","in the midst",98,110],["H5869","of thee in the sight",111,131],["H1471","of the nations",132,146]]},"5:9":{"text":"And I will do in thee that which I have not done, and whereunto I will not do any more the like, because of all thine abominations.","words":[["H6213","And I will do",0,13],["H6213","in thee that which I have not done",14,48],["H6213","and whereunto I will not do",50,77],["H3282","any more the like, because",78,104],["H8441","of all thine abominations",105,130]]},"5:10":{"text":"Therefore the fathers shall eat the sons in the midst of thee, and the sons shall eat their fathers; and I will execute judgments in thee, and the whole remnant of thee will I scatter into all the winds.","words":[["H0001","Therefore the fathers",0,21],["H0398","shall eat",22,31],["H1121","the sons",32,40],["H8432","in the midst",41,53],["H1121","of thee, and the sons",54,75],["H0398","shall eat",76,85],["H0001","their fathers",86,99],["H6213","and I will execute",101,119],["H8201","judgments",120,129],["H7611","in thee, and the whole remnant",130,160],["H2219","of thee will I scatter",161,183],["H7307","into all the winds",184,202]]},"5:11":{"text":"Wherefore, as I live, saith the Lord GOD; Surely, because thou hast defiled my sanctuary with all thy detestable things, and with all thine abominations, therefore will I also diminish thee; neither shall mine eye spare, neither will I have any pity.","words":[["H2416","Wherefore, as I live",0,20],["H5002","saith",22,27],["H0136","the Lord",28,36],["H3069","GOD",37,40],["H2930","Surely, because thou hast defiled",42,75],["H4720","my sanctuary",76,88],["H8251","with all thy detestable things",89,119],["H8441","and with all thine abominations",121,152],["H1639","therefore will I also diminish",154,184],["H5869","thee; neither shall mine eye",185,213],["H2347","spare",214,219],["H2550","neither will I have any pity",221,249]]},"5:12":{"text":"A third part of thee shall die with the pestilence, and with famine shall they be consumed in the midst of thee: and a third part shall fall by the sword round about thee; and I will scatter a third part into all the winds, and I will draw out a sword after them.","words":[["H7992","A third part",0,12],["H4191","of thee shall die",13,30],["H1698","with the pestilence",31,50],["H7458","and with famine",52,67],["H3615","shall they be consumed",68,90],["H8432","in the midst",91,103],["H7992","of thee: and a third part",104,129],["H5307","shall fall",130,140],["H2719","by the sword",141,153],["H5439","round about",154,165],["H2219","thee; and I will scatter",166,190],["H7992","a third part",191,203],["H7307","into all the winds",204,222],["H7324","and I will draw out",224,243],["H2719","a sword",244,251],["H0310","after",252,257]]},"5:13":{"text":"Thus shall mine anger be accomplished, and I will cause my fury to rest upon them, and I will be comforted: and they shall know that I the LORD have spoken it in my zeal, when I have accomplished my fury in them.","words":[["H0639","Thus shall mine anger",0,21],["H3615","be accomplished",22,37],["H2534","and I will cause my fury",39,63],["H5117","to rest",64,71],["H5162","upon them, and I will be comforted",72,106],["H3045","and they shall know",108,127],["H3068","that I the LORD",128,143],["H1696","have spoken",144,155],["H7068","it in my zeal",156,169],["H3615","when I have accomplished",171,195],["H2534","my fury",196,203]]},"5:14":{"text":"Moreover I will make thee waste, and a reproach among the nations that are round about thee, in the sight of all that pass by.","words":[["H5414","Moreover I will make",0,20],["H2723","thee waste",21,31],["H2781","and a reproach",33,47],["H1471","among the nations",48,65],["H5439","that are round about",66,86],["H5869","thee, in the sight",87,105],["H5674","of all that pass by",106,125]]},"5:15":{"text":"So it shall be a reproach and a taunt, an instruction and an astonishment unto the nations that are round about thee, when I shall execute judgments in thee in anger and in fury and in furious rebukes. I the LORD have spoken it.","words":[["H2781","So it shall be a reproach",0,25],["H1422","and a taunt",26,37],["H4148","an instruction",39,53],["H4923","and an astonishment",54,73],["H1471","unto the nations",74,90],["H5439","that are round about",91,111],["H6213","thee, when I shall execute",112,138],["H8201","judgments",139,148],["H0639","in thee in anger",149,165],["H2534","and in fury",166,177],["H2534","and in furious",178,192],["H8433","rebukes",193,200],["H3068","I the LORD",202,212],["H1696","have spoken",213,224]]},"5:16":{"text":"When I shall send upon them the evil arrows of famine, which shall be for their destruction, and which I will send to destroy you: and I will increase the famine upon you, and will break your staff of bread:","words":[["H7971","When I shall send",0,17],["H7451","upon them the evil",18,36],["H2671","arrows",37,43],["H7458","of famine",44,53],["H4889","which shall be for their destruction",55,91],["H7971","and which I will send",93,114],["H7843","to destroy",115,125],["H3254","you: and I will increase",126,150],["H7458","the famine",151,161],["H7665","upon you, and will break",162,186],["H4294","your staff",187,197],["H3899","of bread",198,206]]},"5:17":{"text":"So will I send upon you famine and evil beasts, and they shall bereave thee; and pestilence and blood shall pass through thee; and I will bring the sword upon thee. I the LORD have spoken it.","words":[["H7971","So will I send",0,14],["H7458","upon you famine",15,30],["H7451","and evil",31,39],["H2416","beasts",40,46],["H7921","and they shall bereave",48,70],["H1698","thee; and pestilence",71,91],["H1818","and blood",92,101],["H5674","shall pass through",102,120],["H0935","thee; and I will bring",121,143],["H2719","the sword",144,153],["H3068","upon thee. I the LORD",154,175],["H1696","have spoken",176,187]]},"6:1":{"text":"And the word of the LORD came unto me, saying,","words":[["H1697","And the word",0,12],["H3068","of the LORD",13,24],["H0559","came unto me, saying",25,45]]},"6:2":{"text":"Son of man, set thy face toward the mountains of Israel, and prophesy against them,","words":[["H1121","Son",0,3],["H0120","of man",4,10],["H7760","set",12,15],["H6440","thy face",16,24],["H2022","toward the mountains",25,45],["H3478","of Israel",46,55],["H5012","and prophesy",57,69]]},"6:3":{"text":"And say, Ye mountains of Israel, hear the word of the Lord GOD; Thus saith the Lord GOD to the mountains, and to the hills, to the rivers, and to the valleys; Behold, I, even I, will bring a sword upon you, and I will destroy your high places.","words":[["H0559","And say",0,7],["H2022","Ye mountains",9,21],["H3478","of Israel",22,31],["H8085","hear",33,37],["H1697","the word",38,46],["H0136","of the Lord",47,58],["H3069","GOD",59,62],["H0559","Thus saith",64,74],["H0136","the Lord",75,83],["H3069","GOD",84,87],["H2022","to the mountains",88,104],["H1389","and to the hills",106,122],["H0650","to the rivers",124,137],["H1516","and to the valleys",139,157],["H0935","Behold, I, even I, will bring",159,188],["H2719","a sword",189,196],["H0006","upon you, and I will destroy",197,225],["H1116","your high places",226,242]]},"6:4":{"text":"And your altars shall be desolate, and your images shall be broken: and I will cast down your slain men before your idols.","words":[["H4196","And your altars",0,15],["H8074","shall be desolate",16,33],["H2553","and your images",35,50],["H7665","shall be broken",51,66],["H5307","and I will cast down",68,88],["H2491","your slain",89,99],["H6440","men before",100,110],["H1544","your idols",111,121]]},"6:5":{"text":"And I will lay the dead carcases of the children of Israel before their idols; and I will scatter your bones round about your altars.","words":[["H5414","And I will lay",0,14],["H6297","the dead carcases",15,32],["H1121","of the children",33,48],["H3478","of Israel",49,58],["H6440","before",59,65],["H1544","their idols",66,77],["H2219","and I will scatter",79,97],["H6106","your bones",98,108],["H5439","round about",109,120],["H4196","your altars",121,132]]},"6:6":{"text":"In all your dwellingplaces the cities shall be laid waste, and the high places shall be desolate; that your altars may be laid waste and made desolate, and your idols may be broken and cease, and your images may be cut down, and your works may be abolished.","words":[["H4186","In all your dwellingplaces",0,26],["H5892","the cities",27,37],["H2717","shall be laid waste",38,57],["H1116","and the high places",59,78],["H3456","shall be desolate",79,96],["H4196","that your altars",98,114],["H2717","may be laid waste",115,132],["H0816","and made desolate",133,150],["H1544","and your idols",152,166],["H7665","may be broken",167,180],["H7673","and cease",181,190],["H2553","and your images",192,207],["H1438","may be cut down",208,223],["H4639","and your works",225,239],["H4229","may be abolished",240,256]]},"6:7":{"text":"And the slain shall fall in the midst of you, and ye shall know that I am the LORD.","words":[["H2491","And the slain",0,13],["H5307","shall fall",14,24],["H8432","in the midst",25,37],["H3045","of you, and ye shall know",38,63],["H3068","that I am the LORD",64,82]]},"6:8":{"text":"Yet will I leave a remnant, that ye may have some that shall escape the sword among the nations, when ye shall be scattered through the countries.","words":[["H3498","Yet will I leave a remnant",0,26],["H6412","that ye may have some that shall escape",28,67],["H2719","the sword",68,77],["H1471","among the nations",78,95],["H2219","when ye shall be scattered",97,123],["H0776","through the countries",124,145]]},"6:9":{"text":"And they that escape of you shall remember me among the nations whither they shall be carried captives, because I am broken with their whorish heart, which hath departed from me, and with their eyes, which go a whoring after their idols: and they shall lothe themselves for the evils which they have committed in all their abominations.","words":[["H6412","And they that escape",0,20],["H2142","of you shall remember",21,42],["H1471","me among the nations",43,63],["H7617","whither they shall be carried captives",64,102],["H7665","because I am broken",104,123],["H2181","with their whorish",124,142],["H3820","heart",143,148],["H5493","which hath departed",150,169],["H5869","from me, and with their eyes",170,198],["H2181","which go a whoring",200,218],["H0310","after",219,224],["H1544","their idols",225,236],["H6962","and they shall lothe",238,258],["H6440","themselves",259,269],["H7451","for the evils",270,283],["H6213","which they have committed",284,309],["H8441","in all their abominations",310,335]]},"6:10":{"text":"And they shall know that I am the LORD, and that I have not said in vain that I would do this evil unto them.","words":[["H3045","And they shall know",0,19],["H3068","that I am the LORD",20,38],["H1696","and that I have not said",40,64],["H2600","in vain",65,72],["H6213","that I would do",73,88],["H7451","this evil",89,98]]},"6:11":{"text":"Thus saith the Lord GOD; Smite with thine hand, and stamp with thy foot, and say, Alas for all the evil abominations of the house of Israel! for they shall fall by the sword, by the famine, and by the pestilence.","words":[["H0559","Thus saith",0,10],["H0136","the Lord",11,19],["H3069","GOD",20,23],["H5221","Smite",25,30],["H3709","with thine hand",31,46],["H7554","and stamp",48,57],["H7272","with thy foot",58,71],["H0559","and say",73,80],["H0253","Alas",82,86],["H7451","for all the evil",87,103],["H8441","abominations",104,116],["H1004","of the house",117,129],["H3478","of Israel",130,139],["H5307","for they shall fall",141,160],["H2719","by the sword",161,173],["H7458","by the famine",175,188],["H1698","and by the pestilence",190,211]]},"6:12":{"text":"He that is far off shall die of the pestilence; and he that is near shall fall by the sword; and he that remaineth and is besieged shall die by the famine: thus will I accomplish my fury upon them.","words":[["H7350","He that is far off",0,18],["H4191","shall die",19,28],["H1698","of the pestilence",29,46],["H7138","and he that is near",48,67],["H5307","shall fall",68,78],["H2719","by the sword",79,91],["H7604","and he that remaineth",93,114],["H5341","and is besieged",115,130],["H4191","shall die",131,140],["H7458","by the famine",141,154],["H3615","thus will I accomplish",156,178],["H2534","my fury",179,186]]},"6:13":{"text":"Then shall ye know that I am the LORD, when their slain men shall be among their idols round about their altars, upon every high hill, in all the tops of the mountains, and under every green tree, and under every thick oak, the place where they did offer sweet savour to all their idols.","words":[["H3045","Then shall ye know",0,18],["H3068","that I am the LORD",19,37],["H2491","when their slain",39,55],["H8432","men shall be among",56,74],["H1544","their idols",75,86],["H5439","round about",87,98],["H4196","their altars",99,111],["H7311","upon every high",113,128],["H1389","hill",129,133],["H7218","in all the tops",135,150],["H2022","of the mountains",151,167],["H7488","and under every green",169,190],["H6086","tree",191,195],["H5687","and under every thick",197,218],["H0424","oak",219,222],["H4725","the place",224,233],["H5414","where they did offer",234,254],["H5207","sweet",255,260],["H7381","savour",261,267],["H1544","to all their idols",268,286]]},"6:14":{"text":"So will I stretch out my hand upon them, and make the land desolate, yea, more desolate than the wilderness toward Diblath, in all their habitations: and they shall know that I am the LORD.","words":[["H5186","So will I stretch out",0,21],["H3027","my hand",22,29],["H5414","upon them, and make",30,49],["H0776","the land",50,58],["H8077","desolate",59,67],["H4923","yea, more desolate",69,87],["H4057","than the wilderness",88,107],["H1689","toward Diblath",108,122],["H4186","in all their habitations",124,148],["H3045","and they shall know",150,169],["H3068","that I am the LORD",170,188]]},"7:1":{"text":"Moreover the word of the LORD came unto me, saying,","words":[["H1697","Moreover the word",0,17],["H3068","of the LORD",18,29],["H0559","came unto me, saying",30,50]]},"7:2":{"text":"Also, thou son of man, thus saith the Lord GOD unto the land of Israel; An end, the end is come upon the four corners of the land.","words":[["H1121","Also, thou son",0,14],["H0120","of man",15,21],["H0559","thus saith",23,33],["H0136","the Lord",34,42],["H3069","GOD",43,46],["H0127","unto the land",47,60],["H3478","of Israel",61,70],["H7093","An end",72,78],["H7093","the end",80,87],["H0935","is come",88,95],["H0702","upon the four",96,109],["H3671","corners",110,117],["H0776","of the land",118,129]]},"7:3":{"text":"Now is the end come upon thee, and I will send mine anger upon thee, and will judge thee according to thy ways, and will recompense upon thee all thine abominations.","words":[["H7093","Now is the end",0,14],["H7971","come upon thee, and I will send",15,46],["H0639","mine anger",47,57],["H8199","upon thee, and will judge",58,83],["H1870","thee according to thy ways",84,110],["H5414","and will recompense",112,131],["H8441","upon thee all thine abominations",132,164]]},"7:4":{"text":"And mine eye shall not spare thee, neither will I have pity: but I will recompense thy ways upon thee, and thine abominations shall be in the midst of thee: and ye shall know that I am the LORD.","words":[["H5869","And mine eye",0,12],["H2347","shall not spare",13,28],["H2550","thee, neither will I have pity",29,59],["H5414","but I will recompense",61,82],["H1870","thy ways",83,91],["H8441","upon thee, and thine abominations",92,125],["H8432","shall be in the midst",126,147],["H3045","of thee: and ye shall know",148,174],["H3068","that I am the LORD",175,193]]},"7:5":{"text":"Thus saith the Lord GOD; An evil, an only evil, behold, is come.","words":[["H0559","Thus saith",0,10],["H0136","the Lord",11,19],["H3069","GOD",20,23],["H7451","An evil",25,32],["H0259","an only",34,41],["H7451","evil",42,46],["H0935","behold, is come",48,63]]},"7:6":{"text":"An end is come, the end is come: it watcheth for thee; behold, it is come.","words":[["H7093","An end",0,6],["H0935","is come",7,14],["H7093","the end",16,23],["H0935","is come",24,31],["H6974","it watcheth",33,44],["H0935","for thee; behold, it is come",45,73]]},"7:7":{"text":"The morning is come unto thee, O thou that dwellest in the land: the time is come, the day of trouble is near, and not the sounding again of the mountains.","words":[["H6843","The morning",0,11],["H0935","is come",12,19],["H3427","unto thee, O thou that dwellest",20,51],["H0776","in the land",52,63],["H6256","the time",65,73],["H0935","is come",74,81],["H0935","is come",74,81],["H3117","the day",83,90],["H4103","of trouble",91,101],["H7138","is near",102,109],["H1906","and not the sounding again",111,137],["H2022","of the mountains",138,154]]},"7:8":{"text":"Now will I shortly pour out my fury upon thee, and accomplish mine anger upon thee: and I will judge thee according to thy ways, and will recompense thee for all thine abominations.","words":[["H7138","Now will I shortly",0,18],["H8210","pour out",19,27],["H2534","my fury",28,35],["H3615","upon thee, and accomplish",36,61],["H0639","mine anger",62,72],["H8199","upon thee: and I will judge",73,100],["H1870","thee according to thy ways",101,127],["H5414","and will recompense",129,148],["H8441","thee for all thine abominations",149,180]]},"7:9":{"text":"And mine eye shall not spare, neither will I have pity: I will recompense thee according to thy ways and thine abominations that are in the midst of thee; and ye shall know that I am the LORD that smiteth.","words":[["H5869","And mine eye",0,12],["H2347","shall not spare",13,28],["H2550","neither will I have pity",30,54],["H5414","I will recompense",56,73],["H1870","thee according to thy ways",74,100],["H8441","and thine abominations",101,123],["H8432","that are in the midst",124,145],["H3045","of thee; and ye shall know",146,172],["H3068","that I am the LORD",173,191],["H5221","that smiteth",192,204]]},"7:10":{"text":"Behold the day, behold, it is come: the morning is gone forth; the rod hath blossomed, pride hath budded.","words":[["H3117","Behold the day",0,14],["H0935","behold, it is come",16,34],["H6843","the morning",36,47],["H3318","is gone forth",48,61],["H4294","the rod",63,70],["H6692","hath blossomed",71,85],["H2087","pride",87,92],["H6524","hath budded",93,104]]},"7:11":{"text":"Violence is risen up into a rod of wickedness: none of them shall remain, nor of their multitude, nor of any of theirs: neither shall there be wailing for them.","words":[["H2555","Violence",0,8],["H6965","is risen up",9,20],["H4294","into a rod",21,31],["H7562","of wickedness",32,45],["H1995","none of them shall remain, nor of their multitude",47,96],["H1991","nor of any",98,108],["H5089","of theirs: neither shall there be wailing",109,150]]},"7:12":{"text":"The time is come, the day draweth near: let not the buyer rejoice, nor the seller mourn: for wrath is upon all the multitude thereof.","words":[["H6256","The time",0,8],["H0935","is come",9,16],["H3117","the day",18,25],["H5060","draweth near",26,38],["H7069","let not the buyer",40,57],["H8055","rejoice",58,65],["H4376","nor the seller",67,81],["H0056","mourn",82,87],["H2740","for wrath",89,98],["H1995","is upon all the multitude",99,124]]},"7:13":{"text":"For the seller shall not return to that which is sold, although they were yet alive: for the vision is touching the whole multitude thereof, which shall not return; neither shall any strengthen himself in the iniquity of his life.","words":[["H4376","For the seller",0,14],["H7725","shall not return",15,31],["H4465","to that which is sold",32,53],["H2416","although they were yet alive",55,83],["H2377","for the vision",85,99],["H1995","is touching the whole multitude",100,131],["H7725","thereof, which shall not return",132,163],["H0376","neither shall any",165,182],["H2388","strengthen",183,193],["H5771","himself in the iniquity",194,217],["H2416","of his life",218,229]]},"7:14":{"text":"They have blown the trumpet, even to make all ready; but none goeth to the battle: for my wrath is upon all the multitude thereof.","words":[["H8628","They have blown",0,15],["H8619","the trumpet",16,27],["H3559","even to make all ready",29,51],["H1980","but none goeth",53,67],["H4421","to the battle",68,81],["H2740","for my wrath",83,95],["H1995","is upon all the multitude",96,121]]},"7:15":{"text":"The sword is without, and the pestilence and the famine within: he that is in the field shall die with the sword; and he that is in the city, famine and pestilence shall devour him.","words":[["H2719","The sword",0,9],["H2351","is without",10,20],["H1698","and the pestilence",22,40],["H7458","and the famine",41,55],["H1004","within",56,62],["H7704","he that is in the field",64,87],["H4191","shall die",88,97],["H2719","with the sword",98,112],["H5892","and he that is in the city",114,140],["H7458","famine",142,148],["H1698","and pestilence",149,163],["H0398","shall devour",164,176]]},"7:16":{"text":"But they that escape of them shall escape, and shall be on the mountains like doves of the valleys, all of them mourning, every one for his iniquity.","words":[["H6403","But they that escape",0,20],["H6412","of them shall escape",21,41],["H2022","and shall be on the mountains",43,72],["H3123","like doves",73,83],["H1516","of the valleys",84,98],["H1993","all of them mourning",100,120],["H0376","every one",122,131],["H5771","for his iniquity",132,148]]},"7:17":{"text":"All hands shall be feeble, and all knees shall be weak as water.","words":[["H3027","All hands",0,9],["H7503","shall be feeble",10,25],["H1290","and all knees",27,40],["H3212","shall be weak",41,54],["H4325","as water",55,63]]},"7:18":{"text":"They shall also gird themselves with sackcloth, and horror shall cover them; and shame shall be upon all faces, and baldness upon all their heads.","words":[["H2296","They shall also gird",0,20],["H8242","themselves with sackcloth",21,46],["H6427","and horror",48,58],["H3680","shall cover",59,70],["H0955","them; and shame",71,86],["H6440","shall be upon all faces",87,110],["H7144","and baldness",112,124],["H7218","upon all their heads",125,145]]},"7:19":{"text":"They shall cast their silver in the streets, and their gold shall be removed: their silver and their gold shall not be able to deliver them in the day of the wrath of the LORD: they shall not satisfy their souls, neither fill their bowels: because it is the stumblingblock of their iniquity.","words":[["H7993","They shall cast",0,15],["H3701","their silver",16,28],["H2351","in the streets",29,43],["H2091","and their gold",45,59],["H5079","shall be removed",60,76],["H3701","their silver",78,90],["H2091","and their gold",91,105],["H3201","shall not be able",106,123],["H5337","to deliver",124,134],["H3117","them in the day",135,150],["H5678","of the wrath",151,163],["H3068","of the LORD",164,175],["H7646","they shall not satisfy",177,199],["H5315","their souls",200,211],["H4390","neither fill",213,225],["H4578","their bowels",226,238],["H4383","because it is the stumblingblock",240,272],["H5771","of their iniquity",273,290]]},"7:20":{"text":"As for the beauty of his ornament, he set it in majesty: but they made the images of their abominations and of their detestable things therein: therefore have I set it far from them.","words":[["H6643","As for the beauty",0,17],["H5716","of his ornament",18,33],["H7760","he set",35,41],["H1347","it in majesty",42,55],["H6213","but they made",57,70],["H6754","the images",71,81],["H8441","of their abominations",82,103],["H8251","and of their detestable things",104,134],["H5414","therein: therefore have I set",135,164],["H5079","it far",165,171]]},"7:21":{"text":"And I will give it into the hands of the strangers for a prey, and to the wicked of the earth for a spoil; and they shall pollute it.","words":[["H5414","And I will give",0,15],["H3027","it into the hands",16,33],["H2114","of the strangers",34,50],["H0957","for a prey",51,61],["H7563","and to the wicked",63,80],["H0776","of the earth",81,93],["H7998","for a spoil",94,105],["H2490","and they shall pollute",107,129]]},"7:22":{"text":"My face will I turn also from them, and they shall pollute my secret place: for the robbers shall enter into it, and defile it.","words":[["H6440","My face",0,7],["H5437","will I turn",8,19],["H2490","also from them, and they shall pollute",20,58],["H6845","my secret",59,68],["H6530","place: for the robbers",69,91],["H0935","shall enter",92,103],["H2490","into it, and defile",104,123]]},"7:23":{"text":"Make a chain: for the land is full of bloody crimes, and the city is full of violence.","words":[["H6213","Make",0,4],["H7569","a chain",5,12],["H0776","for the land",14,26],["H4390","is full",27,34],["H1818","of bloody",35,44],["H4941","crimes",45,51],["H5892","and the city",53,65],["H4390","is full",66,73],["H2555","of violence",74,85]]},"7:24":{"text":"Wherefore I will bring the worst of the heathen, and they shall possess their houses: I will also make the pomp of the strong to cease; and their holy places shall be defiled.","words":[["H0935","Wherefore I will bring",0,22],["H7451","the worst",23,32],["H1471","of the heathen",33,47],["H3423","and they shall possess",49,71],["H1004","their houses",72,84],["H1347","I will also make the pomp",86,111],["H5794","of the strong",112,125],["H7673","to cease",126,134],["H6942","and their holy places",136,157],["H2490","shall be defiled",158,174],["H5157","shall be defiled",158,174]]},"7:25":{"text":"Destruction cometh; and they shall seek peace, and there shall be none.","words":[["H7089","Destruction",0,11],["H0935","cometh",12,18],["H1245","and they shall seek",20,39],["H7965","peace",40,45]]},"7:26":{"text":"Mischief shall come upon mischief, and rumour shall be upon rumour; then shall they seek a vision of the prophet; but the law shall perish from the priest, and counsel from the ancients.","words":[["H1943","Mischief",0,8],["H0935","shall come",9,19],["H1943","upon mischief",20,33],["H8052","and rumour",35,45],["H8052","shall be upon rumour",46,66],["H1245","then shall they seek",68,88],["H2377","a vision",89,97],["H5030","of the prophet",98,112],["H8451","but the law",114,125],["H0006","shall perish",126,138],["H3548","from the priest",139,154],["H6098","and counsel",156,167],["H2205","from the ancients",168,185]]},"7:27":{"text":"The king shall mourn, and the prince shall be clothed with desolation, and the hands of the people of the land shall be troubled: I will do unto them after their way, and according to their deserts will I judge them; and they shall know that I am the LORD.","words":[["H4428","The king",0,8],["H0056","shall mourn",9,20],["H5387","and the prince",22,36],["H3847","shall be clothed",37,53],["H8077","with desolation",54,69],["H3027","and the hands",71,84],["H5971","of the people",85,98],["H0776","of the land",99,110],["H0926","shall be troubled",111,128],["H6213","I will do",130,139],["H1870","unto them after their way",140,165],["H4941","and according to their deserts",167,197],["H8199","will I judge",198,210],["H3045","them; and they shall know",211,236],["H3068","that I am the LORD",237,255]]},"8:1":{"text":"And it came to pass in the sixth year, in the sixth month, in the fifth day of the month, as I sat in mine house, and the elders of Judah sat before me, that the hand of the Lord GOD fell there upon me.","words":[["H8345","And it came to pass in the sixth",0,32],["H8141","year",33,37],["H8345","in the sixth",39,51],["H2568","month, in the fifth",52,71],["H2320","day of the month",72,88],["H3427","as I sat",90,98],["H1004","in mine house",99,112],["H2205","and the elders",114,128],["H3063","of Judah",129,137],["H3427","sat",138,141],["H6440","before",142,148],["H3027","me, that the hand",149,166],["H0136","of the Lord",167,178],["H3069","GOD",179,182],["H5307","fell",183,187]]},"8:2":{"text":"Then I beheld, and lo a likeness as the appearance of fire: from the appearance of his loins even downward, fire; and from his loins even upward, as the appearance of brightness, as the colour of amber.","words":[["H7200","Then I beheld",0,13],["H1823","and lo a likeness",15,32],["H4758","as the appearance",33,50],["H0784","of fire",51,58],["H4758","from the appearance",60,79],["H4975","of his loins",80,92],["H4295","even downward",93,106],["H0784","fire",108,112],["H4975","and from his loins",114,132],["H4605","even upward",133,144],["H4758","as the appearance",146,163],["H2096","of brightness",164,177],["H5869","as the colour",179,192],["H2830","of amber",193,201]]},"8:3":{"text":"And he put forth the form of an hand, and took me by a lock of mine head; and the spirit lifted me up between the earth and the heaven, and brought me in the visions of God to Jerusalem, to the door of the inner gate that looketh toward the north; where was the seat of the image of jealousy, which provoketh to jealousy.","words":[["H7971","And he put forth",0,16],["H8403","the form",17,25],["H3027","of an hand",26,36],["H3947","and took",38,46],["H6734","me by a lock",47,59],["H7218","of mine head",60,72],["H7307","and the spirit",74,88],["H5375","lifted me up",89,101],["H0776","between the earth",102,119],["H8064","and the heaven",120,134],["H0935","and brought",136,147],["H4759","me in the visions",148,165],["H0430","of God",166,172],["H3389","to Jerusalem",173,185],["H6607","to the door",187,198],["H6442","of the inner",199,211],["H8179","gate",212,216],["H6437","that looketh",217,229],["H6828","toward the north",230,246],["H4186","where was the seat",248,266],["H5566","of the image",267,279],["H7068","of jealousy",280,291],["H7069","which provoketh to jealousy",293,320]]},"8:4":{"text":"And, behold, the glory of the God of Israel was there, according to the vision that I saw in the plain.","words":[["H3519","And, behold, the glory",0,22],["H0430","of the God",23,33],["H3478","of Israel",34,43],["H4758","was there, according to the vision",44,78],["H7200","that I saw",79,89],["H1237","in the plain",90,102]]},"8:5":{"text":"Then said he unto me, Son of man, lift up thine eyes now the way toward the north. So I lifted up mine eyes the way toward the north, and behold northward at the gate of the altar this image of jealousy in the entry.","words":[["H0559","Then said",0,9],["H1121","he unto me, Son",10,25],["H0120","of man",26,32],["H5375","lift up",34,41],["H5869","thine eyes",42,52],["H1870","now the way",53,64],["H6828","toward the north",65,81],["H5375","So I lifted up",83,97],["H5869","mine eyes",98,107],["H1870","the way",108,115],["H6828","toward the north",116,132],["H6828","and behold northward",134,154],["H8179","at the gate",155,166],["H4196","of the altar",167,179],["H5566","this image",180,190],["H7068","of jealousy",191,202],["H0872","in the entry",203,215]]},"8:6":{"text":"He said furthermore unto me, Son of man, seest thou what they do? even the great abominations that the house of Israel committeth here, that I should go far off from my sanctuary? but turn thee yet again, and thou shalt see greater abominations.","words":[["H0559","He said",0,7],["H1121","furthermore unto me, Son",8,32],["H0120","of man",33,39],["H7200","seest",41,46],["H6213","thou what they do",47,64],["H1419","even the great",66,80],["H8441","abominations",81,93],["H1004","that the house",94,108],["H3478","of Israel",109,118],["H6213","committeth",119,129],["H7368","here, that I should go far off",130,160],["H4720","from my sanctuary",161,178],["H7725","but turn",180,188],["H7200","thee yet again, and thou shalt see",189,223],["H1419","greater",224,231],["H8441","abominations",232,244]]},"8:7":{"text":"And he brought me to the door of the court; and when I looked, behold a hole in the wall.","words":[["H0935","And he brought",0,14],["H6607","me to the door",15,29],["H2691","of the court",30,42],["H7200","and when I looked",44,61],["H0259","behold a",63,71],["H2356","hole",72,76],["H7023","in the wall",77,88]]},"8:8":{"text":"Then said he unto me, Son of man, dig now in the wall: and when I had digged in the wall, behold a door.","words":[["H0559","Then said",0,9],["H1121","he unto me, Son",10,25],["H0120","of man",26,32],["H2864","dig",34,37],["H7023","now in the wall",38,53],["H2864","and when I had digged",55,76],["H7023","in the wall",77,88],["H0259","behold a",90,98],["H6607","door",99,103]]},"8:9":{"text":"And he said unto me, Go in, and behold the wicked abominations that they do here.","words":[["H0559","And he said",0,11],["H0935","unto me, Go in",12,26],["H7200","and behold",28,38],["H7451","the wicked",39,49],["H8441","abominations",50,62],["H6213","that they do",63,75]]},"8:10":{"text":"So I went in and saw; and behold every form of creeping things, and abominable beasts, and all the idols of the house of Israel, pourtrayed upon the wall round about.","words":[["H0935","So I went in",0,12],["H7200","and saw",13,20],["H8403","and behold every form",22,43],["H7431","of creeping things",44,62],["H8263","and abominable",64,78],["H0929","beasts",79,85],["H1544","and all the idols",87,104],["H1004","of the house",105,117],["H3478","of Israel",118,127],["H2707","pourtrayed",129,139],["H7023","upon the wall",140,153],["H5439","round about",154,165]]},"8:11":{"text":"And there stood before them seventy men of the ancients of the house of Israel, and in the midst of them stood Jaazaniah the son of Shaphan, with every man his censer in his hand; and a thick cloud of incense went up.","words":[["H5975","And there stood",0,15],["H6440","before",16,22],["H7657","them seventy",23,35],["H0376","men",36,39],["H2205","of the ancients",40,55],["H1004","of the house",56,68],["H3478","of Israel",69,78],["H8432","and in the midst",80,96],["H5975","of them stood",97,110],["H2970","Jaazaniah",111,120],["H1121","the son",121,128],["H8227","of Shaphan",129,139],["H0376","with every man",141,155],["H4730","his censer",156,166],["H3027","in his hand",167,178],["H6282","and a thick",180,191],["H6051","cloud",192,197],["H7004","of incense",198,208],["H5927","went up",209,216]]},"8:12":{"text":"Then said he unto me, Son of man, hast thou seen what the ancients of the house of Israel do in the dark, every man in the chambers of his imagery? for they say, The LORD seeth us not; the LORD hath forsaken the earth.","words":[["H0559","Then said",0,9],["H1121","he unto me, Son",10,25],["H0120","of man",26,32],["H7200","hast thou seen",34,48],["H2205","what the ancients",49,66],["H1004","of the house",67,79],["H3478","of Israel",80,89],["H6213","do",90,92],["H2822","in the dark",93,104],["H0376","every man",106,115],["H2315","in the chambers",116,131],["H4906","of his imagery",132,146],["H0559","for they say",148,160],["H3068","The LORD",162,170],["H7200","seeth",171,176],["H3068","us not; the LORD",177,193],["H5800","hath forsaken",194,207],["H0776","the earth",208,217]]},"8:13":{"text":"He said also unto me, Turn thee yet again, and thou shalt see greater abominations that they do.","words":[["H0559","He said",0,7],["H7725","also unto me, Turn",8,26],["H7200","thee yet again, and thou shalt see",27,61],["H1419","greater",62,69],["H8441","abominations",70,82],["H6213","that they do",83,95]]},"8:14":{"text":"Then he brought me to the door of the gate of the LORD'S house which was toward the north; and, behold, there sat women weeping for Tammuz.","words":[["H0935","Then he brought",0,15],["H6607","me to the door",16,30],["H8179","of the gate",31,42],["H3068","of the LORD'S",43,56],["H1004","house",57,62],["H6828","which was toward the north",63,89],["H3427","and, behold, there sat",91,113],["H0802","women",114,119],["H1058","weeping",120,127],["H8542","for Tammuz",128,138]]},"8:15":{"text":"Then said he unto me, Hast thou seen this, O son of man? turn thee yet again, and thou shalt see greater abominations than these.","words":[["H0559","Then said",0,9],["H7200","he unto me, Hast thou seen",10,36],["H1121","this, O son",37,48],["H0120","of man",49,55],["H7725","turn",57,61],["H7200","thee yet again, and thou shalt see",62,96],["H1419","greater",97,104],["H8441","abominations",105,117]]},"8:16":{"text":"And he brought me into the inner court of the LORD'S house, and, behold, at the door of the temple of the LORD, between the porch and the altar, were about five and twenty men, with their backs toward the temple of the LORD, and their faces toward the east; and they worshipped the sun toward the east.","words":[["H0935","And he brought",0,14],["H6442","me into the inner",15,32],["H2691","court",33,38],["H3068","of the LORD'S",39,52],["H1004","house",53,58],["H6607","and, behold, at the door",60,84],["H1964","of the temple",85,98],["H3068","of the LORD",99,110],["H0197","between the porch",112,129],["H4196","and the altar",130,143],["H2568","were about five",145,160],["H6242","and twenty",161,171],["H0376","men",172,175],["H0268","with their backs",177,193],["H1964","toward the temple",194,211],["H3068","of the LORD",212,223],["H6440","and their faces",225,240],["H6924","toward the east",241,256],["H7812","and they worshipped",258,277],["H8121","the sun",278,285],["H6924","toward the east",286,301]]},"8:17":{"text":"Then he said unto me, Hast thou seen this, O son of man? Is it a light thing to the house of Judah that they commit the abominations which they commit here? for they have filled the land with violence, and have returned to provoke me to anger: and, lo, they put the branch to their nose.","words":[["H0559","Then he said",0,12],["H7200","unto me, Hast thou seen",13,36],["H1121","this, O son",37,48],["H0120","of man",49,55],["H7043","Is it a light thing",57,76],["H1004","to the house",77,89],["H3063","of Judah",90,98],["H6213","that they commit",99,115],["H8441","the abominations",116,132],["H6213","which they commit",133,150],["H4390","here? for they have filled",151,177],["H0776","the land",178,186],["H2555","with violence",187,200],["H7725","and have returned",202,219],["H3707","to provoke me to anger",220,242],["H7971","and, lo, they put",244,261],["H2156","the branch",262,272],["H0639","to their nose",273,286]]},"8:18":{"text":"Therefore will I also deal in fury: mine eye shall not spare, neither will I have pity: and though they cry in mine ears with a loud voice, yet will I not hear them.","words":[["H6213","Therefore will I also deal",0,26],["H2534","in fury",27,34],["H5869","mine eye",36,44],["H2347","shall not spare",45,60],["H2550","neither will I have pity",62,86],["H7121","and though they cry",88,107],["H0241","in mine ears",108,120],["H1419","with a loud",121,132],["H6963","voice",133,138],["H8085","yet will I not hear",140,159]]},"9:1":{"text":"He cried also in mine ears with a loud voice, saying, Cause them that have charge over the city to draw near, even every man with his destroying weapon in his hand.","words":[["H7121","He cried",0,8],["H0241","also in mine ears",9,26],["H1419","with a loud",27,38],["H6963","voice",39,44],["H0559","saying",46,52],["H6486","Cause them that have charge",54,81],["H5892","over the city",82,95],["H7126","to draw near",96,108],["H0376","even every man",110,124],["H4892","with his destroying",125,144],["H3627","weapon",145,151],["H3027","in his hand",152,163]]},"9:2":{"text":"And, behold, six men came from the way of the higher gate, which lieth toward the north, and every man a slaughter weapon in his hand; and one man among them was clothed with linen, with a writer's inkhorn by his side: and they went in, and stood beside the brasen altar.","words":[["H8337","And, behold, six",0,16],["H0582","men",17,20],["H0935","came",21,25],["H1870","from the way",26,38],["H5945","of the higher",39,52],["H8179","gate",53,57],["H6437","which lieth",59,70],["H6828","toward the north",71,87],["H0376","and every man",89,102],["H4660","a slaughter",103,114],["H3627","weapon",115,121],["H3027","in his hand",122,133],["H0259","and one",135,142],["H0376","man",143,146],["H8432","among",147,152],["H3847","them was clothed",153,169],["H0906","with linen",170,180],["H5608","with a writer's",182,197],["H7083","inkhorn",198,205],["H4975","by his side",206,217],["H0935","and they went in",219,235],["H5975","and stood",237,246],["H0681","beside",247,253],["H5178","the brasen",254,264],["H4196","altar",265,270]]},"9:3":{"text":"And the glory of the God of Israel was gone up from the cherub, whereupon he was, to the threshold of the house. And he called to the man clothed with linen, which had the writer's inkhorn by his side;","words":[["H3519","And the glory",0,13],["H0430","of the God",14,24],["H3478","of Israel",25,34],["H5927","was gone up",35,46],["H3742","from the cherub",47,62],["H4670","whereupon he was, to the threshold",64,98],["H1004","of the house",99,111],["H7121","And he called",113,126],["H0376","to the man",127,137],["H3847","clothed",138,145],["H0906","with linen",146,156],["H5608","which had the writer's",158,180],["H7083","inkhorn",181,188],["H4975","by his side",189,200]]},"9:4":{"text":"And the LORD said unto him, Go through the midst of the city, through the midst of Jerusalem, and set a mark upon the foreheads of the men that sigh and that cry for all the abominations that be done in the midst thereof.","words":[["H3068","And the LORD",0,12],["H0559","said",13,17],["H5674","unto him, Go through",18,38],["H8432","the midst",39,48],["H5892","of the city",49,60],["H8432","through the midst",62,79],["H3389","of Jerusalem",80,92],["H8427","and set",94,101],["H8420","a mark",102,108],["H4696","upon the foreheads",109,127],["H0582","of the men",128,138],["H0584","that sigh",139,148],["H0602","and that cry",149,161],["H8441","for all the abominations",162,186],["H6213","that be done",187,199],["H8432","in the midst",200,212]]},"9:5":{"text":"And to the others he said in mine hearing, Go ye after him through the city, and smite: let not your eye spare, neither have ye pity:","words":[["H0428","And to the others",0,17],["H0559","he said",18,25],["H0241","in mine hearing",26,41],["H5674","Go",43,45],["H0310","ye after",46,54],["H5892","him through the city",55,75],["H5221","and smite",77,86],["H5869","let not your eye",88,104],["H2347","spare",105,110],["H2550","neither have ye pity",112,132]]},"9:6":{"text":"Slay utterly old and young, both maids, and little children, and women: but come not near any man upon whom is the mark; and begin at my sanctuary. Then they began at the ancient men which were before the house.","words":[["H2026","Slay",0,4],["H4889","utterly",5,12],["H2205","old",13,16],["H0970","and young",17,26],["H1330","both maids",28,38],["H2945","and little children",40,59],["H0802","and women",61,70],["H5066","but come not near",72,89],["H0376","any man",90,97],["H8420","upon whom is the mark",98,119],["H2490","and begin",121,130],["H4720","at my sanctuary",131,146],["H2490","Then they began",148,163],["H2205","at the ancient",164,178],["H0582","men",179,182],["H6440","which were before",183,200],["H1004","the house",201,210]]},"9:7":{"text":"And he said unto them, Defile the house, and fill the courts with the slain: go ye forth. And they went forth, and slew in the city.","words":[["H0559","And he said",0,11],["H2930","unto them, Defile",12,29],["H1004","the house",30,39],["H4390","and fill",41,49],["H2691","the courts",50,60],["H2491","with the slain",61,75],["H3318","go ye forth",77,88],["H3318","And they went forth",90,109],["H5221","and slew",111,119],["H5892","in the city",120,131]]},"9:8":{"text":"And it came to pass, while they were slaying them, and I was left, that I fell upon my face, and cried, and said, Ah Lord GOD! wilt thou destroy all the residue of Israel in thy pouring out of thy fury upon Jerusalem?","words":[["H5221","And it came to pass, while they were slaying",0,44],["H7604","them, and I was left",45,65],["H5307","that I fell",67,78],["H6440","upon my face",79,91],["H2199","and cried",93,102],["H0559","and said",104,112],["H0162","Ah",114,116],["H0136","Lord",117,121],["H3069","GOD",122,125],["H7843","wilt thou destroy",127,144],["H7611","all the residue",145,160],["H3478","of Israel",161,170],["H8210","in thy pouring out",171,189],["H2534","of thy fury",190,201],["H3389","upon Jerusalem",202,216]]},"9:9":{"text":"Then said he unto me, The iniquity of the house of Israel and Judah is exceeding great, and the land is full of blood, and the city full of perverseness: for they say, The LORD hath forsaken the earth, and the LORD seeth not.","words":[["H0559","Then said",0,9],["H5771","he unto me, The iniquity",10,34],["H1004","of the house",35,47],["H3478","of Israel",48,57],["H3063","and Judah",58,67],["H3966","is exceeding",68,80],["H3966","is exceeding",68,80],["H1419","great",81,86],["H0776","and the land",88,100],["H4390","is full",101,108],["H1818","of blood",109,117],["H5892","and the city",119,131],["H4390","full",132,136],["H4297","of perverseness",137,152],["H0559","for they say",154,166],["H3068","The LORD",168,176],["H5800","hath forsaken",177,190],["H0776","the earth",191,200],["H3068","and the LORD",202,214],["H7200","seeth",215,220]]},"9:10":{"text":"And as for me also, mine eye shall not spare, neither will I have pity, but I will recompense their way upon their head.","words":[["H5869","And as for me also, mine eye",0,28],["H2347","shall not spare",29,44],["H2550","neither will I have pity",46,70],["H5414","but I will recompense",72,93],["H1870","their way",94,103],["H7218","upon their head",104,119]]},"9:11":{"text":"And, behold, the man clothed with linen, which had the inkhorn by his side, reported the matter, saying, I have done as thou hast commanded me.","words":[["H0376","And, behold, the man",0,20],["H3847","clothed",21,28],["H0906","with linen",29,39],["H7083","which had the inkhorn",41,62],["H4975","by his side",63,74],["H7725","reported",76,84],["H1697","the matter",85,95],["H0559","saying",97,103],["H6213","I have done",105,116],["H6680","as thou hast commanded",117,139]]},"10:1":{"text":"Then I looked, and, behold, in the firmament that was above the head of the cherubims there appeared over them as it were a sapphire stone, as the appearance of the likeness of a throne.","words":[["H7200","Then I looked",0,13],["H7549","and, behold, in the firmament",15,44],["H7218","that was above the head",45,68],["H3742","of the cherubims",69,85],["H7200","there appeared",86,100],["H5601","over them as it were a sapphire",101,132],["H0068","stone",133,138],["H4758","as the appearance",140,157],["H1823","of the likeness",158,173],["H3678","of a throne",174,185]]},"10:2":{"text":"And he spake unto the man clothed with linen, and said, Go in between the wheels, even under the cherub, and fill thine hand with coals of fire from between the cherubims, and scatter them over the city. And he went in in my sight.","words":[["H0559","And he spake",0,12],["H0376","unto the man",13,25],["H3847","clothed",26,33],["H0906","with linen",34,44],["H0559","and said",46,54],["H0935","Go in",56,61],["H0996","between",62,69],["H1534","the wheels",70,80],["H3742","even under the cherub",82,103],["H4390","and fill",105,113],["H2651","thine hand",114,124],["H1513","with coals",125,135],["H0784","of fire",136,143],["H0996","from between",144,156],["H3742","the cherubims",157,170],["H2236","and scatter",172,183],["H5892","them over the city",184,202],["H0935","And he went in",204,218],["H5869","in my sight",219,230]]},"10:3":{"text":"Now the cherubims stood on the right side of the house, when the man went in; and the cloud filled the inner court.","words":[["H3742","Now the cherubims",0,17],["H5975","stood",18,23],["H3225","on the right side",24,41],["H1004","of the house",42,54],["H0376","when the man",56,68],["H0935","went in",69,76],["H6051","and the cloud",78,91],["H4390","filled",92,98],["H6442","the inner",99,108],["H2691","court",109,114]]},"10:4":{"text":"Then the glory of the LORD went up from the cherub, and stood over the threshold of the house; and the house was filled with the cloud, and the court was full of the brightness of the LORD'S glory.","words":[["H3519","Then the glory",0,14],["H3068","of the LORD",15,26],["H7311","went up",27,34],["H3742","from the cherub",35,50],["H4670","and stood over the threshold",52,80],["H1004","of the house",81,93],["H1004","and the house",95,108],["H4390","was filled",109,119],["H6051","with the cloud",120,134],["H2691","and the court",136,149],["H4390","was full",150,158],["H5051","of the brightness",159,176],["H3068","of the LORD'S",177,190],["H3519","glory",191,196]]},"10:5":{"text":"And the sound of the cherubims' wings was heard even to the outer court, as the voice of the Almighty God when he speaketh.","words":[["H6963","And the sound",0,13],["H3742","of the cherubims'",14,31],["H3671","wings",32,37],["H8085","was heard",38,47],["H2435","even to the outer",48,65],["H2691","court",66,71],["H6963","as the voice",73,85],["H7706","of the Almighty",86,101],["H0410","God",102,105],["H1696","when he speaketh",106,122]]},"10:6":{"text":"And it came to pass, that when he had commanded the man clothed with linen, saying, Take fire from between the wheels, from between the cherubims; then he went in, and stood beside the wheels.","words":[["H6680","And it came to pass, that when he had commanded",0,47],["H0376","the man",48,55],["H3847","clothed",56,63],["H0906","with linen",64,74],["H0559","saying",76,82],["H3947","Take",84,88],["H0784","fire",89,93],["H1534","from between the wheels",94,117],["H3742","from between the cherubims",119,145],["H0935","then he went in",147,162],["H5975","and stood",164,173],["H0681","beside",174,180],["H0212","the wheels",181,191]]},"10:7":{"text":"And one cherub stretched forth his hand from between the cherubims unto the fire that was between the cherubims, and took thereof, and put it into the hands of him that was clothed with linen: who took it, and went out.","words":[["H3742","And one cherub",0,14],["H7971","stretched forth",15,30],["H3027","his hand",31,39],["H3742","from between the cherubims",40,66],["H0784","unto the fire",67,80],["H3742","that was between the cherubims",81,111],["H5375","and took",113,121],["H5414","thereof, and put",122,138],["H2651","it into the hands",139,156],["H3847","of him that was clothed",157,180],["H0906","with linen",181,191],["H3947","who took",193,201],["H3318","it, and went out",202,218]]},"10:8":{"text":"And there appeared in the cherubims the form of a man's hand under their wings.","words":[["H7200","And there appeared",0,18],["H3742","in the cherubims",19,35],["H8403","the form",36,44],["H0120","of a man's",45,55],["H3027","hand",56,60],["H3671","under their wings",61,78]]},"10:9":{"text":"And when I looked, behold the four wheels by the cherubims, one wheel by one cherub, and another wheel by another cherub: and the appearance of the wheels was as the colour of a beryl stone.","words":[["H7200","And when I looked",0,17],["H0702","behold the four",19,34],["H0212","wheels",35,41],["H0681","by",42,44],["H3742","the cherubims",45,58],["H0259","one",60,63],["H0212","wheel",64,69],["H0681","by",70,72],["H0259","one",73,76],["H3742","cherub",77,83],["H0259","and another",85,96],["H0212","wheel",97,102],["H0681","by",103,105],["H0259","another",106,113],["H3742","cherub",114,120],["H4758","and the appearance",122,140],["H0212","of the wheels",141,154],["H5869","was as the colour",155,172],["H8658","of a beryl",173,183],["H0068","stone",184,189]]},"10:10":{"text":"And as for their appearances, they four had one likeness, as if a wheel had been in the midst of a wheel.","words":[["H4758","And as for their appearances",0,28],["H0702","they four",30,39],["H0259","had one",40,47],["H1823","likeness",48,56],["H0212","as if a wheel",58,71],["H8432","had been in the midst",72,93],["H0212","of a wheel",94,104]]},"10:11":{"text":"When they went, they went upon their four sides; they turned not as they went, but to the place whither the head looked they followed it; they turned not as they went.","words":[["H3212","When they went",0,14],["H3212","they went",16,25],["H0702","upon their four",26,41],["H7253","sides",42,47],["H5437","they turned",49,60],["H3212","not as they went",61,77],["H4725","but to the place",79,95],["H7218","whither the head",96,112],["H6437","looked",113,119],["H3212","they followed",120,133],["H0310","they followed",120,133],["H5437","it; they turned",134,149],["H3212","not as they went",150,166]]},"10:12":{"text":"And their whole body, and their backs, and their hands, and their wings, and the wheels, were full of eyes round about, even the wheels that they four had.","words":[["H1320","And their whole body",0,20],["H1354","and their backs",22,37],["H3027","and their hands",39,54],["H3671","and their wings",56,71],["H0212","and the wheels",73,87],["H4392","were full",89,98],["H5869","of eyes",99,106],["H5439","round about",107,118],["H0212","even the wheels",120,135],["H0702","that they four",136,150]]},"10:13":{"text":"As for the wheels, it was cried unto them in my hearing, O wheel.","words":[["H0212","As for the wheels",0,17],["H7121","it was cried",19,31],["H0241","unto them in my hearing",32,55],["H1534","O wheel",57,64]]},"10:14":{"text":"And every one had four faces: the first face was the face of a cherub, and the second face was the face of a man, and the third the face of a lion, and the fourth the face of an eagle.","words":[["H0259","And every one",0,13],["H0702","had four",14,22],["H6440","faces",23,28],["H0259","the first",30,39],["H6440","face",40,44],["H6440","was the face",45,57],["H3742","of a cherub",58,69],["H8145","and the second",71,85],["H6440","face",86,90],["H6440","was the face",91,103],["H0120","of a man",104,112],["H7992","and the third",114,127],["H6440","the face",128,136],["H0738","of a lion",137,146],["H7243","and the fourth",148,162],["H6440","the face",163,171],["H5404","of an eagle",172,183]]},"10:15":{"text":"And the cherubims were lifted up. This is the living creature that I saw by the river of Chebar.","words":[["H3742","And the cherubims",0,17],["H7426","were lifted up",18,32],["H2416","This is the living creature",34,61],["H7200","that I saw",62,72],["H5104","by the river",73,85],["H3529","of Chebar",86,95]]},"10:16":{"text":"And when the cherubims went, the wheels went by them: and when the cherubims lifted up their wings to mount up from the earth, the same wheels also turned not from beside them.","words":[["H3742","And when the cherubims",0,22],["H3212","went",23,27],["H0212","the wheels",29,39],["H3212","went",40,44],["H0681","by them",45,52],["H3742","and when the cherubims",54,76],["H5375","lifted up",77,86],["H3671","their wings",87,98],["H7311","to mount up",99,110],["H0776","from the earth",111,125],["H0212","the same wheels",127,142],["H1992","also",143,147],["H5437","turned",148,154],["H0681","not from beside",155,170]]},"10:17":{"text":"When they stood, these stood; and when they were lifted up, these lifted up themselves also: for the spirit of the living creature was in them.","words":[["H5975","When they stood",0,15],["H5975","these stood",17,28],["H7311","and when they were lifted up",30,58],["H7426","these lifted up",60,75],["H7307","themselves also: for the spirit",76,107],["H2416","of the living creature",108,130]]},"10:18":{"text":"Then the glory of the LORD departed from off the threshold of the house, and stood over the cherubims.","words":[["H3519","Then the glory",0,14],["H3068","of the LORD",15,26],["H3318","departed",27,35],["H4670","from off the threshold",36,58],["H1004","of the house",59,71],["H5975","and stood",73,82],["H3742","over the cherubims",83,101]]},"10:19":{"text":"And the cherubims lifted up their wings, and mounted up from the earth in my sight: when they went out, the wheels also were beside them, and every one stood at the door of the east gate of the LORD'S house; and the glory of the God of Israel was over them above.","words":[["H3742","And the cherubims",0,17],["H5375","lifted up",18,27],["H3671","their wings",28,39],["H7426","and mounted up",41,55],["H0776","from the earth",56,70],["H5869","in my sight",71,82],["H3318","when they went out",84,102],["H0212","the wheels",104,114],["H5980","also were beside",115,131],["H5975","them, and every one stood",132,157],["H6607","at the door",158,169],["H6931","of the east",170,181],["H8179","gate",182,186],["H3068","of the LORD'S",187,200],["H1004","house",201,206],["H3519","and the glory",208,221],["H0430","of the God",222,232],["H3478","of Israel",233,242],["H4605","was over them above",243,262]]},"10:20":{"text":"This is the living creature that I saw under the God of Israel by the river of Chebar; and I knew that they were the cherubims.","words":[["H2416","This is the living creature",0,27],["H7200","that I saw",28,38],["H0430","under the God",39,52],["H3478","of Israel",53,62],["H5104","by the river",63,75],["H3529","of Chebar",76,85],["H3045","and I knew",87,97],["H3742","that they were the cherubims",98,126]]},"10:21":{"text":"Every one had four faces apiece, and every one four wings; and the likeness of the hands of a man was under their wings.","words":[["H0259","Every one",0,9],["H0702","had four",10,18],["H6440","faces",19,24],["H0259","apiece",25,31],["H0259","and every one",33,46],["H0702","four",47,51],["H3671","wings",52,57],["H1823","and the likeness",59,75],["H3027","of the hands",76,88],["H0120","of a man",89,97],["H3671","was under their wings",98,119]]},"10:22":{"text":"And the likeness of their faces was the same faces which I saw by the river of Chebar, their appearances and themselves: they went every one straight forward.","words":[["H1823","And the likeness",0,16],["H6440","of their faces",17,31],["H1992","was the same",32,44],["H6440","faces",45,50],["H7200","which I saw",51,62],["H5104","by the river",63,75],["H3529","of Chebar",76,85],["H4758","their appearances",87,104],["H3212","and themselves: they went",105,130],["H0376","every one",131,140],["H5676","straight",141,149],["H6440","forward",150,157]]},"11:1":{"text":"Moreover the spirit lifted me up, and brought me unto the east gate of the LORD'S house, which looketh eastward: and behold at the door of the gate five and twenty men; among whom I saw Jaazaniah the son of Azur, and Pelatiah the son of Benaiah, princes of the people.","words":[["H7307","Moreover the spirit",0,19],["H5375","lifted me up",20,32],["H0935","and brought",34,45],["H6931","me unto the east",46,62],["H8179","gate",63,67],["H3068","of the LORD'S",68,81],["H1004","house",82,87],["H6437","which looketh",89,102],["H6921","eastward",103,111],["H6607","and behold at the door",113,135],["H8179","of the gate",136,147],["H2568","five",148,152],["H6242","and twenty",153,163],["H0376","men",164,167],["H8432","among",169,174],["H7200","whom I saw",175,185],["H2970","Jaazaniah",186,195],["H1121","the son",196,203],["H5809","of Azur",204,211],["H6410","and Pelatiah",213,225],["H1121","the son",226,233],["H1141","of Benaiah",234,244],["H8269","princes",246,253],["H5971","of the people",254,267]]},"11:2":{"text":"Then said he unto me, Son of man, these are the men that devise mischief, and give wicked counsel in this city:","words":[["H0559","Then said",0,9],["H1121","he unto me, Son",10,25],["H0120","of man",26,32],["H0582","these are the men",34,51],["H2803","that devise",52,63],["H0205","mischief",64,72],["H3289","and give",74,82],["H7451","wicked",83,89],["H6098","counsel",90,97],["H5892","in this city",98,110]]},"11:3":{"text":"Which say, It is not near; let us build houses: this city is the caldron, and we be the flesh.","words":[["H0559","Which say",0,9],["H7138","It is not near",11,25],["H1129","let us build",27,39],["H1004","houses",40,46],["H5518","this city is the caldron",48,72],["H1320","and we be the flesh",74,93]]},"11:4":{"text":"Therefore prophesy against them, prophesy, O son of man.","words":[["H5012","Therefore prophesy",0,18],["H5012","against them, prophesy",19,41],["H1121","O son",43,48],["H0120","of man",49,55]]},"11:5":{"text":"And the Spirit of the LORD fell upon me, and said unto me, Speak; Thus saith the LORD; Thus have ye said, O house of Israel: for I know the things that come into your mind, every one of them.","words":[["H7307","And the Spirit",0,14],["H3068","of the LORD",15,26],["H5307","fell",27,31],["H0559","upon me, and said",32,49],["H0559","unto me, Speak",50,64],["H0559","Thus saith",66,76],["H3068","the LORD",77,85],["H0559","Thus have ye said",87,104],["H1004","O house",106,113],["H3478","of Israel",114,123],["H3045","for I know",125,135],["H4609","the things that come",136,156],["H7307","into your mind",157,171]]},"11:6":{"text":"Ye have multiplied your slain in this city, and ye have filled the streets thereof with the slain.","words":[["H7235","Ye have multiplied",0,18],["H2491","your slain",19,29],["H5892","in this city",30,42],["H4390","and ye have filled",44,62],["H2351","the streets",63,74],["H2491","thereof with the slain",75,97]]},"11:7":{"text":"Therefore thus saith the Lord GOD; Your slain whom ye have laid in the midst of it, they are the flesh, and this city is the caldron: but I will bring you forth out of the midst of it.","words":[["H0559","Therefore thus saith",0,20],["H0136","the Lord",21,29],["H3069","GOD",30,33],["H2491","Your slain",35,45],["H7760","whom ye have laid",46,63],["H8432","in the midst",64,76],["H1320","of it, they are the flesh",77,102],["H5518","and this city is the caldron",104,132],["H3318","but I will bring you forth",134,160],["H8432","out of the midst",161,177]]},"11:8":{"text":"Ye have feared the sword; and I will bring a sword upon you, saith the Lord GOD.","words":[["H3372","Ye have feared",0,14],["H2719","the sword",15,24],["H0935","and I will bring",26,42],["H2719","a sword",43,50],["H5002","upon you, saith",51,66],["H0136","the Lord",67,75],["H3069","GOD",76,79]]},"11:9":{"text":"And I will bring you out of the midst thereof, and deliver you into the hands of strangers, and will execute judgments among you.","words":[["H3318","And I will bring you out",0,24],["H8432","of the midst",25,37],["H5414","thereof, and deliver",38,58],["H3027","you into the hands",59,77],["H2114","of strangers",78,90],["H6213","and will execute",92,108],["H8201","judgments",109,118]]},"11:10":{"text":"Ye shall fall by the sword; I will judge you in the border of Israel; and ye shall know that I am the LORD.","words":[["H5307","Ye shall fall",0,13],["H2719","by the sword",14,26],["H8199","I will judge",28,40],["H1366","you in the border",41,58],["H3478","of Israel",59,68],["H3045","and ye shall know",70,87],["H3068","that I am the LORD",88,106]]},"11:11":{"text":"This city shall not be your caldron, neither shall ye be the flesh in the midst thereof; but I will judge you in the border of Israel:","words":[["H5518","This city shall not be your caldron",0,35],["H1320","neither shall ye be the flesh",37,66],["H8432","in the midst",67,79],["H8199","thereof; but I will judge",80,105],["H1366","you in the border",106,123],["H3478","of Israel",124,133]]},"11:12":{"text":"And ye shall know that I am the LORD: for ye have not walked in my statutes, neither executed my judgments, but have done after the manners of the heathen that are round about you.","words":[["H3045","And ye shall know",0,17],["H3068","that I am the LORD",18,36],["H1980","for ye have not walked",38,60],["H2706","in my statutes",61,75],["H6213","neither executed",77,93],["H4941","my judgments",94,106],["H6213","but have done",108,121],["H4941","after the manners",122,139],["H1471","of the heathen",140,154],["H5439","that are round about",155,175]]},"11:13":{"text":"And it came to pass, when I prophesied, that Pelatiah the son of Benaiah died. Then fell I down upon my face, and cried with a loud voice, and said, Ah Lord GOD! wilt thou make a full end of the remnant of Israel?","words":[["H5012","And it came to pass, when I prophesied",0,38],["H6410","that Pelatiah",40,53],["H1121","the son",54,61],["H1141","of Benaiah",62,72],["H4191","died",73,77],["H5307","Then fell I down",79,95],["H6440","upon my face",96,108],["H2199","and cried",110,119],["H1419","with a loud",120,131],["H6963","voice",132,137],["H0559","and said",139,147],["H0162","Ah",149,151],["H0136","Lord",152,156],["H3069","GOD",157,160],["H6213","wilt thou make",162,176],["H3617","a full end",177,187],["H7611","of the remnant",188,202],["H3478","of Israel",203,212]]},"11:14":{"text":"Again the word of the LORD came unto me, saying,","words":[["H1697","Again the word",0,14],["H3068","of the LORD",15,26],["H0559","came unto me, saying",27,47]]},"11:15":{"text":"Son of man, thy brethren, even thy brethren, the men of thy kindred, and all the house of Israel wholly, are they unto whom the inhabitants of Jerusalem have said, Get you far from the LORD: unto us is this land given in possession.","words":[["H1121","Son",0,3],["H0120","of man",4,10],["H0251","thy brethren",12,24],["H0251","even thy brethren",26,43],["H0582","the men",45,52],["H1353","of thy kindred",53,67],["H1004","and all the house",69,86],["H3478","of Israel",87,96],["H3427","wholly, are they unto whom the inhabitants",97,139],["H3389","of Jerusalem",140,152],["H0559","have said",153,162],["H7368","Get you far",164,175],["H3068","from the LORD",176,189],["H0776","unto us is this land",191,211],["H5414","given",212,217],["H4181","in possession",218,231]]},"11:16":{"text":"Therefore say, Thus saith the Lord GOD; Although I have cast them far off among the heathen, and although I have scattered them among the countries, yet will I be to them as a little sanctuary in the countries where they shall come.","words":[["H0559","Therefore say",0,13],["H0559","Thus saith",15,25],["H0136","the Lord",26,34],["H3069","GOD",35,38],["H7368","Although I have cast them far off",40,73],["H1471","among the heathen",74,91],["H6327","and although I have scattered",93,122],["H0776","them among the countries",123,147],["H4592","yet will I be to them as a little",149,182],["H4720","sanctuary",183,192],["H0776","in the countries",193,209],["H0935","where they shall come",210,231]]},"11:17":{"text":"Therefore say, Thus saith the Lord GOD; I will even gather you from the people, and assemble you out of the countries where ye have been scattered, and I will give you the land of Israel.","words":[["H0559","Therefore say",0,13],["H0559","Thus saith",15,25],["H0136","the Lord",26,34],["H3069","GOD",35,38],["H6908","I will even gather",40,58],["H5971","you from the people",59,78],["H0622","and assemble",80,92],["H0776","you out of the countries",93,117],["H6327","where ye have been scattered",118,146],["H5414","and I will give",148,163],["H0127","you the land",164,176],["H3478","of Israel",177,186]]},"11:18":{"text":"And they shall come thither, and they shall take away all the detestable things thereof and all the abominations thereof from thence.","words":[["H0935","And they shall come",0,19],["H5493","thither, and they shall take away",20,53],["H8251","all the detestable things",54,79],["H8441","thereof and all the abominations",80,112]]},"11:19":{"text":"And I will give them one heart, and I will put a new spirit within you; and I will take the stony heart out of their flesh, and will give them an heart of flesh:","words":[["H5414","And I will give",0,15],["H0259","them one",16,24],["H3820","heart",25,30],["H5414","and I will put",32,46],["H2319","a new",47,52],["H7307","spirit",53,59],["H7130","within",60,66],["H5493","you; and I will take",67,87],["H0068","the stony",88,97],["H3820","heart",98,103],["H1320","out of their flesh",104,122],["H5414","and will give",124,137],["H3820","them an heart",138,151],["H1320","of flesh",152,160]]},"11:20":{"text":"That they may walk in my statutes, and keep mine ordinances, and do them: and they shall be my people, and I will be their God.","words":[["H3212","That they may walk",0,18],["H2708","in my statutes",19,33],["H8104","and keep",35,43],["H4941","mine ordinances",44,59],["H6213","and do",61,67],["H5971","them: and they shall be my people",68,101],["H0430","and I will be their God",103,126]]},"11:21":{"text":"But as for them whose heart walketh after the heart of their detestable things and their abominations, I will recompense their way upon their own heads, saith the Lord GOD.","words":[["H3820","But as for them whose heart",0,27],["H1980","walketh",28,35],["H3820","after the heart",36,51],["H8251","of their detestable things",52,78],["H8441","and their abominations",79,101],["H5414","I will recompense",103,120],["H1870","their way",121,130],["H7218","upon their own heads",131,151],["H5002","saith",153,158],["H0136","the Lord",159,167],["H3069","GOD",168,171]]},"11:22":{"text":"Then did the cherubims lift up their wings, and the wheels beside them; and the glory of the God of Israel was over them above.","words":[["H3742","Then did the cherubims",0,22],["H5375","lift up",23,30],["H3671","their wings",31,42],["H0212","and the wheels",44,58],["H5980","beside",59,65],["H3519","them; and the glory",66,85],["H0430","of the God",86,96],["H3478","of Israel",97,106],["H4605","was over them above",107,126]]},"11:23":{"text":"And the glory of the LORD went up from the midst of the city, and stood upon the mountain which is on the east side of the city.","words":[["H3519","And the glory",0,13],["H3068","of the LORD",14,25],["H5927","went up",26,33],["H8432","from the midst",34,48],["H5892","of the city",49,60],["H5975","and stood",62,71],["H2022","upon the mountain",72,89],["H6924","which is on the east side",90,115],["H5892","of the city",116,127]]},"11:24":{"text":"Afterwards the spirit took me up, and brought me in a vision by the Spirit of God into Chaldea, to them of the captivity. So the vision that I had seen went up from me.","words":[["H7307","Afterwards the spirit",0,21],["H5375","took me up",22,32],["H0935","and brought",34,45],["H4758","me in a vision",46,60],["H7307","by the Spirit",61,74],["H0430","of God",75,81],["H3778","into Chaldea",82,94],["H1473","to them of the captivity",96,120],["H4758","So the vision",122,135],["H7200","that I had seen",136,151],["H5927","went up",152,159]]},"11:25":{"text":"Then I spake unto them of the captivity all the things that the LORD had shewed me.","words":[["H1696","Then I spake",0,12],["H1473","unto them of the captivity",13,39],["H1697","all the things",40,54],["H3068","that the LORD",55,68],["H7200","had shewed",69,79]]},"12:1":{"text":"The word of the LORD also came unto me, saying,","words":[["H1697","The word",0,8],["H3068","of the LORD",9,20],["H0559","also came unto me, saying",21,46]]},"12:2":{"text":"Son of man, thou dwellest in the midst of a rebellious house, which have eyes to see, and see not; they have ears to hear, and hear not: for they are a rebellious house.","words":[["H1121","Son",0,3],["H0120","of man",4,10],["H3427","thou dwellest",12,25],["H8432","in the midst",26,38],["H4805","of a rebellious",39,54],["H1004","house",55,60],["H5869","which have eyes",62,77],["H7200","to see",78,84],["H7200","and see",86,93],["H0241","not; they have ears",94,113],["H8085","to hear",114,121],["H8085","and hear",123,131],["H4805","not: for they are a rebellious",132,162],["H1004","house",163,168]]},"12:3":{"text":"Therefore, thou son of man, prepare thee stuff for removing, and remove by day in their sight; and thou shalt remove from thy place to another place in their sight: it may be they will consider, though they be a rebellious house.","words":[["H1121","Therefore, thou son",0,19],["H0120","of man",20,26],["H6213","prepare",28,35],["H3627","thee stuff",36,46],["H1473","for removing",47,59],["H1540","and remove",61,71],["H3119","by day",72,78],["H5869","in their sight",79,93],["H1540","and thou shalt remove",95,116],["H4725","from thy place",117,131],["H0312","to another",132,142],["H4725","place",143,148],["H5869","in their sight",149,163],["H7200","it may be they will consider",165,193],["H4805","though they be a rebellious",195,222],["H1004","house",223,228]]},"12:4":{"text":"Then shalt thou bring forth thy stuff by day in their sight, as stuff for removing: and thou shalt go forth at even in their sight, as they that go forth into captivity.","words":[["H3318","Then shalt thou bring forth",0,27],["H3627","thy stuff",28,37],["H3119","by day",38,44],["H5869","in their sight",45,59],["H3627","as stuff",61,69],["H1473","for removing",70,82],["H3318","and thou shalt go forth",84,107],["H6153","at even",108,115],["H5869","in their sight",116,130],["H4161","as they that go forth",132,153],["H1473","into captivity",154,168]]},"12:5":{"text":"Dig thou through the wall in their sight, and carry out thereby.","words":[["H2864","Dig",0,3],["H7023","thou through the wall",4,25],["H5869","in their sight",26,40],["H3318","and carry out",42,55]]},"12:6":{"text":"In their sight shalt thou bear it upon thy shoulders, and carry it forth in the twilight: thou shalt cover thy face, that thou see not the ground: for I have set thee for a sign unto the house of Israel.","words":[["H5869","In their sight",0,14],["H5375","shalt thou bear",15,30],["H3802","it upon thy shoulders",31,52],["H3318","and carry it forth",54,72],["H5939","in the twilight",73,88],["H3680","thou shalt cover",90,106],["H6440","thy face",107,115],["H7200","that thou see",117,130],["H0776","not the ground",131,145],["H5414","for I have set",147,161],["H4159","thee for a sign",162,177],["H1004","unto the house",178,192],["H3478","of Israel",193,202]]},"12:7":{"text":"And I did so as I was commanded: I brought forth my stuff by day, as stuff for captivity, and in the even I digged through the wall with mine hand; I brought it forth in the twilight, and I bare it upon my shoulder in their sight.","words":[["H6213","And I did",0,9],["H6680","so as I was commanded",10,31],["H3318","I brought forth",33,48],["H3627","my stuff",49,57],["H3119","by day",58,64],["H3627","as stuff",66,74],["H1473","for captivity",75,88],["H6153","and in the even",90,105],["H2864","I digged",106,114],["H7023","through the wall",115,131],["H3027","with mine hand",132,146],["H3318","I brought it forth",148,166],["H5939","in the twilight",167,182],["H5375","and I bare",184,194],["H3802","it upon my shoulder",195,214],["H5869","in their sight",215,229]]},"12:8":{"text":"And in the morning came the word of the LORD unto me, saying,","words":[["H1242","And in the morning",0,18],["H1697","came the word",19,32],["H3068","of the LORD",33,44],["H0559","unto me, saying",45,60]]},"12:9":{"text":"Son of man, hath not the house of Israel, the rebellious house, said unto thee, What doest thou?","words":[["H1121","Son",0,3],["H0120","of man",4,10],["H1004","hath not the house",12,30],["H3478","of Israel",31,40],["H4805","the rebellious",42,56],["H1004","house",57,62],["H0559","said",64,68],["H6213","unto thee, What doest",69,90]]},"12:10":{"text":"Say thou unto them, Thus saith the Lord GOD; This burden concerneth the prince in Jerusalem, and all the house of Israel that are among them.","words":[["H0559","Say",0,3],["H0559","thou unto them, Thus saith",4,30],["H0136","the Lord",31,39],["H3069","GOD",40,43],["H4853","This burden",45,56],["H5387","concerneth the prince",57,78],["H3389","in Jerusalem",79,91],["H1004","and all the house",93,110],["H3478","of Israel",111,120],["H8432","that are among",121,135]]},"12:11":{"text":"Say, I am your sign: like as I have done, so shall it be done unto them: they shall remove and go into captivity.","words":[["H0559","Say",0,3],["H4159","I am your sign",5,19],["H6213","like as I have done",21,40],["H6213","so shall it be done",42,61],["H1473","unto them: they shall remove",62,90],["H3212","and go",91,97],["H7628","into captivity",98,112]]},"12:12":{"text":"And the prince that is among them shall bear upon his shoulder in the twilight, and shall go forth: they shall dig through the wall to carry out thereby: he shall cover his face, that he see not the ground with his eyes.","words":[["H5387","And the prince",0,14],["H8432","that is among",15,28],["H5375","them shall bear",29,44],["H3802","upon his shoulder",45,62],["H5939","in the twilight",63,78],["H3318","and shall go forth",80,98],["H2864","they shall dig",100,114],["H7023","through the wall",115,131],["H3318","to carry out",132,144],["H3680","thereby: he shall cover",145,168],["H6440","his face",169,177],["H3282","that",179,183],["H7200","he see",184,190],["H0776","not the ground",191,205],["H5869","with his eyes",206,219]]},"12:13":{"text":"My net also will I spread upon him, and he shall be taken in my snare: and I will bring him to Babylon to the land of the Chaldeans; yet shall he not see it, though he shall die there.","words":[["H7568","My net",0,6],["H6566","also will I spread",7,25],["H8610","upon him, and he shall be taken",26,57],["H4686","in my snare",58,69],["H0935","and I will bring",71,87],["H0894","him to Babylon",88,102],["H0776","to the land",103,114],["H3778","of the Chaldeans",115,131],["H7200","yet shall he not see",133,153],["H4191","it, though he shall die",154,177]]},"12:14":{"text":"And I will scatter toward every wind all that are about him to help him, and all his bands; and I will draw out the sword after them.","words":[["H2219","And I will scatter",0,18],["H7307","toward every wind",19,36],["H5439","all that are about",37,55],["H5828","him to help",56,67],["H0102","him, and all his bands",68,90],["H7324","and I will draw out",92,111],["H2719","the sword",112,121],["H0310","after",122,127]]},"12:15":{"text":"And they shall know that I am the LORD, when I shall scatter them among the nations, and disperse them in the countries.","words":[["H3045","And they shall know",0,19],["H3068","that I am the LORD",20,38],["H6327","when I shall scatter",40,60],["H1471","them among the nations",61,83],["H2219","and disperse",85,97],["H0776","them in the countries",98,119]]},"12:16":{"text":"But I will leave a few men of them from the sword, from the famine, and from the pestilence; that they may declare all their abominations among the heathen whither they come; and they shall know that I am the LORD.","words":[["H3498","But I will leave",0,16],["H4557","a few",17,22],["H0582","men",23,26],["H2719","of them from the sword",27,49],["H7458","from the famine",51,66],["H1698","and from the pestilence",68,91],["H5608","that they may declare",93,114],["H8441","all their abominations",115,137],["H1471","among the heathen",138,155],["H0935","whither they come",156,173],["H3045","and they shall know",175,194],["H3068","that I am the LORD",195,213]]},"12:17":{"text":"Moreover the word of the LORD came to me, saying,","words":[["H1697","Moreover the word",0,17],["H3068","of the LORD",18,29],["H0559","came to me, saying",30,48]]},"12:18":{"text":"Son of man, eat thy bread with quaking, and drink thy water with trembling and with carefulness;","words":[["H1121","Son",0,3],["H0120","of man",4,10],["H0398","eat",12,15],["H3899","thy bread",16,25],["H7494","with quaking",26,38],["H8354","and drink",40,49],["H4325","thy water",50,59],["H7269","with trembling",60,74],["H1674","and with carefulness",75,95]]},"12:19":{"text":"And say unto the people of the land, Thus saith the Lord GOD of the inhabitants of Jerusalem, and of the land of Israel; They shall eat their bread with carefulness, and drink their water with astonishment, that her land may be desolate from all that is therein, because of the violence of all them that dwell therein.","words":[["H0559","And say",0,7],["H5971","unto the people",8,23],["H0127","of the land",24,35],["H0559","Thus saith",37,47],["H0136","the Lord",48,56],["H3069","GOD",57,60],["H3427","of the inhabitants",61,79],["H3389","of Jerusalem",80,92],["H0776","and of the land",94,109],["H3478","of Israel",110,119],["H0398","They shall eat",121,135],["H3899","their bread",136,147],["H1674","with carefulness",148,164],["H8354","and drink",166,175],["H4325","their water",176,187],["H8078","with astonishment",188,205],["H0776","that her land",207,220],["H3456","may be desolate",221,236],["H4393","from all that is therein",237,261],["H2555","because of the violence",263,286],["H3427","of all them that dwell",287,309]]},"12:20":{"text":"And the cities that are inhabited shall be laid waste, and the land shall be desolate; and ye shall know that I am the LORD.","words":[["H5892","And the cities",0,14],["H3427","that are inhabited",15,33],["H2717","shall be laid waste",34,53],["H0776","and the land",55,67],["H8077","shall be desolate",68,85],["H3045","and ye shall know",87,104],["H3068","that I am the LORD",105,123]]},"12:21":{"text":"And the word of the LORD came unto me, saying,","words":[["H1697","And the word",0,12],["H3068","of the LORD",13,24],["H0559","came unto me, saying",25,45]]},"12:22":{"text":"Son of man, what is that proverb that ye have in the land of Israel, saying, The days are prolonged, and every vision faileth?","words":[["H1121","Son",0,3],["H0120","of man",4,10],["H4912","what is that proverb",12,32],["H0127","that ye have in the land",33,57],["H3478","of Israel",58,67],["H0559","saying",69,75],["H3117","The days",77,85],["H0748","are prolonged",86,99],["H2377","and every vision",101,117],["H0006","faileth",118,125]]},"12:23":{"text":"Tell them therefore, Thus saith the Lord GOD; I will make this proverb to cease, and they shall no more use it as a proverb in Israel; but say unto them, The days are at hand, and the effect of every vision.","words":[["H0559","Tell",0,4],["H0559","them therefore, Thus saith",5,31],["H0136","the Lord",32,40],["H3069","GOD",41,44],["H4912","I will make this proverb",46,70],["H7673","to cease",71,79],["H4911","and they shall no more use it as a proverb",81,123],["H3478","in Israel",124,133],["H1696","but say",135,142],["H3117","unto them, The days",143,162],["H7126","are at hand",163,174],["H1697","and the effect",176,190],["H2377","of every vision",191,206]]},"12:24":{"text":"For there shall be no more any vain vision nor flattering divination within the house of Israel.","words":[["H7723","For there shall be no more any vain",0,35],["H2377","vision",36,42],["H2509","nor flattering",43,57],["H4738","divination",58,68],["H8432","within",69,75],["H1004","the house",76,85],["H3478","of Israel",86,95]]},"12:25":{"text":"For I am the LORD: I will speak, and the word that I shall speak shall come to pass; it shall be no more prolonged: for in your days, O rebellious house, will I say the word, and will perform it, saith the Lord GOD.","words":[["H3068","For I am the LORD",0,17],["H1696","I will speak",19,31],["H1697","and the word",33,45],["H1696","that I shall speak",46,64],["H6213","shall come to pass",65,83],["H4900","it shall be no more prolonged",85,114],["H3117","for in your days",116,132],["H4805","O rebellious",134,146],["H1004","house",147,152],["H1696","will I say",154,164],["H1697","the word",165,173],["H6213","and will perform",175,191],["H5002","it, saith",192,201],["H0136","the Lord",202,210],["H3069","GOD",211,214]]},"12:26":{"text":"Again the word of the LORD came to me, saying,","words":[["H1697","Again the word",0,14],["H3068","of the LORD",15,26],["H0559","came to me, saying",27,45]]},"12:27":{"text":"Son of man, behold, they of the house of Israel say, The vision that he seeth is for many days to come, and he prophesieth of the times that are far off.","words":[["H1121","Son",0,3],["H0120","of man",4,10],["H1004","behold, they of the house",12,37],["H3478","of Israel",38,47],["H0559","say",48,51],["H2377","The vision",53,63],["H2372","that he seeth",64,77],["H7227","is for many",78,89],["H3117","days",90,94],["H5012","to come, and he prophesieth",95,122],["H6256","of the times",123,135],["H7350","that are far",136,148]]},"12:28":{"text":"Therefore say unto them, Thus saith the Lord GOD; There shall none of my words be prolonged any more, but the word which I have spoken shall be done, saith the Lord GOD.","words":[["H0559","Therefore say",0,13],["H0559","unto them, Thus saith",14,35],["H0136","the Lord",36,44],["H3069","GOD",45,48],["H1697","There shall none of my words",50,78],["H4900","be prolonged",79,91],["H1697","any more, but the word",92,114],["H1696","which I have spoken",115,134],["H6213","shall be done",135,148],["H5002","saith",150,155],["H0136","the Lord",156,164],["H3069","GOD",165,168]]},"13:1":{"text":"And the word of the LORD came unto me, saying,","words":[["H1697","And the word",0,12],["H3068","of the LORD",13,24],["H0559","came unto me, saying",25,45]]},"13:2":{"text":"Son of man, prophesy against the prophets of Israel that prophesy, and say thou unto them that prophesy out of their own hearts, Hear ye the word of the LORD;","words":[["H1121","Son",0,3],["H0120","of man",4,10],["H5012","prophesy",12,20],["H5030","against the prophets",21,41],["H3478","of Israel",42,51],["H5012","that prophesy",52,65],["H0559","and say",67,74],["H5030","thou unto them that prophesy",75,103],["H3820","out of their own hearts",104,127],["H8085","Hear",129,133],["H1697","ye the word",134,145],["H3068","of the LORD",146,157]]},"13:3":{"text":"Thus saith the Lord GOD; Woe unto the foolish prophets, that follow their own spirit, and have seen nothing!","words":[["H0559","Thus saith",0,10],["H0136","the Lord",11,19],["H3069","GOD",20,23],["H1945","Woe",25,28],["H5036","unto the foolish",29,45],["H5030","prophets",46,54],["H1980","that follow",56,67],["H0310","that follow",56,67],["H7307","their own spirit",68,84],["H7200","and have seen",86,99]]},"13:4":{"text":"O Israel, thy prophets are like the foxes in the deserts.","words":[["H3478","O Israel",0,8],["H5030","thy prophets",10,22],["H7776","are like the foxes",23,41],["H2723","in the deserts",42,56]]},"13:5":{"text":"Ye have not gone up into the gaps, neither made up the hedge for the house of Israel to stand in the battle in the day of the LORD.","words":[["H5927","Ye have not gone up",0,19],["H6556","into the gaps",20,33],["H1443","neither made up",35,50],["H1447","the hedge",51,60],["H1004","for the house",61,74],["H3478","of Israel",75,84],["H5975","to stand",85,93],["H4421","in the battle",94,107],["H3117","in the day",108,118],["H3068","of the LORD",119,130]]},"13:6":{"text":"They have seen vanity and lying divination, saying, The LORD saith: and the LORD hath not sent them: and they have made others to hope that they would confirm the word.","words":[["H2372","They have seen",0,14],["H7723","vanity",15,21],["H3577","and lying",22,31],["H7081","divination",32,42],["H0559","saying",44,50],["H3068","The LORD",52,60],["H5002","saith",61,66],["H3068","and the LORD",68,80],["H7971","hath not sent",81,94],["H3176","them: and they have made others to hope",95,134],["H6965","that they would confirm",135,158],["H1697","the word",159,167]]},"13:7":{"text":"Have ye not seen a vain vision, and have ye not spoken a lying divination, whereas ye say, The LORD saith it; albeit I have not spoken?","words":[["H2372","Have ye not seen",0,16],["H7723","a vain",17,23],["H4236","vision",24,30],["H1696","and have ye not spoken",32,54],["H3577","a lying",55,62],["H4738","divination",63,73],["H0559","whereas ye say",75,89],["H3068","The LORD",91,99],["H5002","saith",100,105],["H0559","it; albeit I have not spoken",106,134]]},"13:8":{"text":"Therefore thus saith the Lord GOD; Because ye have spoken vanity, and seen lies, therefore, behold, I am against you, saith the Lord GOD.","words":[["H0559","Therefore thus saith",0,20],["H0136","the Lord",21,29],["H3069","GOD",30,33],["H1696","Because ye have spoken",35,57],["H7723","vanity",58,64],["H2372","and seen",66,74],["H3577","lies",75,79],["H5002","therefore, behold, I am against you, saith",81,123],["H0136","the Lord",124,132],["H3069","GOD",133,136]]},"13:9":{"text":"And mine hand shall be upon the prophets that see vanity, and that divine lies: they shall not be in the assembly of my people, neither shall they be written in the writing of the house of Israel, neither shall they enter into the land of Israel; and ye shall know that I am the Lord GOD.","words":[["H3027","And mine hand",0,13],["H5030","shall be upon the prophets",14,40],["H2374","that see",41,49],["H7723","vanity",50,56],["H7080","and that divine",58,73],["H3577","lies",74,78],["H5475","they shall not be in the assembly",80,113],["H5971","of my people",114,126],["H3789","neither shall they be written",128,157],["H3791","in the writing",158,172],["H1004","of the house",173,185],["H3478","of Israel",186,195],["H0935","neither shall they enter",197,221],["H0127","into the land",222,235],["H3478","of Israel",236,245],["H3045","and ye shall know",247,264],["H0136","that I am the Lord",265,283],["H3069","GOD",284,287]]},"13:10":{"text":"Because, even because they have seduced my people, saying, Peace; and there was no peace; and one built up a wall, and, lo, others daubed it with untempered morter:","words":[["H2937","Because, even because they have seduced",0,39],["H5971","my people",40,49],["H0559","saying",51,57],["H7965","Peace",59,64],["H7965","and there was no peace",66,88],["H1129","and one built up",90,106],["H2434","a wall",107,113],["H2009","and, lo",115,122],["H2902","others daubed",124,137],["H8602","it with untempered",138,156]]},"13:11":{"text":"Say unto them which daub it with untempered morter, that it shall fall: there shall be an overflowing shower; and ye, O great hailstones, shall fall; and a stormy wind shall rend it.","words":[["H0559","Say",0,3],["H2902","unto them which daub",4,24],["H8602","it with untempered",25,43],["H5307","morter, that it shall fall",44,70],["H7857","there shall be an overflowing",72,101],["H1653","shower",102,108],["H0859","and ye",110,116],["H0417","O great hailstones",118,136],["H0068","O great hailstones",118,136],["H5307","shall fall",138,148],["H5591","and a stormy",150,162],["H7307","wind",163,167],["H1234","shall rend",168,178]]},"13:12":{"text":"Lo, when the wall is fallen, shall it not be said unto you, Where is the daubing wherewith ye have daubed it?","words":[["H7023","Lo, when the wall",0,17],["H5307","is fallen",18,27],["H0559","shall it not be said",29,49],["H2915","unto you, Where is the daubing",50,80],["H2902","wherewith ye have daubed",81,105]]},"13:13":{"text":"Therefore thus saith the Lord GOD; I will even rend it with a stormy wind in my fury; and there shall be an overflowing shower in mine anger, and great hailstones in my fury to consume it.","words":[["H0559","Therefore thus saith",0,20],["H0136","the Lord",21,29],["H3069","GOD",30,33],["H1234","I will even rend",35,51],["H5591","it with a stormy",52,68],["H7307","wind",69,73],["H2534","in my fury",74,84],["H7857","and there shall be an overflowing",86,119],["H1653","shower",120,126],["H0639","in mine anger",127,140],["H0417","and great hailstones",142,162],["H0068","and great hailstones",142,162],["H2534","in my fury",163,173],["H3617","to consume",174,184]]},"13:14":{"text":"So will I break down the wall that ye have daubed with untempered morter, and bring it down to the ground, so that the foundation thereof shall be discovered, and it shall fall, and ye shall be consumed in the midst thereof: and ye shall know that I am the LORD.","words":[["H2040","So will I break down",0,20],["H7023","the wall",21,29],["H2902","that ye have daubed",30,49],["H8602","with untempered",50,65],["H5060","morter, and bring",66,83],["H0776","it down to the ground",84,105],["H3247","so that the foundation",107,129],["H1540","thereof shall be discovered",130,157],["H5307","and it shall fall",159,176],["H3615","and ye shall be consumed",178,202],["H8432","in the midst",203,215],["H3045","thereof: and ye shall know",216,242],["H3068","that I am the LORD",243,261]]},"13:15":{"text":"Thus will I accomplish my wrath upon the wall, and upon them that have daubed it with untempered morter, and will say unto you, The wall is no more, neither they that daubed it;","words":[["H3615","Thus will I accomplish",0,22],["H2534","my wrath",23,31],["H7023","upon the wall",32,45],["H2902","and upon them that have daubed",47,77],["H8602","it with untempered",78,96],["H0559","morter, and will say",97,117],["H7023","unto you, The wall",118,136],["H2902","is no more, neither they that daubed",137,173]]},"13:16":{"text":"To wit, the prophets of Israel which prophesy concerning Jerusalem, and which see visions of peace for her, and there is no peace, saith the Lord GOD.","words":[["H5030","To wit, the prophets",0,20],["H3478","of Israel",21,30],["H5012","which prophesy",31,45],["H3389","concerning Jerusalem",46,66],["H2374","and which see",68,81],["H2377","visions",82,89],["H7965","of peace",90,98],["H7965","for her, and there is no peace",99,129],["H5002","saith",131,136],["H0136","the Lord",137,145],["H3069","GOD",146,149]]},"13:17":{"text":"Likewise, thou son of man, set thy face against the daughters of thy people, which prophesy out of their own heart; and prophesy thou against them,","words":[["H1121","Likewise, thou son",0,18],["H0120","of man",19,25],["H7760","set",27,30],["H6440","thy face",31,39],["H1323","against the daughters",40,61],["H5971","of thy people",62,75],["H5012","which prophesy",77,91],["H3820","out of their own heart",92,114],["H5012","and prophesy",116,128]]},"13:18":{"text":"And say, Thus saith the Lord GOD; Woe to the women that sew pillows to all armholes, and make kerchiefs upon the head of every stature to hunt souls! Will ye hunt the souls of my people, and will ye save the souls alive that come unto you?","words":[["H0559","And say",0,7],["H0559","Thus saith",9,19],["H0136","the Lord",20,28],["H3069","GOD",29,32],["H1945","Woe",34,37],["H8609","to the women that sew",38,59],["H3704","pillows",60,67],["H0679","to all armholes",68,83],["H3027","to all armholes",68,83],["H6213","and make",85,93],["H4555","kerchiefs",94,103],["H7218","upon the head",104,117],["H6967","of every stature",118,134],["H6679","to hunt",135,142],["H5315","souls",143,148],["H6679","Will ye hunt",150,162],["H5315","the souls",163,172],["H5971","of my people",173,185],["H2421","and will ye save",187,203],["H5315","the souls",204,213],["H2421","alive",214,219]]},"13:19":{"text":"And will ye pollute me among my people for handfuls of barley and for pieces of bread, to slay the souls that should not die, and to save the souls alive that should not live, by your lying to my people that hear your lies?","words":[["H2490","And will ye pollute",0,19],["H5971","me among my people",20,38],["H8168","for handfuls",39,51],["H8184","of barley",52,61],["H6595","and for pieces",62,76],["H3899","of bread",77,85],["H4191","to slay",87,94],["H5315","the souls",95,104],["H4191","that should not die",105,124],["H2421","and to save",126,137],["H5315","the souls",138,147],["H2421","alive",148,153],["H2421","that should not live",154,174],["H3576","by your lying",176,189],["H5971","to my people",190,202],["H8085","that hear",203,212],["H3577","your lies",213,222]]},"13:20":{"text":"Wherefore thus saith the Lord GOD; Behold, I am against your pillows, wherewith ye there hunt the souls to make them fly, and I will tear them from your arms, and will let the souls go, even the souls that ye hunt to make them fly.","words":[["H0559","Wherefore thus saith",0,20],["H0136","the Lord",21,29],["H3069","GOD",30,33],["H3704","Behold, I am against your pillows",35,68],["H0859","wherewith ye",70,82],["H6679","there hunt",83,93],["H5315","the souls",94,103],["H6524","to make them fly",104,120],["H7167","and I will tear",122,137],["H2220","them from your arms",138,157],["H5315","and will let the souls",159,181],["H7971","go",182,184],["H5315","even the souls",186,200],["H6679","that ye hunt",201,213],["H6524","to make them fly",214,230]]},"13:21":{"text":"Your kerchiefs also will I tear, and deliver my people out of your hand, and they shall be no more in your hand to be hunted; and ye shall know that I am the LORD.","words":[["H4555","Your kerchiefs",0,14],["H7167","also will I tear",15,31],["H5337","and deliver",33,44],["H5971","my people",45,54],["H3027","out of your hand",55,71],["H3027","and they shall be no more in your hand",73,111],["H4686","to be hunted",112,124],["H3045","and ye shall know",126,143],["H3068","that I am the LORD",144,162]]},"13:22":{"text":"Because with lies ye have made the heart of the righteous sad, whom I have not made sad; and strengthened the hands of the wicked, that he should not return from his wicked way, by promising him life:","words":[["H8267","Because with lies",0,17],["H3820","ye have made the heart",18,40],["H6662","of the righteous",41,57],["H3512","sad",58,61],["H3510","whom I have not made sad",63,87],["H2388","and strengthened",89,105],["H3027","the hands",106,115],["H7451","of the wicked",116,129],["H7725","that he should not return",131,156],["H7563","from his wicked",157,172],["H1870","way",173,176],["H2421","by promising him life",178,199]]},"13:23":{"text":"Therefore ye shall see no more vanity, nor divine divinations: for I will deliver my people out of your hand: and ye shall know that I am the LORD.","words":[["H2372","Therefore ye shall see",0,22],["H7723","no more vanity",23,37],["H7080","nor divine",39,49],["H7081","divinations",50,61],["H5337","for I will deliver",63,81],["H5971","my people",82,91],["H3027","out of your hand",92,108],["H3045","and ye shall know",110,127],["H3068","that I am the LORD",128,146]]},"14:1":{"text":"Then came certain of the elders of Israel unto me, and sat before me.","words":[["H0935","Then came",0,9],["H0582","certain",10,17],["H2205","of the elders",18,31],["H3478","of Israel",32,41],["H3427","unto me, and sat",42,58],["H6440","before",59,65]]},"14:2":{"text":"And the word of the LORD came unto me, saying,","words":[["H1697","And the word",0,12],["H3068","of the LORD",13,24],["H0559","came unto me, saying",25,45]]},"14:3":{"text":"Son of man, these men have set up their idols in their heart, and put the stumblingblock of their iniquity before their face: should I be enquired of at all by them?","words":[["H1121","Son",0,3],["H0120","of man",4,10],["H0582","these men",12,21],["H5927","have set up",22,33],["H1544","their idols",34,45],["H3820","in their heart",46,60],["H5414","and put",62,69],["H4383","the stumblingblock",70,88],["H5771","of their iniquity",89,106],["H5227","before",107,113],["H6440","their face",114,124],["H1875","should I be enquired",126,146],["H1875","of at all",147,156]]},"14:4":{"text":"Therefore speak unto them, and say unto them, Thus saith the Lord GOD; Every man of the house of Israel that setteth up his idols in his heart, and putteth the stumblingblock of his iniquity before his face, and cometh to the prophet; I the LORD will answer him that cometh according to the multitude of his idols;","words":[["H1696","Therefore speak",0,15],["H0559","unto them, and say",16,34],["H0559","unto them, Thus saith",35,56],["H0136","the Lord",57,65],["H3069","GOD",66,69],["H0376","Every man",71,80],["H1004","of the house",81,93],["H3478","of Israel",94,103],["H5927","that setteth up",104,119],["H1544","his idols",120,129],["H3820","in his heart",130,142],["H7760","and putteth",144,155],["H4383","the stumblingblock",156,174],["H5771","of his iniquity",175,190],["H5227","before",191,197],["H6440","his face",198,206],["H0935","and cometh",208,218],["H5030","to the prophet",219,233],["H3068","I the LORD",235,245],["H6030","will answer",246,257],["H0935","him that cometh",258,273],["H7230","according to the multitude",274,300],["H1544","of his idols",301,313]]},"14:5":{"text":"That I may take the house of Israel in their own heart, because they are all estranged from me through their idols.","words":[["H8610","That I may take",0,15],["H1004","the house",16,25],["H3478","of Israel",26,35],["H3820","in their own heart",36,54],["H2114","because they are all estranged",56,86],["H1544","from me through their idols",87,114]]},"14:6":{"text":"Therefore say unto the house of Israel, Thus saith the Lord GOD; Repent, and turn yourselves from your idols; and turn away your faces from all your abominations.","words":[["H0559","Therefore say",0,13],["H1004","unto the house",14,28],["H3478","of Israel",29,38],["H0559","Thus saith",40,50],["H0136","the Lord",51,59],["H3069","GOD",60,63],["H7725","Repent",65,71],["H7725","and turn",73,81],["H1544","yourselves from your idols",82,108],["H7725","and turn away",110,123],["H6440","your faces",124,134],["H8441","from all your abominations",135,161]]},"14:7":{"text":"For every one of the house of Israel, or of the stranger that sojourneth in Israel, which separateth himself from me, and setteth up his idols in his heart, and putteth the stumblingblock of his iniquity before his face, and cometh to a prophet to enquire of him concerning me; I the LORD will answer him by myself:","words":[["H0376","For every one",0,13],["H1004","of the house",14,26],["H3478","of Israel",27,36],["H1616","or of the stranger",38,56],["H1481","that sojourneth",57,72],["H3478","in Israel",73,82],["H5144","which separateth",84,100],["H0310","himself from me",101,116],["H5927","and setteth up",118,132],["H1544","his idols",133,142],["H3820","in his heart",143,155],["H7760","and putteth",157,168],["H4383","the stumblingblock",169,187],["H5771","of his iniquity",188,203],["H5227","before",204,210],["H6440","his face",211,219],["H0935","and cometh",221,231],["H5030","to a prophet",232,244],["H1875","to enquire",245,255],["H3068","of him concerning me; I the LORD",256,288],["H6030","will answer",289,300]]},"14:8":{"text":"And I will set my face against that man, and will make him a sign and a proverb, and I will cut him off from the midst of my people; and ye shall know that I am the LORD.","words":[["H5414","And I will set",0,14],["H6440","my face",15,22],["H0376","against that man",23,39],["H8074","and will make",41,54],["H0226","him a sign",55,65],["H4912","and a proverb",66,79],["H3772","and I will cut him off",81,103],["H8432","from the midst",104,118],["H5971","of my people",119,131],["H3045","and ye shall know",133,150],["H3068","that I am the LORD",151,169]]},"14:9":{"text":"And if the prophet be deceived when he hath spoken a thing, I the LORD have deceived that prophet, and I will stretch out my hand upon him, and will destroy him from the midst of my people Israel.","words":[["H5030","And if the prophet",0,18],["H6601","be deceived",19,30],["H1696","when he hath spoken",31,50],["H1697","a thing",51,58],["H3068","I the LORD",60,70],["H6601","have deceived",71,84],["H5030","that prophet",85,97],["H5186","and I will stretch out",99,121],["H3027","my hand",122,129],["H8045","upon him, and will destroy",130,156],["H8432","him from the midst",157,175],["H5971","of my people",176,188],["H3478","Israel",189,195]]},"14:10":{"text":"And they shall bear the punishment of their iniquity: the punishment of the prophet shall be even as the punishment of him that seeketh unto him;","words":[["H5375","And they shall bear",0,19],["H5771","the punishment of their iniquity",20,52],["H5771","the punishment",54,68],["H5030","of the prophet",69,83],["H5771","shall be even as the punishment",84,115],["H1875","of him that seeketh",116,135]]},"14:11":{"text":"That the house of Israel may go no more astray from me, neither be polluted any more with all their transgressions; but that they may be my people, and I may be their God, saith the Lord GOD.","words":[["H1004","That the house",0,14],["H3478","of Israel",15,24],["H8582","may go no more astray",25,46],["H0310","from me",47,54],["H2930","neither be polluted",56,75],["H6588","any more with all their transgressions",76,114],["H5971","but that they may be my people",116,146],["H0430","and I may be their God",148,170],["H5002","saith",172,177],["H0136","the Lord",178,186],["H3069","GOD",187,190]]},"14:12":{"text":"The word of the LORD came again to me, saying,","words":[["H1697","The word",0,8],["H3068","of the LORD",9,20],["H0559","came again to me, saying",21,45]]},"14:13":{"text":"Son of man, when the land sinneth against me by trespassing grievously, then will I stretch out mine hand upon it, and will break the staff of the bread thereof, and will send famine upon it, and will cut off man and beast from it:","words":[["H1121","Son",0,3],["H0120","of man",4,10],["H0776","when the land",12,25],["H2398","sinneth",26,33],["H4603","against me by trespassing",34,59],["H4604","grievously",60,70],["H5186","then will I stretch out",72,95],["H3027","mine hand",96,105],["H7665","upon it, and will break",106,129],["H4294","the staff",130,139],["H3899","of the bread",140,152],["H7971","thereof, and will send",153,175],["H7458","famine",176,182],["H3772","upon it, and will cut off",183,208],["H0120","man",209,212],["H0929","and beast",213,222]]},"14:14":{"text":"Though these three men, Noah, Daniel, and Job, were in it, they should deliver but their own souls by their righteousness, saith the Lord GOD.","words":[["H7969","Though these three",0,18],["H0582","men",19,22],["H5146","Noah",24,28],["H1840","Daniel",30,36],["H0347","and Job",38,45],["H8432","were in it",47,57],["H5337","they should deliver",59,78],["H5315","but their own souls",79,98],["H6666","by their righteousness",99,121],["H5002","saith",123,128],["H0136","the Lord",129,137],["H3069","GOD",138,141]]},"14:15":{"text":"If I cause noisome beasts to pass through the land, and they spoil it, so that it be desolate, that no man may pass through because of the beasts:","words":[["H3863","If",0,2],["H7451","I cause noisome",3,18],["H2416","beasts",19,25],["H5674","to pass through",26,41],["H0776","the land",42,50],["H7921","and they spoil",52,66],["H8077","it, so that it be desolate",67,93],["H5674","that no man may pass through",95,123],["H6440","because",124,131],["H2416","of the beasts",132,145]]},"14:16":{"text":"Though these three men were in it, as I live, saith the Lord GOD, they shall deliver neither sons nor daughters; they only shall be delivered, but the land shall be desolate.","words":[["H7969","Though these three",0,18],["H0582","men",19,22],["H8432","were in it",23,33],["H2416","as I live",35,44],["H5002","saith",46,51],["H0136","the Lord",52,60],["H3069","GOD",61,64],["H5337","they shall deliver",66,84],["H1121","neither sons",85,97],["H1323","nor daughters",98,111],["H5337","they only shall be delivered",113,141],["H0776","but the land",143,155],["H8077","shall be desolate",156,173]]},"14:17":{"text":"Or if I bring a sword upon that land, and say, Sword, go through the land; so that I cut off man and beast from it:","words":[["H0935","Or if I bring",0,13],["H2719","a sword",14,21],["H0776","upon that land",22,36],["H0559","and say",38,45],["H2719","Sword",47,52],["H5674","go through",54,64],["H0776","the land",65,73],["H3772","so that I cut off",75,92],["H0120","man",93,96],["H0929","and beast",97,106]]},"14:18":{"text":"Though these three men were in it, as I live, saith the Lord GOD, they shall deliver neither sons nor daughters, but they only shall be delivered themselves.","words":[["H7969","Though these three",0,18],["H0582","men",19,22],["H8432","were in it",23,33],["H2416","as I live",35,44],["H5002","saith",46,51],["H0136","the Lord",52,60],["H3069","GOD",61,64],["H5337","they shall deliver",66,84],["H1121","neither sons",85,97],["H1323","nor daughters",98,111],["H5337","but they only shall be delivered",113,145]]},"14:19":{"text":"Or if I send a pestilence into that land, and pour out my fury upon it in blood, to cut off from it man and beast:","words":[["H7971","Or if I send",0,12],["H1698","a pestilence",13,25],["H0776","into that land",26,40],["H8210","and pour out",42,54],["H2534","my fury",55,62],["H1818","upon it in blood",63,79],["H3772","to cut off",81,91],["H0120","from it man",92,103],["H0929","and beast",104,113]]},"14:20":{"text":"Though Noah, Daniel, and Job, were in it, as I live, saith the Lord GOD, they shall deliver neither son nor daughter; they shall but deliver their own souls by their righteousness.","words":[["H5146","Though Noah",0,11],["H1840","Daniel",13,19],["H0347","and Job",21,28],["H8432","were in it",30,40],["H2416","as I live",42,51],["H5002","saith",53,58],["H0136","the Lord",59,67],["H3069","GOD",68,71],["H5337","they shall deliver",73,91],["H1121","neither son",92,103],["H0518","nor",104,107],["H1323","daughter",108,116],["H5337","they shall but deliver",118,140],["H5315","their own souls",141,156],["H6666","by their righteousness",157,179]]},"14:21":{"text":"For thus saith the Lord GOD; How much more when I send my four sore judgments upon Jerusalem, the sword, and the famine, and the noisome beast, and the pestilence, to cut off from it man and beast?","words":[["H0559","For thus saith",0,14],["H0136","the Lord",15,23],["H3069","GOD",24,27],["H7971","How much more when I send",29,54],["H0702","my four",55,62],["H7451","sore",63,67],["H8201","judgments",68,77],["H3389","upon Jerusalem",78,92],["H2719","the sword",94,103],["H7458","and the famine",105,119],["H7451","and the noisome",121,136],["H2416","beast",137,142],["H1698","and the pestilence",144,162],["H3772","to cut off",164,174],["H0120","from it man",175,186],["H0929","and beast",187,196]]},"14:22":{"text":"Yet, behold, therein shall be left a remnant that shall be brought forth, both sons and daughters: behold, they shall come forth unto you, and ye shall see their way and their doings: and ye shall be comforted concerning the evil that I have brought upon Jerusalem, even concerning all that I have brought upon it.","words":[["H3498","Yet, behold, therein shall be left",0,34],["H6413","a remnant",35,44],["H3318","that shall be brought forth",45,72],["H1121","both sons",74,83],["H1323","and daughters",84,97],["H3318","behold, they shall come forth",99,128],["H7200","unto you, and ye shall see",129,155],["H1870","their way",156,165],["H5949","and their doings",166,182],["H5162","and ye shall be comforted",184,209],["H7451","concerning the evil",210,229],["H0935","that I have brought",230,249],["H3389","upon Jerusalem",250,264],["H0935","even concerning all that I have brought",266,305]]},"14:23":{"text":"And they shall comfort you, when ye see their ways and their doings: and ye shall know that I have not done without cause all that I have done in it, saith the Lord GOD.","words":[["H5162","And they shall comfort",0,22],["H7200","you, when ye see",23,39],["H1870","their ways",40,50],["H5949","and their doings",51,67],["H3045","and ye shall know",69,86],["H6213","that I have not done",87,107],["H2600","without cause",108,121],["H6213","all that I have done",122,142],["H5002","in it, saith",143,155],["H0136","the Lord",156,164],["H3069","GOD",165,168]]},"15:1":{"text":"And the word of the LORD came unto me, saying,","words":[["H1697","And the word",0,12],["H3068","of the LORD",13,24],["H0559","came unto me, saying",25,45]]},"15:2":{"text":"Son of man, What is the vine tree more than any tree, or than a branch which is among the trees of the forest?","words":[["H1121","Son",0,3],["H0120","of man",4,10],["H1612","What is the vine",12,28],["H6086","tree",29,33],["H6086","more than any tree",34,52],["H2156","or than a branch",54,70],["H6086","which is among the trees",71,95],["H3293","of the forest",96,109]]},"15:3":{"text":"Shall wood be taken thereof to do any work? or will men take a pin of it to hang any vessel thereon?","words":[["H6086","Shall wood",0,10],["H3947","be taken",11,19],["H6213","thereof to do",20,33],["H4399","any work",34,42],["H3947","or will men take",44,60],["H3489","a pin",61,66],["H8518","of it to hang",67,80],["H3627","any vessel",81,91]]},"15:4":{"text":"Behold, it is cast into the fire for fuel; the fire devoureth both the ends of it, and the midst of it is burned. Is it meet for any work?","words":[["H5414","Behold, it is cast",0,18],["H0784","into the fire",19,32],["H0402","for fuel",33,41],["H0784","the fire",43,51],["H0398","devoureth",52,61],["H8147","both",62,66],["H7098","the ends",67,75],["H8432","of it, and the midst",76,96],["H2787","of it is burned",97,112],["H6743","Is it meet",114,124],["H4399","for any work",125,137]]},"15:5":{"text":"Behold, when it was whole, it was meet for no work: how much less shall it be meet yet for any work, when the fire hath devoured it, and it is burned?","words":[["H8549","Behold, when it was whole",0,25],["H6213","it was meet",27,38],["H4399","for no work",39,50],["H6213","how much less shall it be meet",52,82],["H4399","yet for any work",83,99],["H0784","when the fire",101,114],["H0398","hath devoured",115,128],["H2787","it, and it is burned",129,149]]},"15:6":{"text":"Therefore thus saith the Lord GOD; As the vine tree among the trees of the forest, which I have given to the fire for fuel, so will I give the inhabitants of Jerusalem.","words":[["H0559","Therefore thus saith",0,20],["H0136","the Lord",21,29],["H3069","GOD",30,33],["H1612","As the vine",35,46],["H6086","tree",47,51],["H6086","among the trees",52,67],["H3293","of the forest",68,81],["H5414","which I have given",83,101],["H0784","to the fire",102,113],["H0402","for fuel",114,122],["H5414","so will I give",124,138],["H3427","the inhabitants",139,154],["H3389","of Jerusalem",155,167]]},"15:7":{"text":"And I will set my face against them; they shall go out from one fire, and another fire shall devour them; and ye shall know that I am the LORD, when I set my face against them.","words":[["H5414","And I will set",0,14],["H6440","my face",15,22],["H3318","against them; they shall go out",23,54],["H0784","from one fire",55,68],["H0784","and another fire",70,86],["H0398","shall devour",87,99],["H3045","them; and ye shall know",100,123],["H3068","that I am the LORD",124,142],["H7760","when I set",144,154],["H6440","my face",155,162]]},"15:8":{"text":"And I will make the land desolate, because they have committed a trespass, saith the Lord GOD.","words":[["H5414","And I will make",0,15],["H0776","the land",16,24],["H8077","desolate",25,33],["H4603","because they have committed",35,62],["H4604","a trespass",63,73],["H5002","saith",75,80],["H0136","the Lord",81,89],["H3069","GOD",90,93]]},"16:1":{"text":"Again the word of the LORD came unto me, saying,","words":[["H1697","Again the word",0,14],["H3068","of the LORD",15,26],["H0559","came unto me, saying",27,47]]},"16:2":{"text":"Son of man, cause Jerusalem to know her abominations,","words":[["H1121","Son",0,3],["H0120","of man",4,10],["H3389","cause Jerusalem",12,27],["H3045","to know",28,35],["H8441","her abominations",36,52]]},"16:3":{"text":"And say, Thus saith the Lord GOD unto Jerusalem; Thy birth and thy nativity is of the land of Canaan; thy father was an Amorite, and thy mother an Hittite.","words":[["H0559","And say",0,7],["H0559","Thus saith",9,19],["H0136","the Lord",20,28],["H3069","GOD",29,32],["H3389","unto Jerusalem",33,47],["H4351","Thy birth",49,58],["H4138","and thy nativity",59,75],["H0776","is of the land",76,90],["H3669","of Canaan",91,100],["H0001","thy father",102,112],["H0567","was an Amorite",113,127],["H0517","and thy mother",129,143],["H2850","an Hittite",144,154]]},"16:4":{"text":"And as for thy nativity, in the day thou wast born thy navel was not cut, neither wast thou washed in water to supple thee; thou wast not salted at all, nor swaddled at all.","words":[["H4138","And as for thy nativity",0,23],["H3117","in the day",25,35],["H3205","thou wast born",36,50],["H8270","thy navel",51,60],["H3772","was not cut",61,72],["H7364","neither wast thou washed",74,98],["H4325","in water",99,107],["H4935","to supple",108,117],["H4414","thee; thou wast not salted",118,144],["H4414","at all",145,151],["H2853","nor swaddled",153,165],["H2853","at all",166,172]]},"16:5":{"text":"None eye pitied thee, to do any of these unto thee, to have compassion upon thee; but thou wast cast out in the open field, to the lothing of thy person, in the day that thou wast born.","words":[["H5869","None eye",0,8],["H2347","pitied",9,15],["H6213","thee, to do",16,27],["H0259","any",28,31],["H2550","of these unto thee, to have compassion",32,70],["H7993","upon thee; but thou wast cast out",71,104],["H6440","in the open",105,116],["H7704","field",117,122],["H1604","to the lothing",124,138],["H5315","of thy person",139,152],["H3117","in the day",154,164],["H3205","that thou wast born",165,184]]},"16:6":{"text":"And when I passed by thee, and saw thee polluted in thine own blood, I said unto thee when thou wast in thy blood, Live; yea, I said unto thee when thou wast in thy blood, Live.","words":[["H5674","And when I passed",0,17],["H7200","by thee, and saw",18,34],["H0947","thee polluted",35,48],["H1818","in thine own blood",49,67],["H0559","I said",69,75],["H1818","unto thee when thou wast in thy blood",76,113],["H2421","Live",115,119],["H0559","yea, I said",121,132],["H1818","unto thee when thou wast in thy blood",133,170],["H2421","Live",172,176]]},"16:7":{"text":"I have caused thee to multiply as the bud of the field, and thou hast increased and waxen great, and thou art come to excellent ornaments: thy breasts are fashioned, and thine hair is grown, whereas thou wast naked and bare.","words":[["H5414","I have caused",0,13],["H7233","thee to multiply",14,30],["H6780","as the bud",31,41],["H7704","of the field",42,54],["H7235","and thou hast increased",56,79],["H1431","and waxen great",80,95],["H0935","and thou art come",97,114],["H5716","to excellent",115,127],["H5716","ornaments",128,137],["H7699","thy breasts",139,150],["H3559","are fashioned",151,164],["H8181","and thine hair",166,180],["H6779","is grown",181,189],["H5903","whereas thou wast naked",191,214],["H6181","and bare",215,223]]},"16:8":{"text":"Now when I passed by thee, and looked upon thee, behold, thy time was the time of love; and I spread my skirt over thee, and covered thy nakedness: yea, I sware unto thee, and entered into a covenant with thee, saith the Lord GOD, and thou becamest mine.","words":[["H5674","Now when I passed",0,17],["H7200","by thee, and looked",18,37],["H6256","upon thee, behold, thy time",38,65],["H6256","was the time",66,78],["H1730","of love",79,86],["H6566","and I spread",88,100],["H3671","my skirt",101,109],["H3680","over thee, and covered",110,132],["H6172","thy nakedness",133,146],["H7650","yea, I sware",148,160],["H0935","unto thee, and entered",161,183],["H1285","into a covenant",184,199],["H5002","with thee, saith",200,216],["H0136","the Lord",217,225],["H3069","GOD",226,229]]},"16:9":{"text":"Then washed I thee with water; yea, I throughly washed away thy blood from thee, and I anointed thee with oil.","words":[["H7364","Then washed",0,11],["H4325","I thee with water",12,29],["H7857","yea, I throughly washed away",31,59],["H1818","thy blood",60,69],["H5480","from thee, and I anointed",70,95],["H8081","thee with oil",96,109]]},"16:10":{"text":"I clothed thee also with broidered work, and shod thee with badgers' skin, and I girded thee about with fine linen, and I covered thee with silk.","words":[["H3847","I clothed",0,9],["H7553","thee also with broidered work",10,39],["H5274","and shod",41,49],["H8476","thee with badgers' skin",50,73],["H2280","and I girded",75,87],["H8336","thee about with fine linen",88,114],["H3680","and I covered",116,129],["H4897","thee with silk",130,144]]},"16:11":{"text":"I decked thee also with ornaments, and I put bracelets upon thy hands, and a chain on thy neck.","words":[["H5710","I decked",0,8],["H5716","thee also with ornaments",9,33],["H5414","and I put",35,44],["H6781","bracelets",45,54],["H3027","upon thy hands",55,69],["H7242","and a chain",71,82],["H1627","on thy neck",83,94]]},"16:12":{"text":"And I put a jewel on thy forehead, and earrings in thine ears, and a beautiful crown upon thine head.","words":[["H5414","And I put",0,9],["H5141","a jewel",10,17],["H0639","on thy forehead",18,33],["H5694","and earrings",35,47],["H0241","in thine ears",48,61],["H8597","and a beautiful",63,78],["H5850","crown",79,84],["H7218","upon thine head",85,100]]},"16:13":{"text":"Thus wast thou decked with gold and silver; and thy raiment was of fine linen, and silk, and broidered work; thou didst eat fine flour, and honey, and oil: and thou wast exceeding beautiful, and thou didst prosper into a kingdom.","words":[["H5710","Thus wast thou decked",0,21],["H2091","with gold",22,31],["H3701","and silver",32,42],["H4403","and thy raiment",44,59],["H8336","was of fine linen",60,77],["H8336","was of fine linen",60,77],["H4897","and silk",79,87],["H7553","and broidered work",89,107],["H0398","thou didst eat",109,123],["H5560","fine flour",124,134],["H1706","and honey",136,145],["H8081","and oil",147,154],["H3966","and thou wast exceeding",156,179],["H3302","beautiful",180,189],["H6743","and thou didst prosper",191,213],["H4410","into a kingdom",214,228]]},"16:14":{"text":"And thy renown went forth among the heathen for thy beauty: for it was perfect through my comeliness, which I had put upon thee, saith the Lord GOD.","words":[["H8034","And thy renown",0,14],["H3318","went forth",15,25],["H1471","among the heathen",26,43],["H3308","for thy beauty",44,58],["H3632","for it was perfect",60,78],["H1926","through my comeliness",79,100],["H7760","which I had put",102,117],["H5002","upon thee, saith",118,134],["H0136","the Lord",135,143],["H3069","GOD",144,147]]},"16:15":{"text":"But thou didst trust in thine own beauty, and playedst the harlot because of thy renown, and pouredst out thy fornications on every one that passed by; his it was.","words":[["H0982","But thou didst trust",0,20],["H3308","in thine own beauty",21,40],["H2181","and playedst the harlot",42,65],["H8034","because of thy renown",66,87],["H8210","and pouredst out",89,105],["H8457","thy fornications",106,122],["H5674","on every one that passed by",123,150]]},"16:16":{"text":"And of thy garments thou didst take, and deckedst thy high places with divers colours, and playedst the harlot thereupon: the like things shall not come, neither shall it be so.","words":[["H0899","And of thy garments",0,19],["H3947","thou didst take",20,35],["H6213","and deckedst",37,49],["H1116","thy high places",50,65],["H2921","with divers colours",66,85],["H2181","and playedst the harlot",87,110],["H0935","thereupon: the like things shall not come",111,152]]},"16:17":{"text":"Thou hast also taken thy fair jewels of my gold and of my silver, which I had given thee, and madest to thyself images of men, and didst commit whoredom with them,","words":[["H3947","Thou hast also taken",0,20],["H8597","thy fair",21,29],["H3627","jewels",30,36],["H2091","of my gold",37,47],["H3701","and of my silver",48,64],["H5414","which I had given",66,83],["H6213","thee, and madest",84,100],["H6754","to thyself images",101,118],["H2145","of men",119,125],["H2181","and didst commit whoredom",127,152]]},"16:18":{"text":"And tookest thy broidered garments, and coveredst them: and thou hast set mine oil and mine incense before them.","words":[["H3947","And tookest",0,11],["H7553","thy broidered",12,25],["H0899","garments",26,34],["H3680","and coveredst",36,49],["H5414","them: and thou hast set",50,73],["H8081","mine oil",74,82],["H7004","and mine incense",83,99],["H6440","before",100,106]]},"16:19":{"text":"My meat also which I gave thee, fine flour, and oil, and honey, wherewith I fed thee, thou hast even set it before them for a sweet savour: and thus it was, saith the Lord GOD.","words":[["H3899","My meat",0,7],["H5414","also which I gave",8,25],["H5560","thee, fine flour",26,42],["H8081","and oil",44,51],["H1706","and honey",53,62],["H0398","wherewith I fed",64,79],["H5414","thee, thou hast even set",80,104],["H6440","it before",105,114],["H5207","them for a sweet",115,131],["H7381","savour",132,138],["H5002","and thus it was, saith",140,162],["H0136","the Lord",163,171],["H3069","GOD",172,175]]},"16:20":{"text":"Moreover thou hast taken thy sons and thy daughters, whom thou hast borne unto me, and these hast thou sacrificed unto them to be devoured. Is this of thy whoredoms a small matter,","words":[["H3947","Moreover thou hast taken",0,24],["H1121","thy sons",25,33],["H1323","and thy daughters",34,51],["H3205","whom thou hast borne",53,73],["H2076","unto me, and these hast thou sacrificed",74,113],["H0398","unto them to be devoured",114,138],["H8457","Is this of thy whoredoms",140,164],["H4592","a small matter",165,179]]},"16:21":{"text":"That thou hast slain my children, and delivered them to cause them to pass through the fire for them?","words":[["H7819","That thou hast slain",0,20],["H1121","my children",21,32],["H5414","and delivered",34,47],["H5674","them to cause them to pass through",48,82]]},"16:22":{"text":"And in all thine abominations and thy whoredoms thou hast not remembered the days of thy youth, when thou wast naked and bare, and wast polluted in thy blood.","words":[["H8441","And in all thine abominations",0,29],["H8457","and thy whoredoms",30,47],["H2142","thou hast not remembered",48,72],["H3117","the days",73,81],["H5271","of thy youth",82,94],["H5903","when thou wast naked",96,116],["H6181","and bare",117,125],["H0947","and wast polluted",127,144],["H1818","in thy blood",145,157]]},"16:23":{"text":"And it came to pass after all thy wickedness, (woe, woe unto thee! saith the Lord GOD;)","words":[["H0310","And it came to pass after",0,25],["H7451","all thy wickedness",26,44],["H0188","(woe",46,50],["H0188","woe",52,55],["H5002","unto thee! saith",56,72],["H0136","the Lord",73,81],["H3069","GOD",82,85]]},"16:24":{"text":"That thou hast also built unto thee an eminent place, and hast made thee an high place in every street.","words":[["H1129","That thou hast also built",0,25],["H1354","unto thee an eminent place",26,52],["H6213","and hast made",54,67],["H7413","thee an high place",68,86],["H7339","in every street",87,102]]},"16:25":{"text":"Thou hast built thy high place at every head of the way, and hast made thy beauty to be abhorred, and hast opened thy feet to every one that passed by, and multiplied thy whoredoms.","words":[["H1129","Thou hast built",0,15],["H7413","thy high place",16,30],["H7218","at every head",31,44],["H1870","of the way",45,55],["H3308","and hast made thy beauty",57,81],["H8581","to be abhorred",82,96],["H6589","and hast opened",98,113],["H7272","thy feet",114,122],["H5674","to every one that passed by",123,150],["H7235","and multiplied",152,166],["H8457","thy whoredoms",167,180]]},"16:26":{"text":"Thou hast also committed fornication with the Egyptians thy neighbours, great of flesh; and hast increased thy whoredoms, to provoke me to anger.","words":[["H2181","Thou hast also committed fornication",0,36],["H1121","with the Egyptians",37,55],["H4714","with the Egyptians",37,55],["H7934","thy neighbours",56,70],["H1432","great",72,77],["H1320","of flesh",78,86],["H7235","and hast increased",88,106],["H8457","thy whoredoms",107,120],["H3707","to provoke me to anger",122,144]]},"16:27":{"text":"Behold, therefore I have stretched out my hand over thee, and have diminished thine ordinary food, and delivered thee unto the will of them that hate thee, the daughters of the Philistines, which are ashamed of thy lewd way.","words":[["H5186","Behold, therefore I have stretched out",0,38],["H3027","my hand",39,46],["H1639","over thee, and have diminished",47,77],["H2706","thine ordinary",78,92],["H5414","food, and delivered",93,112],["H5315","thee unto the will",113,131],["H8130","of them that hate",132,149],["H1323","thee, the daughters",150,169],["H6430","of the Philistines",170,188],["H3637","which are ashamed",190,207],["H2154","of thy lewd",208,219],["H1870","way",220,223]]},"16:28":{"text":"Thou hast played the whore also with the Assyrians, because thou wast unsatiable; yea, thou hast played the harlot with them, and yet couldest not be satisfied.","words":[["H2181","Thou hast played the whore",0,26],["H1121","also with the Assyrians",27,50],["H0804","also with the Assyrians",27,50],["H1115","because",52,59],["H7646","thou wast unsatiable",60,80],["H2181","yea, thou hast played the harlot",82,114],["H7654","with them, and yet couldest not be satisfied",115,159]]},"16:29":{"text":"Thou hast moreover multiplied thy fornication in the land of Canaan unto Chaldea; and yet thou wast not satisfied herewith.","words":[["H7235","Thou hast moreover multiplied",0,29],["H8457","thy fornication",30,45],["H0776","in the land",46,57],["H3667","of Canaan",58,67],["H3778","unto Chaldea",68,80],["H7646","and yet thou wast not satisfied",82,113],["H2063","herewith",114,122]]},"16:30":{"text":"How weak is thine heart, saith the Lord GOD, seeing thou doest all these things, the work of an imperious whorish woman;","words":[["H0535","How weak",0,8],["H3826","is thine heart",9,23],["H5002","saith",25,30],["H0136","the Lord",31,39],["H3069","GOD",40,43],["H6213","seeing thou doest",45,62],["H4639","all these things, the work",63,89],["H7986","of an imperious",90,105],["H2181","whorish",106,113],["H0802","woman",114,119]]},"16:31":{"text":"In that thou buildest thine eminent place in the head of every way, and makest thine high place in every street; and hast not been as an harlot, in that thou scornest hire;","words":[["H1129","In that thou buildest",0,21],["H1354","thine eminent place",22,41],["H7218","in the head",42,53],["H1870","of every way",54,66],["H6213","and makest",68,78],["H7413","thine high place",79,95],["H7339","in every street",96,111],["H2181","and hast not been as an harlot",113,143],["H7046","in that thou scornest",145,166],["H0868","hire",167,171]]},"16:32":{"text":"But as a wife that committeth adultery, which taketh strangers instead of her husband!","words":[["H0802","But as a wife",0,13],["H5003","that committeth adultery",14,38],["H3947","which taketh",40,52],["H2114","strangers",53,62],["H0376","instead of her husband",63,85]]},"16:33":{"text":"They give gifts to all whores: but thou givest thy gifts to all thy lovers, and hirest them, that they may come unto thee on every side for thy whoredom.","words":[["H5414","They give",0,9],["H5078","gifts",10,15],["H2181","to all whores",16,29],["H5414","but thou givest",31,46],["H5083","thy gifts",47,56],["H0157","to all thy lovers",57,74],["H7809","and hirest",76,86],["H0935","them, that they may come",87,111],["H5439","unto thee on every side",112,135],["H8457","for thy whoredom",136,152]]},"16:34":{"text":"And the contrary is in thee from other women in thy whoredoms, whereas none followeth thee to commit whoredoms: and in that thou givest a reward, and no reward is given unto thee, therefore thou art contrary.","words":[["H2016","And the contrary",0,16],["H0802","is in thee from other women",17,44],["H8457","in thy whoredoms",45,61],["H0310","whereas none followeth",63,85],["H2181","thee to commit whoredoms",86,110],["H5414","and in that thou givest",112,135],["H0868","a reward",136,144],["H0868","and no reward",146,159],["H5414","is given",160,168],["H1961","unto thee, therefore thou art",169,198],["H2016","contrary",199,207]]},"16:35":{"text":"Wherefore, O harlot, hear the word of the LORD:","words":[["H2181","Wherefore, O harlot",0,19],["H8085","hear",21,25],["H1697","the word",26,34],["H3068","of the LORD",35,46]]},"16:36":{"text":"Thus saith the Lord GOD; Because thy filthiness was poured out, and thy nakedness discovered through thy whoredoms with thy lovers, and with all the idols of thy abominations, and by the blood of thy children, which thou didst give unto them;","words":[["H0559","Thus saith",0,10],["H0136","the Lord",11,19],["H3069","GOD",20,23],["H5178","Because thy filthiness",25,47],["H8210","was poured out",48,62],["H6172","and thy nakedness",64,81],["H1540","discovered",82,92],["H8457","through thy whoredoms",93,114],["H0157","with thy lovers",115,130],["H1544","and with all the idols",132,154],["H8441","of thy abominations",155,174],["H1818","and by the blood",176,192],["H1121","of thy children",193,208],["H5414","which thou didst give",210,231]]},"16:37":{"text":"Behold, therefore I will gather all thy lovers, with whom thou hast taken pleasure, and all them that thou hast loved, with all them that thou hast hated; I will even gather them round about against thee, and will discover thy nakedness unto them, that they may see all thy nakedness.","words":[["H6908","Behold, therefore I will gather",0,31],["H0157","all thy lovers",32,46],["H6149","with whom thou hast taken pleasure",48,82],["H0157","and all them that thou hast loved",84,117],["H8130","with all them that thou hast hated",119,153],["H6908","I will even gather",155,173],["H5439","them round about",174,190],["H1540","against thee, and will discover",191,222],["H6172","thy nakedness",223,236],["H7200","unto them, that they may see",237,265],["H6172","all thy nakedness",266,283]]},"16:38":{"text":"And I will judge thee, as women that break wedlock and shed blood are judged; and I will give thee blood in fury and jealousy.","words":[["H8199","And I will judge",0,16],["H5003","thee, as women that break wedlock",17,50],["H8210","and shed",51,59],["H1818","blood",60,65],["H4941","are judged",66,76],["H5414","and I will give",78,93],["H1818","thee blood",94,104],["H2534","in fury",105,112],["H7068","and jealousy",113,125]]},"16:39":{"text":"And I will also give thee into their hand, and they shall throw down thine eminent place, and shall break down thy high places: they shall strip thee also of thy clothes, and shall take thy fair jewels, and leave thee naked and bare.","words":[["H5414","And I will also give",0,20],["H3027","thee into their hand",21,41],["H2040","and they shall throw down",43,68],["H1354","thine eminent place",69,88],["H5422","and shall break down",90,110],["H7413","thy high places",111,126],["H6584","they shall strip",128,144],["H0899","thee also of thy clothes",145,169],["H3947","and shall take",171,185],["H8597","thy fair",186,194],["H3627","jewels",195,201],["H3240","and leave",203,212],["H5903","thee naked",213,223],["H6181","and bare",224,232]]},"16:40":{"text":"They shall also bring up a company against thee, and they shall stone thee with stones, and thrust thee through with their swords.","words":[["H5927","They shall also bring up",0,24],["H6951","a company",25,34],["H7275","against thee, and they shall stone",35,69],["H0068","thee with stones",70,86],["H1333","and thrust thee through",88,111],["H2719","with their swords",112,129]]},"16:41":{"text":"And they shall burn thine houses with fire, and execute judgments upon thee in the sight of many women: and I will cause thee to cease from playing the harlot, and thou also shalt give no hire any more.","words":[["H8313","And they shall burn",0,19],["H1004","thine houses",20,32],["H0784","with fire",33,42],["H6213","and execute",44,55],["H8201","judgments",56,65],["H5869","upon thee in the sight",66,88],["H7227","of many",89,96],["H0802","women",97,102],["H7673","and I will cause thee to cease",104,134],["H2181","from playing the harlot",135,158],["H5414","and thou also shalt give",160,184],["H0868","no hire",185,192]]},"16:42":{"text":"So will I make my fury toward thee to rest, and my jealousy shall depart from thee, and I will be quiet, and will be no more angry.","words":[["H2534","So will I make my fury",0,22],["H5117","toward thee to rest",23,42],["H7068","and my jealousy",44,59],["H5493","shall depart",60,72],["H8252","from thee, and I will be quiet",73,103],["H3707","and will be no more angry",105,130]]},"16:43":{"text":"Because thou hast not remembered the days of thy youth, but hast fretted me in all these things; behold, therefore I also will recompense thy way upon thine head, saith the Lord GOD: and thou shalt not commit this lewdness above all thine abominations.","words":[["H2142","Because thou hast not remembered",0,32],["H3117","the days",33,41],["H5271","of thy youth",42,54],["H7264","but hast fretted",56,72],["H1887","me in all these things; behold",73,103],["H5414","therefore I also will recompense",105,137],["H1870","thy way",138,145],["H7218","upon thine head",146,161],["H5002","saith",163,168],["H0136","the Lord",169,177],["H3069","GOD",178,181],["H6213","and thou shalt not commit",183,208],["H2154","this lewdness",209,222],["H8441","above all thine abominations",223,251]]},"16:44":{"text":"Behold, every one that useth proverbs shall use this proverb against thee, saying, As is the mother, so is her daughter.","words":[["H4911","Behold, every one that useth proverbs",0,37],["H4911","shall use this proverb",38,60],["H0559","against thee, saying",61,81],["H0517","As is the mother",83,99],["H1323","so is her daughter",101,119]]},"16:45":{"text":"Thou art thy mother's daughter, that lotheth her husband and her children; and thou art the sister of thy sisters, which lothed their husbands and their children: your mother was an Hittite, and your father an Amorite.","words":[["H0517","Thou art thy mother's",0,21],["H1323","daughter",22,30],["H1602","that lotheth",32,44],["H0376","her husband",45,56],["H1121","and her children",57,73],["H0269","and thou art the sister",75,98],["H0269","of thy sisters",99,113],["H1602","which lothed",115,127],["H0582","their husbands",128,142],["H1121","and their children",143,161],["H0517","your mother",163,174],["H2850","was an Hittite",175,189],["H0001","and your father",191,206],["H0567","an Amorite",207,217]]},"16:46":{"text":"And thine elder sister is Samaria, she and her daughters that dwell at thy left hand: and thy younger sister, that dwelleth at thy right hand, is Sodom and her daughters.","words":[["H1419","And thine elder",0,15],["H0269","sister",16,22],["H8111","is Samaria",23,33],["H1323","she and her daughters",35,56],["H3427","that dwell",57,67],["H8040","at thy left hand",68,84],["H6996","and thy younger",86,101],["H0269","sister",102,108],["H3427","that dwelleth",110,123],["H3225","at thy right hand",124,141],["H5467","is Sodom",143,151],["H1323","and her daughters",152,169]]},"16:47":{"text":"Yet hast thou not walked after their ways, nor done after their abominations: but, as if that were a very little thing, thou wast corrupted more than they in all thy ways.","words":[["H1980","Yet hast thou not walked",0,24],["H1870","after their ways",25,41],["H6213","nor done",43,51],["H8441","after their abominations",52,76],["H6985","but, as if that were a very",78,105],["H4592","little",106,112],["H6962","little",106,112],["H7843","thing, thou wast corrupted",113,139],["H2004","more than they",140,154],["H1870","in all thy ways",155,170]]},"16:48":{"text":"As I live, saith the Lord GOD, Sodom thy sister hath not done, she nor her daughters, as thou hast done, thou and thy daughters.","words":[["H2416","As I live",0,9],["H5002","saith",11,16],["H0136","the Lord",17,25],["H3069","GOD",26,29],["H5467","Sodom",31,36],["H0269","thy sister",37,47],["H6213","hath not done",48,61],["H1323","she nor her daughters",63,84],["H6213","as thou hast done",86,103],["H1323","thou and thy daughters",105,127]]},"16:49":{"text":"Behold, this was the iniquity of thy sister Sodom, pride, fulness of bread, and abundance of idleness was in her and in her daughters, neither did she strengthen the hand of the poor and needy.","words":[["H5771","Behold, this was the iniquity",0,29],["H0269","of thy sister",30,43],["H5467","Sodom",44,49],["H1347","pride",51,56],["H7653","fulness",58,65],["H3899","of bread",66,74],["H7962","and abundance",76,89],["H8252","of idleness",90,101],["H1323","was in her and in her daughters",102,133],["H2388","neither did she strengthen",135,161],["H3027","the hand",162,170],["H6041","of the poor",171,182],["H0034","and needy",183,192]]},"16:50":{"text":"And they were haughty, and committed abomination before me: therefore I took them away as I saw good.","words":[["H1361","And they were haughty",0,21],["H6213","and committed",23,36],["H8441","abomination",37,48],["H6440","before",49,55],["H5493","me: therefore I took them away",56,86],["H7200","as I saw",87,95]]},"16:51":{"text":"Neither hath Samaria committed half of thy sins; but thou hast multiplied thine abominations more than they, and hast justified thy sisters in all thine abominations which thou hast done.","words":[["H8111","Neither hath Samaria",0,20],["H2398","committed",21,30],["H2677","half",31,35],["H2403","of thy sins",36,47],["H7235","but thou hast multiplied",49,73],["H8441","thine abominations",74,92],["H2007","more than they",93,107],["H6663","and hast justified",109,127],["H0269","thy sisters",128,139],["H8441","in all thine abominations",140,165],["H6213","which thou hast done",166,186]]},"16:52":{"text":"Thou also, which hast judged thy sisters, bear thine own shame for thy sins that thou hast committed more abominable than they: they are more righteous than thou: yea, be thou confounded also, and bear thy shame, in that thou hast justified thy sisters.","words":[["H6419","Thou also, which hast judged",0,28],["H0269","thy sisters",29,40],["H5375","bear",42,46],["H3639","thine own shame",47,62],["H2403","for thy sins",63,75],["H8581","that thou hast committed more abominable",76,116],["H2004","than they",117,126],["H6663","they are more righteous",128,151],["H0954","than thou: yea, be thou confounded",152,186],["H5375","also, and bear",187,201],["H3639","thy shame",202,211],["H6663","in that thou hast justified",213,240],["H0269","thy sisters",241,252]]},"16:53":{"text":"When I shall bring again their captivity, the captivity of Sodom and her daughters, and the captivity of Samaria and her daughters, then will I bring again the captivity of thy captives in the midst of them:","words":[["H7725","When I shall bring again",0,24],["H7622","their captivity",25,40],["H7622","their captivity",25,40],["H7622","the captivity",42,55],["H7622","the captivity",42,55],["H5467","of Sodom",56,64],["H1323","and her daughters",65,82],["H7622","and the captivity",84,101],["H7622","and the captivity",84,101],["H8111","of Samaria",102,112],["H1323","and her daughters",113,130],["H7622","then will I bring again the captivity",132,169],["H7622","then will I bring again the captivity",132,169],["H7622","of thy captives",170,185],["H8432","in the midst",186,198]]},"16:54":{"text":"That thou mayest bear thine own shame, and mayest be confounded in all that thou hast done, in that thou art a comfort unto them.","words":[["H5375","That thou mayest bear",0,21],["H3639","thine own shame",22,37],["H3637","and mayest be confounded",39,63],["H6213","in all that thou hast done",64,90],["H5162","in that thou art a comfort",92,118]]},"16:55":{"text":"When thy sisters, Sodom and her daughters, shall return to their former estate, and Samaria and her daughters shall return to their former estate, then thou and thy daughters shall return to your former estate.","words":[["H0269","When thy sisters",0,16],["H5467","Sodom",18,23],["H1323","and her daughters",24,41],["H7725","shall return",43,55],["H6927","to their former estate",56,78],["H8111","and Samaria",80,91],["H1323","and her daughters",92,109],["H7725","shall return",110,122],["H6927","to their former estate",123,145],["H1323","then thou and thy daughters",147,174],["H7725","shall return",175,187],["H6927","to your former estate",188,209]]},"16:56":{"text":"For thy sister Sodom was not mentioned by thy mouth in the day of thy pride,","words":[["H0269","For thy sister",0,14],["H5467","Sodom",15,20],["H8052","was not mentioned",21,38],["H6310","by thy mouth",39,51],["H3117","in the day",52,62],["H1347","of thy pride",63,75]]},"16:57":{"text":"Before thy wickedness was discovered, as at the time of thy reproach of the daughters of Syria, and all that are round about her, the daughters of the Philistines, which despise thee round about.","words":[["H7451","Before thy wickedness",0,21],["H1540","was discovered",22,36],["H6256","as at the time",38,52],["H2781","of thy reproach",53,68],["H1323","of the daughters",69,85],["H0758","of Syria",86,94],["H5439","and all that are round about",96,124],["H1323","her, the daughters",125,143],["H6430","of the Philistines",144,162],["H7590","which despise",164,177],["H5439","thee round about",178,194]]},"16:58":{"text":"Thou hast borne thy lewdness and thine abominations, saith the LORD.","words":[["H5375","Thou hast borne",0,15],["H2154","thy lewdness",16,28],["H8441","and thine abominations",29,51],["H5002","saith",53,58],["H3068","the LORD",59,67]]},"16:59":{"text":"For thus saith the Lord GOD; I will even deal with thee as thou hast done, which hast despised the oath in breaking the covenant.","words":[["H0559","For thus saith",0,14],["H0136","the Lord",15,23],["H3069","GOD",24,27],["H6213","I will even deal",29,45],["H6213","with thee as thou hast done",46,73],["H0959","which hast despised",75,94],["H0423","the oath",95,103],["H6565","in breaking",104,115],["H1285","the covenant",116,128]]},"16:60":{"text":"Nevertheless I will remember my covenant with thee in the days of thy youth, and I will establish unto thee an everlasting covenant.","words":[["H2142","Nevertheless I will remember",0,28],["H1285","my covenant",29,40],["H3117","with thee in the days",41,62],["H5271","of thy youth",63,75],["H6965","and I will establish",77,97],["H5769","unto thee an everlasting",98,122],["H1285","covenant",123,131]]},"16:61":{"text":"Then thou shalt remember thy ways, and be ashamed, when thou shalt receive thy sisters, thine elder and thy younger: and I will give them unto thee for daughters, but not by thy covenant.","words":[["H2142","Then thou shalt remember",0,24],["H1870","thy ways",25,33],["H3637","and be ashamed",35,49],["H3947","when thou shalt receive",51,74],["H0269","thy sisters",75,86],["H1419","thine elder",88,99],["H6996","and thy younger",100,115],["H5414","and I will give",117,132],["H1323","them unto thee for daughters",133,161],["H1285","but not by thy covenant",163,186]]},"16:62":{"text":"And I will establish my covenant with thee; and thou shalt know that I am the LORD:","words":[["H6965","And I will establish",0,20],["H1285","my covenant",21,32],["H3045","with thee; and thou shalt know",33,63],["H3068","that I am the LORD",64,82]]},"16:63":{"text":"That thou mayest remember, and be confounded, and never open thy mouth any more because of thy shame, when I am pacified toward thee for all that thou hast done, saith the Lord GOD.","words":[["H2142","That thou mayest remember",0,25],["H0954","and be confounded",27,44],["H6610","and never open",46,60],["H6310","thy mouth",61,70],["H6440","any more because",71,87],["H3639","of thy shame",88,100],["H3722","when I am pacified",102,120],["H6213","toward thee for all that thou hast done",121,160],["H5002","saith",162,167],["H0136","the Lord",168,176],["H3069","GOD",177,180]]},"17:1":{"text":"And the word of the LORD came unto me, saying,","words":[["H1697","And the word",0,12],["H3068","of the LORD",13,24],["H0559","came unto me, saying",25,45]]},"17:2":{"text":"Son of man, put forth a riddle, and speak a parable unto the house of Israel;","words":[["H1121","Son",0,3],["H0120","of man",4,10],["H2330","put forth",12,21],["H2420","a riddle",22,30],["H4911","and speak",32,41],["H4912","a parable",42,51],["H1004","unto the house",52,66],["H3478","of Israel",67,76]]},"17:3":{"text":"And say, Thus saith the Lord GOD; A great eagle with great wings, longwinged, full of feathers, which had divers colours, came unto Lebanon, and took the highest branch of the cedar:","words":[["H0559","And say",0,7],["H0559","Thus saith",9,19],["H0136","the Lord",20,28],["H3069","GOD",29,32],["H1419","A great",34,41],["H5404","eagle",42,47],["H1419","with great",48,58],["H3671","wings",59,64],["H0083","longwinged",66,76],["H0750","longwinged",66,76],["H4392","full",78,82],["H5133","of feathers",83,94],["H7553","which had divers colours",96,120],["H0935","came",122,126],["H3844","unto Lebanon",127,139],["H3947","and took",141,149],["H6788","the highest branch",150,168],["H0730","of the cedar",169,181]]},"17:4":{"text":"He cropped off the top of his young twigs, and carried it into a land of traffick; he set it in a city of merchants.","words":[["H6998","He cropped off",0,14],["H7218","the top",15,22],["H3242","of his young twigs",23,41],["H0935","and carried",43,54],["H0776","it into a land",55,69],["H3667","of traffick",70,81],["H7760","he set",83,89],["H5892","it in a city",90,102],["H7402","of merchants",103,115]]},"17:5":{"text":"He took also of the seed of the land, and planted it in a fruitful field; he placed it by great waters, and set it as a willow tree.","words":[["H3947","He took",0,7],["H2233","also of the seed",8,24],["H0776","of the land",25,36],["H5414","and planted",38,49],["H2233","it in a fruitful",50,66],["H7704","field",67,72],["H3947","he placed",74,83],["H7227","it by great",84,95],["H4325","waters",96,102],["H7760","and set",104,111],["H6851","it as a willow tree",112,131]]},"17:6":{"text":"And it grew, and became a spreading vine of low stature, whose branches turned toward him, and the roots thereof were under him: so it became a vine, and brought forth branches, and shot forth sprigs.","words":[["H6779","And it grew",0,11],["H5628","and became a spreading",13,35],["H1612","vine",36,40],["H8217","of low",41,47],["H6967","stature",48,55],["H1808","whose branches",57,71],["H6437","turned",72,78],["H8328","toward him, and the roots",79,104],["H1612","thereof were under him: so it became a vine",105,148],["H6213","and brought forth",150,167],["H0905","branches",168,176],["H7971","and shot",178,186],["H6288","forth sprigs",187,199]]},"17:7":{"text":"There was also another great eagle with great wings and many feathers: and, behold, this vine did bend her roots toward him, and shot forth her branches toward him, that he might water it by the furrows of her plantation.","words":[["H0259","There was also another",0,22],["H1419","great",23,28],["H5404","eagle",29,34],["H1419","with great",35,45],["H3671","wings",46,51],["H7227","and many",52,60],["H5133","feathers",61,69],["H1612","and, behold, this vine",71,93],["H3719","did bend",94,102],["H8328","her roots",103,112],["H7971","toward him, and shot forth",113,139],["H1808","her branches",140,152],["H8248","toward him, that he might water",153,184],["H6170","it by the furrows",185,202],["H4302","of her plantation",203,220]]},"17:8":{"text":"It was planted in a good soil by great waters, that it might bring forth branches, and that it might bear fruit, that it might be a goodly vine.","words":[["H8362","It was planted",0,14],["H2896","in a good",15,24],["H7704","soil",25,29],["H7227","by great",30,38],["H4325","waters",39,45],["H6213","that it might bring forth",47,72],["H6057","branches",73,81],["H5375","and that it might bear",83,105],["H6529","fruit",106,111],["H0155","that it might be a goodly",113,138],["H1612","vine",139,143]]},"17:9":{"text":"Say thou, Thus saith the Lord GOD; Shall it prosper? shall he not pull up the roots thereof, and cut off the fruit thereof, that it wither? it shall wither in all the leaves of her spring, even without great power or many people to pluck it up by the roots thereof.","words":[["H0559","Say",0,3],["H0559","thou, Thus saith",4,20],["H0136","the Lord",21,29],["H3069","GOD",30,33],["H6743","Shall it prosper",35,51],["H5423","shall he not pull up",53,73],["H8328","the roots",74,83],["H7082","thereof, and cut off",84,104],["H6529","the fruit",105,114],["H3001","thereof, that it wither",115,138],["H3001","it shall wither",140,155],["H2964","in all the leaves",156,173],["H6780","of her spring",174,187],["H1419","even without great",189,207],["H2220","power",208,213],["H7227","or many",214,221],["H5971","people",222,228],["H5375","to pluck it up",229,243],["H8328","by the roots",244,256]]},"17:10":{"text":"Yea, behold, being planted, shall it prosper? shall it not utterly wither, when the east wind toucheth it? it shall wither in the furrows where it grew.","words":[["H8362","Yea, behold, being planted",0,26],["H6743","shall it prosper",28,44],["H3001","shall it not utterly",46,66],["H3001","wither",67,73],["H6921","when the east",75,88],["H7307","wind",89,93],["H5060","toucheth",94,102],["H3001","it? it shall wither",103,122],["H6170","in the furrows",123,137],["H6780","where it grew",138,151]]},"17:11":{"text":"Moreover the word of the LORD came unto me, saying,","words":[["H1697","Moreover the word",0,17],["H3068","of the LORD",18,29],["H0559","came unto me, saying",30,50]]},"17:12":{"text":"Say now to the rebellious house, Know ye not what these things mean? tell them, Behold, the king of Babylon is come to Jerusalem, and hath taken the king thereof, and the princes thereof, and led them with him to Babylon;","words":[["H0559","Say",0,3],["H4805","now to the rebellious",4,25],["H1004","house",26,31],["H3045","Know",33,37],["H0559","ye not what these things mean? tell",38,73],["H4428","them, Behold, the king",74,96],["H0894","of Babylon",97,107],["H0935","is come",108,115],["H3389","to Jerusalem",116,128],["H3947","and hath taken",130,144],["H4428","the king",145,153],["H8269","thereof, and the princes",154,178],["H0935","thereof, and led",179,195],["H0894","them with him to Babylon",196,220]]},"17:13":{"text":"And hath taken of the king's seed, and made a covenant with him, and hath taken an oath of him: he hath also taken the mighty of the land:","words":[["H3947","And hath taken",0,14],["H4410","of the king's",15,28],["H2233","seed",29,33],["H3772","and made",35,43],["H1285","a covenant",44,54],["H0935","with him, and hath taken",55,79],["H0423","an oath",80,87],["H3947","of him: he hath also taken",88,114],["H0352","the mighty",115,125],["H0776","of the land",126,137]]},"17:14":{"text":"That the kingdom might be base, that it might not lift itself up, but that by keeping of his covenant it might stand.","words":[["H4467","That the kingdom",0,16],["H8217","might be base",17,30],["H5375","that it might not lift itself up",32,64],["H8104","but that by keeping",66,85],["H1285","of his covenant",86,101],["H5975","it might stand",102,116]]},"17:15":{"text":"But he rebelled against him in sending his ambassadors into Egypt, that they might give him horses and much people. Shall he prosper? shall he escape that doeth such things? or shall he break the covenant, and be delivered?","words":[["H4775","But he rebelled",0,15],["H7971","against him in sending",16,38],["H4397","his ambassadors",39,54],["H4714","into Egypt",55,65],["H5414","that they might give",67,87],["H5483","him horses",88,98],["H7227","and much",99,107],["H5971","people",108,114],["H6743","Shall he prosper",116,132],["H4422","shall he escape",134,149],["H6213","that doeth",150,160],["H6565","such things? or shall he break",161,191],["H1285","the covenant",192,204],["H4422","and be delivered",206,222]]},"17:16":{"text":"As I live, saith the Lord GOD, surely in the place where the king dwelleth that made him king, whose oath he despised, and whose covenant he brake, even with him in the midst of Babylon he shall die.","words":[["H2416","As I live",0,9],["H5002","saith",11,16],["H0136","the Lord",17,25],["H3069","GOD",26,29],["H4725","surely in the place",31,50],["H4428","where the king",51,65],["H4427","dwelleth that made him king",66,93],["H0423","whose oath",95,105],["H0959","he despised",106,117],["H1285","and whose covenant",119,137],["H6565","he brake",138,146],["H8432","even with him in the midst",148,174],["H0894","of Babylon",175,185],["H4191","he shall die",186,198]]},"17:17":{"text":"Neither shall Pharaoh with his mighty army and great company make for him in the war, by casting up mounts, and building forts, to cut off many persons:","words":[["H6547","Neither shall Pharaoh",0,21],["H1419","with his mighty",22,37],["H2428","army",38,42],["H7227","and great",43,52],["H6951","company",53,60],["H6213","make",61,65],["H4421","for him in the war",66,84],["H8210","by casting up",86,99],["H5550","mounts",100,106],["H1129","and building",108,120],["H1785","forts",121,126],["H3772","to cut off",128,138],["H7227","many",139,143],["H5315","persons",144,151]]},"17:18":{"text":"Seeing he despised the oath by breaking the covenant, when, lo, he had given his hand, and hath done all these things, he shall not escape.","words":[["H0959","Seeing he despised",0,18],["H0423","the oath",19,27],["H6565","by breaking",28,39],["H1285","the covenant",40,52],["H5414","when, lo, he had given",54,76],["H3027","his hand",77,85],["H6213","and hath done",87,100],["H4422","all these things, he shall not escape",101,138]]},"17:19":{"text":"Therefore thus saith the Lord GOD; As I live, surely mine oath that he hath despised, and my covenant that he hath broken, even it will I recompense upon his own head.","words":[["H0559","Therefore thus saith",0,20],["H0136","the Lord",21,29],["H3069","GOD",30,33],["H2416","As I live",35,44],["H0423","surely mine oath",46,62],["H0959","that he hath despised",63,84],["H1285","and my covenant",86,101],["H6331","that he hath broken",102,121],["H5414","even it will I recompense",123,148],["H7218","upon his own head",149,166]]},"17:20":{"text":"And I will spread my net upon him, and he shall be taken in my snare, and I will bring him to Babylon, and will plead with him there for his trespass that he hath trespassed against me.","words":[["H6566","And I will spread",0,17],["H7568","my net",18,24],["H8610","upon him, and he shall be taken",25,56],["H4686","in my snare",57,68],["H0935","and I will bring",70,86],["H0894","him to Babylon",87,101],["H8199","and will plead",103,117],["H4603","with him there for his trespass",118,149],["H4604","that he hath trespassed",150,173]]},"17:21":{"text":"And all his fugitives with all his bands shall fall by the sword, and they that remain shall be scattered toward all winds: and ye shall know that I the LORD have spoken it.","words":[["H4015","And all his fugitives",0,21],["H0102","with all his bands",22,40],["H5307","shall fall",41,51],["H2719","by the sword",52,64],["H7604","and they that remain",66,86],["H6566","shall be scattered",87,105],["H7307","toward all winds",106,122],["H3045","and ye shall know",124,141],["H3068","that I the LORD",142,157],["H1696","have spoken",158,169]]},"17:22":{"text":"Thus saith the Lord GOD; I will also take of the highest branch of the high cedar, and will set it; I will crop off from the top of his young twigs a tender one, and will plant it upon an high mountain and eminent:","words":[["H0559","Thus saith",0,10],["H0136","the Lord",11,19],["H3069","GOD",20,23],["H3947","I will also take",25,41],["H6788","of the highest branch",42,63],["H7311","of the high",64,75],["H0730","cedar",76,81],["H5414","and will set",83,95],["H6998","it; I will crop off",96,115],["H7218","from the top",116,128],["H3127","of his young twigs",129,147],["H7390","a tender one",148,160],["H8362","and will plant",162,176],["H1364","it upon an high",177,192],["H2022","mountain",193,201],["H8524","and eminent",202,213]]},"17:23":{"text":"In the mountain of the height of Israel will I plant it: and it shall bring forth boughs, and bear fruit, and be a goodly cedar: and under it shall dwell all fowl of every wing; in the shadow of the branches thereof shall they dwell.","words":[["H2022","In the mountain",0,15],["H4791","of the height",16,29],["H3478","of Israel",30,39],["H8362","will I plant",40,52],["H5375","it: and it shall bring forth",53,81],["H6057","boughs",82,88],["H6213","and bear",90,98],["H6529","fruit",99,104],["H0117","and be a goodly",106,121],["H0730","cedar",122,127],["H7931","and under it shall dwell",129,153],["H6833","all fowl",154,162],["H3671","of every wing",163,176],["H6738","in the shadow",178,191],["H1808","of the branches",192,207],["H7931","thereof shall they dwell",208,232]]},"17:24":{"text":"And all the trees of the field shall know that I the LORD have brought down the high tree, have exalted the low tree, have dried up the green tree, and have made the dry tree to flourish: I the LORD have spoken and have done it.","words":[["H6086","And all the trees",0,17],["H7704","of the field",18,30],["H3045","shall know",31,41],["H3068","that I the LORD",42,57],["H8213","have brought down",58,75],["H1364","the high",76,84],["H6086","tree",85,89],["H1361","have exalted",91,103],["H8217","the low",104,111],["H6086","tree",112,116],["H3001","have dried",118,128],["H3892","up the green",129,141],["H6086","tree",142,146],["H3002","and have made the dry",148,169],["H6086","tree",170,174],["H6524","to flourish",175,186],["H3068","I the LORD",188,198],["H1696","have spoken",199,210],["H6213","and have done",211,224]]},"18:1":{"text":"The word of the LORD came unto me again, saying,","words":[["H1697","The word",0,8],["H3068","of the LORD",9,20],["H0559","came unto me again, saying",21,47]]},"18:2":{"text":"What mean ye, that ye use this proverb concerning the land of Israel, saying, The fathers have eaten sour grapes, and the children's teeth are set on edge?","words":[["H4911","What mean ye, that ye use",0,25],["H4912","this proverb",26,38],["H0127","concerning the land",39,58],["H3478","of Israel",59,68],["H0559","saying",70,76],["H0001","The fathers",78,89],["H0398","have eaten",90,100],["H1155","sour grapes",101,112],["H1121","and the children's",114,132],["H8127","teeth",133,138],["H6949","are set on edge",139,154]]},"18:3":{"text":"As I live, saith the Lord GOD, ye shall not have occasion any more to use this proverb in Israel.","words":[["H2416","As I live",0,9],["H5002","saith",11,16],["H0136","the Lord",17,25],["H3069","GOD",26,29],["H4911","ye shall not have occasion any more to use",31,73],["H4912","this proverb",74,86],["H3478","in Israel",87,96]]},"18:4":{"text":"Behold, all souls are mine; as the soul of the father, so also the soul of the son is mine: the soul that sinneth, it shall die.","words":[["H5315","Behold, all souls",0,17],["H5315","are mine; as the soul",18,39],["H0001","of the father",40,53],["H5315","so also the soul",55,71],["H1121","of the son",72,82],["H5315","is mine: the soul",83,100],["H2398","that sinneth",101,113],["H4191","it shall die",115,127]]},"18:5":{"text":"But if a man be just, and do that which is lawful and right,","words":[["H0376","But if a man",0,12],["H6662","be just",13,20],["H6213","and do",22,28],["H4941","that which is lawful",29,49],["H6666","and right",50,59]]},"18:6":{"text":"And hath not eaten upon the mountains, neither hath lifted up his eyes to the idols of the house of Israel, neither hath defiled his neighbour's wife, neither hath come near to a menstruous woman,","words":[["H0398","And hath not eaten",0,18],["H2022","upon the mountains",19,37],["H5375","neither hath lifted up",39,61],["H5869","his eyes",62,70],["H1544","to the idols",71,83],["H1004","of the house",84,96],["H3478","of Israel",97,106],["H2930","neither hath defiled",108,128],["H7453","his neighbour's",129,144],["H0802","wife",145,149],["H7126","neither hath come near",151,173],["H5079","to a menstruous",174,189],["H0802","woman",190,195]]},"18:7":{"text":"And hath not oppressed any, but hath restored to the debtor his pledge, hath spoiled none by violence, hath given his bread to the hungry, and hath covered the naked with a garment;","words":[["H3238","And hath not oppressed",0,22],["H0376","any",23,26],["H7725","but hath restored",28,45],["H2326","to the debtor",46,59],["H2258","his pledge",60,70],["H1497","hath spoiled",72,84],["H1500","none by violence",85,101],["H5414","hath given",103,113],["H3899","his bread",114,123],["H7457","to the hungry",124,137],["H3680","and hath covered",139,155],["H5903","the naked",156,165],["H0899","with a garment",166,180]]},"18:8":{"text":"He that hath not given forth upon usury, neither hath taken any increase, that hath withdrawn his hand from iniquity, hath executed true judgment between man and man,","words":[["H5414","He that hath not given forth",0,28],["H5392","upon usury",29,39],["H3947","neither hath taken",41,59],["H8636","any increase",60,72],["H7725","that hath withdrawn",74,93],["H3027","his hand",94,102],["H5766","from iniquity",103,116],["H6213","hath executed",118,131],["H0571","true",132,136],["H4941","judgment",137,145],["H0376","between man",146,157],["H0376","and man",158,165]]},"18:9":{"text":"Hath walked in my statutes, and hath kept my judgments, to deal truly; he is just, he shall surely live, saith the Lord GOD.","words":[["H1980","Hath walked",0,11],["H2708","in my statutes",12,26],["H8104","and hath kept",28,41],["H4941","my judgments",42,54],["H6213","to deal",56,63],["H0571","truly",64,69],["H6662","he is just",71,81],["H2421","he shall surely",83,98],["H2421","live",99,103],["H5002","saith",105,110],["H0136","the Lord",111,119],["H3069","GOD",120,123]]},"18:10":{"text":"If he beget a son that is a robber, a shedder of blood, and that doeth the like to any one of these things,","words":[["H3205","If he beget",0,11],["H1121","a son",12,17],["H6530","that is a robber",18,34],["H8210","a shedder",36,45],["H1818","of blood",46,54],["H6213","and that doeth",56,70],["H0251","the like",71,79],["H0259","to any one",80,90]]},"18:11":{"text":"And that doeth not any of those duties, but even hath eaten upon the mountains, and defiled his neighbour's wife,","words":[["H6213","And that doeth",0,14],["H0398","not any of those duties, but even hath eaten",15,59],["H2022","upon the mountains",60,78],["H2930","and defiled",80,91],["H7453","his neighbour's",92,107],["H0802","wife",108,112]]},"18:12":{"text":"Hath oppressed the poor and needy, hath spoiled by violence, hath not restored the pledge, and hath lifted up his eyes to the idols, hath committed abomination,","words":[["H3238","Hath oppressed",0,14],["H6041","the poor",15,23],["H0034","and needy",24,33],["H1497","hath spoiled",35,47],["H1500","by violence",48,59],["H7725","hath not restored",61,78],["H2258","the pledge",79,89],["H5375","and hath lifted up",91,109],["H5869","his eyes",110,118],["H1544","to the idols",119,131],["H6213","hath committed",133,147],["H8441","abomination",148,159]]},"18:13":{"text":"Hath given forth upon usury, and hath taken increase: shall he then live? he shall not live: he hath done all these abominations; he shall surely die; his blood shall be upon him.","words":[["H5414","Hath given forth",0,16],["H5392","upon usury",17,27],["H3947","and hath taken",29,43],["H8636","increase",44,52],["H2425","shall he then live",54,72],["H2421","he shall not live",74,91],["H6213","he hath done",93,105],["H8441","all these abominations",106,128],["H4191","he shall surely",130,145],["H4191","die",146,149],["H1818","his blood",151,160]]},"18:14":{"text":"Now, lo, if he beget a son, that seeth all his father's sins which he hath done, and considereth, and doeth not such like,","words":[["H3205","Now, lo, if he beget",0,20],["H1121","a son",21,26],["H7200","that seeth",28,38],["H0001","all his father's",39,55],["H2403","sins",56,60],["H6213","which he hath done",61,79],["H7200","and considereth",81,96],["H6213","and doeth",98,107],["H2004","not such like",108,121]]},"18:15":{"text":"That hath not eaten upon the mountains, neither hath lifted up his eyes to the idols of the house of Israel, hath not defiled his neighbour's wife,","words":[["H0398","That hath not eaten",0,19],["H2022","upon the mountains",20,38],["H5375","neither hath lifted up",40,62],["H5869","his eyes",63,71],["H1544","to the idols",72,84],["H1004","of the house",85,97],["H3478","of Israel",98,107],["H2930","hath not defiled",109,125],["H7453","his neighbour's",126,141],["H0802","wife",142,146]]},"18:16":{"text":"Neither hath oppressed any, hath not withholden the pledge, neither hath spoiled by violence, but hath given his bread to the hungry, and hath covered the naked with a garment,","words":[["H3238","Neither hath oppressed",0,22],["H0376","any",23,26],["H2254","hath not withholden",28,47],["H2258","the pledge",48,58],["H1497","neither hath spoiled",60,80],["H1500","by violence",81,92],["H5414","but hath given",94,108],["H3899","his bread",109,118],["H7457","to the hungry",119,132],["H3680","and hath covered",134,150],["H5903","the naked",151,160],["H0899","with a garment",161,175]]},"18:17":{"text":"That hath taken off his hand from the poor, that hath not received usury nor increase, hath executed my judgments, hath walked in my statutes; he shall not die for the iniquity of his father, he shall surely live.","words":[["H7725","That hath taken off",0,19],["H3027","his hand",20,28],["H6041","from the poor",29,42],["H3947","that hath not received",44,66],["H5392","usury",67,72],["H8636","nor increase",73,85],["H6213","hath executed",87,100],["H4941","my judgments",101,113],["H1980","hath walked",115,126],["H2708","in my statutes",127,141],["H4191","he shall not die",143,159],["H5771","for the iniquity",160,176],["H0001","of his father",177,190],["H2421","he shall surely",192,207],["H2421","live",208,212]]},"18:18":{"text":"As for his father, because he cruelly oppressed, spoiled his brother by violence, and did that which is not good among his people, lo, even he shall die in his iniquity.","words":[["H0001","As for his father",0,17],["H6233","because he cruelly",19,37],["H6231","oppressed",38,47],["H1497","spoiled",49,56],["H0251","his brother",57,68],["H1499","by violence",69,80],["H6213","and did",82,89],["H2896","that which is not good",90,112],["H8432","among",113,118],["H5971","his people",119,129],["H4191","lo, even he shall die",131,152],["H5771","in his iniquity",153,168]]},"18:19":{"text":"Yet say ye, Why? doth not the son bear the iniquity of the father? When the son hath done that which is lawful and right, and hath kept all my statutes, and hath done them, he shall surely live.","words":[["H0559","Yet say",0,7],["H1121","ye, Why? doth not the son",8,33],["H5375","bear",34,38],["H5771","the iniquity",39,51],["H0001","of the father",52,65],["H1121","When the son",67,79],["H6213","hath done",80,89],["H4941","that which is lawful",90,110],["H6666","and right",111,120],["H8104","and hath kept",122,135],["H2708","all my statutes",136,151],["H6213","and hath done",153,166],["H2421","them, he shall surely",167,188],["H2421","live",189,193]]},"18:20":{"text":"The soul that sinneth, it shall die. The son shall not bear the iniquity of the father, neither shall the father bear the iniquity of the son: the righteousness of the righteous shall be upon him, and the wickedness of the wicked shall be upon him.","words":[["H5315","The soul",0,8],["H2398","that sinneth",9,21],["H4191","it shall die",23,35],["H1121","The son",37,44],["H5375","shall not bear",45,59],["H5771","the iniquity",60,72],["H0001","of the father",73,86],["H0001","neither shall the father",88,112],["H5375","bear",113,117],["H5771","the iniquity",118,130],["H1121","of the son",131,141],["H6666","the righteousness",143,160],["H6662","of the righteous",161,177],["H7564","shall be upon him, and the wickedness",178,215],["H7563","of the wicked",216,229]]},"18:21":{"text":"But if the wicked will turn from all his sins that he hath committed, and keep all my statutes, and do that which is lawful and right, he shall surely live, he shall not die.","words":[["H7563","But if the wicked",0,17],["H7725","will turn",18,27],["H2403","from all his sins",28,45],["H6213","that he hath committed",46,68],["H8104","and keep",70,78],["H2708","all my statutes",79,94],["H6213","and do",96,102],["H4941","that which is lawful",103,123],["H6666","and right",124,133],["H2421","he shall surely",135,150],["H2421","live",151,155],["H4191","he shall not die",157,173]]},"18:22":{"text":"All his transgressions that he hath committed, they shall not be mentioned unto him: in his righteousness that he hath done he shall live.","words":[["H6588","All his transgressions",0,22],["H6213","that he hath committed",23,45],["H2142","they shall not be mentioned",47,74],["H6666","unto him: in his righteousness",75,105],["H6213","that he hath done",106,123],["H2421","he shall live",124,137]]},"18:23":{"text":"Have I any pleasure at all that the wicked should die? saith the Lord GOD: and not that he should return from his ways, and live?","words":[["H2654","Have I any pleasure",0,19],["H2654","at all",20,26],["H7563","that the wicked",27,42],["H4194","should die",43,53],["H5002","saith",55,60],["H0136","the Lord",61,69],["H3069","GOD",70,73],["H7725","and not that he should return",75,104],["H1870","from his ways",105,118],["H2421","and live",120,128]]},"18:24":{"text":"But when the righteous turneth away from his righteousness, and committeth iniquity, and doeth according to all the abominations that the wicked man doeth, shall he live? All his righteousness that he hath done shall not be mentioned: in his trespass that he hath trespassed, and in his sin that he hath sinned, in them shall he die.","words":[["H6662","But when the righteous",0,22],["H7725","turneth away",23,35],["H6666","from his righteousness",36,58],["H6213","and committeth",60,74],["H5766","iniquity",75,83],["H6213","and doeth",85,94],["H8441","according to all the abominations",95,128],["H7563","that the wicked",129,144],["H6213","man doeth",145,154],["H2425","shall he live",156,169],["H6666","All his righteousness",171,192],["H6213","that he hath done",193,210],["H2142","shall not be mentioned",211,233],["H4603","in his trespass",235,250],["H4604","that he hath trespassed",251,274],["H2403","and in his sin",276,290],["H2398","that he hath sinned",291,310],["H4191","in them shall he die",312,332]]},"18:25":{"text":"Yet ye say, The way of the Lord is not equal. Hear now, O house of Israel; Is not my way equal? are not your ways unequal?","words":[["H0559","Yet ye say",0,10],["H1870","The way",12,19],["H0136","of the Lord",20,31],["H8505","is not equal",32,44],["H8085","Hear",46,50],["H1004","now, O house",51,63],["H3478","of Israel",64,73],["H1870","Is not my way",75,88],["H8505","equal",89,94],["H1870","are not your ways",96,113],["H8505","unequal",114,121]]},"18:26":{"text":"When a righteous man turneth away from his righteousness, and committeth iniquity, and dieth in them; for his iniquity that he hath done shall he die.","words":[["H6662","When a righteous",0,16],["H7725","man turneth away",17,33],["H6666","from his righteousness",34,56],["H6213","and committeth",58,72],["H5766","iniquity",73,81],["H4191","and dieth",83,92],["H5766","in them; for his iniquity",93,118],["H6213","that he hath done",119,136],["H4191","shall he die",137,149]]},"18:27":{"text":"Again, when the wicked man turneth away from his wickedness that he hath committed, and doeth that which is lawful and right, he shall save his soul alive.","words":[["H7563","Again, when the wicked",0,22],["H7725","man turneth away",23,39],["H7564","from his wickedness",40,59],["H6213","that he hath committed",60,82],["H6213","and doeth",84,93],["H4941","that which is lawful",94,114],["H6666","and right",115,124],["H2421","he shall save",126,139],["H5315","his soul",140,148],["H2421","alive",149,154]]},"18:28":{"text":"Because he considereth, and turneth away from all his transgressions that he hath committed, he shall surely live, he shall not die.","words":[["H7200","Because he considereth",0,22],["H7725","and turneth away",24,40],["H6588","from all his transgressions",41,68],["H6213","that he hath committed",69,91],["H2421","he shall surely",93,108],["H2421","live",109,113],["H4191","he shall not die",115,131]]},"18:29":{"text":"Yet saith the house of Israel, The way of the Lord is not equal. O house of Israel, are not my ways equal? are not your ways unequal?","words":[["H0559","Yet saith",0,9],["H1004","the house",10,19],["H3478","of Israel",20,29],["H1870","The way",31,38],["H0136","of the Lord",39,50],["H8505","is not equal",51,63],["H1004","O house",65,72],["H3478","of Israel",73,82],["H1870","are not my ways",84,99],["H8505","equal",100,105],["H1870","are not your ways",107,124],["H8505","unequal",125,132]]},"18:30":{"text":"Therefore I will judge you, O house of Israel, every one according to his ways, saith the Lord GOD. Repent, and turn yourselves from all your transgressions; so iniquity shall not be your ruin.","words":[["H8199","Therefore I will judge",0,22],["H1004","you, O house",23,35],["H3478","of Israel",36,45],["H0376","every one",47,56],["H1870","according to his ways",57,78],["H5002","saith",80,85],["H0136","the Lord",86,94],["H3069","GOD",95,98],["H7725","Repent",100,106],["H7725","and turn",108,116],["H6588","yourselves from all your transgressions",117,156],["H5771","so iniquity",158,169],["H4383","shall not be your ruin",170,192]]},"18:31":{"text":"Cast away from you all your transgressions, whereby ye have transgressed; and make you a new heart and a new spirit: for why will ye die, O house of Israel?","words":[["H7993","Cast away",0,9],["H6588","from you all your transgressions",10,42],["H6586","whereby ye have transgressed",44,72],["H6213","and make",74,82],["H2319","you a new",83,92],["H3820","heart",93,98],["H2319","and a new",99,108],["H7307","spirit",109,115],["H4191","for why will ye die",117,136],["H1004","O house",138,145],["H3478","of Israel",146,155]]},"18:32":{"text":"For I have no pleasure in the death of him that dieth, saith the Lord GOD: wherefore turn yourselves, and live ye.","words":[["H2654","For I have no pleasure",0,22],["H4194","in the death",23,35],["H4191","of him that dieth",36,53],["H5002","saith",55,60],["H0136","the Lord",61,69],["H3069","GOD",70,73],["H7725","wherefore turn",75,89],["H2421","yourselves, and live",90,110]]},"19:1":{"text":"Moreover take thou up a lamentation for the princes of Israel,","words":[["H5375","Moreover take thou up",0,21],["H7015","a lamentation",22,35],["H5387","for the princes",36,51],["H3478","of Israel",52,61]]},"19:2":{"text":"And say, What is thy mother? A lioness: she lay down among lions, she nourished her whelps among young lions.","words":[["H0559","And say",0,7],["H0517","What is thy mother",9,27],["H3833","A lioness",29,38],["H7257","she lay down",40,52],["H0738","among lions",53,64],["H7235","she nourished",66,79],["H1482","her whelps",80,90],["H8432","among",91,96],["H3715","young lions",97,108]]},"19:3":{"text":"And she brought up one of her whelps: it became a young lion, and it learned to catch the prey; it devoured men.","words":[["H5927","And she brought up",0,18],["H0259","one",19,22],["H1482","of her whelps",23,36],["H3715","it became a young lion",38,60],["H3925","and it learned",62,76],["H2963","to catch",77,85],["H2964","the prey",86,94],["H0398","it devoured",96,107],["H0120","men",108,111]]},"19:4":{"text":"The nations also heard of him; he was taken in their pit, and they brought him with chains unto the land of Egypt.","words":[["H1471","The nations",0,11],["H8085","also heard",12,22],["H8610","of him; he was taken",23,43],["H7845","in their pit",44,56],["H0935","and they brought",58,74],["H2397","him with chains",75,90],["H0776","unto the land",91,104],["H4714","of Egypt",105,113]]},"19:5":{"text":"Now when she saw that she had waited, and her hope was lost, then she took another of her whelps, and made him a young lion.","words":[["H7200","Now when she saw",0,16],["H3176","that she had waited",17,36],["H8615","and her hope",38,50],["H0006","was lost",51,59],["H3947","then she took",61,74],["H0259","another",75,82],["H1482","of her whelps",83,96],["H7760","and made",98,106],["H3715","him a young lion",107,123]]},"19:6":{"text":"And he went up and down among the lions, he became a young lion, and learned to catch the prey, and devoured men.","words":[["H1980","And he went up and down",0,23],["H8432","among",24,29],["H0738","the lions",30,39],["H3715","he became a young lion",41,63],["H3925","and learned",65,76],["H2963","to catch",77,85],["H2964","the prey",86,94],["H0398","and devoured",96,108],["H0120","men",109,112]]},"19:7":{"text":"And he knew their desolate palaces, and he laid waste their cities; and the land was desolate, and the fulness thereof, by the noise of his roaring.","words":[["H3045","And he knew",0,11],["H0490","their desolate palaces",12,34],["H2717","and he laid waste",36,53],["H5892","their cities",54,66],["H0776","and the land",68,80],["H3456","was desolate",81,93],["H4393","and the fulness",95,110],["H6963","thereof, by the noise",111,132],["H7581","of his roaring",133,147]]},"19:8":{"text":"Then the nations set against him on every side from the provinces, and spread their net over him: he was taken in their pit.","words":[["H1471","Then the nations",0,16],["H5414","set",17,20],["H5439","against him on every side",21,46],["H4082","from the provinces",47,65],["H6566","and spread",67,77],["H7568","their net",78,87],["H8610","over him: he was taken",88,110],["H7845","in their pit",111,123]]},"19:9":{"text":"And they put him in ward in chains, and brought him to the king of Babylon: they brought him into holds, that his voice should no more be heard upon the mountains of Israel.","words":[["H5414","And they put",0,12],["H5474","him in ward",13,24],["H2397","in chains",25,34],["H0935","and brought",36,47],["H4428","him to the king",48,63],["H0894","of Babylon",64,74],["H0935","they brought",76,88],["H4685","him into holds",89,103],["H6963","that his voice",105,119],["H8085","should no more be heard",120,143],["H2022","upon the mountains",144,162],["H3478","of Israel",163,172]]},"19:10":{"text":"Thy mother is like a vine in thy blood, planted by the waters: she was fruitful and full of branches by reason of many waters.","words":[["H0517","Thy mother",0,10],["H1612","is like a vine",11,25],["H1818","in thy blood",26,38],["H1818","in thy blood",26,38],["H8362","planted",40,47],["H4325","by the waters",48,61],["H6509","she was fruitful",63,79],["H6058","and full of branches",80,100],["H7227","by reason of many",101,118],["H4325","waters",119,125]]},"19:11":{"text":"And she had strong rods for the sceptres of them that bare rule, and her stature was exalted among the thick branches, and she appeared in her height with the multitude of her branches.","words":[["H5797","And she had strong",0,18],["H4294","rods",19,23],["H7626","for the sceptres",24,40],["H4910","of them that bare rule",41,63],["H6967","and her stature",65,80],["H1361","was exalted",81,92],["H5688","among the thick branches",93,117],["H7200","and she appeared",119,135],["H1363","in her height",136,149],["H7230","with the multitude",150,168],["H1808","of her branches",169,184]]},"19:12":{"text":"But she was plucked up in fury, she was cast down to the ground, and the east wind dried up her fruit: her strong rods were broken and withered; the fire consumed them.","words":[["H5428","But she was plucked up",0,22],["H2534","in fury",23,30],["H7993","she was cast down",32,49],["H0776","to the ground",50,63],["H6921","and the east",65,77],["H7307","wind",78,82],["H3001","dried up",83,91],["H6529","her fruit",92,101],["H5797","her strong",103,113],["H4294","rods",114,118],["H6561","were broken",119,130],["H3001","and withered",131,143],["H0784","the fire",145,153],["H0398","consumed",154,162]]},"19:13":{"text":"And now she is planted in the wilderness, in a dry and thirsty ground.","words":[["H8362","And now she is planted",0,22],["H4057","in the wilderness",23,40],["H6723","in a dry",42,50],["H6772","and thirsty",51,62],["H0776","ground",63,69]]},"19:14":{"text":"And fire is gone out of a rod of her branches, which hath devoured her fruit, so that she hath no strong rod to be a sceptre to rule. This is a lamentation, and shall be for a lamentation.","words":[["H0784","And fire",0,8],["H3318","is gone out",9,20],["H4294","of a rod",21,29],["H0905","of her branches",30,45],["H0398","which hath devoured",47,66],["H6529","her fruit",67,76],["H5797","so that she hath no strong",78,104],["H4294","rod",105,108],["H7626","to be a sceptre",109,124],["H4910","to rule",125,132],["H7015","This is a lamentation",134,155],["H7015","and shall be for a lamentation",157,187]]},"20:1":{"text":"And it came to pass in the seventh year, in the fifth month, the tenth day of the month, that certain of the elders of Israel came to enquire of the LORD, and sat before me.","words":[["H7637","And it came to pass in the seventh",0,34],["H8141","year",35,39],["H2549","in the fifth",41,53],["H6218","month, the tenth",54,70],["H2320","day of the month",71,87],["H0582","that certain",89,101],["H2205","of the elders",102,115],["H3478","of Israel",116,125],["H0935","came",126,130],["H1875","to enquire",131,141],["H3068","of the LORD",142,153],["H3427","and sat",155,162],["H6440","before",163,169]]},"20:2":{"text":"Then came the word of the LORD unto me, saying,","words":[["H1697","Then came the word",0,18],["H3068","of the LORD",19,30],["H0559","unto me, saying",31,46]]},"20:3":{"text":"Son of man, speak unto the elders of Israel, and say unto them, Thus saith the Lord GOD; Are ye come to enquire of me? As I live, saith the Lord GOD, I will not be enquired of by you.","words":[["H1121","Son",0,3],["H0120","of man",4,10],["H1696","speak",12,17],["H2205","unto the elders",18,33],["H3478","of Israel",34,43],["H0559","and say",45,52],["H0559","unto them, Thus saith",53,74],["H0136","the Lord",75,83],["H3069","GOD",84,87],["H0935","Are ye come",89,100],["H1875","to enquire",101,111],["H2416","of me? As I live",112,128],["H5002","saith",130,135],["H0136","the Lord",136,144],["H3069","GOD",145,148],["H1875","I will not be enquired",150,172]]},"20:4":{"text":"Wilt thou judge them, son of man, wilt thou judge them? cause them to know the abominations of their fathers:","words":[["H8199","Wilt thou judge",0,15],["H1121","them, son",16,25],["H0120","of man",26,32],["H8199","wilt thou judge",34,49],["H3045","them? cause them to know",50,74],["H8441","the abominations",75,91],["H0001","of their fathers",92,108]]},"20:5":{"text":"And say unto them, Thus saith the Lord GOD; In the day when I chose Israel, and lifted up mine hand unto the seed of the house of Jacob, and made myself known unto them in the land of Egypt, when I lifted up mine hand unto them, saying, I am the LORD your God;","words":[["H0559","And say",0,7],["H0559","unto them, Thus saith",8,29],["H0136","the Lord",30,38],["H3069","GOD",39,42],["H3117","In the day",44,54],["H0977","when I chose",55,67],["H3478","Israel",68,74],["H5375","and lifted up",76,89],["H3027","mine hand",90,99],["H2233","unto the seed",100,113],["H1004","of the house",114,126],["H3290","of Jacob",127,135],["H3045","and made myself known",137,158],["H0776","unto them in the land",159,180],["H4714","of Egypt",181,189],["H5375","when I lifted",191,204],["H3027","up mine hand",205,217],["H0559","unto them, saying",218,235],["H3068","I am the LORD",237,250],["H0430","your God",251,259]]},"20:6":{"text":"In the day that I lifted up mine hand unto them, to bring them forth of the land of Egypt into a land that I had espied for them, flowing with milk and honey, which is the glory of all lands:","words":[["H3117","In the day",0,10],["H5375","that I lifted up",11,27],["H3027","mine hand",28,37],["H3318","unto them, to bring them forth",38,68],["H0776","of the land",69,80],["H4714","of Egypt",81,89],["H0776","into a land",90,101],["H8446","that I had espied",102,119],["H2100","for them, flowing",120,137],["H2461","with milk",138,147],["H1706","and honey",148,157],["H6643","which is the glory",159,177],["H0776","of all lands",178,190]]},"20:7":{"text":"Then said I unto them, Cast ye away every man the abominations of his eyes, and defile not yourselves with the idols of Egypt: I am the LORD your God.","words":[["H0559","Then said",0,9],["H7993","I unto them, Cast ye away",10,35],["H0376","every man",36,45],["H8251","the abominations",46,62],["H5869","of his eyes",63,74],["H2930","and defile",76,86],["H1544","not yourselves with the idols",87,116],["H4714","of Egypt",117,125],["H3068","I am the LORD",127,140],["H0430","your God",141,149]]},"20:8":{"text":"But they rebelled against me, and would not hearken unto me: they did not every man cast away the abominations of their eyes, neither did they forsake the idols of Egypt: then I said, I will pour out my fury upon them, to accomplish my anger against them in the midst of the land of Egypt.","words":[["H4784","But they rebelled",0,17],["H0014","against me, and would",18,39],["H8085","not hearken",40,51],["H0376","unto me: they did not every man",52,83],["H7993","cast away",84,93],["H8251","the abominations",94,110],["H5869","of their eyes",111,124],["H5800","neither did they forsake",126,150],["H1544","the idols",151,160],["H4714","of Egypt",161,169],["H0559","then I said",171,182],["H8210","I will pour out",184,199],["H2534","my fury",200,207],["H3615","upon them, to accomplish",208,232],["H0639","my anger",233,241],["H8432","against them in the midst",242,267],["H0776","of the land",268,279],["H4714","of Egypt",280,288]]},"20:9":{"text":"But I wrought for my name's sake, that it should not be polluted before the heathen, among whom they were, in whose sight I made myself known unto them, in bringing them forth out of the land of Egypt.","words":[["H6213","But I wrought",0,13],["H8034","for my name's",14,27],["H2490","sake, that it should not be polluted",28,64],["H5869","before",65,71],["H1471","the heathen",72,83],["H8432","among",85,90],["H5869","whom they were, in whose sight",91,121],["H3045","I made myself known",122,141],["H3318","unto them, in bringing them forth",142,175],["H0776","out of the land",176,191],["H4714","of Egypt",192,200]]},"20:10":{"text":"Wherefore I caused them to go forth out of the land of Egypt, and brought them into the wilderness.","words":[["H3318","Wherefore I caused them to go forth",0,35],["H0776","out of the land",36,51],["H4714","of Egypt",52,60],["H0935","and brought",62,73],["H4057","them into the wilderness",74,98]]},"20:11":{"text":"And I gave them my statutes, and shewed them my judgments, which if a man do, he shall even live in them.","words":[["H5414","And I gave",0,10],["H2708","them my statutes",11,27],["H3045","and shewed",29,39],["H4941","them my judgments",40,57],["H0120","which if a man",59,73],["H6213","do",74,76],["H2425","he shall even live",78,96]]},"20:12":{"text":"Moreover also I gave them my sabbaths, to be a sign between me and them, that they might know that I am the LORD that sanctify them.","words":[["H5414","Moreover also I gave",0,20],["H7676","them my sabbaths",21,37],["H0226","to be a sign",39,51],["H3045","between me and them, that they might know",52,93],["H3068","that I am the LORD",94,112],["H6942","that sanctify",113,126]]},"20:13":{"text":"But the house of Israel rebelled against me in the wilderness: they walked not in my statutes, and they despised my judgments, which if a man do, he shall even live in them; and my sabbaths they greatly polluted: then I said, I would pour out my fury upon them in the wilderness, to consume them.","words":[["H1004","But the house",0,13],["H3478","of Israel",14,23],["H4784","rebelled",24,32],["H4057","against me in the wilderness",33,61],["H1980","they walked",63,74],["H2708","not in my statutes",75,93],["H3988","and they despised",95,112],["H4941","my judgments",113,125],["H0120","which if a man",127,141],["H6213","do",142,144],["H2425","he shall even live",146,164],["H7676","in them; and my sabbaths",165,189],["H3966","they greatly",190,202],["H2490","polluted",203,211],["H0559","then I said",213,224],["H8210","I would pour out",226,242],["H2534","my fury",243,250],["H4057","upon them in the wilderness",251,278],["H3615","to consume",280,290]]},"20:14":{"text":"But I wrought for my name's sake, that it should not be polluted before the heathen, in whose sight I brought them out.","words":[["H6213","But I wrought",0,13],["H8034","for my name's",14,27],["H2490","sake, that it should not be polluted",28,64],["H5869","before",65,71],["H1471","the heathen",72,83],["H5869","in whose sight",85,99],["H3318","I brought them out",100,118]]},"20:15":{"text":"Yet also I lifted up my hand unto them in the wilderness, that I would not bring them into the land which I had given them, flowing with milk and honey, which is the glory of all lands;","words":[["H5375","Yet also I lifted up",0,20],["H3027","my hand",21,28],["H4057","unto them in the wilderness",29,56],["H0935","that I would not bring",58,80],["H0776","them into the land",81,99],["H5414","which I had given",100,117],["H2100","them, flowing",118,131],["H2461","with milk",132,141],["H1706","and honey",142,151],["H6643","which is the glory",153,171],["H0776","of all lands",172,184]]},"20:16":{"text":"Because they despised my judgments, and walked not in my statutes, but polluted my sabbaths: for their heart went after their idols.","words":[["H3988","Because they despised",0,21],["H4941","my judgments",22,34],["H1980","and walked",36,46],["H2708","not in my statutes",47,65],["H2490","but polluted",67,79],["H7676","my sabbaths",80,91],["H3820","for their heart",93,108],["H1980","went",109,113],["H0310","after",114,119],["H1544","their idols",120,131]]},"20:17":{"text":"Nevertheless mine eye spared them from destroying them, neither did I make an end of them in the wilderness.","words":[["H5869","Nevertheless mine eye",0,21],["H2347","spared",22,28],["H7843","them from destroying",29,49],["H6213","them, neither did I make",50,74],["H3617","an end",75,81],["H4057","of them in the wilderness",82,107]]},"20:18":{"text":"But I said unto their children in the wilderness, Walk ye not in the statutes of your fathers, neither observe their judgments, nor defile yourselves with their idols:","words":[["H0559","But I said",0,10],["H1121","unto their children",11,30],["H4057","in the wilderness",31,48],["H3212","Walk",50,54],["H2706","ye not in the statutes",55,77],["H0001","of your fathers",78,93],["H8104","neither observe",95,110],["H4941","their judgments",111,126],["H2930","nor defile",128,138],["H1544","yourselves with their idols",139,166]]},"20:19":{"text":"I am the LORD your God; walk in my statutes, and keep my judgments, and do them;","words":[["H3068","I am the LORD",0,13],["H0430","your God",14,22],["H3212","walk",24,28],["H2708","in my statutes",29,43],["H8104","and keep",45,53],["H4941","my judgments",54,66],["H6213","and do",68,74]]},"20:20":{"text":"And hallow my sabbaths; and they shall be a sign between me and you, that ye may know that I am the LORD your God.","words":[["H6942","And hallow",0,10],["H7676","my sabbaths",11,22],["H0226","and they shall be a sign",24,48],["H3045","between me and you, that ye may know",49,85],["H3068","that I am the LORD",86,104],["H0430","your God",105,113]]},"20:21":{"text":"Notwithstanding the children rebelled against me: they walked not in my statutes, neither kept my judgments to do them, which if a man do, he shall even live in them; they polluted my sabbaths: then I said, I would pour out my fury upon them, to accomplish my anger against them in the wilderness.","words":[["H1121","Notwithstanding the children",0,28],["H4784","rebelled",29,37],["H1980","against me: they walked",38,61],["H2708","not in my statutes",62,80],["H8104","neither kept",82,94],["H4941","my judgments",95,107],["H6213","to do",108,113],["H0120","them, which if a man",114,134],["H6213","do",135,137],["H2425","he shall even live",139,157],["H2490","in them; they polluted",158,180],["H7676","my sabbaths",181,192],["H0559","then I said",194,205],["H8210","I would pour out",207,223],["H2534","my fury",224,231],["H3615","upon them, to accomplish",232,256],["H0639","my anger",257,265],["H4057","against them in the wilderness",266,296]]},"20:22":{"text":"Nevertheless I withdrew mine hand, and wrought for my name's sake, that it should not be polluted in the sight of the heathen, in whose sight I brought them forth.","words":[["H7725","Nevertheless I withdrew",0,23],["H3027","mine hand",24,33],["H6213","and wrought",35,46],["H8034","for my name's",47,60],["H2490","sake, that it should not be polluted",61,97],["H5869","in the sight",98,110],["H1471","of the heathen",111,125],["H5869","in whose sight",127,141],["H3318","I brought them forth",142,162]]},"20:23":{"text":"I lifted up mine hand unto them also in the wilderness, that I would scatter them among the heathen, and disperse them through the countries;","words":[["H5375","I lifted up",0,11],["H3027","mine hand",12,21],["H4057","unto them also in the wilderness",22,54],["H6327","that I would scatter",56,76],["H1471","them among the heathen",77,99],["H2219","and disperse",101,113],["H0776","them through the countries",114,140]]},"20:24":{"text":"Because they had not executed my judgments, but had despised my statutes, and had polluted my sabbaths, and their eyes were after their fathers' idols.","words":[["H6213","Because they had not executed",0,29],["H4941","my judgments",30,42],["H3988","but had despised",44,60],["H2708","my statutes",61,72],["H2490","and had polluted",74,90],["H7676","my sabbaths",91,102],["H5869","and their eyes",104,118],["H0310","were after",119,129],["H0001","their fathers'",130,144],["H1544","idols",145,150]]},"20:25":{"text":"Wherefore I gave them also statutes that were not good, and judgments whereby they should not live;","words":[["H5414","Wherefore I gave",0,16],["H2706","them also statutes",17,35],["H2896","that were not good",36,54],["H4941","and judgments",56,69],["H2421","whereby they should not live",70,98]]},"20:26":{"text":"And I polluted them in their own gifts, in that they caused to pass through the fire all that openeth the womb, that I might make them desolate, to the end that they might know that I am the LORD.","words":[["H2930","And I polluted",0,14],["H4979","them in their own gifts",15,38],["H5674","in that they caused to pass through",40,75],["H6363","the fire all that openeth",76,101],["H7356","the womb",102,110],["H8074","that I might make them desolate",112,143],["H3045","to the end that they might know",145,176],["H3068","that I am the LORD",177,195]]},"20:27":{"text":"Therefore, son of man, speak unto the house of Israel, and say unto them, Thus saith the Lord GOD; Yet in this your fathers have blasphemed me, in that they have committed a trespass against me.","words":[["H1121","Therefore, son",0,14],["H0120","of man",15,21],["H1696","speak",23,28],["H1004","unto the house",29,43],["H3478","of Israel",44,53],["H0559","and say",55,62],["H0559","unto them, Thus saith",63,84],["H0136","the Lord",85,93],["H3069","GOD",94,97],["H0001","Yet in this your fathers",99,123],["H1442","have blasphemed",124,139],["H4603","me, in that they have committed",140,171],["H4604","a trespass",172,182]]},"20:28":{"text":"For when I had brought them into the land, for the which I lifted up mine hand to give it to them, then they saw every high hill, and all the thick trees, and they offered there their sacrifices, and there they presented the provocation of their offering: there also they made their sweet savour, and poured out there their drink offerings.","words":[["H0935","For when I had brought",0,22],["H0776","them into the land",23,41],["H5375","for the which I lifted up",43,68],["H3027","mine hand",69,78],["H5414","to give",79,86],["H7200","it to them, then they saw",87,112],["H7311","every high",113,123],["H1389","hill",124,128],["H5687","and all the thick",130,147],["H6086","trees",148,153],["H2076","and they offered",155,171],["H2077","there their sacrifices",172,194],["H5414","and there they presented",196,220],["H3708","the provocation",221,236],["H7133","of their offering",237,254],["H7760","there also they made",256,276],["H5207","their sweet",277,288],["H7381","savour",289,295],["H5258","and poured out",297,311],["H5262","there their drink offerings",312,339]]},"20:29":{"text":"Then I said unto them, What is the high place whereunto ye go? And the name thereof is called Bamah unto this day.","words":[["H0559","Then I said",0,11],["H1116","unto them, What is the high place",12,45],["H0935","whereunto ye go",46,61],["H8034","And the name",63,75],["H7121","thereof is called",76,93],["H1117","Bamah",94,99],["H3117","unto this day",100,113]]},"20:30":{"text":"Wherefore say unto the house of Israel, Thus saith the Lord GOD; Are ye polluted after the manner of your fathers? and commit ye whoredom after their abominations?","words":[["H0559","Wherefore say",0,13],["H1004","unto the house",14,28],["H3478","of Israel",29,38],["H0559","Thus saith",40,50],["H0136","the Lord",51,59],["H3069","GOD",60,63],["H2930","Are ye polluted",65,80],["H1870","after the manner",81,97],["H0001","of your fathers",98,113],["H2181","and commit ye whoredom",115,137],["H0310","after",138,143],["H8251","their abominations",144,162]]},"20:31":{"text":"For when ye offer your gifts, when ye make your sons to pass through the fire, ye pollute yourselves with all your idols, even unto this day: and shall I be enquired of by you, O house of Israel? As I live, saith the Lord GOD, I will not be enquired of by you.","words":[["H5375","For when ye offer",0,17],["H4979","your gifts",18,28],["H1121","when ye make your sons",30,52],["H5674","to pass through",53,68],["H0784","the fire",69,77],["H2930","ye pollute",79,89],["H1544","yourselves with all your idols",90,120],["H3117","even unto this day",122,140],["H1875","and shall I be enquired",142,165],["H1004","of by you, O house",166,184],["H3478","of Israel",185,194],["H2416","As I live",196,205],["H5002","saith",207,212],["H0136","the Lord",213,221],["H3069","GOD",222,225],["H1875","I will not be enquired",227,249]]},"20:32":{"text":"And that which cometh into your mind shall not be at all, that ye say, We will be as the heathen, as the families of the countries, to serve wood and stone.","words":[["H5927","And that which cometh",0,21],["H7307","into your mind",22,36],["H0559","shall not be at all, that ye say",37,69],["H1961","We will be",71,81],["H1471","as the heathen",82,96],["H4940","as the families",98,113],["H0776","of the countries",114,130],["H8334","to serve",132,140],["H6086","wood",141,145],["H0068","and stone",146,155]]},"20:33":{"text":"As I live, saith the Lord GOD, surely with a mighty hand, and with a stretched out arm, and with fury poured out, will I rule over you:","words":[["H2416","As I live",0,9],["H5002","saith",11,16],["H0136","the Lord",17,25],["H3069","GOD",26,29],["H2389","surely with a mighty",31,51],["H3027","hand",52,56],["H5186","and with a stretched out",58,82],["H2220","arm",83,86],["H2534","and with fury",88,101],["H8210","poured out",102,112],["H4427","will I rule",114,125]]},"20:34":{"text":"And I will bring you out from the people, and will gather you out of the countries wherein ye are scattered, with a mighty hand, and with a stretched out arm, and with fury poured out.","words":[["H3318","And I will bring you out",0,24],["H5971","from the people",25,40],["H6908","and will gather",42,57],["H0776","you out of the countries",58,82],["H6327","wherein ye are scattered",83,107],["H2389","with a mighty",109,122],["H3027","hand",123,127],["H5186","and with a stretched out",129,153],["H2220","arm",154,157],["H2534","and with fury",159,172],["H8210","poured out",173,183]]},"20:35":{"text":"And I will bring you into the wilderness of the people, and there will I plead with you face to face.","words":[["H0935","And I will bring",0,16],["H4057","you into the wilderness",17,40],["H5971","of the people",41,54],["H8199","and there will I plead",56,78],["H6440","with you face",79,92],["H6440","to face",93,100]]},"20:36":{"text":"Like as I pleaded with your fathers in the wilderness of the land of Egypt, so will I plead with you, saith the Lord GOD.","words":[["H8199","Like as I pleaded",0,17],["H0001","with your fathers",18,35],["H4057","in the wilderness",36,53],["H0776","of the land",54,65],["H4714","of Egypt",66,74],["H8199","so will I plead",76,91],["H5002","with you, saith",92,107],["H0136","the Lord",108,116],["H3069","GOD",117,120]]},"20:37":{"text":"And I will cause you to pass under the rod, and I will bring you into the bond of the covenant:","words":[["H5674","And I will cause you to pass",0,28],["H7626","under the rod",29,42],["H0935","and I will bring",44,60],["H4562","you into the bond",61,78],["H1285","of the covenant",79,94]]},"20:38":{"text":"And I will purge out from among you the rebels, and them that transgress against me: I will bring them forth out of the country where they sojourn, and they shall not enter into the land of Israel: and ye shall know that I am the LORD.","words":[["H1305","And I will purge out",0,20],["H4775","from among you the rebels",21,46],["H6586","and them that transgress",48,72],["H3318","against me: I will bring them forth",73,108],["H0776","out of the country",109,127],["H4033","where they sojourn",128,146],["H0935","and they shall not enter",148,172],["H0127","into the land",173,186],["H3478","of Israel",187,196],["H3045","and ye shall know",198,215],["H3068","that I am the LORD",216,234]]},"20:39":{"text":"As for you, O house of Israel, thus saith the Lord GOD; Go ye, serve ye every one his idols, and hereafter also, if ye will not hearken unto me: but pollute ye my holy name no more with your gifts, and with your idols.","words":[["H1004","As for you, O house",0,19],["H3478","of Israel",20,29],["H0559","thus saith",31,41],["H0136","the Lord",42,50],["H3069","GOD",51,54],["H3212","Go",56,58],["H5647","ye, serve",59,68],["H0376","ye every one",69,81],["H1544","his idols",82,91],["H0310","and hereafter",93,106],["H8085","also, if ye will not hearken",107,135],["H2490","unto me: but pollute",136,156],["H6944","ye my holy",157,167],["H8034","name",168,172],["H4979","no more with your gifts",173,196],["H1544","and with your idols",198,217]]},"20:40":{"text":"For in mine holy mountain, in the mountain of the height of Israel, saith the Lord GOD, there shall all the house of Israel, all of them in the land, serve me: there will I accept them, and there will I require your offerings, and the firstfruits of your oblations, with all your holy things.","words":[["H6944","For in mine holy",0,16],["H2022","mountain",17,25],["H2022","in the mountain",27,42],["H4791","of the height",43,56],["H3478","of Israel",57,66],["H5002","saith",68,73],["H0136","the Lord",74,82],["H3069","GOD",83,86],["H1004","there shall all the house",88,113],["H3478","of Israel",114,123],["H0776","all of them in the land",125,148],["H5647","serve",150,155],["H7521","me: there will I accept",156,179],["H1875","them, and there will I require",180,210],["H8641","your offerings",211,225],["H7225","and the firstfruits",227,246],["H4864","of your oblations",247,264],["H6944","with all your holy things",266,291]]},"20:41":{"text":"I will accept you with your sweet savour, when I bring you out from the people, and gather you out of the countries wherein ye have been scattered; and I will be sanctified in you before the heathen.","words":[["H7521","I will accept",0,13],["H5207","you with your sweet",14,33],["H7381","savour",34,40],["H3318","when I bring you out",42,62],["H5971","from the people",63,78],["H6908","and gather",80,90],["H0776","you out of the countries",91,115],["H6327","wherein ye have been scattered",116,146],["H6942","and I will be sanctified",148,172],["H5869","in you before",173,186],["H1471","the heathen",187,198]]},"20:42":{"text":"And ye shall know that I am the LORD, when I shall bring you into the land of Israel, into the country for the which I lifted up mine hand to give it to your fathers.","words":[["H3045","And ye shall know",0,17],["H3068","that I am the LORD",18,36],["H0935","when I shall bring",38,56],["H0127","you into the land",57,74],["H3478","of Israel",75,84],["H0776","into the country",86,102],["H5375","for the which I lifted up",103,128],["H3027","mine hand",129,138],["H5414","to give",139,146],["H0001","it to your fathers",147,165]]},"20:43":{"text":"And there shall ye remember your ways, and all your doings, wherein ye have been defiled; and ye shall lothe yourselves in your own sight for all your evils that ye have committed.","words":[["H2142","And there shall ye remember",0,27],["H1870","your ways",28,37],["H5949","and all your doings",39,58],["H2930","wherein ye have been defiled",60,88],["H6962","and ye shall lothe",90,108],["H6440","yourselves in your own sight",109,137],["H7451","for all your evils",138,156],["H6213","that ye have committed",157,179]]},"20:44":{"text":"And ye shall know that I am the LORD, when I have wrought with you for my name's sake, not according to your wicked ways, nor according to your corrupt doings, O ye house of Israel, saith the Lord GOD.","words":[["H3045","And ye shall know",0,17],["H3068","that I am the LORD",18,36],["H6213","when I have wrought",38,57],["H8034","with you for my name's",58,80],["H7451","sake, not according to your wicked",81,115],["H1870","ways",116,120],["H7843","nor according to your corrupt",122,151],["H5949","doings",152,158],["H1004","O ye house",160,170],["H3478","of Israel",171,180],["H5002","saith",182,187],["H0136","the Lord",188,196],["H3069","GOD",197,200]]},"20:45":{"text":"Moreover the word of the LORD came unto me, saying,","words":[["H1697","Moreover the word",0,17],["H3068","of the LORD",18,29],["H0559","came unto me, saying",30,50]]},"20:46":{"text":"Son of man, set thy face toward the south, and drop thy word toward the south, and prophesy against the forest of the south field;","words":[["H1121","Son",0,3],["H0120","of man",4,10],["H7760","set",12,15],["H6440","thy face",16,24],["H1870","toward",25,31],["H8486","the south",32,41],["H5197","and drop",43,51],["H1864","thy word toward the south",52,77],["H5012","and prophesy",79,91],["H3293","against the forest",92,110],["H5045","of the south",111,123],["H7704","field",124,129]]},"20:47":{"text":"And say to the forest of the south, Hear the word of the LORD; Thus saith the Lord GOD; Behold, I will kindle a fire in thee, and it shall devour every green tree in thee, and every dry tree: the flaming flame shall not be quenched, and all faces from the south to the north shall be burned therein.","words":[["H0559","And say",0,7],["H3293","to the forest",8,21],["H5045","of the south",22,34],["H8085","Hear",36,40],["H1697","the word",41,49],["H3068","of the LORD",50,61],["H0559","Thus saith",63,73],["H0136","the Lord",74,82],["H3069","GOD",83,86],["H3341","Behold, I will kindle",88,109],["H0784","a fire",110,116],["H0398","in thee, and it shall devour",117,145],["H3892","every green",146,157],["H6086","tree",158,162],["H3002","in thee, and every dry",163,185],["H6086","tree",186,190],["H3852","the flaming",192,203],["H7957","flame",204,209],["H3518","shall not be quenched",210,231],["H6440","and all faces",233,246],["H5045","from the south",247,261],["H6828","to the north",262,274],["H6866","shall be burned",275,290]]},"20:48":{"text":"And all flesh shall see that I the LORD have kindled it: it shall not be quenched.","words":[["H1320","And all flesh",0,13],["H7200","shall see",14,23],["H3068","that I the LORD",24,39],["H1197","have kindled",40,52],["H3518","it: it shall not be quenched",53,81]]},"20:49":{"text":"Then said I, Ah Lord GOD! they say of me, Doth he not speak parables?","words":[["H0559","Then said",0,9],["H0162","I, Ah",10,15],["H0136","Lord",16,20],["H3069","GOD",21,24],["H0559","they say",26,34],["H4911","of me, Doth he not speak",35,59],["H4912","parables",60,68]]},"21:1":{"text":"And the word of the LORD came unto me, saying,","words":[["H1697","And the word",0,12],["H3068","of the LORD",13,24],["H0559","came unto me, saying",25,45]]},"21:2":{"text":"Son of man, set thy face toward Jerusalem, and drop thy word toward the holy places, and prophesy against the land of Israel,","words":[["H1121","Son",0,3],["H0120","of man",4,10],["H7760","set",12,15],["H6440","thy face",16,24],["H3389","toward Jerusalem",25,41],["H5197","and drop",43,51],["H4720","thy word toward the holy places",52,83],["H5012","and prophesy",85,97],["H0127","against the land",98,114],["H3478","of Israel",115,124]]},"21:3":{"text":"And say to the land of Israel, Thus saith the LORD; Behold, I am against thee, and will draw forth my sword out of his sheath, and will cut off from thee the righteous and the wicked.","words":[["H0559","And say",0,7],["H0127","to the land",8,19],["H3478","of Israel",20,29],["H0559","Thus saith",31,41],["H3068","the LORD",42,50],["H3318","Behold, I am against thee, and will draw forth",52,98],["H2719","my sword",99,107],["H8593","out of his sheath",108,125],["H3772","and will cut off",127,143],["H6662","from thee the righteous",144,167],["H7563","and the wicked",168,182]]},"21:4":{"text":"Seeing then that I will cut off from thee the righteous and the wicked, therefore shall my sword go forth out of his sheath against all flesh from the south to the north:","words":[["H3282","Seeing",0,6],["H3772","then that I will cut off",7,31],["H6662","from thee the righteous",32,55],["H7563","and the wicked",56,70],["H2719","therefore shall my sword",72,96],["H3318","go forth",97,105],["H8593","out of his sheath",106,123],["H1320","against all flesh",124,141],["H5045","from the south",142,156],["H6828","to the north",157,169]]},"21:5":{"text":"That all flesh may know that I the LORD have drawn forth my sword out of his sheath: it shall not return any more.","words":[["H1320","That all flesh",0,14],["H3045","may know",15,23],["H3068","that I the LORD",24,39],["H3318","have drawn forth",40,56],["H2719","my sword",57,65],["H8593","out of his sheath",66,83],["H7725","it shall not return",85,104]]},"21:6":{"text":"Sigh therefore, thou son of man, with the breaking of thy loins; and with bitterness sigh before their eyes.","words":[["H0584","Sigh",0,4],["H1121","therefore, thou son",5,24],["H0120","of man",25,31],["H7670","with the breaking",33,50],["H4975","of thy loins",51,63],["H4814","and with bitterness",65,84],["H0584","sigh",85,89],["H5869","before their eyes",90,107]]},"21:7":{"text":"And it shall be, when they say unto thee, Wherefore sighest thou? that thou shalt answer, For the tidings; because it cometh: and every heart shall melt, and all hands shall be feeble, and every spirit shall faint, and all knees shall be weak as water: behold, it cometh, and shall be brought to pass, saith the Lord GOD.","words":[["H0559","And it shall be, when they say",0,30],["H0584","unto thee, Wherefore sighest",31,59],["H0559","thou? that thou shalt answer",60,88],["H8052","For the tidings",90,105],["H0935","because it cometh",107,124],["H3820","and every heart",126,141],["H4549","shall melt",142,152],["H3027","and all hands",154,167],["H7503","shall be feeble",168,183],["H7307","and every spirit",185,201],["H3543","shall faint",202,213],["H1290","and all knees",215,228],["H3212","shall be weak",229,242],["H4325","as water",243,251],["H0935","behold, it cometh",253,270],["H1961","and shall be brought to pass",272,300],["H5002","saith",302,307],["H0136","the Lord",308,316],["H3069","GOD",317,320]]},"21:8":{"text":"Again the word of the LORD came unto me, saying,","words":[["H1697","Again the word",0,14],["H3068","of the LORD",15,26],["H0559","came unto me, saying",27,47]]},"21:9":{"text":"Son of man, prophesy, and say, Thus saith the LORD; Say, A sword, a sword is sharpened, and also furbished:","words":[["H1121","Son",0,3],["H0120","of man",4,10],["H5012","prophesy",12,20],["H0559","and say",22,29],["H0559","Thus saith",31,41],["H3068","the LORD",42,50],["H0559","Say",52,55],["H2719","A sword",57,64],["H2719","a sword",66,73],["H2300","is sharpened",74,86],["H4803","and also furbished",88,106]]},"21:10":{"text":"It is sharpened to make a sore slaughter; it is furbished that it may glitter: should we then make mirth? it contemneth the rod of my son, as every tree.","words":[["H2300","It is sharpened",0,15],["H2874","to make a sore",16,30],["H2873","slaughter",31,40],["H4178","it is furbished",42,57],["H1300","that it may glitter",58,77],["H0176","should",79,85],["H7797","we then make mirth",86,104],["H3988","it contemneth",106,119],["H7626","the rod",120,127],["H1121","of my son",128,137],["H6086","as every tree",139,152]]},"21:11":{"text":"And he hath given it to be furbished, that it may be handled: this sword is sharpened, and it is furbished, to give it into the hand of the slayer.","words":[["H5414","And he hath given",0,17],["H4803","it to be furbished",18,36],["H3709","that it may be handled",38,60],["H8610","that it may be handled",38,60],["H2719","this sword",62,72],["H2300","is sharpened",73,85],["H4178","and it is furbished",87,106],["H5414","to give",108,115],["H3027","it into the hand",116,132],["H2026","of the slayer",133,146]]},"21:12":{"text":"Cry and howl, son of man: for it shall be upon my people, it shall be upon all the princes of Israel: terrors by reason of the sword shall be upon my people: smite therefore upon thy thigh.","words":[["H2199","Cry",0,3],["H3213","and howl",4,12],["H1121","son",14,17],["H0120","of man",18,24],["H5971","for it shall be upon my people",26,56],["H5387","it shall be upon all the princes",58,90],["H3478","of Israel",91,100],["H4048","terrors",102,109],["H0413","by reason of",110,122],["H2719","the sword",123,132],["H5971","shall be upon my people",133,156],["H5606","smite",158,163],["H3409","therefore upon thy thigh",164,188]]},"21:13":{"text":"Because it is a trial, and what if the sword contemn even the rod? it shall be no more, saith the Lord GOD.","words":[["H0974","Because it is a trial",0,21],["H3988","and what if the sword contemn",23,52],["H7626","even the rod",53,65],["H5002","it shall be no more, saith",67,93],["H0136","the Lord",94,102],["H3069","GOD",103,106]]},"21:14":{"text":"Thou therefore, son of man, prophesy, and smite thine hands together, and let the sword be doubled the third time, the sword of the slain: it is the sword of the great men that are slain, which entereth into their privy chambers.","words":[["H1121","Thou therefore, son",0,19],["H0120","of man",20,26],["H5012","prophesy",28,36],["H5221","and smite",38,47],["H3709","thine hands",48,59],["H3709","thine hands",48,59],["H5221","together",60,68],["H2719","and let the sword",70,87],["H3717","be doubled",88,98],["H7992","the third",99,108],["H2719","time, the sword",109,124],["H2491","of the slain",125,137],["H2719","it is the sword",139,154],["H1419","of the great",155,167],["H2491","men that are slain",168,186],["H2314","which entereth into their privy chambers",188,228]]},"21:15":{"text":"I have set the point of the sword against all their gates, that their heart may faint, and their ruins be multiplied: ah! it is made bright, it is wrapped up for the slaughter.","words":[["H5414","I have set",0,10],["H0019","the point",11,20],["H2719","of the sword",21,33],["H8179","against all their gates",34,57],["H3820","that their heart",59,75],["H4127","may faint",76,85],["H4383","and their ruins",87,102],["H7235","be multiplied",103,116],["H0253","ah",118,120],["H6213","it is made",122,132],["H1300","bright",133,139],["H4593","it is wrapped up",141,157],["H2874","for the slaughter",158,175]]},"21:16":{"text":"Go thee one way or other, either on the right hand, or on the left, whithersoever thy face is set.","words":[["H0258","Go thee one way or other",0,24],["H7760","either on",26,35],["H3231","the right hand",36,50],["H8041","or on the left",52,66],["H0575","whithersoever",68,81],["H6440","thy face",82,90],["H3259","is set",91,97]]},"21:17":{"text":"I will also smite mine hands together, and I will cause my fury to rest: I the LORD have said it.","words":[["H5221","I will also smite",0,17],["H3709","mine hands",18,28],["H3709","together",29,37],["H2534","and I will cause my fury",39,63],["H5117","to rest",64,71],["H3068","I the LORD",73,83],["H1696","have said",84,93]]},"21:18":{"text":"The word of the LORD came unto me again, saying,","words":[["H1697","The word",0,8],["H3068","of the LORD",9,20],["H0559","came unto me again, saying",21,47]]},"21:19":{"text":"Also, thou son of man, appoint thee two ways, that the sword of the king of Babylon may come: both twain shall come forth out of one land: and choose thou a place, choose it at the head of the way to the city.","words":[["H1121","Also, thou son",0,14],["H0120","of man",15,21],["H7760","appoint",23,30],["H8147","thee two",31,39],["H1870","ways",40,44],["H2719","that the sword",46,60],["H4428","of the king",61,72],["H0894","of Babylon",73,83],["H0935","may come",84,92],["H8147","both twain",94,104],["H3318","shall come forth",105,121],["H0259","out of one",122,132],["H0776","land",133,137],["H1254","and choose",139,149],["H3027","thou a place",150,162],["H1254","choose",164,170],["H7218","it at the head",171,185],["H1870","of the way",186,196],["H5892","to the city",197,208]]},"21:20":{"text":"Appoint a way, that the sword may come to Rabbath of the Ammonites, and to Judah in Jerusalem the defenced.","words":[["H7760","Appoint",0,7],["H1870","a way",8,13],["H2719","that the sword",15,29],["H0935","may come",30,38],["H7237","to Rabbath",39,49],["H1121","of the Ammonites",50,66],["H5983","of the Ammonites",50,66],["H3063","and to Judah",68,80],["H3389","in Jerusalem",81,93],["H1219","the defenced",94,106]]},"21:21":{"text":"For the king of Babylon stood at the parting of the way, at the head of the two ways, to use divination: he made his arrows bright, he consulted with images, he looked in the liver.","words":[["H4428","For the king",0,12],["H0894","of Babylon",13,23],["H5975","stood",24,29],["H0517","at the parting",30,44],["H1870","of the way",45,55],["H7218","at the head",57,68],["H8147","of the two",69,79],["H1870","ways",80,84],["H7080","to use",86,92],["H7081","divination",93,103],["H2671","he made his arrows",105,123],["H7043","bright",124,130],["H7592","he consulted",132,144],["H8655","with images",145,156],["H7200","he looked",158,167],["H3516","in the liver",168,180]]},"21:22":{"text":"At his right hand was the divination for Jerusalem, to appoint captains, to open the mouth in the slaughter, to lift up the voice with shouting, to appoint battering rams against the gates, to cast a mount, and to build a fort.","words":[["H3225","At his right hand",0,17],["H7081","was the divination",18,36],["H3389","for Jerusalem",37,50],["H7760","to appoint",52,62],["H3733","captains",63,71],["H6605","to open",73,80],["H6310","the mouth",81,90],["H7524","in the slaughter",91,107],["H7311","to lift up",109,119],["H6963","the voice",120,129],["H8643","with shouting",130,143],["H7760","to appoint",145,155],["H3733","battering rams",156,170],["H8179","against the gates",171,188],["H8210","to cast",190,197],["H5550","a mount",198,205],["H1129","and to build",207,219],["H1785","a fort",220,226]]},"21:23":{"text":"And it shall be unto them as a false divination in their sight, to them that have sworn oaths: but he will call to remembrance the iniquity, that they may be taken.","words":[["H7723","And it shall be unto them as a false",0,36],["H7080","divination",37,47],["H5869","in their sight",48,62],["H7650","to them that have sworn",64,87],["H7621","oaths",88,93],["H2142","but he will call to remembrance",95,126],["H5771","the iniquity",127,139],["H8610","that they may be taken",141,163]]},"21:24":{"text":"Therefore thus saith the Lord GOD; Because ye have made your iniquity to be remembered, in that your transgressions are discovered, so that in all your doings your sins do appear; because, I say, that ye are come to remembrance, ye shall be taken with the hand.","words":[["H0559","Therefore thus saith",0,20],["H0136","the Lord",21,29],["H3069","GOD",30,33],["H5771","Because ye have made your iniquity",35,69],["H2142","to be remembered",70,86],["H6588","in that your transgressions",88,115],["H1540","are discovered",116,130],["H5949","so that in all your doings",132,158],["H2403","your sins",159,168],["H7200","do appear",169,178],["H2142","because, I say, that ye are come to remembrance",180,227],["H8610","ye shall be taken",229,246],["H3709","with the hand",247,260]]},"21:25":{"text":"And thou, profane wicked prince of Israel, whose day is come, when iniquity shall have an end,","words":[["H2491","And thou, profane",0,17],["H7563","wicked",18,24],["H5387","prince",25,31],["H3478","of Israel",32,41],["H3117","whose day",43,52],["H0935","is come",53,60],["H6256","when",62,66],["H5771","iniquity",67,75],["H7093","shall have an end",76,93]]},"21:26":{"text":"Thus saith the Lord GOD; Remove the diadem, and take off the crown: this shall not be the same: exalt him that is low, and abase him that is high.","words":[["H0559","Thus saith",0,10],["H0136","the Lord",11,19],["H3069","GOD",20,23],["H5493","Remove",25,31],["H4701","the diadem",32,42],["H7311","and take off",44,56],["H5850","the crown",57,66],["H2063","this shall not be the same",68,94],["H1361","exalt",96,101],["H8217","him that is low",102,117],["H8213","and abase",119,128],["H1364","him that is high",129,145]]},"21:27":{"text":"I will overturn, overturn, overturn, it: and it shall be no more, until he come whose right it is; and I will give it him.","words":[["H5754","I will overturn",0,15],["H5754","overturn",17,25],["H5754","overturn",27,35],["H7760","it: and it shall be",37,56],["H0935","no more, until he come",57,79],["H4941","whose right",80,91],["H5414","it is; and I will give",92,114]]},"21:28":{"text":"And thou, son of man, prophesy and say, Thus saith the Lord GOD concerning the Ammonites, and concerning their reproach; even say thou, The sword, the sword is drawn: for the slaughter it is furbished, to consume because of the glittering:","words":[["H1121","And thou, son",0,13],["H0120","of man",14,20],["H5012","prophesy",22,30],["H0559","and say",31,38],["H0559","Thus saith",40,50],["H0136","the Lord",51,59],["H3069","GOD",60,63],["H1121","concerning the Ammonites",64,88],["H5983","concerning the Ammonites",64,88],["H2781","and concerning their reproach",90,119],["H0559","even say",121,129],["H2719","thou, The sword",130,145],["H2719","the sword",147,156],["H6605","is drawn",157,165],["H2874","for the slaughter",167,184],["H4803","it is furbished",185,200],["H0398","to consume",202,212],["H1300","because of the glittering",213,238]]},"21:29":{"text":"Whiles they see vanity unto thee, whiles they divine a lie unto thee, to bring thee upon the necks of them that are slain, of the wicked, whose day is come, when their iniquity shall have an end.","words":[["H2372","Whiles they see",0,15],["H7723","vanity",16,22],["H7080","unto thee, whiles they divine",23,52],["H3577","a lie",53,58],["H5414","unto thee, to bring",59,78],["H6677","thee upon the necks",79,98],["H2491","of them that are slain",99,121],["H7563","of the wicked",123,136],["H3117","whose day",138,147],["H0935","is come",148,155],["H6256","when",157,161],["H5771","their iniquity",162,176],["H7093","shall have an end",177,194]]},"21:30":{"text":"Shall I cause it to return into his sheath? I will judge thee in the place where thou wast created, in the land of thy nativity.","words":[["H7725","Shall I cause it to return",0,26],["H8593","into his sheath",27,42],["H8199","I will judge",44,56],["H4725","thee in the place",57,74],["H1254","where thou wast created",75,98],["H0776","in the land",100,111],["H4351","of thy nativity",112,127]]},"21:31":{"text":"And I will pour out mine indignation upon thee, I will blow against thee in the fire of my wrath, and deliver thee into the hand of brutish men, and skilful to destroy.","words":[["H8210","And I will pour out",0,19],["H2195","mine indignation",20,36],["H6315","upon thee, I will blow",37,59],["H0784","against thee in the fire",60,84],["H5678","of my wrath",85,96],["H5414","and deliver",98,109],["H3027","thee into the hand",110,128],["H1197","of brutish",129,139],["H0582","men",140,143],["H2796","and skilful",145,156],["H4889","to destroy",157,167]]},"21:32":{"text":"Thou shalt be for fuel to the fire; thy blood shall be in the midst of the land; thou shalt be no more remembered: for I the LORD have spoken it.","words":[["H0402","Thou shalt be for fuel",0,22],["H0784","to the fire",23,34],["H1818","thy blood",36,45],["H8432","shall be in the midst",46,67],["H0776","of the land",68,79],["H2142","thou shalt be no more remembered",81,113],["H3068","for I the LORD",115,129],["H1696","have spoken",130,141]]},"22:1":{"text":"Moreover the word of the LORD came unto me, saying,","words":[["H1697","Moreover the word",0,17],["H3068","of the LORD",18,29],["H0559","came unto me, saying",30,50]]},"22:2":{"text":"Now, thou son of man, wilt thou judge, wilt thou judge the bloody city? yea, thou shalt shew her all her abominations.","words":[["H1121","Now, thou son",0,13],["H0120","of man",14,20],["H8199","wilt thou judge",22,37],["H8199","wilt thou judge",39,54],["H1818","the bloody",55,65],["H5892","city",66,70],["H3045","yea, thou shalt shew",72,92],["H8441","her all her abominations",93,117]]},"22:3":{"text":"Then say thou, Thus saith the Lord GOD, The city sheddeth blood in the midst of it, that her time may come, and maketh idols against herself to defile herself.","words":[["H0559","Then say",0,8],["H0559","thou, Thus saith",9,25],["H0136","the Lord",26,34],["H3069","GOD",35,38],["H5892","The city",40,48],["H8210","sheddeth",49,57],["H1818","blood",58,63],["H8432","in the midst",64,76],["H6256","of it, that her time",77,97],["H0935","may come",98,106],["H6213","and maketh",108,118],["H1544","idols",119,124],["H2930","against herself to defile",125,150]]},"22:4":{"text":"Thou art become guilty in thy blood that thou hast shed; and hast defiled thyself in thine idols which thou hast made; and thou hast caused thy days to draw near, and art come even unto thy years: therefore have I made thee a reproach unto the heathen, and a mocking to all countries.","words":[["H0816","Thou art become guilty",0,22],["H1818","in thy blood",23,35],["H8210","that thou hast shed",36,55],["H2930","and hast defiled",57,73],["H1544","thyself in thine idols",74,96],["H6213","which thou hast made",97,117],["H3117","and thou hast caused thy days",119,148],["H7126","to draw near",149,161],["H0935","and art come",163,175],["H8141","even unto thy years",176,195],["H5414","therefore have I made",197,218],["H2781","thee a reproach",219,234],["H1471","unto the heathen",235,251],["H7048","and a mocking",253,266],["H0776","to all countries",267,283]]},"22:5":{"text":"Those that be near, and those that be far from thee, shall mock thee, which art infamous and much vexed.","words":[["H7138","Those that be near",0,18],["H7350","and those that be far",20,41],["H7046","from thee, shall mock",42,63],["H2931","thee, which art infamous",64,88],["H8034","thee, which art infamous",64,88],["H7227","and much",89,97],["H4103","vexed",98,103]]},"22:6":{"text":"Behold, the princes of Israel, every one were in thee to their power to shed blood.","words":[["H5387","Behold, the princes",0,19],["H3478","of Israel",20,29],["H0376","every one",31,40],["H2220","were in thee to their power",41,68],["H8210","to shed",69,76],["H1818","blood",77,82]]},"22:7":{"text":"In thee have they set light by father and mother: in the midst of thee have they dealt by oppression with the stranger: in thee have they vexed the fatherless and the widow.","words":[["H7043","In thee have they set light",0,27],["H0001","by father",28,37],["H0517","and mother",38,48],["H8432","in the midst",50,62],["H6213","of thee have they dealt",63,86],["H6233","by oppression",87,100],["H1616","with the stranger",101,118],["H3238","in thee have they vexed",120,143],["H3490","the fatherless",144,158],["H0490","and the widow",159,172]]},"22:8":{"text":"Thou hast despised mine holy things, and hast profaned my sabbaths.","words":[["H0959","Thou hast despised",0,18],["H6944","mine holy things",19,35],["H2490","and hast profaned",37,54],["H7676","my sabbaths",55,66]]},"22:9":{"text":"In thee are men that carry tales to shed blood: and in thee they eat upon the mountains: in the midst of thee they commit lewdness.","words":[["H0582","In thee are men",0,15],["H7400","that carry tales",16,32],["H8210","to shed",33,40],["H1818","blood",41,46],["H0398","and in thee they eat",48,68],["H2022","upon the mountains",69,87],["H8432","in the midst",89,101],["H6213","of thee they commit",102,121],["H2154","lewdness",122,130]]},"22:10":{"text":"In thee have they discovered their fathers' nakedness: in thee have they humbled her that was set apart for pollution.","words":[["H1540","In thee have they discovered",0,28],["H0001","their fathers'",29,43],["H6172","nakedness",44,53],["H6031","in thee have they humbled",55,80],["H5079","her that was set apart",81,103],["H2931","for pollution",104,117]]},"22:11":{"text":"And one hath committed abomination with his neighbour's wife; and another hath lewdly defiled his daughter in law; and another in thee hath humbled his sister, his father's daughter.","words":[["H0376","And one",0,7],["H6213","hath committed",8,22],["H8441","abomination",23,34],["H7453","with his neighbour's",35,55],["H0802","wife",56,60],["H0376","and another",62,73],["H2154","hath lewdly",74,85],["H2930","defiled",86,93],["H3618","his daughter in law",94,113],["H0376","and another",115,126],["H6031","in thee hath humbled",127,147],["H0269","his sister",148,158],["H0001","his father's",160,172],["H1323","daughter",173,181]]},"22:12":{"text":"In thee have they taken gifts to shed blood; thou hast taken usury and increase, and thou hast greedily gained of thy neighbours by extortion, and hast forgotten me, saith the Lord GOD.","words":[["H3947","In thee have they taken",0,23],["H7810","gifts",24,29],["H8210","to shed",30,37],["H1818","blood",38,43],["H3947","thou hast taken",45,60],["H5392","usury",61,66],["H8636","and increase",67,79],["H1214","and thou hast greedily gained",81,110],["H7453","of thy neighbours",111,128],["H6233","by extortion",129,141],["H7911","and hast forgotten",143,161],["H5002","me, saith",162,171],["H0136","the Lord",172,180],["H3069","GOD",181,184]]},"22:13":{"text":"Behold, therefore I have smitten mine hand at thy dishonest gain which thou hast made, and at thy blood which hath been in the midst of thee.","words":[["H5221","Behold, therefore I have smitten",0,32],["H3709","mine hand",33,42],["H1215","at thy dishonest gain",43,64],["H6213","which thou hast made",65,85],["H1818","and at thy blood",87,103],["H8432","which hath been in the midst",104,132]]},"22:14":{"text":"Can thine heart endure, or can thine hands be strong, in the days that I shall deal with thee? I the LORD have spoken it, and will do it.","words":[["H3820","Can thine heart",0,15],["H5975","endure",16,22],["H3027","or can thine hands",24,42],["H2388","be strong",43,52],["H3117","in the days",54,65],["H6213","that I shall deal",66,83],["H3068","with thee? I the LORD",84,105],["H1696","have spoken",106,117],["H6213","it, and will do",118,133]]},"22:15":{"text":"And I will scatter thee among the heathen, and disperse thee in the countries, and will consume thy filthiness out of thee.","words":[["H6327","And I will scatter",0,18],["H1471","thee among the heathen",19,41],["H2219","and disperse",43,55],["H0776","thee in the countries",56,77],["H8552","and will consume",79,95],["H2932","thy filthiness",96,110]]},"22:16":{"text":"And thou shalt take thine inheritance in thyself in the sight of the heathen, and thou shalt know that I am the LORD.","words":[["H2490","And thou shalt take thine inheritance",0,37],["H5157","And thou shalt take thine inheritance",0,37],["H5869","in thyself in the sight",38,61],["H1471","of the heathen",62,76],["H3045","and thou shalt know",78,97],["H3068","that I am the LORD",98,116]]},"22:17":{"text":"And the word of the LORD came unto me, saying,","words":[["H1697","And the word",0,12],["H3068","of the LORD",13,24],["H0559","came unto me, saying",25,45]]},"22:18":{"text":"Son of man, the house of Israel is to me become dross: all they are brass, and tin, and iron, and lead, in the midst of the furnace; they are even the dross of silver.","words":[["H1121","Son",0,3],["H0120","of man",4,10],["H1004","the house",12,21],["H3478","of Israel",22,31],["H5509","is to me become dross",32,53],["H5178","all they are brass",55,73],["H0913","and tin",75,82],["H1270","and iron",84,92],["H5777","and lead",94,102],["H8432","in the midst",104,116],["H3564","of the furnace",117,131],["H5509","they are even the dross",133,156],["H3701","of silver",157,166]]},"22:19":{"text":"Therefore thus saith the Lord GOD; Because ye are all become dross, behold, therefore I will gather you into the midst of Jerusalem.","words":[["H0559","Therefore thus saith",0,20],["H0136","the Lord",21,29],["H3069","GOD",30,33],["H5509","Because ye are all become dross",35,66],["H6908","behold, therefore I will gather",68,99],["H8432","you into the midst",100,118],["H3389","of Jerusalem",119,131]]},"22:20":{"text":"As they gather silver, and brass, and iron, and lead, and tin, into the midst of the furnace, to blow the fire upon it, to melt it; so will I gather you in mine anger and in my fury, and I will leave you there, and melt you.","words":[["H6910","As they gather",0,14],["H3701","silver",15,21],["H5178","and brass",23,32],["H1270","and iron",34,42],["H5777","and lead",44,52],["H0913","and tin",54,61],["H8432","into the midst",63,77],["H3564","of the furnace",78,92],["H5301","to blow",94,101],["H0784","the fire",102,110],["H5413","upon it, to melt",111,127],["H6908","it; so will I gather",128,148],["H0639","you in mine anger",149,166],["H2534","and in my fury",167,181],["H3240","and I will leave",183,199],["H5413","you there, and melt",200,219]]},"22:21":{"text":"Yea, I will gather you, and blow upon you in the fire of my wrath, and ye shall be melted in the midst thereof.","words":[["H3664","Yea, I will gather",0,18],["H5301","you, and blow",19,32],["H0784","upon you in the fire",33,53],["H5678","of my wrath",54,65],["H5413","and ye shall be melted",67,89],["H8432","in the midst",90,102]]},"22:22":{"text":"As silver is melted in the midst of the furnace, so shall ye be melted in the midst thereof; and ye shall know that I the LORD have poured out my fury upon you.","words":[["H3701","As silver",0,9],["H2046","is melted",10,19],["H8432","in the midst",20,32],["H3564","of the furnace",33,47],["H5413","so shall ye be melted",49,70],["H8432","in the midst",71,83],["H3045","thereof; and ye shall know",84,110],["H3068","that I the LORD",111,126],["H8210","have poured out",127,142],["H2534","my fury",143,150]]},"22:23":{"text":"And the word of the LORD came unto me, saying,","words":[["H1697","And the word",0,12],["H3068","of the LORD",13,24],["H0559","came unto me, saying",25,45]]},"22:24":{"text":"Son of man, say unto her, Thou art the land that is not cleansed, nor rained upon in the day of indignation.","words":[["H1121","Son",0,3],["H0120","of man",4,10],["H0559","say",12,15],["H0776","unto her, Thou art the land",16,43],["H2891","that is not cleansed",44,64],["H1656","nor rained",66,76],["H3117","upon in the day",77,92],["H2195","of indignation",93,107]]},"22:25":{"text":"There is a conspiracy of her prophets in the midst thereof, like a roaring lion ravening the prey; they have devoured souls; they have taken the treasure and precious things; they have made her many widows in the midst thereof.","words":[["H7195","There is a conspiracy",0,21],["H5030","of her prophets",22,37],["H8432","in the midst",38,50],["H7580","thereof, like a roaring",51,74],["H0738","lion",75,79],["H2963","ravening",80,88],["H2964","the prey",89,97],["H0398","they have devoured",99,117],["H5315","souls",118,123],["H3947","they have taken",125,140],["H2633","the treasure",141,153],["H3366","and precious things",154,173],["H7235","they have made her many",175,198],["H0490","widows",199,205],["H8432","in the midst",206,218]]},"22:26":{"text":"Her priests have violated my law, and have profaned mine holy things: they have put no difference between the holy and profane, neither have they shewed difference between the unclean and the clean, and have hid their eyes from my sabbaths, and I am profaned among them.","words":[["H3548","Her priests",0,11],["H2554","have violated",12,25],["H8451","my law",26,32],["H2490","and have profaned",34,51],["H6944","mine holy things",52,68],["H0914","they have put no difference",70,97],["H6944","between the holy",98,114],["H2455","and profane",115,126],["H3045","neither have they shewed",128,152],["H2931","difference between the unclean",153,183],["H2889","and the clean",184,197],["H5956","and have hid",199,211],["H5869","their eyes",212,222],["H7676","from my sabbaths",223,239],["H2490","and I am profaned",241,258],["H8432","among",259,264]]},"22:27":{"text":"Her princes in the midst thereof are like wolves ravening the prey, to shed blood, and to destroy souls, to get dishonest gain.","words":[["H8269","Her princes",0,11],["H7130","in the midst",12,24],["H2061","thereof are like wolves",25,48],["H2963","ravening",49,57],["H2964","the prey",58,66],["H8210","to shed",68,75],["H1818","blood",76,81],["H0006","and to destroy",83,97],["H5315","souls",98,103],["H1214","to get",105,111],["H1215","dishonest gain",112,126]]},"22:28":{"text":"And her prophets have daubed them with untempered morter, seeing vanity, and divining lies unto them, saying, Thus saith the Lord GOD, when the LORD hath not spoken.","words":[["H5030","And her prophets",0,16],["H2902","have daubed",17,28],["H8602","them with untempered",29,49],["H2374","morter, seeing",50,64],["H7723","vanity",65,71],["H7080","and divining",73,85],["H3577","lies",86,90],["H0559","unto them, saying",91,108],["H0559","Thus saith",110,120],["H0136","the Lord",121,129],["H3069","GOD",130,133],["H3068","when the LORD",135,148],["H1696","hath not spoken",149,164]]},"22:29":{"text":"The people of the land have used oppression, and exercised robbery, and have vexed the poor and needy: yea, they have oppressed the stranger wrongfully.","words":[["H5971","The people",0,10],["H0776","of the land",11,22],["H6231","have used oppression",23,43],["H6233","have used oppression",23,43],["H1497","and exercised",45,58],["H1498","robbery",59,66],["H3238","and have vexed",68,82],["H6041","the poor",83,91],["H0034","and needy",92,101],["H6231","yea, they have oppressed",103,127],["H1616","the stranger",128,140],["H4941","wrongfully",141,151]]},"22:30":{"text":"And I sought for a man among them, that should make up the hedge, and stand in the gap before me for the land, that I should not destroy it: but I found none.","words":[["H1245","And I sought",0,12],["H0376","for a man",13,22],["H1443","among them, that should make up",23,54],["H1447","the hedge",55,64],["H5975","and stand",66,75],["H6556","in the gap",76,86],["H6440","before",87,93],["H0776","me for the land",94,109],["H7843","that I should not destroy",111,136],["H4672","it: but I found",137,152]]},"22:31":{"text":"Therefore have I poured out mine indignation upon them; I have consumed them with the fire of my wrath: their own way have I recompensed upon their heads, saith the Lord GOD.","words":[["H8210","Therefore have I poured out",0,27],["H2195","mine indignation",28,44],["H3615","upon them; I have consumed",45,71],["H0784","them with the fire",72,90],["H5678","of my wrath",91,102],["H1870","their own way",104,117],["H5414","have I recompensed",118,136],["H7218","upon their heads",137,153],["H5002","saith",155,160],["H0136","the Lord",161,169],["H3069","GOD",170,173]]},"23:1":{"text":"The word of the LORD came again unto me, saying,","words":[["H1697","The word",0,8],["H3068","of the LORD",9,20],["H0559","came again unto me, saying",21,47]]},"23:2":{"text":"Son of man, there were two women, the daughters of one mother:","words":[["H1121","Son",0,3],["H0120","of man",4,10],["H8147","there were two",12,26],["H0802","women",27,32],["H1323","the daughters",34,47],["H0259","of one",48,54],["H0517","mother",55,61]]},"23:3":{"text":"And they committed whoredoms in Egypt; they committed whoredoms in their youth: there were their breasts pressed, and there they bruised the teats of their virginity.","words":[["H2181","And they committed whoredoms",0,28],["H4714","in Egypt",29,37],["H2181","they committed whoredoms",39,63],["H5271","in their youth",64,78],["H7699","there were their breasts",80,104],["H4600","pressed",105,112],["H6213","and there they bruised",114,136],["H1717","the teats",137,146],["H1331","of their virginity",147,165]]},"23:4":{"text":"And the names of them were Aholah the elder, and Aholibah her sister: and they were mine, and they bare sons and daughters. Thus were their names; Samaria is Aholah, and Jerusalem Aholibah.","words":[["H8034","And the names",0,13],["H0170","of them were Aholah",14,33],["H1419","the elder",34,43],["H0172","and Aholibah",45,57],["H0269","her sister",58,68],["H3205","and they were mine, and they bare",70,103],["H1121","sons",104,108],["H1323","and daughters",109,122],["H8034","Thus were their names",124,145],["H8111","Samaria",147,154],["H0170","is Aholah",155,164],["H3389","and Jerusalem",166,179],["H0172","Aholibah",180,188]]},"23:5":{"text":"And Aholah played the harlot when she was mine; and she doted on her lovers, on the Assyrians her neighbours,","words":[["H0170","And Aholah",0,10],["H2181","played the harlot",11,28],["H8478","when she was mine",29,46],["H5689","and she doted",48,61],["H0157","on her lovers",62,75],["H0804","on the Assyrians",77,93],["H7138","her neighbours",94,108]]},"23:6":{"text":"Which were clothed with blue, captains and rulers, all of them desirable young men, horsemen riding upon horses.","words":[["H3847","Which were clothed",0,18],["H8504","with blue",19,28],["H6346","captains",30,38],["H5461","and rulers",39,49],["H2531","all of them desirable",51,72],["H0970","young men",73,82],["H6571","horsemen",84,92],["H7392","riding",93,99],["H5483","upon horses",100,111]]},"23:7":{"text":"Thus she committed her whoredoms with them, with all them that were the chosen men of Assyria, and with all on whom she doted: with all their idols she defiled herself.","words":[["H5414","Thus she committed",0,18],["H8457","her whoredoms",19,32],["H4005","with them, with all them that were the chosen",33,78],["H1121","men",79,82],["H0804","of Assyria",83,93],["H5689","and with all on whom she doted",95,125],["H1544","with all their idols",127,147],["H2930","she defiled",148,159]]},"23:8":{"text":"Neither left she her whoredoms brought from Egypt: for in her youth they lay with her, and they bruised the breasts of her virginity, and poured their whoredom upon her.","words":[["H5800","Neither left",0,12],["H8457","she her whoredoms",13,30],["H4714","brought from Egypt",31,49],["H5271","for in her youth",51,67],["H7901","they lay",68,76],["H6213","with her, and they bruised",77,103],["H1717","the breasts",104,115],["H1331","of her virginity",116,132],["H8210","and poured",134,144],["H8457","their whoredom",145,159]]},"23:9":{"text":"Wherefore I have delivered her into the hand of her lovers, into the hand of the Assyrians, upon whom she doted.","words":[["H5414","Wherefore I have delivered",0,26],["H3027","her into the hand",27,44],["H0157","of her lovers",45,58],["H3027","into the hand",60,73],["H1121","of the Assyrians",74,90],["H0804","of the Assyrians",74,90],["H5689","upon whom she doted",92,111]]},"23:10":{"text":"These discovered her nakedness: they took her sons and her daughters, and slew her with the sword: and she became famous among women; for they had executed judgment upon her.","words":[["H1540","These discovered",0,16],["H6172","her nakedness",17,30],["H3947","they took",32,41],["H1121","her sons",42,50],["H1323","and her daughters",51,68],["H2026","and slew",70,78],["H2719","her with the sword",79,97],["H8034","and she became famous",99,120],["H0802","among women",121,132],["H6213","for they had executed",134,155],["H8196","judgment",156,164]]},"23:11":{"text":"And when her sister Aholibah saw this, she was more corrupt in her inordinate love than she, and in her whoredoms more than her sister in her whoredoms.","words":[["H0269","And when her sister",0,19],["H0172","Aholibah",20,28],["H7200","saw",29,32],["H7843","this, she was more corrupt",33,59],["H5691","in her inordinate love",60,82],["H8457","than she, and in her whoredoms",83,113],["H0269","more than her sister",114,134],["H2183","in her whoredoms",135,151]]},"23:12":{"text":"She doted upon the Assyrians her neighbours, captains and rulers clothed most gorgeously, horsemen riding upon horses, all of them desirable young men.","words":[["H5689","She doted",0,9],["H1121","upon the Assyrians",10,28],["H0804","upon the Assyrians",10,28],["H7138","her neighbours",29,43],["H6346","captains",45,53],["H5461","and rulers",54,64],["H3847","clothed",65,72],["H4358","most gorgeously",73,88],["H6571","horsemen",90,98],["H7392","riding",99,105],["H5483","upon horses",106,117],["H2531","all of them desirable",119,140],["H0970","young men",141,150]]},"23:13":{"text":"Then I saw that she was defiled, that they took both one way,","words":[["H7200","Then I saw",0,10],["H2930","that she was defiled",11,31],["H8147","that they took both",33,52],["H0259","one",53,56],["H1870","way",57,60]]},"23:14":{"text":"And that she increased her whoredoms: for when she saw men pourtrayed upon the wall, the images of the Chaldeans pourtrayed with vermilion,","words":[["H3254","And that she increased",0,22],["H8457","her whoredoms",23,36],["H7200","for when she saw",38,54],["H0582","men",55,58],["H2707","pourtrayed",59,69],["H7023","upon the wall",70,83],["H6754","the images",85,95],["H3778","of the Chaldeans",96,112],["H2710","pourtrayed",113,123],["H8350","with vermilion",124,138]]},"23:15":{"text":"Girded with girdles upon their loins, exceeding in dyed attire upon their heads, all of them princes to look to, after the manner of the Babylonians of Chaldea, the land of their nativity:","words":[["H2289","Girded",0,6],["H0232","with girdles",7,19],["H4975","upon their loins",20,36],["H5628","exceeding",38,47],["H2871","in dyed attire",48,62],["H7218","upon their heads",63,79],["H7991","all of them princes",81,100],["H4758","to look to",101,111],["H1823","after the manner",113,129],["H1121","of the Babylonians",130,148],["H0894","of the Babylonians",130,148],["H3778","of Chaldea",149,159],["H0776","the land",161,169],["H4138","of their nativity",170,187]]},"23:16":{"text":"And as soon as she saw them with her eyes, she doted upon them, and sent messengers unto them into Chaldea.","words":[["H4758","And as soon as she saw",0,22],["H5869","them with her eyes",23,41],["H5689","she doted",43,52],["H7971","upon them, and sent",53,72],["H4397","messengers",73,83],["H3778","unto them into Chaldea",84,106]]},"23:17":{"text":"And the Babylonians came to her into the bed of love, and they defiled her with their whoredom, and she was polluted with them, and her mind was alienated from them.","words":[["H1121","And the Babylonians",0,19],["H0894","And the Babylonians",0,19],["H0935","came",20,24],["H4904","to her into the bed",25,44],["H1730","of love",45,52],["H2930","and they defiled",54,70],["H8457","her with their whoredom",71,94],["H2930","and she was polluted",96,116],["H5315","with them, and her mind",117,140],["H3363","was alienated",141,154]]},"23:18":{"text":"So she discovered her whoredoms, and discovered her nakedness: then my mind was alienated from her, like as my mind was alienated from her sister.","words":[["H1540","So she discovered",0,17],["H8457","her whoredoms",18,31],["H1540","and discovered",33,47],["H6172","her nakedness",48,61],["H5315","then my mind",63,75],["H3363","was alienated",76,89],["H5315","from her, like as my mind",90,115],["H5361","was alienated",116,129],["H0269","from her sister",130,145]]},"23:19":{"text":"Yet she multiplied her whoredoms, in calling to remembrance the days of her youth, wherein she had played the harlot in the land of Egypt.","words":[["H7235","Yet she multiplied",0,18],["H8457","her whoredoms",19,32],["H2142","in calling to remembrance",34,59],["H3117","the days",60,68],["H5271","of her youth",69,81],["H2181","wherein she had played the harlot",83,116],["H0776","in the land",117,128],["H4714","of Egypt",129,137]]},"23:20":{"text":"For she doted upon their paramours, whose flesh is as the flesh of asses, and whose issue is like the issue of horses.","words":[["H5689","For she doted",0,13],["H6370","upon their paramours",14,34],["H1320","whose flesh",36,47],["H1320","is as the flesh",48,63],["H2543","of asses",64,72],["H2231","and whose issue",74,89],["H2231","is like the issue",90,107],["H5483","of horses",108,117]]},"23:21":{"text":"Thus thou calledst to remembrance the lewdness of thy youth, in bruising thy teats by the Egyptians for the paps of thy youth.","words":[["H6485","Thus thou calledst to remembrance",0,33],["H2154","the lewdness",34,46],["H5271","of thy youth",47,59],["H6213","in bruising",61,72],["H1717","thy teats",73,82],["H4714","by the Egyptians",83,99],["H7699","for the paps",100,112],["H5271","of thy youth",113,125]]},"23:22":{"text":"Therefore, O Aholibah, thus saith the Lord GOD; Behold, I will raise up thy lovers against thee, from whom thy mind is alienated, and I will bring them against thee on every side;","words":[["H0172","Therefore, O Aholibah",0,21],["H0559","thus saith",23,33],["H0136","the Lord",34,42],["H3069","GOD",43,46],["H5782","Behold, I will raise up",48,71],["H0157","thy lovers",72,82],["H5315","against thee, from whom thy mind",83,115],["H5361","is alienated",116,128],["H0935","and I will bring",130,146],["H5439","them against thee on every side",147,178]]},"23:23":{"text":"The Babylonians, and all the Chaldeans, Pekod, and Shoa, and Koa, and all the Assyrians with them: all of them desirable young men, captains and rulers, great lords and renowned, all of them riding upon horses.","words":[["H1121","The Babylonians",0,15],["H0894","The Babylonians",0,15],["H3778","and all the Chaldeans",17,38],["H6489","Pekod",40,45],["H7772","and Shoa",47,55],["H6970","and Koa",57,64],["H1121","and all the Assyrians",66,87],["H0804","and all the Assyrians",66,87],["H2531","with them: all of them desirable",88,120],["H0970","young men",121,130],["H6346","captains",132,140],["H5461","and rulers",141,151],["H7991","great lords",153,164],["H7121","and renowned",165,177],["H7392","all of them riding",179,197],["H5483","upon horses",198,209]]},"23:24":{"text":"And they shall come against thee with chariots, wagons, and wheels, and with an assembly of people, which shall set against thee buckler and shield and helmet round about: and I will set judgment before them, and they shall judge thee according to their judgments.","words":[["H0935","And they shall come",0,19],["H2021","against thee with chariots",20,46],["H7393","wagons",48,54],["H1534","and wheels",56,66],["H6951","and with an assembly",68,88],["H5971","of people",89,98],["H7760","which shall set",100,115],["H6793","against thee buckler",116,136],["H4043","and shield",137,147],["H6959","and helmet",148,158],["H5439","round about",159,170],["H5414","and I will set",172,186],["H4941","judgment",187,195],["H6440","before",196,202],["H8199","them, and they shall judge",203,229],["H4941","thee according to their judgments",230,263]]},"23:25":{"text":"And I will set my jealousy against thee, and they shall deal furiously with thee: they shall take away thy nose and thine ears; and thy remnant shall fall by the sword: they shall take thy sons and thy daughters; and thy residue shall be devoured by the fire.","words":[["H5414","And I will set",0,14],["H7068","my jealousy",15,26],["H6213","against thee, and they shall deal",27,60],["H2534","furiously",61,70],["H5493","with thee: they shall take away",71,102],["H0639","thy nose",103,111],["H0241","and thine ears",112,126],["H0319","and thy remnant",128,143],["H5307","shall fall",144,154],["H2719","by the sword",155,167],["H3947","they shall take",169,184],["H1121","thy sons",185,193],["H1323","and thy daughters",194,211],["H0319","and thy residue",213,228],["H0398","shall be devoured",229,246],["H0784","by the fire",247,258]]},"23:26":{"text":"They shall also strip thee out of thy clothes, and take away thy fair jewels.","words":[["H6584","They shall also strip",0,21],["H0899","thee out of thy clothes",22,45],["H3947","and take away",47,60],["H8597","thy fair",61,69],["H3627","jewels",70,76]]},"23:27":{"text":"Thus will I make thy lewdness to cease from thee, and thy whoredom brought from the land of Egypt: so that thou shalt not lift up thine eyes unto them, nor remember Egypt any more.","words":[["H2154","Thus will I make thy lewdness",0,29],["H7673","to cease",30,38],["H2184","from thee, and thy whoredom",39,66],["H0776","brought from the land",67,88],["H4714","of Egypt",89,97],["H5375","so that thou shalt not lift up",99,129],["H5869","thine eyes",130,140],["H2142","unto them, nor remember",141,164],["H4714","Egypt",165,170]]},"23:28":{"text":"For thus saith the Lord GOD; Behold, I will deliver thee into the hand of them whom thou hatest, into the hand of them from whom thy mind is alienated:","words":[["H0559","For thus saith",0,14],["H0136","the Lord",15,23],["H3069","GOD",24,27],["H5414","Behold, I will deliver",29,51],["H3027","thee into the hand",52,70],["H8130","of them whom thou hatest",71,95],["H3027","into the hand",97,110],["H5315","of them from whom thy mind",111,137],["H5361","is alienated",138,150]]},"23:29":{"text":"And they shall deal with thee hatefully, and shall take away all thy labour, and shall leave thee naked and bare: and the nakedness of thy whoredoms shall be discovered, both thy lewdness and thy whoredoms.","words":[["H6213","And they shall deal",0,19],["H8135","with thee hatefully",20,39],["H3947","and shall take away",41,60],["H3018","all thy labour",61,75],["H5800","and shall leave",77,92],["H5903","thee naked",93,103],["H6181","and bare",104,112],["H6172","and the nakedness",114,131],["H2183","of thy whoredoms",132,148],["H1540","shall be discovered",149,168],["H2154","both thy lewdness",170,187],["H8457","and thy whoredoms",188,205]]},"23:30":{"text":"I will do these things unto thee, because thou hast gone a whoring after the heathen, and because thou art polluted with their idols.","words":[["H6213","I will do",0,9],["H2181","these things unto thee, because thou hast gone a whoring",10,66],["H0310","after",67,72],["H1471","the heathen",73,84],["H2930","and because thou art polluted",86,115],["H1544","with their idols",116,132]]},"23:31":{"text":"Thou hast walked in the way of thy sister; therefore will I give her cup into thine hand.","words":[["H1980","Thou hast walked",0,16],["H1870","in the way",17,27],["H0269","of thy sister",28,41],["H5414","therefore will I give",43,64],["H3563","her cup",65,72],["H3027","into thine hand",73,88]]},"23:32":{"text":"Thus saith the Lord GOD; Thou shalt drink of thy sister's cup deep and large: thou shalt be laughed to scorn and had in derision; it containeth much.","words":[["H0559","Thus saith",0,10],["H0136","the Lord",11,19],["H3069","GOD",20,23],["H8354","Thou shalt drink",25,41],["H0269","of thy sister's",42,57],["H3563","cup",58,61],["H6013","deep",62,66],["H7342","and large",67,76],["H6712","thou shalt be laughed to scorn",78,108],["H3933","and had in derision",109,128],["H3557","it containeth",130,143],["H4767","much",144,148]]},"23:33":{"text":"Thou shalt be filled with drunkenness and sorrow, with the cup of astonishment and desolation, with the cup of thy sister Samaria.","words":[["H4390","Thou shalt be filled",0,20],["H7943","with drunkenness",21,37],["H3015","and sorrow",38,48],["H3563","with the cup",50,62],["H8047","of astonishment",63,78],["H8077","and desolation",79,93],["H3563","with the cup",95,107],["H0269","of thy sister",108,121],["H8111","Samaria",122,129]]},"23:34":{"text":"Thou shalt even drink it and suck it out, and thou shalt break the sherds thereof, and pluck off thine own breasts: for I have spoken it, saith the Lord GOD.","words":[["H8354","Thou shalt even drink",0,21],["H4680","it and suck it out",22,40],["H1633","and thou shalt break",42,62],["H2789","the sherds",63,73],["H5423","thereof, and pluck off",74,96],["H7699","thine own breasts",97,114],["H1696","for I have spoken",116,133],["H5002","it, saith",134,143],["H0136","the Lord",144,152],["H3069","GOD",153,156]]},"23:35":{"text":"Therefore thus saith the Lord GOD; Because thou hast forgotten me, and cast me behind thy back, therefore bear thou also thy lewdness and thy whoredoms.","words":[["H0559","Therefore thus saith",0,20],["H0136","the Lord",21,29],["H3069","GOD",30,33],["H7911","Because thou hast forgotten",35,62],["H7993","me, and cast",63,75],["H0310","me behind",76,85],["H1458","thy back",86,94],["H5375","therefore bear",96,110],["H2154","thou also thy lewdness",111,133],["H8457","and thy whoredoms",134,151]]},"23:36":{"text":"The LORD said moreover unto me; Son of man, wilt thou judge Aholah and Aholibah? yea, declare unto them their abominations;","words":[["H3068","The LORD",0,8],["H0559","said",9,13],["H1121","moreover unto me; Son",14,35],["H0120","of man",36,42],["H8199","wilt thou judge",44,59],["H0170","Aholah",60,66],["H0172","and Aholibah",67,79],["H5046","yea, declare",81,93],["H8441","unto them their abominations",94,122]]},"23:37":{"text":"That they have committed adultery, and blood is in their hands, and with their idols have they committed adultery, and have also caused their sons, whom they bare unto me, to pass for them through the fire, to devour them.","words":[["H5003","That they have committed adultery",0,33],["H1818","and blood",35,44],["H3027","is in their hands",45,62],["H1544","and with their idols",64,84],["H5003","have they committed adultery",85,113],["H1121","and have also caused their sons",115,146],["H3205","whom they bare",148,162],["H5674","unto me, to pass for them through",163,196],["H0402","the fire, to devour",197,216]]},"23:38":{"text":"Moreover this they have done unto me: they have defiled my sanctuary in the same day, and have profaned my sabbaths.","words":[["H6213","Moreover this they have done",0,28],["H2930","unto me: they have defiled",29,55],["H4720","my sanctuary",56,68],["H3117","in the same day",69,84],["H2490","and have profaned",86,103],["H7676","my sabbaths",104,115]]},"23:39":{"text":"For when they had slain their children to their idols, then they came the same day into my sanctuary to profane it; and, lo, thus have they done in the midst of mine house.","words":[["H7819","For when they had slain",0,23],["H1121","their children",24,38],["H1544","to their idols",39,53],["H0935","then they came",55,69],["H3117","the same day",70,82],["H4720","into my sanctuary",83,100],["H2490","to profane",101,111],["H6213","it; and, lo, thus have they done",112,144],["H8432","in the midst",145,157],["H1004","of mine house",158,171]]},"23:40":{"text":"And furthermore, that ye have sent for men to come from far, unto whom a messenger was sent; and, lo, they came: for whom thou didst wash thyself, paintedst thy eyes, and deckedst thyself with ornaments,","words":[["H0637","And furthermore",0,15],["H7971","that ye have sent",17,34],["H0582","for men",35,42],["H0935","to come",43,50],["H4801","from far",51,59],["H4397","unto whom a messenger",61,82],["H7971","was sent",83,91],["H0935","and, lo, they came",93,111],["H7364","for whom thou didst wash",113,137],["H3583","thyself, paintedst",138,156],["H5869","thy eyes",157,165],["H5710","and deckedst",167,179],["H5716","thyself with ornaments",180,202]]},"23:41":{"text":"And satest upon a stately bed, and a table prepared before it, whereupon thou hast set mine incense and mine oil.","words":[["H3427","And satest",0,10],["H3520","upon a stately",11,25],["H4296","bed",26,29],["H7979","and a table",31,42],["H6186","prepared",43,51],["H6440","before",52,58],["H7760","it, whereupon thou hast set",59,86],["H7004","mine incense",87,99],["H8081","and mine oil",100,112]]},"23:42":{"text":"And a voice of a multitude being at ease was with her: and with the men of the common sort were brought Sabeans from the wilderness, which put bracelets upon their hands, and beautiful crowns upon their heads.","words":[["H6963","And a voice",0,11],["H1995","of a multitude",12,26],["H7961","being at ease",27,40],["H0582","was with her: and with the men",41,71],["H7230","of the common sort",72,90],["H0120","of the common sort",72,90],["H0935","were brought",91,103],["H5436","Sabeans",104,111],["H5433","Sabeans",104,111],["H4057","from the wilderness",112,131],["H5414","which put",133,142],["H6781","bracelets",143,152],["H3027","upon their hands",153,169],["H8597","and beautiful",171,184],["H5850","crowns",185,191],["H7218","upon their heads",192,208]]},"23:43":{"text":"Then said I unto her that was old in adulteries, Will they now commit whoredoms with her, and she with them?","words":[["H0559","Then said",0,9],["H1087","I unto her that was old",10,33],["H5004","in adulteries",34,47],["H2181","Will they now commit",49,69],["H8457","whoredoms",70,79]]},"23:44":{"text":"Yet they went in unto her, as they go in unto a woman that playeth the harlot: so went they in unto Aholah and unto Aholibah, the lewd women.","words":[["H0935","Yet they went in",0,16],["H0935","unto her, as they go in",17,40],["H0802","unto a woman",41,53],["H2181","that playeth the harlot",54,77],["H0935","so went they in",79,94],["H0170","unto Aholah",95,106],["H0172","and unto Aholibah",107,124],["H2154","the lewd",126,134],["H0802","women",135,140]]},"23:45":{"text":"And the righteous men, they shall judge them after the manner of adulteresses, and after the manner of women that shed blood; because they are adulteresses, and blood is in their hands.","words":[["H6662","And the righteous",0,17],["H0582","men",18,21],["H8199","they shall judge",23,39],["H4941","them after the manner",40,61],["H5003","of adulteresses",62,77],["H4941","and after the manner",79,99],["H8210","of women that shed",100,118],["H1818","blood",119,124],["H5003","because they are adulteresses",126,155],["H1818","and blood",157,166],["H3027","is in their hands",167,184]]},"23:46":{"text":"For thus saith the Lord GOD; I will bring up a company upon them, and will give them to be removed and spoiled.","words":[["H0559","For thus saith",0,14],["H0136","the Lord",15,23],["H3069","GOD",24,27],["H5927","I will bring up",29,44],["H6951","a company",45,54],["H5414","upon them, and will give",55,79],["H2189","them to be removed",80,98],["H0957","and spoiled",99,110]]},"23:47":{"text":"And the company shall stone them with stones, and dispatch them with their swords; they shall slay their sons and their daughters, and burn up their houses with fire.","words":[["H6951","And the company",0,15],["H7275","shall stone",16,27],["H0068","them with stones",28,44],["H1254","and dispatch",46,58],["H2719","them with their swords",59,81],["H2026","they shall slay",83,98],["H1121","their sons",99,109],["H1323","and their daughters",110,129],["H8313","and burn up",131,142],["H1004","their houses",143,155],["H0784","with fire",156,165]]},"23:48":{"text":"Thus will I cause lewdness to cease out of the land, that all women may be taught not to do after your lewdness.","words":[["H2154","Thus will I cause lewdness",0,26],["H7673","to cease",27,35],["H0776","out of the land",36,51],["H0802","that all women",53,67],["H3256","may be taught",68,81],["H6213","not to do",82,91],["H2154","after your lewdness",92,111]]},"23:49":{"text":"And they shall recompense your lewdness upon you, and ye shall bear the sins of your idols: and ye shall know that I am the Lord GOD.","words":[["H5414","And they shall recompense",0,25],["H2154","your lewdness",26,39],["H5375","upon you, and ye shall bear",40,67],["H2399","the sins",68,76],["H1544","of your idols",77,90],["H3045","and ye shall know",92,109],["H0136","that I am the Lord",110,128],["H3069","GOD",129,132]]},"24:1":{"text":"Again in the ninth year, in the tenth month, in the tenth day of the month, the word of the LORD came unto me, saying,","words":[["H8671","Again in the ninth",0,18],["H8141","year",19,23],["H6224","in the tenth",25,37],["H2320","month",38,43],["H6218","in the tenth",45,57],["H2320","day of the month",58,74],["H1697","the word",76,84],["H3068","of the LORD",85,96],["H0559","came unto me, saying",97,117]]},"24:2":{"text":"Son of man, write thee the name of the day, even of this same day: the king of Babylon set himself against Jerusalem this same day.","words":[["H1121","Son",0,3],["H0120","of man",4,10],["H3789","write",12,17],["H8034","thee the name",18,31],["H3117","of the day",32,42],["H6106","even of this same",44,61],["H3117","day",62,65],["H4428","the king",67,75],["H0894","of Babylon",76,86],["H5564","set",87,90],["H3389","himself against Jerusalem",91,116],["H6106","this same",117,126],["H3117","day",127,130]]},"24:3":{"text":"And utter a parable unto the rebellious house, and say unto them, Thus saith the Lord GOD; Set on a pot, set it on, and also pour water into it:","words":[["H4911","And utter",0,9],["H4912","a parable",10,19],["H4805","unto the rebellious",20,39],["H1004","house",40,45],["H0559","and say",47,54],["H0559","unto them, Thus saith",55,76],["H0136","the Lord",77,85],["H3069","GOD",86,89],["H8239","Set on",91,97],["H5518","a pot",98,103],["H8239","set it on",105,114],["H3332","and also pour",116,129],["H4325","water",130,135]]},"24:4":{"text":"Gather the pieces thereof into it, even every good piece, the thigh, and the shoulder; fill it with the choice bones.","words":[["H0622","Gather",0,6],["H5409","the pieces",7,17],["H2896","thereof into it, even every good",18,50],["H5409","piece",51,56],["H3409","the thigh",58,67],["H3802","and the shoulder",69,85],["H4390","fill",87,91],["H4005","it with the choice",92,110],["H6106","bones",111,116]]},"24:5":{"text":"Take the choice of the flock, and burn also the bones under it, and make it boil well, and let them seethe the bones of it therein.","words":[["H3947","Take",0,4],["H4005","the choice",5,15],["H6629","of the flock",16,28],["H1754","and burn",30,38],["H6106","also the bones",39,53],["H7570","under it, and make it boil",54,80],["H7571","well",81,85],["H1310","and let them seethe",87,106],["H6106","the bones",107,116],["H8432","of it therein",117,130]]},"24:6":{"text":"Wherefore thus saith the Lord GOD; Woe to the bloody city, to the pot whose scum is therein, and whose scum is not gone out of it! bring it out piece by piece; let no lot fall upon it.","words":[["H0559","Wherefore thus saith",0,20],["H0136","the Lord",21,29],["H3069","GOD",30,33],["H0188","Woe",35,38],["H1818","to the bloody",39,52],["H5892","city",53,57],["H5518","to the pot",59,69],["H2457","whose scum",70,80],["H2457","is therein, and whose scum",81,107],["H3318","is not gone out",108,123],["H3318","of it! bring it out",124,143],["H5409","piece",144,149],["H5409","by piece",150,158],["H1486","let no lot",160,170],["H5307","fall",171,175]]},"24:7":{"text":"For her blood is in the midst of her; she set it upon the top of a rock; she poured it not upon the ground, to cover it with dust;","words":[["H1818","For her blood",0,13],["H8432","is in the midst",14,29],["H7760","of her; she set",30,45],["H6706","it upon the top",46,61],["H5553","of a rock",62,71],["H8210","she poured",73,83],["H0776","it not upon the ground",84,106],["H3680","to cover",108,116],["H6083","it with dust",117,129]]},"24:8":{"text":"That it might cause fury to come up to take vengeance; I have set her blood upon the top of a rock, that it should not be covered.","words":[["H2534","That it might cause fury",0,24],["H5927","to come up",25,35],["H5358","to take",36,43],["H5359","vengeance",44,53],["H5414","I have set",55,65],["H1818","her blood",66,75],["H6706","upon the top",76,88],["H5553","of a rock",89,98],["H3680","that it should not be covered",100,129]]},"24:9":{"text":"Therefore thus saith the Lord GOD; Woe to the bloody city! I will even make the pile for fire great.","words":[["H0559","Therefore thus saith",0,20],["H0136","the Lord",21,29],["H3069","GOD",30,33],["H0188","Woe",35,38],["H1818","to the bloody",39,52],["H5892","city",53,57],["H4071","I will even make the pile",59,84],["H1431","for fire great",85,99]]},"24:10":{"text":"Heap on wood, kindle the fire, consume the flesh, and spice it well, and let the bones be burned.","words":[["H7235","Heap",0,4],["H6086","on wood",5,12],["H1814","kindle",14,20],["H0784","the fire",21,29],["H8552","consume",31,38],["H1320","the flesh",39,48],["H7543","and spice",50,59],["H4841","it well",60,67],["H6106","and let the bones",69,86],["H2787","be burned",87,96]]},"24:11":{"text":"Then set it empty upon the coals thereof, that the brass of it may be hot, and may burn, and that the filthiness of it may be molten in it, that the scum of it may be consumed.","words":[["H5975","Then set",0,8],["H7386","it empty",9,17],["H1513","upon the coals",18,32],["H5178","thereof, that the brass",33,56],["H3179","of it may be hot",57,73],["H2787","and may burn",75,87],["H2932","and that the filthiness",89,112],["H5413","of it may be molten",113,132],["H8432","in it",133,138],["H2457","that the scum",140,153],["H8552","of it may be consumed",154,175]]},"24:12":{"text":"She hath wearied herself with lies, and her great scum went not forth out of her: her scum shall be in the fire.","words":[["H3811","She hath wearied",0,16],["H8383","herself with lies",17,34],["H7227","and her great",36,49],["H2457","scum",50,54],["H3318","went not forth",55,69],["H2457","out of her: her scum",70,90],["H0784","shall be in the fire",91,111]]},"24:13":{"text":"In thy filthiness is lewdness: because I have purged thee, and thou wast not purged, thou shalt not be purged from thy filthiness any more, till I have caused my fury to rest upon thee.","words":[["H2932","In thy filthiness",0,17],["H2154","is lewdness",18,29],["H2891","because I have purged",31,52],["H2891","thee, and thou wast not purged",53,83],["H2891","thou shalt not be purged",85,109],["H2932","from thy filthiness",110,129],["H2534","any more, till I have caused my fury",130,166],["H5117","to rest",167,174]]},"24:14":{"text":"I the LORD have spoken it: it shall come to pass, and I will do it; I will not go back, neither will I spare, neither will I repent; according to thy ways, and according to thy doings, shall they judge thee, saith the Lord GOD.","words":[["H3068","I the LORD",0,10],["H1696","have spoken",11,22],["H0935","it: it shall come to pass",23,48],["H6213","and I will do",50,63],["H6544","it; I will not go back",64,86],["H2347","neither will I spare",88,108],["H5162","neither will I repent",110,131],["H1870","according to thy ways",133,154],["H5949","and according to thy doings",156,183],["H8199","shall they judge",185,201],["H5002","thee, saith",202,213],["H0136","the Lord",214,222],["H3069","GOD",223,226]]},"24:15":{"text":"Also the word of the LORD came unto me, saying,","words":[["H1697","Also the word",0,13],["H3068","of the LORD",14,25],["H0559","came unto me, saying",26,46]]},"24:16":{"text":"Son of man, behold, I take away from thee the desire of thine eyes with a stroke: yet neither shalt thou mourn nor weep, neither shall thy tears run down.","words":[["H1121","Son",0,3],["H0120","of man",4,10],["H3947","behold, I take away",12,31],["H4261","from thee the desire",32,52],["H5869","of thine eyes",53,66],["H4046","with a stroke",67,80],["H5594","yet neither shalt thou mourn",82,110],["H1058","nor weep",111,119],["H1832","neither shall thy tears",121,144],["H0935","run down",145,153]]},"24:17":{"text":"Forbear to cry, make no mourning for the dead, bind the tire of thine head upon thee, and put on thy shoes upon thy feet, and cover not thy lips, and eat not the bread of men.","words":[["H1826","Forbear",0,7],["H0602","to cry",8,14],["H6213","make",16,20],["H0060","no mourning",21,32],["H4191","for the dead",33,45],["H2280","bind",47,51],["H6287","the tire of thine head",52,74],["H7760","upon thee, and put on",75,96],["H5275","thy shoes",97,106],["H7272","upon thy feet",107,120],["H5844","and cover",122,131],["H8222","not thy lips",132,144],["H0398","and eat",146,153],["H3899","not the bread",154,167],["H0582","of men",168,174]]},"24:18":{"text":"So I spake unto the people in the morning: and at even my wife died; and I did in the morning as I was commanded.","words":[["H1696","So I spake",0,10],["H5971","unto the people",11,26],["H1242","in the morning",27,41],["H6153","and at even",43,54],["H0802","my wife",55,62],["H4191","died",63,67],["H6213","and I did",69,78],["H1242","in the morning",79,93],["H6680","as I was commanded",94,112]]},"24:19":{"text":"And the people said unto me, Wilt thou not tell us what these things are to us, that thou doest so?","words":[["H5971","And the people",0,14],["H0559","said",15,19],["H5046","unto me, Wilt thou not tell",20,47],["H6213","us what these things are to us, that thou doest",48,95]]},"24:20":{"text":"Then I answered them, The word of the LORD came unto me, saying,","words":[["H0559","Then I answered",0,15],["H1697","them, The word",16,30],["H3068","of the LORD",31,42],["H0559","came unto me, saying",43,63]]},"24:21":{"text":"Speak unto the house of Israel, Thus saith the Lord GOD; Behold, I will profane my sanctuary, the excellency of your strength, the desire of your eyes, and that which your soul pitieth; and your sons and your daughters whom ye have left shall fall by the sword.","words":[["H0559","Speak",0,5],["H1004","unto the house",6,20],["H3478","of Israel",21,30],["H0559","Thus saith",32,42],["H0136","the Lord",43,51],["H3069","GOD",52,55],["H2490","Behold, I will profane",57,79],["H4720","my sanctuary",80,92],["H1347","the excellency",94,108],["H5797","of your strength",109,125],["H4261","the desire",127,137],["H5869","of your eyes",138,150],["H5315","and that which your soul",152,176],["H4263","pitieth",177,184],["H1121","and your sons",186,199],["H1323","and your daughters",200,218],["H5800","whom ye have left",219,236],["H5307","shall fall",237,247],["H2719","by the sword",248,260]]},"24:22":{"text":"And ye shall do as I have done: ye shall not cover your lips, nor eat the bread of men.","words":[["H6213","And ye shall do",0,15],["H6213","as I have done",16,30],["H5844","ye shall not cover",32,50],["H8222","your lips",51,60],["H0398","nor eat",62,69],["H3899","the bread",70,79],["H0582","of men",80,86]]},"24:23":{"text":"And your tires shall be upon your heads, and your shoes upon your feet: ye shall not mourn nor weep; but ye shall pine away for your iniquities, and mourn one toward another.","words":[["H6287","And your tires",0,14],["H7218","shall be upon your heads",15,39],["H5275","and your shoes",41,55],["H7272","upon your feet",56,70],["H5594","ye shall not mourn",72,90],["H1058","nor weep",91,99],["H4743","but ye shall pine away",101,123],["H5771","for your iniquities",124,143],["H5098","and mourn",145,154],["H0376","one",155,158],["H0251","toward another",159,173]]},"24:24":{"text":"Thus Ezekiel is unto you a sign: according to all that he hath done shall ye do: and when this cometh, ye shall know that I am the Lord GOD.","words":[["H3168","Thus Ezekiel",0,12],["H4159","is unto you a sign",13,31],["H6213","according to all that he hath done",33,67],["H6213","shall ye do",68,79],["H0935","and when this cometh",81,101],["H3045","ye shall know",103,116],["H0136","that I am the Lord",117,135],["H3069","GOD",136,139]]},"24:25":{"text":"Also, thou son of man, shall it not be in the day when I take from them their strength, the joy of their glory, the desire of their eyes, and that whereupon they set their minds, their sons and their daughters,","words":[["H1121","Also, thou son",0,14],["H0120","of man",15,21],["H3117","shall it not be in the day",23,49],["H3947","when I take",50,61],["H4581","from them their strength",62,86],["H4885","the joy",88,95],["H8597","of their glory",96,110],["H4261","the desire",112,122],["H5869","of their eyes",123,136],["H4853","and that whereupon they set",138,165],["H5315","their minds",166,177],["H1121","their sons",179,189],["H1323","and their daughters",190,209]]},"24:26":{"text":"That he that escapeth in that day shall come unto thee, to cause thee to hear it with thine ears?","words":[["H6412","That he that escapeth",0,21],["H3117","in that day",22,33],["H0935","shall come",34,44],["H2045","unto thee, to cause thee to hear",45,77],["H0241","it with thine ears",78,96]]},"24:27":{"text":"In that day shall thy mouth be opened to him which is escaped, and thou shalt speak, and be no more dumb: and thou shalt be a sign unto them; and they shall know that I am the LORD.","words":[["H3117","In that day",0,11],["H6310","shall thy mouth",12,27],["H6605","be opened",28,37],["H6412","to him which is escaped",38,61],["H1696","and thou shalt speak",63,83],["H0481","and be no more dumb",85,104],["H4159","and thou shalt be a sign",106,130],["H3045","unto them; and they shall know",131,161],["H3068","that I am the LORD",162,180]]},"25:1":{"text":"The word of the LORD came again unto me, saying,","words":[["H1697","The word",0,8],["H3068","of the LORD",9,20],["H0559","came again unto me, saying",21,47]]},"25:2":{"text":"Son of man, set thy face against the Ammonites, and prophesy against them;","words":[["H1121","Son",0,3],["H0120","of man",4,10],["H7760","set",12,15],["H6440","thy face",16,24],["H1121","against the Ammonites",25,46],["H5983","against the Ammonites",25,46],["H5012","and prophesy",48,60]]},"25:3":{"text":"And say unto the Ammonites, Hear the word of the Lord GOD; Thus saith the Lord GOD; Because thou saidst, Aha, against my sanctuary, when it was profaned; and against the land of Israel, when it was desolate; and against the house of Judah, when they went into captivity;","words":[["H0559","And say",0,7],["H1121","unto the Ammonites",8,26],["H5983","unto the Ammonites",8,26],["H8085","Hear",28,32],["H1697","the word",33,41],["H0136","of the Lord",42,53],["H3069","GOD",54,57],["H0559","Thus saith",59,69],["H0136","the Lord",70,78],["H3069","GOD",79,82],["H0559","Because thou saidst",84,103],["H1889","Aha",105,108],["H4720","against my sanctuary",110,130],["H2490","when it was profaned",132,152],["H0127","and against the land",154,174],["H3478","of Israel",175,184],["H8074","when it was desolate",186,206],["H1004","and against the house",208,229],["H3063","of Judah",230,238],["H1980","when they went",240,254],["H1473","into captivity",255,269]]},"25:4":{"text":"Behold, therefore I will deliver thee to the men of the east for a possession, and they shall set their palaces in thee, and make their dwellings in thee: they shall eat thy fruit, and they shall drink thy milk.","words":[["H5414","Behold, therefore I will deliver",0,32],["H1121","thee to the men",33,48],["H6924","of the east",49,60],["H4181","for a possession",61,77],["H3427","and they shall set",79,97],["H2918","their palaces",98,111],["H5414","in thee, and make",112,129],["H4908","their dwellings",130,145],["H0398","in thee: they shall eat",146,169],["H6529","thy fruit",170,179],["H8354","and they shall drink",181,201],["H2461","thy milk",202,210]]},"25:5":{"text":"And I will make Rabbah a stable for camels, and the Ammonites a couchingplace for flocks: and ye shall know that I am the LORD.","words":[["H5414","And I will make",0,15],["H7237","Rabbah",16,22],["H5116","a stable",23,31],["H1581","for camels",32,42],["H1121","and the Ammonites",44,61],["H5983","and the Ammonites",44,61],["H4769","a couchingplace",62,77],["H6629","for flocks",78,88],["H3045","and ye shall know",90,107],["H3068","that I am the LORD",108,126]]},"25:6":{"text":"For thus saith the Lord GOD; Because thou hast clapped thine hands, and stamped with the feet, and rejoiced in heart with all thy despite against the land of Israel;","words":[["H0559","For thus saith",0,14],["H0136","the Lord",15,23],["H3069","GOD",24,27],["H4222","Because thou hast clapped",29,54],["H3027","thine hands",55,66],["H7554","and stamped",68,79],["H7272","with the feet",80,93],["H8055","and rejoiced",95,107],["H5315","in heart",108,116],["H7589","with all thy despite",117,137],["H0127","against the land",138,154],["H3478","of Israel",155,164]]},"25:7":{"text":"Behold, therefore I will stretch out mine hand upon thee, and will deliver thee for a spoil to the heathen; and I will cut thee off from the people, and I will cause thee to perish out of the countries: I will destroy thee; and thou shalt know that I am the LORD.","words":[["H5186","Behold, therefore I will stretch out",0,36],["H3027","mine hand",37,46],["H5414","upon thee, and will deliver",47,74],["H0957","thee for a spoil",75,91],["H0897","thee for a spoil",75,91],["H1471","to the heathen",92,106],["H3772","and I will cut thee off",108,131],["H5971","from the people",132,147],["H0006","and I will cause thee to perish",149,180],["H0776","out of the countries",181,201],["H8045","I will destroy",203,217],["H3045","thee; and thou shalt know",218,243],["H3068","that I am the LORD",244,262]]},"25:8":{"text":"Thus saith the Lord GOD; Because that Moab and Seir do say, Behold, the house of Judah is like unto all the heathen;","words":[["H0559","Thus saith",0,10],["H0136","the Lord",11,19],["H3069","GOD",20,23],["H3282","Because",25,32],["H4124","that Moab",33,42],["H8165","and Seir",43,51],["H0559","do say",52,58],["H1004","Behold, the house",60,77],["H3063","of Judah",78,86],["H1471","is like unto all the heathen",87,115]]},"25:9":{"text":"Therefore, behold, I will open the side of Moab from the cities, from his cities which are on his frontiers, the glory of the country, Bethjeshimoth, Baalmeon, and Kiriathaim,","words":[["H6605","Therefore, behold, I will open",0,30],["H3802","the side",31,39],["H4124","of Moab",40,47],["H5892","from the cities",48,63],["H5892","from his cities",65,80],["H7097","which are on his frontiers",81,107],["H6643","the glory",109,118],["H0776","of the country",119,133],["H1020","Bethjeshimoth",135,148],["H1186","Baalmeon",150,158],["H7156","and Kiriathaim",160,174]]},"25:10":{"text":"Unto the men of the east with the Ammonites, and will give them in possession, that the Ammonites may not be remembered among the nations.","words":[["H1121","Unto the men",0,12],["H6924","of the east",13,24],["H1121","with the Ammonites",25,43],["H5983","with the Ammonites",25,43],["H5414","and will give",45,58],["H4181","them in possession",59,77],["H1121","that the Ammonites",79,97],["H5983","that the Ammonites",79,97],["H2142","may not be remembered",98,119],["H1471","among the nations",120,137]]},"25:11":{"text":"And I will execute judgments upon Moab; and they shall know that I am the LORD.","words":[["H6213","And I will execute",0,18],["H8201","judgments",19,28],["H4124","upon Moab",29,38],["H3045","and they shall know",40,59],["H3068","that I am the LORD",60,78]]},"25:12":{"text":"Thus saith the Lord GOD; Because that Edom hath dealt against the house of Judah by taking vengeance, and hath greatly offended, and revenged himself upon them;","words":[["H0559","Thus saith",0,10],["H0136","the Lord",11,19],["H3069","GOD",20,23],["H0123","Because that Edom",25,42],["H6213","hath dealt",43,53],["H1004","against the house",54,71],["H3063","of Judah",72,80],["H5358","by taking",81,90],["H5359","vengeance",91,100],["H0816","and hath greatly",102,118],["H0816","offended",119,127],["H5358","and revenged",129,141]]},"25:13":{"text":"Therefore thus saith the Lord GOD; I will also stretch out mine hand upon Edom, and will cut off man and beast from it; and I will make it desolate from Teman; and they of Dedan shall fall by the sword.","words":[["H0559","Therefore thus saith",0,20],["H0136","the Lord",21,29],["H3069","GOD",30,33],["H5186","I will also stretch out",35,58],["H3027","mine hand",59,68],["H0123","upon Edom",69,78],["H3772","and will cut off",80,96],["H0120","man",97,100],["H0929","and beast",101,110],["H5414","from it; and I will make",111,135],["H2723","it desolate",136,147],["H8487","from Teman",148,158],["H1719","and they of Dedan",160,177],["H5307","shall fall",178,188],["H2719","by the sword",189,201]]},"25:14":{"text":"And I will lay my vengeance upon Edom by the hand of my people Israel: and they shall do in Edom according to mine anger and according to my fury; and they shall know my vengeance, saith the Lord GOD.","words":[["H5414","And I will lay",0,14],["H5360","my vengeance",15,27],["H0123","upon Edom",28,37],["H3027","by the hand",38,49],["H5971","of my people",50,62],["H3478","Israel",63,69],["H6213","and they shall do",71,88],["H0123","in Edom",89,96],["H0639","according to mine anger",97,120],["H2534","and according to my fury",121,145],["H3045","and they shall know",147,166],["H5360","my vengeance",167,179],["H5002","saith",181,186],["H0136","the Lord",187,195],["H3069","GOD",196,199]]},"25:15":{"text":"Thus saith the Lord GOD; Because the Philistines have dealt by revenge, and have taken vengeance with a despiteful heart, to destroy it for the old hatred;","words":[["H0559","Thus saith",0,10],["H0136","the Lord",11,19],["H3069","GOD",20,23],["H6430","Because the Philistines",25,48],["H6213","have dealt",49,59],["H5360","by revenge",60,70],["H5358","and have taken",72,86],["H5359","vengeance",87,96],["H7589","with a despiteful",97,114],["H5315","heart",115,120],["H4889","to destroy",122,132],["H5769","it for the old",133,147],["H0342","hatred",148,154]]},"25:16":{"text":"Therefore thus saith the Lord GOD; Behold, I will stretch out mine hand upon the Philistines, and I will cut off the Cherethims, and destroy the remnant of the sea coast.","words":[["H0559","Therefore thus saith",0,20],["H0136","the Lord",21,29],["H3069","GOD",30,33],["H5186","Behold, I will stretch out",35,61],["H3027","mine hand",62,71],["H6430","upon the Philistines",72,92],["H3772","and I will cut off",94,112],["H3774","the Cherethims",113,127],["H0006","and destroy",129,140],["H7611","the remnant",141,152],["H3220","of the sea",153,163],["H2348","coast",164,169]]},"25:17":{"text":"And I will execute great vengeance upon them with furious rebukes; and they shall know that I am the LORD, when I shall lay my vengeance upon them.","words":[["H6213","And I will execute",0,18],["H1419","great",19,24],["H5360","vengeance",25,34],["H2534","upon them with furious",35,57],["H8433","rebukes",58,65],["H3045","and they shall know",67,86],["H3068","that I am the LORD",87,105],["H5414","when I shall lay",107,123],["H5360","my vengeance",124,136]]},"26:1":{"text":"And it came to pass in the eleventh year, in the first day of the month, that the word of the LORD came unto me, saying,","words":[["H6249","And it came to pass in the eleventh",0,35],["H6240","And it came to pass in the eleventh",0,35],["H8141","year",36,40],["H0259","in the first",42,54],["H2320","day of the month",55,71],["H1697","that the word",73,86],["H3068","of the LORD",87,98],["H0559","came unto me, saying",99,119]]},"26:2":{"text":"Son of man, because that Tyrus hath said against Jerusalem, Aha, she is broken that was the gates of the people: she is turned unto me: I shall be replenished, now she is laid waste:","words":[["H1121","Son",0,3],["H0120","of man",4,10],["H6865","because that Tyrus",12,30],["H0559","hath said",31,40],["H3389","against Jerusalem",41,58],["H1889","Aha",60,63],["H7665","she is broken",65,78],["H1817","that was the gates",79,97],["H5971","of the people",98,111],["H5437","she is turned",113,126],["H4390","unto me: I shall be replenished",127,158],["H2717","now she is laid waste",160,181]]},"26:3":{"text":"Therefore thus saith the Lord GOD; Behold, I am against thee, O Tyrus, and will cause many nations to come up against thee, as the sea causeth his waves to come up.","words":[["H0559","Therefore thus saith",0,20],["H0136","the Lord",21,29],["H3069","GOD",30,33],["H6865","Behold, I am against thee, O Tyrus",35,69],["H7227","and will cause many",71,90],["H1471","nations",91,98],["H5927","to come up",99,109],["H3220","against thee, as the sea",110,134],["H1530","causeth his waves",135,152],["H5927","to come up",153,163]]},"26:4":{"text":"And they shall destroy the walls of Tyrus, and break down her towers: I will also scrape her dust from her, and make her like the top of a rock.","words":[["H7843","And they shall destroy",0,22],["H2346","the walls",23,32],["H6865","of Tyrus",33,41],["H2040","and break down",43,57],["H4026","her towers",58,68],["H5500","I will also scrape",70,88],["H6083","her dust",89,97],["H5414","from her, and make",98,116],["H6706","her like the top",117,133],["H5553","of a rock",134,143]]},"26:5":{"text":"It shall be a place for the spreading of nets in the midst of the sea: for I have spoken it, saith the Lord GOD: and it shall become a spoil to the nations.","words":[["H4894","It shall be a place for the spreading",0,37],["H2764","of nets",38,45],["H8432","in the midst",46,58],["H3220","of the sea",59,69],["H1696","for I have spoken",71,88],["H5002","it, saith",89,98],["H0136","the Lord",99,107],["H3069","GOD",108,111],["H0957","and it shall become a spoil",113,140],["H1471","to the nations",141,155]]},"26:6":{"text":"And her daughters which are in the field shall be slain by the sword; and they shall know that I am the LORD.","words":[["H1323","And her daughters",0,17],["H7704","which are in the field",18,40],["H2026","shall be slain",41,55],["H2719","by the sword",56,68],["H3045","and they shall know",70,89],["H3068","that I am the LORD",90,108]]},"26:7":{"text":"For thus saith the Lord GOD; Behold, I will bring upon Tyrus Nebuchadrezzar king of Babylon, a king of kings, from the north, with horses, and with chariots, and with horsemen, and companies, and much people.","words":[["H0559","For thus saith",0,14],["H0136","the Lord",15,23],["H3069","GOD",24,27],["H0935","Behold, I will bring",29,49],["H6865","upon Tyrus",50,60],["H5019","Nebuchadrezzar",61,75],["H4428","king",76,80],["H0894","of Babylon",81,91],["H4428","a king",93,99],["H4428","of kings",100,108],["H6828","from the north",110,124],["H5483","with horses",126,137],["H7393","and with chariots",139,156],["H6571","and with horsemen",158,175],["H6951","and companies",177,190],["H7227","and much",192,200],["H5971","people",201,207]]},"26:8":{"text":"He shall slay with the sword thy daughters in the field: and he shall make a fort against thee, and cast a mount against thee, and lift up the buckler against thee.","words":[["H2026","He shall slay",0,13],["H2719","with the sword",14,28],["H1323","thy daughters",29,42],["H7704","in the field",43,55],["H5414","and he shall make",57,74],["H1785","a fort",75,81],["H8210","against thee, and cast",82,104],["H5550","a mount",105,112],["H6965","against thee, and lift up",113,138],["H6793","the buckler",139,150]]},"26:9":{"text":"And he shall set engines of war against thy walls, and with his axes he shall break down thy towers.","words":[["H5414","And he shall set",0,16],["H4239","engines",17,24],["H6904","of war",25,31],["H2346","against thy walls",32,49],["H2719","and with his axes",51,68],["H5422","he shall break down",69,88],["H4026","thy towers",89,99]]},"26:10":{"text":"By reason of the abundance of his horses their dust shall cover thee: thy walls shall shake at the noise of the horsemen, and of the wheels, and of the chariots, when he shall enter into thy gates, as men enter into a city wherein is made a breach.","words":[["H8229","By reason of the abundance",0,26],["H5483","of his horses",27,40],["H0080","their dust",41,51],["H3680","shall cover",52,63],["H2346","thee: thy walls",64,79],["H7493","shall shake",80,91],["H6963","at the noise",92,104],["H6571","of the horsemen",105,120],["H1534","and of the wheels",122,139],["H7393","and of the chariots",141,160],["H0935","when he shall enter",162,181],["H8179","into thy gates",182,196],["H3996","as men enter",198,210],["H5892","into a city",211,222],["H1234","wherein is made a breach",223,247]]},"26:11":{"text":"With the hoofs of his horses shall he tread down all thy streets: he shall slay thy people by the sword, and thy strong garrisons shall go down to the ground.","words":[["H6541","With the hoofs",0,14],["H5483","of his horses",15,28],["H7429","shall he tread down",29,48],["H2351","all thy streets",49,64],["H2026","he shall slay",66,79],["H5971","thy people",80,90],["H2719","by the sword",91,103],["H5797","and thy strong",105,119],["H4676","garrisons",120,129],["H3381","shall go down",130,143],["H0776","to the ground",144,157]]},"26:12":{"text":"And they shall make a spoil of thy riches, and make a prey of thy merchandise: and they shall break down thy walls, and destroy thy pleasant houses: and they shall lay thy stones and thy timber and thy dust in the midst of the water.","words":[["H7997","And they shall make a spoil",0,27],["H2428","of thy riches",28,41],["H0962","and make a prey",43,58],["H7404","of thy merchandise",59,77],["H2040","and they shall break down",79,104],["H2346","thy walls",105,114],["H5422","and destroy",116,127],["H2532","thy pleasant",128,140],["H1004","houses",141,147],["H7760","and they shall lay",149,167],["H0068","thy stones",168,178],["H6086","and thy timber",179,193],["H6083","and thy dust",194,206],["H8432","in the midst",207,219],["H4325","of the water",220,232]]},"26:13":{"text":"And I will cause the noise of thy songs to cease; and the sound of thy harps shall be no more heard.","words":[["H1995","And I will cause the noise",0,26],["H7892","of thy songs",27,39],["H7673","to cease",40,48],["H6963","and the sound",50,63],["H3658","of thy harps",64,76],["H8085","shall be no more heard",77,99]]},"26:14":{"text":"And I will make thee like the top of a rock: thou shalt be a place to spread nets upon; thou shalt be built no more: for I the LORD have spoken it, saith the Lord GOD.","words":[["H5414","And I will make",0,15],["H6706","thee like the top",16,33],["H5553","of a rock",34,43],["H4894","thou shalt be a place to spread",45,76],["H2764","nets",77,81],["H4894","upon",82,86],["H1129","thou shalt be built",88,107],["H3068","no more: for I the LORD",108,131],["H1696","have spoken",132,143],["H5002","it, saith",144,153],["H0136","the Lord",154,162],["H3069","GOD",163,166]]},"26:15":{"text":"Thus saith the Lord GOD to Tyrus; Shall not the isles shake at the sound of thy fall, when the wounded cry, when the slaughter is made in the midst of thee?","words":[["H0559","Thus saith",0,10],["H0136","the Lord",11,19],["H3069","GOD",20,23],["H6865","to Tyrus",24,32],["H0339","Shall not the isles",34,53],["H7493","shake",54,59],["H6963","at the sound",60,72],["H4658","of thy fall",73,84],["H2491","when the wounded",86,102],["H0602","cry",103,106],["H2027","when the slaughter",108,126],["H2026","is made",127,134],["H8432","in the midst",135,147]]},"26:16":{"text":"Then all the princes of the sea shall come down from their thrones, and lay away their robes, and put off their broidered garments: they shall clothe themselves with trembling; they shall sit upon the ground, and shall tremble at every moment, and be astonished at thee.","words":[["H5387","Then all the princes",0,20],["H3220","of the sea",21,31],["H3381","shall come down",32,47],["H3678","from their thrones",48,66],["H5493","and lay away",68,80],["H4598","their robes",81,92],["H6584","and put off",94,105],["H7553","their broidered",106,121],["H0899","garments",122,130],["H3847","they shall clothe",132,149],["H2731","themselves with trembling",150,175],["H3427","they shall sit",177,191],["H0776","upon the ground",192,207],["H2729","and shall tremble",209,226],["H7281","at every moment",227,242],["H8074","and be astonished",244,261]]},"26:17":{"text":"And they shall take up a lamentation for thee, and say to thee, How art thou destroyed, that wast inhabited of seafaring men, the renowned city, which wast strong in the sea, she and her inhabitants, which cause their terror to be on all that haunt it!","words":[["H5375","And they shall take up",0,22],["H7015","a lamentation",23,36],["H0559","for thee, and say",37,54],["H0006","to thee, How art thou destroyed",55,86],["H3427","that wast inhabited",88,107],["H3220","of seafaring men",108,124],["H1984","the renowned",126,138],["H5892","city",139,143],["H2389","which wast strong",145,162],["H3220","in the sea",163,173],["H3427","she and her inhabitants",175,198],["H5414","which cause",200,211],["H2851","their terror",212,224],["H3427","to be on all that haunt",225,248]]},"26:18":{"text":"Now shall the isles tremble in the day of thy fall; yea, the isles that are in the sea shall be troubled at thy departure.","words":[["H0339","Now shall the isles",0,19],["H2729","tremble",20,27],["H3117","in the day",28,38],["H4658","of thy fall",39,50],["H0339","yea, the isles",52,66],["H3220","that are in the sea",67,86],["H0926","shall be troubled",87,104],["H3318","at thy departure",105,121]]},"26:19":{"text":"For thus saith the Lord GOD; When I shall make thee a desolate city, like the cities that are not inhabited; when I shall bring up the deep upon thee, and great waters shall cover thee;","words":[["H0559","For thus saith",0,14],["H0136","the Lord",15,23],["H3069","GOD",24,27],["H5414","When I shall make",29,46],["H2717","thee a desolate",47,62],["H5892","city",63,67],["H5892","like the cities",69,84],["H3427","that are not inhabited",85,107],["H5927","when I shall bring up",109,130],["H8415","the deep",131,139],["H7227","upon thee, and great",140,160],["H4325","waters",161,167],["H3680","shall cover",168,179]]},"26:20":{"text":"When I shall bring thee down with them that descend into the pit, with the people of old time, and shall set thee in the low parts of the earth, in places desolate of old, with them that go down to the pit, that thou be not inhabited; and I shall set glory in the land of the living;","words":[["H3381","When I shall bring thee down",0,28],["H3381","with them that descend",29,51],["H0953","into the pit",52,64],["H5971","with the people",66,81],["H5769","of old time",82,93],["H3427","and shall set",95,108],["H8482","thee in the low parts",109,130],["H0776","of the earth",131,143],["H2723","in places desolate",145,163],["H5769","of old",164,170],["H3381","with them that go down",172,194],["H0953","to the pit",195,205],["H3427","that thou be not inhabited",207,233],["H5414","and I shall set",235,250],["H6643","glory",251,256],["H0776","in the land",257,268],["H2416","of the living",269,282]]},"26:21":{"text":"I will make thee a terror, and thou shalt be no more: though thou be sought for, yet shalt thou never be found again, saith the Lord GOD.","words":[["H5414","I will make",0,11],["H1091","thee a terror",12,25],["H1245","and thou shalt be no more: though thou be sought for",27,79],["H5769","yet shalt thou never",81,101],["H4672","be found",102,110],["H5002","again, saith",111,123],["H0136","the Lord",124,132],["H3069","GOD",133,136]]},"27:1":{"text":"The word of the LORD came again unto me, saying,","words":[["H1697","The word",0,8],["H3068","of the LORD",9,20],["H0559","came again unto me, saying",21,47]]},"27:2":{"text":"Now, thou son of man, take up a lamentation for Tyrus;","words":[["H1121","Now, thou son",0,13],["H0120","of man",14,20],["H5375","take up",22,29],["H7015","a lamentation",30,43],["H6865","for Tyrus",44,53]]},"27:3":{"text":"And say unto Tyrus, O thou that art situate at the entry of the sea, which art a merchant of the people for many isles, Thus saith the Lord GOD; O Tyrus, thou hast said, I am of perfect beauty.","words":[["H0559","And say",0,7],["H6865","unto Tyrus",8,18],["H3427","O thou that art situate",20,43],["H3997","at the entry",44,56],["H3220","of the sea",57,67],["H7402","which art a merchant",69,89],["H5971","of the people",90,103],["H7227","for many",104,112],["H0339","isles",113,118],["H0559","Thus saith",120,130],["H0136","the Lord",131,139],["H3069","GOD",140,143],["H6865","O Tyrus",145,152],["H0559","thou hast said",154,168],["H3632","I am of perfect",170,185],["H3308","beauty",186,192]]},"27:4":{"text":"Thy borders are in the midst of the seas, thy builders have perfected thy beauty.","words":[["H1366","Thy borders",0,11],["H3820","are in the midst",12,28],["H3220","of the seas",29,40],["H1129","thy builders",42,54],["H3634","have perfected",55,69],["H3308","thy beauty",70,80]]},"27:5":{"text":"They have made all thy ship boards of fir trees of Senir: they have taken cedars from Lebanon to make masts for thee.","words":[["H1129","They have made",0,14],["H3871","all thy ship boards",15,34],["H1265","of fir trees",35,47],["H8149","of Senir",48,56],["H3947","they have taken",58,73],["H0730","cedars",74,80],["H3844","from Lebanon",81,93],["H6213","to make",94,101],["H8650","masts",102,107]]},"27:6":{"text":"Of the oaks of Bashan have they made thine oars; the company of the Ashurites have made thy benches of ivory, brought out of the isles of Chittim.","words":[["H0437","Of the oaks",0,11],["H1316","of Bashan",12,21],["H6213","have they made",22,36],["H4880","thine oars",37,47],["H1323","the company",49,60],["H0839","of the Ashurites",61,77],["H6213","have made",78,87],["H7175","thy benches",88,99],["H8127","of ivory",100,108],["H0339","brought out of the isles",110,134],["H3794","of Chittim",135,145]]},"27:7":{"text":"Fine linen with broidered work from Egypt was that which thou spreadest forth to be thy sail; blue and purple from the isles of Elishah was that which covered thee.","words":[["H8336","Fine linen",0,10],["H7553","with broidered work",11,30],["H4714","from Egypt",31,41],["H4666","was that which thou spreadest forth",42,77],["H5251","to be thy sail",78,92],["H8504","blue",94,98],["H0713","and purple",99,109],["H0339","from the isles",110,124],["H0473","of Elishah",125,135],["H4374","was that which covered",136,158]]},"27:8":{"text":"The inhabitants of Zidon and Arvad were thy mariners: thy wise men, O Tyrus, that were in thee, were thy pilots.","words":[["H3427","The inhabitants",0,15],["H6721","of Zidon",16,24],["H0719","and Arvad",25,34],["H7751","were thy mariners",35,52],["H2450","thy wise",54,62],["H6865","men, O Tyrus",63,75],["H2259","that were in thee, were thy pilots",77,111]]},"27:9":{"text":"The ancients of Gebal and the wise men thereof were in thee thy calkers: all the ships of the sea with their mariners were in thee to occupy thy merchandise.","words":[["H2205","The ancients",0,12],["H1380","of Gebal",13,21],["H2450","and the wise",22,34],["H0919","men thereof were in thee thy calkers",35,71],["H2388","men thereof were in thee thy calkers",35,71],["H0591","all the ships",73,86],["H3220","of the sea",87,97],["H4419","with their mariners",98,117],["H6148","were in thee to occupy",118,140],["H4627","thy merchandise",141,156]]},"27:10":{"text":"They of Persia and of Lud and of Phut were in thine army, thy men of war: they hanged the shield and helmet in thee; they set forth thy comeliness.","words":[["H6539","They of Persia",0,14],["H3865","and of Lud",15,25],["H6316","and of Phut",26,37],["H2428","were in thine army",38,56],["H0582","thy men",58,65],["H4421","of war",66,72],["H8518","they hanged",74,85],["H4043","the shield",86,96],["H3553","and helmet",97,107],["H5414","in thee; they set forth",108,131],["H1926","thy comeliness",132,146]]},"27:11":{"text":"The men of Arvad with thine army were upon thy walls round about, and the Gammadims were in thy towers: they hanged their shields upon thy walls round about; they have made thy beauty perfect.","words":[["H1121","The men",0,7],["H0719","of Arvad",8,16],["H2428","with thine army",17,32],["H2346","were upon thy walls",33,52],["H5439","round about",53,64],["H1575","and the Gammadims",66,83],["H4026","were in thy towers",84,102],["H8518","they hanged",104,115],["H7982","their shields",116,129],["H2346","upon thy walls",130,144],["H5439","round about",145,156],["H3634","they have made",158,172],["H3308","thy beauty",173,183],["H3634","perfect",184,191]]},"27:12":{"text":"Tarshish was thy merchant by reason of the multitude of all kind of riches; with silver, iron, tin, and lead, they traded in thy fairs.","words":[["H8659","Tarshish",0,8],["H5503","was thy merchant",9,25],["H7230","by reason of the multitude",26,52],["H1952","of all kind of riches",53,74],["H3701","with silver",76,87],["H1270","iron",89,93],["H0913","tin",95,98],["H5777","and lead",100,108],["H5414","they traded",110,121],["H5801","in thy fairs",122,134]]},"27:13":{"text":"Javan, Tubal, and Meshech, they were thy merchants: they traded the persons of men and vessels of brass in thy market.","words":[["H3120","Javan",0,5],["H8422","Tubal",7,12],["H4902","and Meshech",14,25],["H7402","they were thy merchants",27,50],["H5414","they traded",52,63],["H5315","the persons",64,75],["H0120","of men",76,82],["H3627","and vessels",83,94],["H5178","of brass",95,103],["H4627","in thy market",104,117]]},"27:14":{"text":"They of the house of Togarmah traded in thy fairs with horses and horsemen and mules.","words":[["H1004","They of the house",0,17],["H8425","of Togarmah",18,29],["H5414","traded",30,36],["H5801","in thy fairs",37,49],["H5483","with horses",50,61],["H6571","and horsemen",62,74],["H6505","and mules",75,84]]},"27:15":{"text":"The men of Dedan were thy merchants; many isles were the merchandise of thine hand: they brought thee for a present horns of ivory and ebony.","words":[["H1121","The men",0,7],["H1719","of Dedan",8,16],["H7402","were thy merchants",17,35],["H7227","many",37,41],["H0339","isles",42,47],["H5506","were the merchandise",48,68],["H3027","of thine hand",69,82],["H7725","they brought",84,96],["H0814","thee for a present",97,115],["H7161","horns",116,121],["H8127","of ivory",122,130],["H1894","and ebony",131,140]]},"27:16":{"text":"Syria was thy merchant by reason of the multitude of the wares of thy making: they occupied in thy fairs with emeralds, purple, and broidered work, and fine linen, and coral, and agate.","words":[["H0758","Syria",0,5],["H5503","was thy merchant",6,22],["H7230","by reason of the multitude",23,49],["H4639","of the wares of thy making",50,76],["H5414","they occupied",78,91],["H5801","in thy fairs",92,104],["H5306","with emeralds",105,118],["H0713","purple",120,126],["H7553","and broidered work",128,146],["H0948","and fine linen",148,162],["H7215","and coral",164,173],["H3539","and agate",175,184]]},"27:17":{"text":"Judah, and the land of Israel, they were thy merchants: they traded in thy market wheat of Minnith, and Pannag, and honey, and oil, and balm.","words":[["H3063","Judah",0,5],["H0776","and the land",7,19],["H3478","of Israel",20,29],["H7402","they were thy merchants",31,54],["H5414","they traded",56,67],["H4627","in thy market",68,81],["H2406","wheat",82,87],["H4511","of Minnith",88,98],["H6436","and Pannag",100,110],["H1706","and honey",112,121],["H8081","and oil",123,130],["H6875","and balm",132,140]]},"27:18":{"text":"Damascus was thy merchant in the multitude of the wares of thy making, for the multitude of all riches; in the wine of Helbon, and white wool.","words":[["H1834","Damascus",0,8],["H5503","was thy merchant",9,25],["H7230","in the multitude",26,42],["H4639","of the wares of thy making",43,69],["H7230","for the multitude",71,88],["H1952","of all riches",89,102],["H3196","in the wine",104,115],["H2463","of Helbon",116,125],["H6713","and white",127,136],["H6785","wool",137,141]]},"27:19":{"text":"Dan also and Javan going to and fro occupied in thy fairs: bright iron, cassia, and calamus, were in thy market.","words":[["H2051","Dan",0,3],["H1835","Dan",0,3],["H3120","also and Javan",4,18],["H0235","going to and fro",19,35],["H5414","occupied",36,44],["H5801","in thy fairs",45,57],["H6219","bright",59,65],["H1270","iron",66,70],["H6916","cassia",72,78],["H7070","and calamus",80,91],["H4627","were in thy market",93,111]]},"27:20":{"text":"Dedan was thy merchant in precious clothes for chariots.","words":[["H1719","Dedan",0,5],["H7402","was thy merchant",6,22],["H2667","in precious",23,34],["H0899","clothes",35,42],["H7396","for chariots",43,55]]},"27:21":{"text":"Arabia, and all the princes of Kedar, they occupied with thee in lambs, and rams, and goats: in these were they thy merchants.","words":[["H6152","Arabia",0,6],["H5387","and all the princes",8,27],["H6938","of Kedar",28,36],["H5503","they occupied",38,51],["H3027","with thee",52,61],["H3733","in lambs",62,70],["H0352","and rams",72,80],["H6260","and goats",82,91],["H5503","in these were they thy merchants",93,125]]},"27:22":{"text":"The merchants of Sheba and Raamah, they were thy merchants: they occupied in thy fairs with chief of all spices, and with all precious stones, and gold.","words":[["H7402","The merchants",0,13],["H7614","of Sheba",14,22],["H7484","and Raamah",23,33],["H7402","they were thy merchants",35,58],["H5414","they occupied",60,73],["H5801","in thy fairs",74,86],["H7218","with chief",87,97],["H1314","of all spices",98,111],["H3368","and with all precious",113,134],["H0068","stones",135,141],["H2091","and gold",143,151]]},"27:23":{"text":"Haran, and Canneh, and Eden, the merchants of Sheba, Asshur, and Chilmad, were thy merchants.","words":[["H2771","Haran",0,5],["H3656","and Canneh",7,17],["H5729","and Eden",19,27],["H7402","the merchants",29,42],["H7614","of Sheba",43,51],["H0804","Asshur",53,59],["H3638","and Chilmad",61,72],["H7402","were thy merchants",74,92]]},"27:24":{"text":"These were thy merchants in all sorts of things, in blue clothes, and broidered work, and in chests of rich apparel, bound with cords, and made of cedar, among thy merchandise.","words":[["H7402","These were thy merchants",0,24],["H4360","in all sorts",25,37],["H8504","of things, in blue",38,56],["H1545","clothes",57,64],["H7553","and broidered work",66,84],["H1595","and in chests",86,99],["H1264","of rich apparel",100,115],["H2280","bound",117,122],["H2256","with cords",123,133],["H0729","and made of cedar",135,152],["H4819","among thy merchandise",154,175]]},"27:25":{"text":"The ships of Tarshish did sing of thee in thy market: and thou wast replenished, and made very glorious in the midst of the seas.","words":[["H0591","The ships",0,9],["H8659","of Tarshish",10,21],["H7788","did sing",22,30],["H4627","of thee in thy market",31,52],["H4390","and thou wast replenished",54,79],["H3966","and made very",81,94],["H3513","glorious",95,103],["H3820","in the midst",104,116],["H3220","of the seas",117,128]]},"27:26":{"text":"Thy rowers have brought thee into great waters: the east wind hath broken thee in the midst of the seas.","words":[["H7751","Thy rowers",0,10],["H0935","have brought",11,23],["H7227","thee into great",24,39],["H4325","waters",40,46],["H6921","the east",48,56],["H7307","wind",57,61],["H7665","hath broken",62,73],["H3820","thee in the midst",74,91],["H3220","of the seas",92,103]]},"27:27":{"text":"Thy riches, and thy fairs, thy merchandise, thy mariners, and thy pilots, thy calkers, and the occupiers of thy merchandise, and all thy men of war, that are in thee, and in all thy company which is in the midst of thee, shall fall into the midst of the seas in the day of thy ruin.","words":[["H1952","Thy riches",0,10],["H5801","and thy fairs",12,25],["H4627","thy merchandise",27,42],["H4419","thy mariners",44,56],["H2259","and thy pilots",58,72],["H0919","thy calkers",74,85],["H2388","thy calkers",74,85],["H6148","and the occupiers",87,104],["H4627","of thy merchandise",105,123],["H0582","and all thy men",125,140],["H4421","of war",141,147],["H6951","that are in thee, and in all thy company",149,189],["H8432","which is in the midst",190,211],["H5307","of thee, shall fall",212,231],["H3820","into the midst",232,246],["H3220","of the seas",247,258],["H3117","in the day",259,269],["H4658","of thy ruin",270,281]]},"27:28":{"text":"The suburbs shall shake at the sound of the cry of thy pilots.","words":[["H4054","The suburbs",0,11],["H7493","shall shake",12,23],["H6963","at the sound",24,36],["H2201","of the cry",37,47],["H2259","of thy pilots",48,61]]},"27:29":{"text":"And all that handle the oar, the mariners, and all the pilots of the sea, shall come down from their ships, they shall stand upon the land;","words":[["H8610","And all that handle",0,19],["H4880","the oar",20,27],["H4419","the mariners",29,41],["H2259","and all the pilots",43,61],["H3220","of the sea",62,72],["H3381","shall come down",74,89],["H0591","from their ships",90,106],["H5975","they shall stand",108,124],["H0776","upon the land",125,138]]},"27:30":{"text":"And shall cause their voice to be heard against thee, and shall cry bitterly, and shall cast up dust upon their heads, they shall wallow themselves in the ashes:","words":[["H6963","And shall cause their voice",0,27],["H8085","to be heard",28,39],["H2199","against thee, and shall cry",40,67],["H4751","bitterly",68,76],["H5927","and shall cast up",78,95],["H6083","dust",96,100],["H7218","upon their heads",101,117],["H6428","they shall wallow",119,136],["H0665","themselves in the ashes",137,160]]},"27:31":{"text":"And they shall make themselves utterly bald for thee, and gird them with sackcloth, and they shall weep for thee with bitterness of heart and bitter wailing.","words":[["H7144","And they shall make themselves utterly",0,38],["H7139","bald",39,43],["H2296","for thee, and gird",44,62],["H8242","them with sackcloth",63,82],["H1058","and they shall weep",84,103],["H4751","for thee with bitterness",104,128],["H5315","of heart",129,137],["H4751","and bitter",138,148],["H4553","wailing",149,156]]},"27:32":{"text":"And in their wailing they shall take up a lamentation for thee, and lament over thee, saying, What city is like Tyrus, like the destroyed in the midst of the sea?","words":[["H5204","And in their wailing",0,20],["H5375","they shall take up",21,39],["H7015","a lamentation",40,53],["H6969","for thee, and lament",54,74],["H6865","over thee, saying, What city is like Tyrus",75,117],["H1822","like the destroyed",119,137],["H8432","in the midst",138,150],["H3220","of the sea",151,161]]},"27:33":{"text":"When thy wares went forth out of the seas, thou filledst many people; thou didst enrich the kings of the earth with the multitude of thy riches and of thy merchandise.","words":[["H5801","When thy wares",0,14],["H3318","went forth",15,25],["H3220","out of the seas",26,41],["H7646","thou filledst",43,56],["H7227","many",57,61],["H5971","people",62,68],["H6238","thou didst enrich",70,87],["H4428","the kings",88,97],["H0776","of the earth",98,110],["H7230","with the multitude",111,129],["H1952","of thy riches",130,143],["H4627","and of thy merchandise",144,166]]},"27:34":{"text":"In the time when thou shalt be broken by the seas in the depths of the waters thy merchandise and all thy company in the midst of thee shall fall.","words":[["H6256","In the time",0,11],["H7665","when thou shalt be broken",12,37],["H3220","by the seas",38,49],["H4615","in the depths",50,63],["H4325","of the waters",64,77],["H4627","thy merchandise",78,93],["H6951","and all thy company",94,113],["H8432","in the midst",114,126],["H5307","of thee shall fall",127,145]]},"27:35":{"text":"All the inhabitants of the isles shall be astonished at thee, and their kings shall be sore afraid, they shall be troubled in their countenance.","words":[["H3427","All the inhabitants",0,19],["H0339","of the isles",20,32],["H8074","shall be astonished",33,52],["H4428","at thee, and their kings",53,77],["H8178","shall be sore",78,91],["H8175","afraid",92,98],["H7481","they shall be troubled",100,122],["H6440","in their countenance",123,143]]},"27:36":{"text":"The merchants among the people shall hiss at thee; thou shalt be a terror, and never shalt be any more.","words":[["H5503","The merchants",0,13],["H5971","among the people",14,30],["H8319","shall hiss",31,41],["H1091","at thee; thou shalt be a terror",42,73],["H5704","and never shalt be any more",75,102],["H5769","and never shalt be any more",75,102]]},"28:1":{"text":"The word of the LORD came again unto me, saying,","words":[["H1697","The word",0,8],["H3068","of the LORD",9,20],["H0559","came again unto me, saying",21,47]]},"28:2":{"text":"Son of man, say unto the prince of Tyrus, Thus saith the Lord GOD; Because thine heart is lifted up, and thou hast said, I am a God, I sit in the seat of God, in the midst of the seas; yet thou art a man, and not God, though thou set thine heart as the heart of God:","words":[["H1121","Son",0,3],["H0120","of man",4,10],["H0559","say",12,15],["H5057","unto the prince",16,31],["H6865","of Tyrus",32,40],["H0559","Thus saith",42,52],["H0136","the Lord",53,61],["H3069","GOD",62,65],["H3820","Because thine heart",67,86],["H1361","is lifted up",87,99],["H0559","and thou hast said",101,119],["H0410","I am a God",121,131],["H3427","I sit",133,138],["H4186","in the seat",139,150],["H0430","of God",151,157],["H3820","in the midst",159,171],["H3220","of the seas",172,183],["H0120","yet thou art a man",185,203],["H0410","and not God",205,216],["H5414","though thou set",218,233],["H3820","thine heart",234,245],["H3820","as the heart",246,258],["H0430","of God",259,265]]},"28:3":{"text":"Behold, thou art wiser than Daniel; there is no secret that they can hide from thee:","words":[["H2450","Behold, thou art wiser",0,22],["H1840","than Daniel",23,34],["H5640","there is no secret",36,54],["H6004","that they can hide",55,73]]},"28:4":{"text":"With thy wisdom and with thine understanding thou hast gotten thee riches, and hast gotten gold and silver into thy treasures:","words":[["H2451","With thy wisdom",0,15],["H8394","and with thine understanding",16,44],["H6213","thou hast gotten",45,61],["H2428","thee riches",62,73],["H6213","and hast gotten",75,90],["H2091","gold",91,95],["H3701","and silver",96,106],["H0214","into thy treasures",107,125]]},"28:5":{"text":"By thy great wisdom and by thy traffick hast thou increased thy riches, and thine heart is lifted up because of thy riches:","words":[["H7230","By thy great",0,12],["H2451","wisdom",13,19],["H7404","and by thy traffick",20,39],["H7235","hast thou increased",40,59],["H2428","thy riches",60,70],["H3824","and thine heart",72,87],["H1361","is lifted up",88,100],["H2428","because of thy riches",101,122]]},"28:6":{"text":"Therefore thus saith the Lord GOD; Because thou hast set thine heart as the heart of God;","words":[["H0559","Therefore thus saith",0,20],["H0136","the Lord",21,29],["H3069","GOD",30,33],["H5414","Because thou hast set",35,56],["H3820","thine heart",57,68],["H3824","as the heart",69,81],["H0430","of God",82,88]]},"28:7":{"text":"Behold, therefore I will bring strangers upon thee, the terrible of the nations: and they shall draw their swords against the beauty of thy wisdom, and they shall defile thy brightness.","words":[["H0935","Behold, therefore I will bring",0,30],["H2114","strangers",31,40],["H6184","upon thee, the terrible",41,64],["H1471","of the nations",65,79],["H7324","and they shall draw",81,100],["H2719","their swords",101,113],["H3308","against the beauty",114,132],["H2451","of thy wisdom",133,146],["H2490","and they shall defile",148,169],["H3314","thy brightness",170,184]]},"28:8":{"text":"They shall bring thee down to the pit, and thou shalt die the deaths of them that are slain in the midst of the seas.","words":[["H3381","They shall bring thee down",0,26],["H7845","to the pit",27,37],["H4191","and thou shalt die",39,57],["H4463","the deaths",58,68],["H2491","of them that are slain",69,91],["H3820","in the midst",92,104],["H3220","of the seas",105,116]]},"28:9":{"text":"Wilt thou yet say before him that slayeth thee, I am God? but thou shalt be a man, and no God, in the hand of him that slayeth thee.","words":[["H0559","Wilt thou yet",0,13],["H0559","say",14,17],["H6440","before",18,24],["H2026","him that slayeth",25,41],["H0430","thee, I am God",42,56],["H0120","but thou shalt be a man",58,81],["H0410","and no God",83,93],["H3027","in the hand",95,106],["H2490","of him that slayeth",107,126]]},"28:10":{"text":"Thou shalt die the deaths of the uncircumcised by the hand of strangers: for I have spoken it, saith the Lord GOD.","words":[["H4191","Thou shalt die",0,14],["H4194","the deaths",15,25],["H6189","of the uncircumcised",26,46],["H3027","by the hand",47,58],["H2114","of strangers",59,71],["H1696","for I have spoken",73,90],["H5002","it, saith",91,100],["H0136","the Lord",101,109],["H3069","GOD",110,113]]},"28:11":{"text":"Moreover the word of the LORD came unto me, saying,","words":[["H1697","Moreover the word",0,17],["H3068","of the LORD",18,29],["H0559","came unto me, saying",30,50]]},"28:12":{"text":"Son of man, take up a lamentation upon the king of Tyrus, and say unto him, Thus saith the Lord GOD; Thou sealest up the sum, full of wisdom, and perfect in beauty.","words":[["H1121","Son",0,3],["H0120","of man",4,10],["H5375","take up",12,19],["H7015","a lamentation",20,33],["H4428","upon the king",34,47],["H6865","of Tyrus",48,56],["H0559","and say",58,65],["H0559","unto him, Thus saith",66,86],["H0136","the Lord",87,95],["H3069","GOD",96,99],["H2856","Thou sealest up",101,116],["H8508","the sum",117,124],["H4392","full",126,130],["H2451","of wisdom",131,140],["H3632","and perfect",142,153],["H3308","in beauty",154,163]]},"28:13":{"text":"Thou hast been in Eden the garden of God; every precious stone was thy covering, the sardius, topaz, and the diamond, the beryl, the onyx, and the jasper, the sapphire, the emerald, and the carbuncle, and gold: the workmanship of thy tabrets and of thy pipes was prepared in thee in the day that thou wast created.","words":[["H5731","Thou hast been in Eden",0,22],["H1588","the garden",23,33],["H0430","of God",34,40],["H3368","every precious",42,56],["H0068","stone",57,62],["H4540","was thy covering",63,79],["H0124","the sardius",81,92],["H6357","topaz",94,99],["H3095","and the diamond",101,116],["H8658","the beryl",118,127],["H7718","the onyx",129,137],["H3471","and the jasper",139,153],["H5601","the sapphire",155,167],["H5306","the emerald",169,180],["H1304","and the carbuncle",182,199],["H2091","and gold",201,209],["H4399","the workmanship",211,226],["H8596","of thy tabrets",227,241],["H5345","and of thy pipes",242,258],["H3559","was prepared",259,271],["H3117","in thee in the day",272,290],["H1254","that thou wast created",291,313]]},"28:14":{"text":"Thou art the anointed cherub that covereth; and I have set thee so: thou wast upon the holy mountain of God; thou hast walked up and down in the midst of the stones of fire.","words":[["H4473","Thou art the anointed",0,21],["H3742","cherub",22,28],["H5526","that covereth",29,42],["H5414","and I have set",44,58],["H6944","thee so: thou wast upon the holy",59,91],["H2022","mountain",92,100],["H0430","of God",101,107],["H1980","thou hast walked up and down",109,137],["H8432","in the midst",138,150],["H0068","of the stones",151,164],["H0784","of fire",165,172]]},"28:15":{"text":"Thou wast perfect in thy ways from the day that thou wast created, till iniquity was found in thee.","words":[["H8549","Thou wast perfect",0,17],["H1870","in thy ways",18,29],["H3117","from the day",30,42],["H1254","that thou wast created",43,65],["H5766","till iniquity",67,80],["H4672","was found",81,90]]},"28:16":{"text":"By the multitude of thy merchandise they have filled the midst of thee with violence, and thou hast sinned: therefore I will cast thee as profane out of the mountain of God: and I will destroy thee, O covering cherub, from the midst of the stones of fire.","words":[["H7230","By the multitude",0,16],["H7404","of thy merchandise",17,35],["H4390","they have filled",36,52],["H8432","the midst",53,62],["H2555","of thee with violence",63,84],["H2398","and thou hast sinned",86,106],["H2490","therefore I will cast thee as profane",108,145],["H2022","out of the mountain",146,165],["H0430","of God",166,172],["H0006","and I will destroy",174,192],["H5526","thee, O covering",193,209],["H3742","cherub",210,216],["H8432","from the midst",218,232],["H0068","of the stones",233,246],["H0784","of fire",247,254]]},"28:17":{"text":"Thine heart was lifted up because of thy beauty, thou hast corrupted thy wisdom by reason of thy brightness: I will cast thee to the ground, I will lay thee before kings, that they may behold thee.","words":[["H3820","Thine heart",0,11],["H1361","was lifted up",12,25],["H3308","because of thy beauty",26,47],["H7843","thou hast corrupted",49,68],["H2451","thy wisdom",69,79],["H5921","by reason of",80,92],["H3314","thy brightness",93,107],["H7993","I will cast",109,120],["H0776","thee to the ground",121,139],["H5414","I will lay",141,151],["H6440","thee before",152,163],["H4428","kings",164,169],["H7200","that they may behold",171,191]]},"28:18":{"text":"Thou hast defiled thy sanctuaries by the multitude of thine iniquities, by the iniquity of thy traffick; therefore will I bring forth a fire from the midst of thee, it shall devour thee, and I will bring thee to ashes upon the earth in the sight of all them that behold thee.","words":[["H2490","Thou hast defiled",0,17],["H4720","thy sanctuaries",18,33],["H7230","by the multitude",34,50],["H5771","of thine iniquities",51,70],["H5766","by the iniquity",72,87],["H7404","of thy traffick",88,103],["H3318","therefore will I bring forth",105,133],["H0784","a fire",134,140],["H8432","from the midst",141,155],["H0398","of thee, it shall devour",156,180],["H5414","thee, and I will bring",181,203],["H0665","thee to ashes",204,217],["H0776","upon the earth",218,232],["H5869","in the sight",233,245],["H7200","of all them that behold",246,269]]},"28:19":{"text":"All they that know thee among the people shall be astonished at thee: thou shalt be a terror, and never shalt thou be any more.","words":[["H3045","All they that know",0,18],["H5971","thee among the people",19,40],["H8074","shall be astonished",41,60],["H1091","at thee: thou shalt be a terror",61,92],["H0369","and never",94,103],["H5704","shalt thou be any more",104,126],["H5769","shalt thou be any more",104,126]]},"28:20":{"text":"Again the word of the LORD came unto me, saying,","words":[["H1697","Again the word",0,14],["H3068","of the LORD",15,26],["H0559","came unto me, saying",27,47]]},"28:21":{"text":"Son of man, set thy face against Zidon, and prophesy against it,","words":[["H1121","Son",0,3],["H0120","of man",4,10],["H7760","set",12,15],["H6440","thy face",16,24],["H6721","against Zidon",25,38],["H5012","and prophesy",40,52]]},"28:22":{"text":"And say, Thus saith the Lord GOD; Behold, I am against thee, O Zidon; and I will be glorified in the midst of thee: and they shall know that I am the LORD, when I shall have executed judgments in her, and shall be sanctified in her.","words":[["H0559","And say",0,7],["H0559","Thus saith",9,19],["H0136","the Lord",20,28],["H3069","GOD",29,32],["H6721","Behold, I am against thee, O Zidon",34,68],["H3513","and I will be glorified",70,93],["H8432","in the midst",94,106],["H3045","of thee: and they shall know",107,135],["H3068","that I am the LORD",136,154],["H6213","when I shall have executed",156,182],["H8201","judgments",183,192],["H6942","in her, and shall be sanctified",193,224]]},"28:23":{"text":"For I will send into her pestilence, and blood into her streets; and the wounded shall be judged in the midst of her by the sword upon her on every side; and they shall know that I am the LORD.","words":[["H7971","For I will send",0,15],["H1698","into her pestilence",16,35],["H1818","and blood",37,46],["H2351","into her streets",47,63],["H2491","and the wounded",65,80],["H5307","shall be judged",81,96],["H8432","in the midst",97,109],["H2719","of her by the sword",110,129],["H5439","upon her on every side",130,152],["H3045","and they shall know",154,173],["H3068","that I am the LORD",174,192]]},"28:24":{"text":"And there shall be no more a pricking brier unto the house of Israel, nor any grieving thorn of all that are round about them, that despised them; and they shall know that I am the Lord GOD.","words":[["H3992","And there shall be no more a pricking",0,37],["H5544","brier",38,43],["H1004","unto the house",44,58],["H3478","of Israel",59,68],["H3510","nor any grieving",70,86],["H6975","thorn",87,92],["H5439","of all that are round about",93,120],["H7590","them, that despised",121,140],["H3045","them; and they shall know",141,166],["H0136","that I am the Lord",167,185],["H3069","GOD",186,189]]},"28:25":{"text":"Thus saith the Lord GOD; When I shall have gathered the house of Israel from the people among whom they are scattered, and shall be sanctified in them in the sight of the heathen, then shall they dwell in their land that I have given to my servant Jacob.","words":[["H0559","Thus saith",0,10],["H0136","the Lord",11,19],["H3069","GOD",20,23],["H6908","When I shall have gathered",25,51],["H1004","the house",52,61],["H3478","of Israel",62,71],["H5971","from the people",72,87],["H6327","among whom they are scattered",88,117],["H6942","and shall be sanctified",119,142],["H5869","in them in the sight",143,163],["H1471","of the heathen",164,178],["H3427","then shall they dwell",180,201],["H0127","in their land",202,215],["H5414","that I have given",216,233],["H5650","to my servant",234,247],["H3290","Jacob",248,253]]},"28:26":{"text":"And they shall dwell safely therein, and shall build houses, and plant vineyards; yea, they shall dwell with confidence, when I have executed judgments upon all those that despise them round about them; and they shall know that I am the LORD their God.","words":[["H3427","And they shall dwell",0,20],["H0983","safely",21,27],["H1129","therein, and shall build",28,52],["H1004","houses",53,59],["H5193","and plant",61,70],["H3754","vineyards",71,80],["H3427","yea, they shall dwell",82,103],["H0983","with confidence",104,119],["H6213","when I have executed",121,141],["H8201","judgments",142,151],["H7590","upon all those that despise",152,179],["H5439","them round about",180,196],["H3045","them; and they shall know",197,222],["H3068","that I am the LORD",223,241],["H0430","their God",242,251]]},"29:1":{"text":"In the tenth year, in the tenth month, in the twelfth day of the month, the word of the LORD came unto me, saying,","words":[["H6224","In the tenth",0,12],["H8141","year",13,17],["H6224","in the tenth",19,31],["H8147","month, in the twelfth",32,53],["H6240","month, in the twelfth",32,53],["H2320","day of the month",54,70],["H1697","the word",72,80],["H3068","of the LORD",81,92],["H0559","came unto me, saying",93,113]]},"29:2":{"text":"Son of man, set thy face against Pharaoh king of Egypt, and prophesy against him, and against all Egypt:","words":[["H1121","Son",0,3],["H0120","of man",4,10],["H7760","set",12,15],["H6440","thy face",16,24],["H6547","against Pharaoh",25,40],["H4428","king",41,45],["H4714","of Egypt",46,54],["H5012","and prophesy",56,68],["H4714","against him, and against all Egypt",69,103]]},"29:3":{"text":"Speak, and say, Thus saith the Lord GOD; Behold, I am against thee, Pharaoh king of Egypt, the great dragon that lieth in the midst of his rivers, which hath said, My river is mine own, and I have made it for myself.","words":[["H1696","Speak",0,5],["H0559","and say",7,14],["H0559","Thus saith",16,26],["H0136","the Lord",27,35],["H3069","GOD",36,39],["H6547","Behold, I am against thee, Pharaoh",41,75],["H4428","king",76,80],["H4714","of Egypt",81,89],["H1419","the great",91,100],["H8577","dragon",101,107],["H7257","that lieth",108,118],["H8432","in the midst",119,131],["H2975","of his rivers",132,145],["H0559","which hath said",147,162],["H2975","My river",164,172],["H6213","is mine own, and I have made",173,201]]},"29:4":{"text":"But I will put hooks in thy jaws, and I will cause the fish of thy rivers to stick unto thy scales, and I will bring thee up out of the midst of thy rivers, and all the fish of thy rivers shall stick unto thy scales.","words":[["H5414","But I will put",0,14],["H2397","hooks",15,20],["H2397","hooks",15,20],["H3895","in thy jaws",21,32],["H1710","and I will cause the fish",34,59],["H2975","of thy rivers",60,73],["H1692","to stick",74,82],["H7193","unto thy scales",83,98],["H5927","and I will bring thee up",100,124],["H8432","out of the midst",125,141],["H2975","of thy rivers",142,155],["H1710","and all the fish",157,173],["H2975","of thy rivers",174,187],["H1692","shall stick",188,199],["H7193","unto thy scales",200,215]]},"29:5":{"text":"And I will leave thee thrown into the wilderness, thee and all the fish of thy rivers: thou shalt fall upon the open fields; thou shalt not be brought together, nor gathered: I have given thee for meat to the beasts of the field and to the fowls of the heaven.","words":[["H5203","And I will leave",0,16],["H4057","thee thrown into the wilderness",17,48],["H1710","thee and all the fish",50,71],["H2975","of thy rivers",72,85],["H5307","thou shalt fall",87,102],["H6440","upon the open",103,116],["H7704","fields",117,123],["H0622","thou shalt not be brought together",125,159],["H6908","nor gathered",161,173],["H5414","I have given",175,187],["H0402","thee for meat",188,201],["H2416","to the beasts",202,215],["H0776","of the field",216,228],["H5775","and to the fowls",229,245],["H8064","of the heaven",246,259]]},"29:6":{"text":"And all the inhabitants of Egypt shall know that I am the LORD, because they have been a staff of reed to the house of Israel.","words":[["H3427","And all the inhabitants",0,23],["H4714","of Egypt",24,32],["H3045","shall know",33,43],["H3068","that I am the LORD",44,62],["H4938","because they have been a staff",64,94],["H7070","of reed",95,102],["H1004","to the house",103,115],["H3478","of Israel",116,125]]},"29:7":{"text":"When they took hold of thee by thy hand, thou didst break, and rend all their shoulder: and when they leaned upon thee, thou brakest, and madest all their loins to be at a stand.","words":[["H8610","When they took hold",0,19],["H3709","of thee by thy hand",20,39],["H7533","thou didst break",41,57],["H1234","and rend",59,67],["H3802","all their shoulder",68,86],["H8172","and when they leaned",88,108],["H7665","upon thee, thou brakest",109,132],["H4975","and madest all their loins",134,160],["H5976","to be at a stand",161,177]]},"29:8":{"text":"Therefore thus saith the Lord GOD; Behold, I will bring a sword upon thee, and cut off man and beast out of thee.","words":[["H0559","Therefore thus saith",0,20],["H0136","the Lord",21,29],["H3069","GOD",30,33],["H0935","Behold, I will bring",35,55],["H2719","a sword",56,63],["H3772","upon thee, and cut off",64,86],["H0120","man",87,90],["H0929","and beast",91,100]]},"29:9":{"text":"And the land of Egypt shall be desolate and waste; and they shall know that I am the LORD: because he hath said, The river is mine, and I have made it.","words":[["H0776","And the land",0,12],["H4714","of Egypt",13,21],["H8077","shall be desolate",22,39],["H2723","and waste",40,49],["H3045","and they shall know",51,70],["H3068","that I am the LORD",71,89],["H0559","because he hath said",91,111],["H2975","The river",113,122],["H6213","is mine, and I have made",123,147]]},"29:10":{"text":"Behold, therefore I am against thee, and against thy rivers, and I will make the land of Egypt utterly waste and desolate, from the tower of Syene even unto the border of Ethiopia.","words":[["H2975","Behold, therefore I am against thee, and against thy rivers",0,59],["H5414","and I will make",61,76],["H0776","the land",77,85],["H4714","of Egypt",86,94],["H2721","utterly",95,102],["H2723","waste",103,108],["H8077","and desolate",109,121],["H4024","from the tower",123,137],["H5482","of Syene",138,146],["H1366","even unto the border",147,167],["H3568","of Ethiopia",168,179]]},"29:11":{"text":"No foot of man shall pass through it, nor foot of beast shall pass through it, neither shall it be inhabited forty years.","words":[["H7272","No foot",0,7],["H0120","of man",8,14],["H5674","shall pass through",15,33],["H7272","it, nor foot",34,46],["H0929","of beast",47,55],["H5674","shall pass through",56,74],["H3427","it, neither shall it be inhabited",75,108],["H0705","forty",109,114],["H8141","years",115,120]]},"29:12":{"text":"And I will make the land of Egypt desolate in the midst of the countries that are desolate, and her cities among the cities that are laid waste shall be desolate forty years: and I will scatter the Egyptians among the nations, and will disperse them through the countries.","words":[["H5414","And I will make",0,15],["H0776","the land",16,24],["H4714","of Egypt",25,33],["H8077","desolate",34,42],["H8432","in the midst",43,55],["H0776","of the countries",56,72],["H8074","that are desolate",73,90],["H5892","and her cities",92,106],["H8432","among",107,112],["H5892","the cities",113,123],["H2717","that are laid waste",124,143],["H8077","shall be desolate",144,161],["H0705","forty",162,167],["H8141","years",168,173],["H6327","and I will scatter",175,193],["H4714","the Egyptians",194,207],["H1471","among the nations",208,225],["H2219","and will disperse",227,244],["H0776","them through the countries",245,271]]},"29:13":{"text":"Yet thus saith the Lord GOD; At the end of forty years will I gather the Egyptians from the people whither they were scattered:","words":[["H0559","Yet thus saith",0,14],["H0136","the Lord",15,23],["H3069","GOD",24,27],["H7093","At the end",29,39],["H0705","of forty",40,48],["H8141","years",49,54],["H6908","will I gather",55,68],["H4714","the Egyptians",69,82],["H5971","from the people",83,98],["H6327","whither they were scattered",99,126]]},"29:14":{"text":"And I will bring again the captivity of Egypt, and will cause them to return into the land of Pathros, into the land of their habitation; and they shall be there a base kingdom.","words":[["H7725","And I will bring again",0,22],["H7622","the captivity",23,36],["H4714","of Egypt",37,45],["H7725","and will cause them to return",47,76],["H0776","into the land",77,90],["H6624","of Pathros",91,101],["H0776","into the land",103,116],["H4351","of their habitation",117,136],["H8217","and they shall be there a base",138,168],["H4467","kingdom",169,176]]},"29:15":{"text":"It shall be the basest of the kingdoms; neither shall it exalt itself any more above the nations: for I will diminish them, that they shall no more rule over the nations.","words":[["H8217","It shall be the basest",0,22],["H4467","of the kingdoms",23,38],["H5375","neither shall it exalt",40,62],["H1471","itself any more above the nations",63,96],["H4591","for I will diminish",98,117],["H7287","them, that they shall no more rule",118,152],["H1471","over the nations",153,169]]},"29:16":{"text":"And it shall be no more the confidence of the house of Israel, which bringeth their iniquity to remembrance, when they shall look after them: but they shall know that I am the Lord GOD.","words":[["H4009","And it shall be no more the confidence",0,38],["H1004","of the house",39,51],["H3478","of Israel",52,61],["H2142","which bringeth",63,77],["H5771","their iniquity",78,92],["H2142","to remembrance",93,107],["H6437","when they shall look",109,129],["H0310","after",130,135],["H3045","them: but they shall know",136,161],["H0136","that I am the Lord",162,180],["H3069","GOD",181,184]]},"29:17":{"text":"And it came to pass in the seven and twentieth year, in the first month, in the first day of the month, the word of the LORD came unto me, saying,","words":[["H7651","And it came to pass in the seven",0,32],["H6242","and twentieth",33,46],["H8141","year",47,51],["H7223","in the first",53,65],["H0259","month, in the first",66,85],["H2320","day of the month",86,102],["H1697","the word",104,112],["H3068","of the LORD",113,124],["H0559","came unto me, saying",125,145]]},"29:18":{"text":"Son of man, Nebuchadrezzar king of Babylon caused his army to serve a great service against Tyrus: every head was made bald, and every shoulder was peeled: yet had he no wages, nor his army, for Tyrus, for the service that he had served against it:","words":[["H1121","Son",0,3],["H0120","of man",4,10],["H5019","Nebuchadrezzar",12,26],["H4428","king",27,31],["H0894","of Babylon",32,42],["H5647","caused",43,49],["H2428","his army",50,58],["H5647","to serve",59,67],["H1419","a great",68,75],["H5656","service",76,83],["H6865","against Tyrus",84,97],["H7218","every head",99,109],["H7139","was made bald",110,123],["H3802","and every shoulder",125,143],["H4803","was peeled",144,154],["H7939","yet had he no wages",156,175],["H2428","nor his army",177,189],["H6865","for Tyrus",191,200],["H5656","for the service",202,217],["H5647","that he had served",218,236]]},"29:19":{"text":"Therefore thus saith the Lord GOD; Behold, I will give the land of Egypt unto Nebuchadrezzar king of Babylon; and he shall take her multitude, and take her spoil, and take her prey; and it shall be the wages for his army.","words":[["H0559","Therefore thus saith",0,20],["H0136","the Lord",21,29],["H3069","GOD",30,33],["H5414","Behold, I will give",35,54],["H0776","the land",55,63],["H4714","of Egypt",64,72],["H5019","unto Nebuchadrezzar",73,92],["H4428","king",93,97],["H0894","of Babylon",98,108],["H5375","and he shall take",110,127],["H1995","her multitude",128,141],["H7997","and take",143,151],["H7998","her spoil",152,161],["H0962","and take",163,171],["H0957","her prey",172,180],["H7939","and it shall be the wages",182,207],["H2428","for his army",208,220]]},"29:20":{"text":"I have given him the land of Egypt for his labour wherewith he served against it, because they wrought for me, saith the Lord GOD.","words":[["H5414","I have given",0,12],["H0776","him the land",13,25],["H4714","of Egypt",26,34],["H6468","for his labour",35,49],["H5647","wherewith he served",50,69],["H6213","against it, because they wrought",70,102],["H5002","for me, saith",103,116],["H0136","the Lord",117,125],["H3069","GOD",126,129]]},"29:21":{"text":"In that day will I cause the horn of the house of Israel to bud forth, and I will give thee the opening of the mouth in the midst of them; and they shall know that I am the LORD.","words":[["H3117","In that day",0,11],["H6779","will I cause",12,24],["H7161","the horn",25,33],["H1004","of the house",34,46],["H3478","of Israel",47,56],["H6779","to bud forth",57,69],["H5414","and I will give",71,86],["H6610","thee the opening",87,103],["H6310","of the mouth",104,116],["H8432","in the midst",117,129],["H3045","of them; and they shall know",130,158],["H3068","that I am the LORD",159,177]]},"30:1":{"text":"The word of the LORD came again unto me, saying,","words":[["H1697","The word",0,8],["H3068","of the LORD",9,20],["H0559","came again unto me, saying",21,47]]},"30:2":{"text":"Son of man, prophesy and say, Thus saith the Lord GOD; Howl ye, Woe worth the day!","words":[["H1121","Son",0,3],["H0120","of man",4,10],["H5012","prophesy",12,20],["H0559","and say",21,28],["H0559","Thus saith",30,40],["H0136","the Lord",41,49],["H3069","GOD",50,53],["H3213","Howl",55,59],["H1929","ye, Woe worth",60,73],["H3117","the day",74,81]]},"30:3":{"text":"For the day is near, even the day of the LORD is near, a cloudy day; it shall be the time of the heathen.","words":[["H3117","For the day",0,11],["H7138","is near",12,19],["H3117","even the day",21,33],["H3068","of the LORD",34,45],["H7138","is near",46,53],["H6051","a cloudy",55,63],["H3117","day",64,67],["H6256","it shall be the time",69,89],["H1471","of the heathen",90,104]]},"30:4":{"text":"And the sword shall come upon Egypt, and great pain shall be in Ethiopia, when the slain shall fall in Egypt, and they shall take away her multitude, and her foundations shall be broken down.","words":[["H2719","And the sword",0,13],["H0935","shall come",14,24],["H4714","upon Egypt",25,35],["H2479","and great pain",37,51],["H3568","shall be in Ethiopia",52,72],["H2491","when the slain",74,88],["H5307","shall fall",89,99],["H4714","in Egypt",100,108],["H3947","and they shall take away",110,134],["H1995","her multitude",135,148],["H3247","and her foundations",150,169],["H2040","shall be broken down",170,190]]},"30:5":{"text":"Ethiopia, and Libya, and Lydia, and all the mingled people, and Chub, and the men of the land that is in league, shall fall with them by the sword.","words":[["H3568","Ethiopia",0,8],["H6316","and Libya",10,19],["H3865","and Lydia",21,30],["H6153","and all the mingled",32,51],["H3552","people, and Chub",52,68],["H1121","and the men",70,81],["H0776","of the land",82,93],["H1285","that is in league",94,111],["H5307","shall fall",113,123],["H2719","with them by the sword",124,146]]},"30:6":{"text":"Thus saith the LORD; They also that uphold Egypt shall fall; and the pride of her power shall come down: from the tower of Syene shall they fall in it by the sword, saith the Lord GOD.","words":[["H0559","Thus saith",0,10],["H3068","the LORD",11,19],["H5564","They also that uphold",21,42],["H4714","Egypt",43,48],["H5307","shall fall",49,59],["H1347","and the pride",61,74],["H5797","of her power",75,87],["H3381","shall come down",88,103],["H4024","from the tower",105,119],["H5482","of Syene",120,128],["H5307","shall they fall",129,144],["H2719","in it by the sword",145,163],["H5002","saith",165,170],["H0136","the Lord",171,179],["H3069","GOD",180,183]]},"30:7":{"text":"And they shall be desolate in the midst of the countries that are desolate, and her cities shall be in the midst of the cities that are wasted.","words":[["H8074","And they shall be desolate",0,26],["H8432","in the midst",27,39],["H0776","of the countries",40,56],["H8074","that are desolate",57,74],["H5892","and her cities",76,90],["H8432","shall be in the midst",91,112],["H5892","of the cities",113,126],["H2717","that are wasted",127,142]]},"30:8":{"text":"And they shall know that I am the LORD, when I have set a fire in Egypt, and when all her helpers shall be destroyed.","words":[["H3045","And they shall know",0,19],["H3068","that I am the LORD",20,38],["H5414","when I have set",40,55],["H0784","a fire",56,62],["H4714","in Egypt",63,71],["H5826","and when all her helpers",73,97],["H7665","shall be destroyed",98,116]]},"30:9":{"text":"In that day shall messengers go forth from me in ships to make the careless Ethiopians afraid, and great pain shall come upon them, as in the day of Egypt: for, lo, it cometh.","words":[["H3117","In that day",0,11],["H4397","shall messengers",12,28],["H3318","go forth",29,37],["H6440","from me",38,45],["H6716","in ships",46,54],["H0983","to make the careless",55,75],["H3568","Ethiopians",76,86],["H2729","afraid",87,93],["H2479","and great pain",95,109],["H3117","shall come upon them, as in the day",110,145],["H4714","of Egypt",146,154],["H0935","for, lo, it cometh",156,174]]},"30:10":{"text":"Thus saith the Lord GOD; I will also make the multitude of Egypt to cease by the hand of Nebuchadrezzar king of Babylon.","words":[["H0559","Thus saith",0,10],["H0136","the Lord",11,19],["H3069","GOD",20,23],["H1995","I will also make the multitude",25,55],["H4714","of Egypt",56,64],["H7673","to cease",65,73],["H3027","by the hand",74,85],["H5019","of Nebuchadrezzar",86,103],["H4428","king",104,108],["H0894","of Babylon",109,119]]},"30:11":{"text":"He and his people with him, the terrible of the nations, shall be brought to destroy the land: and they shall draw their swords against Egypt, and fill the land with the slain.","words":[["H5971","He and his people",0,17],["H6184","with him, the terrible",18,40],["H1471","of the nations",41,55],["H0935","shall be brought",57,73],["H7843","to destroy",74,84],["H0776","the land",85,93],["H7324","and they shall draw",95,114],["H2719","their swords",115,127],["H4714","against Egypt",128,141],["H4390","and fill",143,151],["H0776","the land",152,160],["H2491","with the slain",161,175]]},"30:12":{"text":"And I will make the rivers dry, and sell the land into the hand of the wicked: and I will make the land waste, and all that is therein, by the hand of strangers: I the LORD have spoken it.","words":[["H5414","And I will make",0,15],["H2975","the rivers",16,26],["H2724","dry",27,30],["H4376","and sell",32,40],["H0776","the land",41,49],["H3027","into the hand",50,63],["H7451","of the wicked",64,77],["H0776","and I will make the land",79,103],["H8074","waste",104,109],["H4393","and all that is therein",111,134],["H3027","by the hand",136,147],["H2114","of strangers",148,160],["H3068","I the LORD",162,172],["H1696","have spoken",173,184]]},"30:13":{"text":"Thus saith the Lord GOD; I will also destroy the idols, and I will cause their images to cease out of Noph; and there shall be no more a prince of the land of Egypt: and I will put a fear in the land of Egypt.","words":[["H0559","Thus saith",0,10],["H0136","the Lord",11,19],["H3069","GOD",20,23],["H0006","I will also destroy",25,44],["H1544","the idols",45,54],["H0457","and I will cause their images",56,85],["H7673","to cease",86,94],["H5297","out of Noph",95,106],["H5387","and there shall be no more a prince",108,143],["H0776","of the land",144,155],["H4714","of Egypt",156,164],["H5414","and I will put",166,180],["H3374","a fear",181,187],["H0776","in the land",188,199],["H4714","of Egypt",200,208]]},"30:14":{"text":"And I will make Pathros desolate, and will set fire in Zoan, and will execute judgments in No.","words":[["H6624","And I will make Pathros",0,23],["H8074","desolate",24,32],["H5414","and will set",34,46],["H0784","fire",47,51],["H6814","in Zoan",52,59],["H6213","and will execute",61,77],["H8201","judgments",78,87],["H4996","in No",88,93]]},"30:15":{"text":"And I will pour my fury upon Sin, the strength of Egypt; and I will cut off the multitude of No.","words":[["H8210","And I will pour",0,15],["H2534","my fury",16,23],["H5512","upon Sin",24,32],["H4581","the strength",34,46],["H4714","of Egypt",47,55],["H3772","and I will cut off",57,75],["H1995","the multitude",76,89],["H4996","of No",90,95]]},"30:16":{"text":"And I will set fire in Egypt: Sin shall have great pain, and No shall be rent asunder, and Noph shall have distresses daily.","words":[["H5414","And I will set",0,14],["H0784","fire",15,19],["H4714","in Egypt",20,28],["H5512","Sin",30,33],["H2342","shall have great",34,50],["H2342","pain",51,55],["H4996","and No",57,63],["H1234","shall be rent asunder",64,85],["H5297","and Noph",87,95],["H6862","shall have distresses",96,117],["H3119","daily",118,123]]},"30:17":{"text":"The young men of Aven and of Pibeseth shall fall by the sword: and these cities shall go into captivity.","words":[["H0970","The young men",0,13],["H0206","of Aven",14,21],["H6364","and of Pibeseth",22,37],["H5307","shall fall",38,48],["H2719","by the sword",49,61],["H3212","and these cities shall go",63,88],["H7628","into captivity",89,103]]},"30:18":{"text":"At Tehaphnehes also the day shall be darkened, when I shall break there the yokes of Egypt: and the pomp of her strength shall cease in her: as for her, a cloud shall cover her, and her daughters shall go into captivity.","words":[["H8471","At Tehaphnehes",0,14],["H3117","also the day",15,27],["H2821","shall be darkened",28,45],["H2820","shall be darkened",28,45],["H7665","when I shall break",47,65],["H4133","there the yokes",66,81],["H4714","of Egypt",82,90],["H1347","and the pomp",92,104],["H5797","of her strength",105,120],["H7673","shall cease",121,132],["H1931","in her",133,139],["H6051","as for her, a cloud",141,160],["H3680","shall cover",161,172],["H1323","her, and her daughters",173,195],["H3212","shall go",196,204],["H7628","into captivity",205,219]]},"30:19":{"text":"Thus will I execute judgments in Egypt: and they shall know that I am the LORD.","words":[["H6213","Thus will I execute",0,19],["H8201","judgments",20,29],["H4714","in Egypt",30,38],["H3045","and they shall know",40,59],["H3068","that I am the LORD",60,78]]},"30:20":{"text":"And it came to pass in the eleventh year, in the first month, in the seventh day of the month, that the word of the LORD came unto me, saying,","words":[["H0259","And it came to pass in the eleventh",0,35],["H6240","And it came to pass in the eleventh",0,35],["H8141","year",36,40],["H7223","in the first",42,54],["H7651","month, in the seventh",55,76],["H2320","day of the month",77,93],["H1697","that the word",95,108],["H3068","of the LORD",109,120],["H0559","came unto me, saying",121,141]]},"30:21":{"text":"Son of man, I have broken the arm of Pharaoh king of Egypt; and, lo, it shall not be bound up to be healed, to put a roller to bind it, to make it strong to hold the sword.","words":[["H1121","Son",0,3],["H0120","of man",4,10],["H7665","I have broken",12,25],["H2220","the arm",26,33],["H6547","of Pharaoh",34,44],["H4428","king",45,49],["H4714","of Egypt",50,58],["H2280","and, lo, it shall not be bound up",60,93],["H7499","to be healed",94,106],["H5414","to be healed",94,106],["H7760","to put",108,114],["H2848","a roller",115,123],["H2280","to bind",124,131],["H2388","it, to make it strong",132,153],["H8610","to hold",154,161],["H2719","the sword",162,171]]},"30:22":{"text":"Therefore thus saith the Lord GOD; Behold, I am against Pharaoh king of Egypt, and will break his arms, the strong, and that which was broken; and I will cause the sword to fall out of his hand.","words":[["H0559","Therefore thus saith",0,20],["H0136","the Lord",21,29],["H3069","GOD",30,33],["H6547","Behold, I am against Pharaoh",35,63],["H4428","king",64,68],["H4714","of Egypt",69,77],["H7665","and will break",79,93],["H2220","his arms",94,102],["H2389","the strong",104,114],["H7665","and that which was broken",116,141],["H2719","and I will cause the sword",143,169],["H5307","to fall",170,177],["H3027","out of his hand",178,193]]},"30:23":{"text":"And I will scatter the Egyptians among the nations, and will disperse them through the countries.","words":[["H6327","And I will scatter",0,18],["H4714","the Egyptians",19,32],["H1471","among the nations",33,50],["H2219","and will disperse",52,69],["H0776","them through the countries",70,96]]},"30:24":{"text":"And I will strengthen the arms of the king of Babylon, and put my sword in his hand: but I will break Pharaoh's arms, and he shall groan before him with the groanings of a deadly wounded man.","words":[["H2388","And I will strengthen",0,21],["H2220","the arms",22,30],["H4428","of the king",31,42],["H0894","of Babylon",43,53],["H5414","and put",55,62],["H2719","my sword",63,71],["H3027","in his hand",72,83],["H7665","but I will break",85,101],["H6547","Pharaoh's",102,111],["H2220","arms",112,116],["H5008","and he shall groan",118,136],["H6440","before",137,143],["H5009","him with the groanings",144,166],["H2491","of a deadly wounded",167,186]]},"30:25":{"text":"But I will strengthen the arms of the king of Babylon, and the arms of Pharaoh shall fall down; and they shall know that I am the LORD, when I shall put my sword into the hand of the king of Babylon, and he shall stretch it out upon the land of Egypt.","words":[["H2388","But I will strengthen",0,21],["H2220","the arms",22,30],["H4428","of the king",31,42],["H0894","of Babylon",43,53],["H2220","and the arms",55,67],["H6547","of Pharaoh",68,78],["H5307","shall fall down",79,94],["H3045","and they shall know",96,115],["H3068","that I am the LORD",116,134],["H5414","when I shall put",136,152],["H2719","my sword",153,161],["H3027","into the hand",162,175],["H4428","of the king",176,187],["H0894","of Babylon",188,198],["H5186","and he shall stretch it out",200,227],["H0776","upon the land",228,241],["H4714","of Egypt",242,250]]},"30:26":{"text":"And I will scatter the Egyptians among the nations, and disperse them among the countries; and they shall know that I am the LORD.","words":[["H6327","And I will scatter",0,18],["H4714","the Egyptians",19,32],["H1471","among the nations",33,50],["H2219","and disperse",52,64],["H0776","them among the countries",65,89],["H3045","and they shall know",91,110],["H3068","that I am the LORD",111,129]]},"31:1":{"text":"And it came to pass in the eleventh year, in the third month, in the first day of the month, that the word of the LORD came unto me, saying,","words":[["H0259","And it came to pass in the eleventh",0,35],["H6240","And it came to pass in the eleventh",0,35],["H8141","year",36,40],["H7992","in the third",42,54],["H0259","month, in the first",55,74],["H2320","day of the month",75,91],["H1697","that the word",93,106],["H3068","of the LORD",107,118],["H0559","came unto me, saying",119,139]]},"31:2":{"text":"Son of man, speak unto Pharaoh king of Egypt, and to his multitude; Whom art thou like in thy greatness?","words":[["H1121","Son",0,3],["H0120","of man",4,10],["H0559","speak",12,17],["H6547","unto Pharaoh",18,30],["H4428","king",31,35],["H4714","of Egypt",36,44],["H1995","and to his multitude",46,66],["H1819","Whom art thou like",68,86],["H1433","in thy greatness",87,103]]},"31:3":{"text":"Behold, the Assyrian was a cedar in Lebanon with fair branches, and with a shadowing shroud, and of an high stature; and his top was among the thick boughs.","words":[["H0804","Behold, the Assyrian",0,20],["H0730","was a cedar",21,32],["H3844","in Lebanon",33,43],["H3303","with fair",44,53],["H6057","branches",54,62],["H6751","and with a shadowing",64,84],["H2793","shroud",85,91],["H1362","and of an high",93,107],["H6967","stature",108,115],["H6788","and his top",117,128],["H5688","was among the thick boughs",129,155]]},"31:4":{"text":"The waters made him great, the deep set him up on high with her rivers running round about his plants, and sent out her little rivers unto all the trees of the field.","words":[["H4325","The waters",0,10],["H1431","made him great",11,25],["H8415","the deep",27,35],["H7311","set him up on high",36,54],["H5104","with her rivers",55,70],["H1980","running",71,78],["H5439","round about",79,90],["H4302","his plants",91,101],["H7971","and sent out",103,115],["H8585","her little rivers",116,133],["H6086","unto all the trees",134,152],["H7704","of the field",153,165]]},"31:5":{"text":"Therefore his height was exalted above all the trees of the field, and his boughs were multiplied, and his branches became long because of the multitude of waters, when he shot forth.","words":[["H6967","Therefore his height",0,20],["H1361","was exalted",21,32],["H6086","above all the trees",33,52],["H7704","of the field",53,65],["H5634","and his boughs",67,81],["H7235","were multiplied",82,97],["H6288","and his branches",99,115],["H0748","became long",116,127],["H7227","because of the multitude",128,152],["H4325","of waters",153,162],["H7971","when he shot forth",164,182]]},"31:6":{"text":"All the fowls of heaven made their nests in his boughs, and under his branches did all the beasts of the field bring forth their young, and under his shadow dwelt all great nations.","words":[["H5775","All the fowls",0,13],["H8064","of heaven",14,23],["H7077","made their nests",24,40],["H5589","in his boughs",41,54],["H6288","and under his branches",56,78],["H2416","did all the beasts",79,97],["H7704","of the field",98,110],["H3205","bring forth their young",111,134],["H6738","and under his shadow",136,156],["H3427","dwelt",157,162],["H7227","all great",163,172],["H1471","nations",173,180]]},"31:7":{"text":"Thus was he fair in his greatness, in the length of his branches: for his root was by great waters.","words":[["H3302","Thus was he fair",0,16],["H1433","in his greatness",17,33],["H0753","in the length",35,48],["H1808","of his branches",49,64],["H8328","for his root",66,78],["H7227","was by great",79,91],["H4325","waters",92,98]]},"31:8":{"text":"The cedars in the garden of God could not hide him: the fir trees were not like his boughs, and the chesnut trees were not like his branches; nor any tree in the garden of God was like unto him in his beauty.","words":[["H0730","The cedars",0,10],["H1588","in the garden",11,24],["H0430","of God",25,31],["H6004","could not hide",32,46],["H1265","him: the fir trees",47,65],["H1819","were not like",66,79],["H5589","his boughs",80,90],["H6196","and the chesnut trees",92,113],["H6288","were not like his branches",114,140],["H6086","nor any tree",142,154],["H1588","in the garden",155,168],["H0430","of God",169,175],["H1819","was like",176,184],["H3308","unto him in his beauty",185,207]]},"31:9":{"text":"I have made him fair by the multitude of his branches: so that all the trees of Eden, that were in the garden of God, envied him.","words":[["H6213","I have made",0,11],["H3303","him fair",12,20],["H7230","by the multitude",21,37],["H1808","of his branches",38,53],["H6086","so that all the trees",55,76],["H5731","of Eden",77,84],["H1588","that were in the garden",86,109],["H0430","of God",110,116],["H7065","envied",118,124]]},"31:10":{"text":"Therefore thus saith the Lord GOD; Because thou hast lifted up thyself in height, and he hath shot up his top among the thick boughs, and his heart is lifted up in his height;","words":[["H0559","Therefore thus saith",0,20],["H0136","the Lord",21,29],["H3069","GOD",30,33],["H1361","Because thou hast lifted up",35,62],["H6967","thyself in height",63,80],["H5414","and he hath shot up",82,101],["H6788","his top",102,109],["H5688","among the thick boughs",110,132],["H3824","and his heart",134,147],["H7311","is lifted up",148,160],["H1363","in his height",161,174]]},"31:11":{"text":"I have therefore delivered him into the hand of the mighty one of the heathen; he shall surely deal with him: I have driven him out for his wickedness.","words":[["H5414","I have therefore delivered",0,26],["H3027","him into the hand",27,44],["H0410","of the mighty one",45,62],["H1471","of the heathen",63,77],["H6213","he shall surely",79,94],["H6213","deal",95,99],["H1644","with him: I have driven him out",100,131],["H7562","for his wickedness",132,150]]},"31:12":{"text":"And strangers, the terrible of the nations, have cut him off, and have left him: upon the mountains and in all the valleys his branches are fallen, and his boughs are broken by all the rivers of the land; and all the people of the earth are gone down from his shadow, and have left him.","words":[["H2114","And strangers",0,13],["H6184","the terrible",15,27],["H1471","of the nations",28,42],["H3772","have cut him off",44,60],["H5203","and have left",62,75],["H2022","him: upon the mountains",76,99],["H1516","and in all the valleys",100,122],["H1808","his branches",123,135],["H5307","are fallen",136,146],["H6288","and his boughs",148,162],["H7665","are broken",163,173],["H0650","by all the rivers",174,191],["H0776","of the land",192,203],["H5971","and all the people",205,223],["H0776","of the earth",224,236],["H3381","are gone down",237,250],["H6738","from his shadow",251,266],["H5203","and have left",268,281]]},"31:13":{"text":"Upon his ruin shall all the fowls of the heaven remain, and all the beasts of the field shall be upon his branches:","words":[["H4658","Upon his ruin",0,13],["H5775","shall all the fowls",14,33],["H8064","of the heaven",34,47],["H7931","remain",48,54],["H2416","and all the beasts",56,74],["H7704","of the field",75,87],["H6288","shall be upon his branches",88,114]]},"31:14":{"text":"To the end that none of all the trees by the waters exalt themselves for their height, neither shoot up their top among the thick boughs, neither their trees stand up in their height, all that drink water: for they are all delivered unto death, to the nether parts of the earth, in the midst of the children of men, with them that go down to the pit.","words":[["H6086","To the end that none of all the trees",0,37],["H4325","by the waters",38,51],["H1361","exalt",52,57],["H6967","themselves for their height",58,85],["H5414","neither shoot up",87,103],["H6788","their top",104,113],["H5688","among the thick boughs",114,136],["H0352","neither their trees",138,157],["H5975","stand up",158,166],["H1363","in their height",167,182],["H8354","all that drink",184,198],["H4325","water",199,204],["H5414","for they are all delivered",206,232],["H4194","unto death",233,243],["H8482","to the nether parts",245,264],["H0776","of the earth",265,277],["H8432","in the midst",279,291],["H1121","of the children",292,307],["H0120","of men",308,314],["H3381","with them that go down",316,338],["H0953","to the pit",339,349]]},"31:15":{"text":"Thus saith the Lord GOD; In the day when he went down to the grave I caused a mourning: I covered the deep for him, and I restrained the floods thereof, and the great waters were stayed: and I caused Lebanon to mourn for him, and all the trees of the field fainted for him.","words":[["H0559","Thus saith",0,10],["H0136","the Lord",11,19],["H3069","GOD",20,23],["H3117","In the day",25,35],["H3381","when he went down",36,53],["H7585","to the grave",54,66],["H0056","I caused a mourning",67,86],["H3680","I covered",88,97],["H8415","the deep",98,106],["H4513","for him, and I restrained",107,132],["H5104","the floods",133,143],["H7227","thereof, and the great",144,166],["H4325","waters",167,173],["H3607","were stayed",174,185],["H3844","and I caused Lebanon",187,207],["H6937","to mourn",208,216],["H6086","for him, and all the trees",217,243],["H7704","of the field",244,256],["H5969","fainted",257,264]]},"31:16":{"text":"I made the nations to shake at the sound of his fall, when I cast him down to hell with them that descend into the pit: and all the trees of Eden, the choice and best of Lebanon, all that drink water, shall be comforted in the nether parts of the earth.","words":[["H1471","I made the nations",0,18],["H7493","to shake",19,27],["H6963","at the sound",28,40],["H4658","of his fall",41,52],["H3381","when I cast him down",54,74],["H7585","to hell",75,82],["H3381","with them that descend",83,105],["H0953","into the pit",106,118],["H6086","and all the trees",120,137],["H5731","of Eden",138,145],["H4005","the choice",147,157],["H2896","and best",158,166],["H3844","of Lebanon",167,177],["H8354","all that drink",179,193],["H4325","water",194,199],["H5162","shall be comforted",201,219],["H8482","in the nether parts",220,239],["H0776","of the earth",240,252]]},"31:17":{"text":"They also went down into hell with him unto them that be slain with the sword; and they that were his arm, that dwelt under his shadow in the midst of the heathen.","words":[["H3381","They also went down",0,19],["H7585","into hell",20,29],["H2491","with him unto them that be slain",30,62],["H2719","with the sword",63,77],["H2220","and they that were his arm",79,105],["H3427","that dwelt",107,117],["H6738","under his shadow",118,134],["H8432","in the midst",135,147],["H1471","of the heathen",148,162]]},"31:18":{"text":"To whom art thou thus like in glory and in greatness among the trees of Eden? yet shalt thou be brought down with the trees of Eden unto the nether parts of the earth: thou shalt lie in the midst of the uncircumcised with them that be slain by the sword. This is Pharaoh and all his multitude, saith the Lord GOD.","words":[["H1819","To whom art thou thus like",0,26],["H3519","in glory",27,35],["H1433","and in greatness",36,52],["H6086","among the trees",53,68],["H5731","of Eden",69,76],["H3381","yet shalt thou be brought down",78,108],["H6086","with the trees",109,123],["H5731","of Eden",124,131],["H8482","unto the nether parts",132,153],["H0776","of the earth",154,166],["H7901","thou shalt lie",168,182],["H8432","in the midst",183,195],["H6189","of the uncircumcised",196,216],["H2491","with them that be slain",217,240],["H2719","by the sword",241,253],["H6547","This is Pharaoh",255,270],["H1995","and all his multitude",271,292],["H5002","saith",294,299],["H0136","the Lord",300,308],["H3069","GOD",309,312]]},"32:1":{"text":"And it came to pass in the twelfth year, in the twelfth month, in the first day of the month, that the word of the LORD came unto me, saying,","words":[["H8147","And it came to pass in the twelfth",0,34],["H6240","And it came to pass in the twelfth",0,34],["H8141","year",35,39],["H2320","in the twelfth month",41,61],["H0259","in the first",63,75],["H2320","day of the month",76,92],["H1697","that the word",94,107],["H3068","of the LORD",108,119],["H0559","came unto me, saying",120,140]]},"32:2":{"text":"Son of man, take up a lamentation for Pharaoh king of Egypt, and say unto him, Thou art like a young lion of the nations, and thou art as a whale in the seas: and thou camest forth with thy rivers, and troubledst the waters with thy feet, and fouledst their rivers.","words":[["H1121","Son",0,3],["H0120","of man",4,10],["H5375","take up",12,19],["H7015","a lamentation",20,33],["H6547","for Pharaoh",34,45],["H4428","king",46,50],["H4714","of Egypt",51,59],["H0559","and say",61,68],["H1819","unto him, Thou art like",69,92],["H3715","a young lion",93,105],["H1471","of the nations",106,120],["H8577","and thou art as a whale",122,145],["H8565","and thou art as a whale",122,145],["H3220","in the seas",146,157],["H1518","and thou camest forth",159,180],["H5104","with thy rivers",181,196],["H1804","and troubledst",198,212],["H4325","the waters",213,223],["H7272","with thy feet",224,237],["H7515","and fouledst",239,251],["H5104","their rivers",252,264]]},"32:3":{"text":"Thus saith the Lord GOD; I will therefore spread out my net over thee with a company of many people; and they shall bring thee up in my net.","words":[["H0559","Thus saith",0,10],["H0136","the Lord",11,19],["H3069","GOD",20,23],["H6566","I will therefore spread out",25,52],["H7568","my net",53,59],["H6951","over thee with a company",60,84],["H7227","of many",85,92],["H5971","people",93,99],["H5927","and they shall bring thee up",101,129],["H2764","in my net",130,139]]},"32:4":{"text":"Then will I leave thee upon the land, I will cast thee forth upon the open field, and will cause all the fowls of the heaven to remain upon thee, and I will fill the beasts of the whole earth with thee.","words":[["H5203","Then will I leave",0,17],["H0776","thee upon the land",18,36],["H2904","I will cast thee forth",38,60],["H6440","upon the open",61,74],["H7704","field",75,80],["H5775","and will cause all the fowls",82,110],["H8064","of the heaven",111,124],["H7931","to remain",125,134],["H7646","upon thee, and I will fill",135,161],["H2416","the beasts",162,172],["H0776","of the whole earth",173,191]]},"32:5":{"text":"And I will lay thy flesh upon the mountains, and fill the valleys with thy height.","words":[["H5414","And I will lay",0,14],["H1320","thy flesh",15,24],["H2022","upon the mountains",25,43],["H4390","and fill",45,53],["H1516","the valleys",54,65],["H7419","with thy height",66,81]]},"32:6":{"text":"I will also water with thy blood the land wherein thou swimmest, even to the mountains; and the rivers shall be full of thee.","words":[["H8248","I will also water",0,17],["H1818","with thy blood",18,32],["H0776","the land",33,41],["H6824","wherein thou swimmest",42,63],["H2022","even to the mountains",65,86],["H0650","and the rivers",88,102],["H4390","shall be full",103,116]]},"32:7":{"text":"And when I shall put thee out, I will cover the heaven, and make the stars thereof dark; I will cover the sun with a cloud, and the moon shall not give her light.","words":[["H3518","And when I shall put thee out",0,29],["H3680","I will cover",31,43],["H8064","the heaven",44,54],["H6937","and make",56,64],["H3556","the stars",65,74],["H6937","thereof dark",75,87],["H3680","I will cover",89,101],["H8121","the sun",102,109],["H6051","with a cloud",110,122],["H3394","and the moon",124,136],["H0215","shall not give",137,151],["H0216","her light",152,161]]},"32:8":{"text":"All the bright lights of heaven will I make dark over thee, and set darkness upon thy land, saith the Lord GOD.","words":[["H3974","All the bright",0,14],["H0216","lights",15,21],["H8064","of heaven",22,31],["H6937","will I make dark",32,48],["H5414","over thee, and set",49,67],["H2822","darkness",68,76],["H0776","upon thy land",77,90],["H5002","saith",92,97],["H0136","the Lord",98,106],["H3069","GOD",107,110]]},"32:9":{"text":"I will also vex the hearts of many people, when I shall bring thy destruction among the nations, into the countries which thou hast not known.","words":[["H3707","I will also vex",0,15],["H3820","the hearts",16,26],["H7227","of many",27,34],["H5971","people",35,41],["H0935","when I shall bring",43,61],["H7667","thy destruction",62,77],["H1471","among the nations",78,95],["H0776","into the countries",97,115],["H3045","which thou hast not known",116,141]]},"32:10":{"text":"Yea, I will make many people amazed at thee, and their kings shall be horribly afraid for thee, when I shall brandish my sword before them; and they shall tremble at every moment, every man for his own life, in the day of thy fall.","words":[["H7227","Yea, I will make many",0,21],["H5971","people",22,28],["H8074","amazed",29,35],["H4428","at thee, and their kings",36,60],["H8178","shall be horribly",61,78],["H8175","afraid",79,85],["H5774","for thee, when I shall brandish",86,117],["H2719","my sword",118,126],["H6440","before them",127,138],["H2729","and they shall tremble",140,162],["H7281","at every moment",163,178],["H0376","every man",180,189],["H5315","for his own life",190,206],["H3117","in the day",208,218],["H4658","of thy fall",219,230]]},"32:11":{"text":"For thus saith the Lord GOD; The sword of the king of Babylon shall come upon thee.","words":[["H0559","For thus saith",0,14],["H0136","the Lord",15,23],["H3069","GOD",24,27],["H2719","The sword",29,38],["H4428","of the king",39,50],["H0894","of Babylon",51,61],["H0935","shall come",62,72]]},"32:12":{"text":"By the swords of the mighty will I cause thy multitude to fall, the terrible of the nations, all of them: and they shall spoil the pomp of Egypt, and all the multitude thereof shall be destroyed.","words":[["H2719","By the swords",0,13],["H1368","of the mighty",14,27],["H1995","will I cause thy multitude",28,54],["H5307","to fall",55,62],["H6184","the terrible",64,76],["H1471","of the nations",77,91],["H7703","all of them: and they shall spoil",93,126],["H1347","the pomp",127,135],["H4714","of Egypt",136,144],["H1995","and all the multitude",146,167],["H8045","thereof shall be destroyed",168,194]]},"32:13":{"text":"I will destroy also all the beasts thereof from beside the great waters; neither shall the foot of man trouble them any more, nor the hoofs of beasts trouble them.","words":[["H0006","I will destroy",0,14],["H0929","also all the beasts",15,34],["H5921","thereof from",35,47],["H7227","beside the great",48,64],["H4325","waters",65,71],["H7272","neither shall the foot",73,95],["H0120","of man",96,102],["H1804","trouble",103,110],["H6541","them any more, nor the hoofs",111,139],["H0929","of beasts",140,149],["H1804","trouble",150,157]]},"32:14":{"text":"Then will I make their waters deep, and cause their rivers to run like oil, saith the Lord GOD.","words":[["H4325","Then will I make their waters",0,29],["H8257","deep",30,34],["H5104","and cause their rivers",36,58],["H3212","to run",59,65],["H8081","like oil",66,74],["H5002","saith",76,81],["H0136","the Lord",82,90],["H3069","GOD",91,94]]},"32:15":{"text":"When I shall make the land of Egypt desolate, and the country shall be destitute of that whereof it was full, when I shall smite all them that dwell therein, then shall they know that I am the LORD.","words":[["H5414","When I shall make",0,17],["H0776","the land",18,26],["H4714","of Egypt",27,35],["H8077","desolate",36,44],["H0776","and the country",46,61],["H8074","shall be destitute",62,80],["H4393","of that whereof it was full",81,108],["H5221","when I shall smite",110,128],["H3427","all them that dwell",129,148],["H3045","therein, then shall they know",149,178],["H3068","that I am the LORD",179,197]]},"32:16":{"text":"This is the lamentation wherewith they shall lament her: the daughters of the nations shall lament her: they shall lament for her, even for Egypt, and for all her multitude, saith the Lord GOD.","words":[["H7015","This is the lamentation",0,23],["H6969","wherewith they shall lament",24,51],["H1323","her: the daughters",52,70],["H1471","of the nations",71,85],["H6969","shall lament",86,98],["H6969","her: they shall lament",99,121],["H4714","for her, even for Egypt",122,145],["H1995","and for all her multitude",147,172],["H5002","saith",174,179],["H0136","the Lord",180,188],["H3069","GOD",189,192]]},"32:17":{"text":"It came to pass also in the twelfth year, in the fifteenth day of the month, that the word of the LORD came unto me, saying,","words":[["H8147","It came to pass also in the twelfth",0,35],["H6240","It came to pass also in the twelfth",0,35],["H8141","year",36,40],["H2568","in the fifteenth",42,58],["H6240","in the fifteenth",42,58],["H2320","day of the month",59,75],["H1697","that the word",77,90],["H3068","of the LORD",91,102],["H0559","came unto me, saying",103,123]]},"32:18":{"text":"Son of man, wail for the multitude of Egypt, and cast them down, even her, and the daughters of the famous nations, unto the nether parts of the earth, with them that go down into the pit.","words":[["H1121","Son",0,3],["H0120","of man",4,10],["H5091","wail",12,16],["H1995","for the multitude",17,34],["H4714","of Egypt",35,43],["H3381","and cast them down",45,63],["H1323","even her, and the daughters",65,92],["H0117","of the famous",93,106],["H1471","nations",107,114],["H8482","unto the nether parts",116,137],["H0776","of the earth",138,150],["H3381","with them that go down",152,174],["H0953","into the pit",175,187]]},"32:19":{"text":"Whom dost thou pass in beauty? go down, and be thou laid with the uncircumcised.","words":[["H5276","Whom dost thou pass in beauty",0,29],["H3381","go down",31,38],["H7901","and be thou laid",40,56],["H6189","with the uncircumcised",57,79]]},"32:20":{"text":"They shall fall in the midst of them that are slain by the sword: she is delivered to the sword: draw her and all her multitudes.","words":[["H5307","They shall fall",0,15],["H8432","in the midst",16,28],["H2491","of them that are slain",29,51],["H2719","by the sword",52,64],["H5414","she is delivered",66,82],["H2719","to the sword",83,95],["H4900","draw",97,101],["H1995","her and all her multitudes",102,128]]},"32:21":{"text":"The strong among the mighty shall speak to him out of the midst of hell with them that help him: they are gone down, they lie uncircumcised, slain by the sword.","words":[["H0410","The strong",0,10],["H1368","among the mighty",11,27],["H1696","shall speak",28,39],["H8432","to him out of the midst",40,63],["H7585","of hell",64,71],["H5826","with them that help",72,91],["H3381","him: they are gone down",92,115],["H7901","they lie",117,125],["H6189","uncircumcised",126,139],["H2491","slain",141,146],["H2719","by the sword",147,159]]},"32:22":{"text":"Asshur is there and all her company: his graves are about him: all of them slain, fallen by the sword:","words":[["H0804","Asshur",0,6],["H6951","is there and all her company",7,35],["H6913","his graves",37,47],["H5439","are about",48,57],["H2491","him: all of them slain",58,80],["H5307","fallen",82,88],["H2719","by the sword",89,101]]},"32:23":{"text":"Whose graves are set in the sides of the pit, and her company is round about her grave: all of them slain, fallen by the sword, which caused terror in the land of the living.","words":[["H6913","Whose graves",0,12],["H5414","are set",13,20],["H3411","in the sides",21,33],["H0953","of the pit",34,44],["H6951","and her company",46,61],["H5439","is round about",62,76],["H6900","her grave",77,86],["H2491","all of them slain",88,105],["H5307","fallen",107,113],["H2719","by the sword",114,126],["H5414","which caused",128,140],["H2851","terror",141,147],["H0776","in the land",148,159],["H2416","of the living",160,173]]},"32:24":{"text":"There is Elam and all her multitude round about her grave, all of them slain, fallen by the sword, which are gone down uncircumcised into the nether parts of the earth, which caused their terror in the land of the living; yet have they borne their shame with them that go down to the pit.","words":[["H5867","There is Elam",0,13],["H1995","and all her multitude",14,35],["H5439","round about",36,47],["H6900","her grave",48,57],["H2491","all of them slain",59,76],["H5307","fallen",78,84],["H2719","by the sword",85,97],["H3381","which are gone down",99,118],["H6189","uncircumcised",119,132],["H8482","into the nether parts",133,154],["H0776","of the earth",155,167],["H5414","which caused",169,181],["H2851","their terror",182,194],["H0776","in the land",195,206],["H2416","of the living",207,220],["H5375","yet have they borne",222,241],["H3639","their shame",242,253],["H3381","with them that go down",254,276],["H0953","to the pit",277,287]]},"32:25":{"text":"They have set her a bed in the midst of the slain with all her multitude: her graves are round about him: all of them uncircumcised, slain by the sword: though their terror was caused in the land of the living, yet have they borne their shame with them that go down to the pit: he is put in the midst of them that be slain.","words":[["H5414","They have set",0,13],["H4904","her a bed",14,23],["H8432","in the midst",24,36],["H2491","of the slain",37,49],["H1995","with all her multitude",50,72],["H6913","her graves",74,84],["H5439","are round about",85,100],["H6189","him: all of them uncircumcised",101,131],["H2491","slain",133,138],["H2719","by the sword",139,151],["H2851","though their terror",153,172],["H5414","was caused",173,183],["H0776","in the land",184,195],["H2416","of the living",196,209],["H5375","yet have they borne",211,230],["H3639","their shame",231,242],["H3381","with them that go down",243,265],["H0953","to the pit",266,276],["H5414","he is put",278,287],["H8432","in the midst",288,300],["H2491","of them that be slain",301,322]]},"32:26":{"text":"There is Meshech, Tubal, and all her multitude: her graves are round about him: all of them uncircumcised, slain by the sword, though they caused their terror in the land of the living.","words":[["H4902","There is Meshech",0,16],["H8422","Tubal",18,23],["H1995","and all her multitude",25,46],["H6913","her graves",48,58],["H5439","are round about",59,74],["H6189","him: all of them uncircumcised",75,105],["H2490","slain",107,112],["H2719","by the sword",113,125],["H5414","though they caused",127,145],["H2851","their terror",146,158],["H0776","in the land",159,170],["H2416","of the living",171,184]]},"32:27":{"text":"And they shall not lie with the mighty that are fallen of the uncircumcised, which are gone down to hell with their weapons of war: and they have laid their swords under their heads, but their iniquities shall be upon their bones, though they were the terror of the mighty in the land of the living.","words":[["H7901","And they shall not lie",0,22],["H1368","with the mighty",23,38],["H5307","that are fallen",39,54],["H6189","of the uncircumcised",55,75],["H3381","which are gone down",77,96],["H7585","to hell",97,104],["H3627","with their weapons",105,123],["H4421","of war",124,130],["H5414","and they have laid",132,150],["H2719","their swords",151,163],["H7218","under their heads",164,181],["H5771","but their iniquities",183,203],["H6106","shall be upon their bones",204,229],["H2851","though they were the terror",231,258],["H1368","of the mighty",259,272],["H0776","in the land",273,284],["H2416","of the living",285,298]]},"32:28":{"text":"Yea, thou shalt be broken in the midst of the uncircumcised, and shalt lie with them that are slain with the sword.","words":[["H7665","Yea, thou shalt be broken",0,25],["H8432","in the midst",26,38],["H6189","of the uncircumcised",39,59],["H7901","and shalt lie",61,74],["H2491","with them that are slain",75,99],["H2719","with the sword",100,114]]},"32:29":{"text":"There is Edom, her kings, and all her princes, which with their might are laid by them that were slain by the sword: they shall lie with the uncircumcised, and with them that go down to the pit.","words":[["H0123","There is Edom",0,13],["H4428","her kings",15,24],["H5387","and all her princes",26,45],["H1369","which with their might",47,69],["H5414","are laid",70,78],["H2491","by them that were slain",79,102],["H2719","by the sword",103,115],["H7901","they shall lie",117,131],["H6189","with the uncircumcised",132,154],["H3381","and with them that go down",156,182],["H0953","to the pit",183,193]]},"32:30":{"text":"There be the princes of the north, all of them, and all the Zidonians, which are gone down with the slain; with their terror they are ashamed of their might; and they lie uncircumcised with them that be slain by the sword, and bear their shame with them that go down to the pit.","words":[["H5257","There be the princes",0,20],["H6828","of the north",21,33],["H6722","all of them, and all the Zidonians",35,69],["H3381","which are gone down",71,90],["H2491","with the slain",91,105],["H2851","with their terror",107,124],["H0954","they are ashamed",125,141],["H1369","of their might",142,156],["H7901","and they lie",158,170],["H6189","uncircumcised",171,184],["H2491","with them that be slain",185,208],["H2719","by the sword",209,221],["H5375","and bear",223,231],["H3639","their shame",232,243],["H3381","with them that go down",244,266],["H0953","to the pit",267,277]]},"32:31":{"text":"Pharaoh shall see them, and shall be comforted over all his multitude, even Pharaoh and all his army slain by the sword, saith the Lord GOD.","words":[["H6547","Pharaoh",0,7],["H7200","shall see",8,17],["H5162","them, and shall be comforted",18,46],["H1995","over all his multitude",47,69],["H6547","even Pharaoh",71,83],["H2428","and all his army",84,100],["H2491","slain",101,106],["H2719","by the sword",107,119],["H5002","saith",121,126],["H0136","the Lord",127,135],["H3069","GOD",136,139]]},"32:32":{"text":"For I have caused my terror in the land of the living: and he shall be laid in the midst of the uncircumcised with them that are slain with the sword, even Pharaoh and all his multitude, saith the Lord GOD.","words":[["H5414","For I have caused",0,17],["H2851","my terror",18,27],["H0776","in the land",28,39],["H2416","of the living",40,53],["H7901","and he shall be laid",55,75],["H8432","in the midst",76,88],["H6189","of the uncircumcised",89,109],["H2491","with them that are slain",110,134],["H2719","with the sword",135,149],["H6547","even Pharaoh",151,163],["H1995","and all his multitude",164,185],["H5002","saith",187,192],["H0136","the Lord",193,201],["H3069","GOD",202,205]]},"33:1":{"text":"Again the word of the LORD came unto me, saying,","words":[["H1697","Again the word",0,14],["H3068","of the LORD",15,26],["H0559","came unto me, saying",27,47]]},"33:2":{"text":"Son of man, speak to the children of thy people, and say unto them, When I bring the sword upon a land, if the people of the land take a man of their coasts, and set him for their watchman:","words":[["H1121","Son",0,3],["H0120","of man",4,10],["H1696","speak",12,17],["H1121","to the children",18,33],["H5971","of thy people",34,47],["H0559","and say",49,56],["H0935","unto them, When I bring",57,80],["H2719","the sword",81,90],["H0776","upon a land",91,102],["H5971","if the people",104,117],["H0776","of the land",118,129],["H3947","take",130,134],["H0259","a",135,136],["H0376","man",137,140],["H7097","of their coasts",141,156],["H5414","and set",158,165],["H6822","him for their watchman",166,188]]},"33:3":{"text":"If when he seeth the sword come upon the land, he blow the trumpet, and warn the people;","words":[["H7200","If when he seeth",0,16],["H2719","the sword",17,26],["H0935","come",27,31],["H0776","upon the land",32,45],["H8628","he blow",47,54],["H7782","the trumpet",55,66],["H2094","and warn",68,76],["H5971","the people",77,87]]},"33:4":{"text":"Then whosoever heareth the sound of the trumpet, and taketh not warning; if the sword come, and take him away, his blood shall be upon his own head.","words":[["H8085","Then whosoever",0,14],["H8085","heareth",15,22],["H6963","the sound",23,32],["H7782","of the trumpet",33,47],["H2094","and taketh not warning",49,71],["H2719","if the sword",73,85],["H0935","come",86,90],["H3947","and take him away",92,109],["H1818","his blood",111,120],["H7218","shall be upon his own head",121,147]]},"33:5":{"text":"He heard the sound of the trumpet, and took not warning; his blood shall be upon him. But he that taketh warning shall deliver his soul.","words":[["H8085","He heard",0,8],["H6963","the sound",9,18],["H7782","of the trumpet",19,33],["H2094","and took not warning",35,55],["H1818","his blood",57,66],["H2094","shall be upon him. But he that taketh warning",67,112],["H4422","shall deliver",113,126],["H5315","his soul",127,135]]},"33:6":{"text":"But if the watchman see the sword come, and blow not the trumpet, and the people be not warned; if the sword come, and take any person from among them, he is taken away in his iniquity; but his blood will I require at the watchman's hand.","words":[["H6822","But if the watchman",0,19],["H7200","see",20,23],["H2719","the sword",24,33],["H0935","come",34,38],["H8628","and blow",40,48],["H7782","not the trumpet",49,64],["H5971","and the people",66,80],["H2094","be not warned",81,94],["H2719","if the sword",96,108],["H0935","come",109,113],["H3947","and take",115,123],["H5315","any person",124,134],["H3947","from among them, he is taken away",135,168],["H5771","in his iniquity",169,184],["H1818","but his blood",186,199],["H1875","will I require",200,214],["H6822","at the watchman's",215,232],["H3027","hand",233,237]]},"33:7":{"text":"So thou, O son of man, I have set thee a watchman unto the house of Israel; therefore thou shalt hear the word at my mouth, and warn them from me.","words":[["H1121","So thou, O son",0,14],["H0120","of man",15,21],["H5414","I have set",23,33],["H6822","thee a watchman",34,49],["H1004","unto the house",50,64],["H3478","of Israel",65,74],["H8085","therefore thou shalt hear",76,101],["H1697","the word",102,110],["H6310","at my mouth",111,122],["H2094","and warn",124,132]]},"33:8":{"text":"When I say unto the wicked, O wicked man, thou shalt surely die; if thou dost not speak to warn the wicked from his way, that wicked man shall die in his iniquity; but his blood will I require at thine hand.","words":[["H0559","When I say",0,10],["H7563","unto the wicked",11,26],["H7563","O wicked",28,36],["H4191","man, thou shalt surely",37,59],["H4191","die",60,63],["H1696","if thou dost not speak",65,87],["H2094","to warn",88,95],["H7563","the wicked",96,106],["H1870","from his way",107,119],["H7563","that wicked",121,132],["H4191","man shall die",133,146],["H5771","in his iniquity",147,162],["H1818","but his blood",164,177],["H1245","will I require",178,192],["H3027","at thine hand",193,206]]},"33:9":{"text":"Nevertheless, if thou warn the wicked of his way to turn from it; if he do not turn from his way, he shall die in his iniquity; but thou hast delivered thy soul.","words":[["H2094","Nevertheless, if thou warn",0,26],["H7563","the wicked",27,37],["H1870","of his way",38,48],["H7725","to turn",49,56],["H7725","from it; if he do not turn",57,83],["H1870","from his way",84,96],["H4191","he shall die",98,110],["H5771","in his iniquity",111,126],["H5337","but thou hast delivered",128,151],["H5315","thy soul",152,160]]},"33:10":{"text":"Therefore, O thou son of man, speak unto the house of Israel; Thus ye speak, saying, If our transgressions and our sins be upon us, and we pine away in them, how should we then live?","words":[["H1121","Therefore, O thou son",0,21],["H0120","of man",22,28],["H0559","speak",30,35],["H1004","unto the house",36,50],["H3478","of Israel",51,60],["H0559","Thus ye speak",62,75],["H0559","saying",77,83],["H6588","If our transgressions",85,106],["H2403","and our sins",107,119],["H4743","be upon us, and we pine away",120,148],["H2421","in them, how should we then live",149,181]]},"33:11":{"text":"Say unto them, As I live, saith the Lord GOD, I have no pleasure in the death of the wicked; but that the wicked turn from his way and live: turn ye, turn ye from your evil ways; for why will ye die, O house of Israel?","words":[["H0559","Say",0,3],["H2416","unto them, As I live",4,24],["H5002","saith",26,31],["H0136","the Lord",32,40],["H3069","GOD",41,44],["H2654","I have no pleasure",46,64],["H4194","in the death",65,77],["H7563","of the wicked",78,91],["H7563","but that the wicked",93,112],["H7725","turn",113,117],["H1870","from his way",118,130],["H2421","and live",131,139],["H7725","turn",141,145],["H7725","ye, turn",146,154],["H7451","ye from your evil",155,172],["H1870","ways",173,177],["H4191","for why will ye die",179,198],["H1004","O house",200,207],["H3478","of Israel",208,217]]},"33:12":{"text":"Therefore, thou son of man, say unto the children of thy people, The righteousness of the righteous shall not deliver him in the day of his transgression: as for the wickedness of the wicked, he shall not fall thereby in the day that he turneth from his wickedness; neither shall the righteous be able to live for his righteousness in the day that he sinneth.","words":[["H1121","Therefore, thou son",0,19],["H0120","of man",20,26],["H0559","say",28,31],["H1121","unto the children",32,49],["H5971","of thy people",50,63],["H6666","The righteousness",65,82],["H6662","of the righteous",83,99],["H5337","shall not deliver",100,117],["H3117","him in the day",118,132],["H6588","of his transgression",133,153],["H7564","as for the wickedness",155,176],["H7563","of the wicked",177,190],["H3782","he shall not fall",192,209],["H3117","thereby in the day",210,228],["H7725","that he turneth",229,244],["H7562","from his wickedness",245,264],["H6662","neither shall the righteous",266,293],["H3201","be able",294,301],["H2421","to live",302,309],["H3117","for his righteousness in the day",310,342],["H2398","that he sinneth",343,358]]},"33:13":{"text":"When I shall say to the righteous, that he shall surely live; if he trust to his own righteousness, and commit iniquity, all his righteousnesses shall not be remembered; but for his iniquity that he hath committed, he shall die for it.","words":[["H0559","When I shall say",0,16],["H6662","to the righteous",17,33],["H2421","that he shall surely",35,55],["H2421","live",56,60],["H0982","if he trust",62,73],["H6666","to his own righteousness",74,98],["H6213","and commit",100,110],["H5766","iniquity",111,119],["H6666","all his righteousnesses",121,144],["H2142","shall not be remembered",145,168],["H5766","but for his iniquity",170,190],["H6213","that he hath committed",191,213],["H4191","he shall die",215,227]]},"33:14":{"text":"Again, when I say unto the wicked, Thou shalt surely die; if he turn from his sin, and do that which is lawful and right;","words":[["H0559","Again, when I say",0,17],["H7563","unto the wicked",18,33],["H4191","Thou shalt surely",35,52],["H4191","die",53,56],["H7725","if he turn",58,68],["H2403","from his sin",69,81],["H6213","and do",83,89],["H4941","that which is lawful",90,110],["H6666","and right",111,120]]},"33:15":{"text":"If the wicked restore the pledge, give again that he had robbed, walk in the statutes of life, without committing iniquity; he shall surely live, he shall not die.","words":[["H7563","If the wicked",0,13],["H7725","restore",14,21],["H2258","the pledge",22,32],["H7999","give again",34,44],["H1500","that he had robbed",45,63],["H1980","walk",65,69],["H2708","in the statutes",70,85],["H2416","of life",86,93],["H6213","without committing",95,113],["H5766","iniquity",114,122],["H2421","he shall surely",124,139],["H2421","live",140,144],["H4191","he shall not die",146,162]]},"33:16":{"text":"None of his sins that he hath committed shall be mentioned unto him: he hath done that which is lawful and right; he shall surely live.","words":[["H2403","None of his sins",0,16],["H2398","that he hath committed",17,39],["H2142","shall be mentioned",40,58],["H6213","unto him: he hath done",59,81],["H4941","that which is lawful",82,102],["H6666","and right",103,112],["H2421","he shall surely",114,129],["H2421","live",130,134]]},"33:17":{"text":"Yet the children of thy people say, The way of the Lord is not equal: but as for them, their way is not equal.","words":[["H1121","Yet the children",0,16],["H5971","of thy people",17,30],["H0559","say",31,34],["H1870","The way",36,43],["H0136","of the Lord",44,55],["H8505","is not equal",56,68],["H1870","but as for them, their way",70,96],["H8505","is not equal",97,109]]},"33:18":{"text":"When the righteous turneth from his righteousness, and committeth iniquity, he shall even die thereby.","words":[["H6662","When the righteous",0,18],["H7725","turneth",19,26],["H6666","from his righteousness",27,49],["H6213","and committeth",51,65],["H5766","iniquity",66,74],["H4191","he shall even die",76,93]]},"33:19":{"text":"But if the wicked turn from his wickedness, and do that which is lawful and right, he shall live thereby.","words":[["H7563","But if the wicked",0,17],["H7725","turn",18,22],["H7564","from his wickedness",23,42],["H6213","and do",44,50],["H4941","that which is lawful",51,71],["H6666","and right",72,81],["H2421","he shall live",83,96]]},"33:20":{"text":"Yet ye say, The way of the Lord is not equal. O ye house of Israel, I will judge you every one after his ways.","words":[["H0559","Yet ye say",0,10],["H1870","The way",12,19],["H0136","of the Lord",20,31],["H8505","is not equal",32,44],["H1004","O ye house",46,56],["H3478","of Israel",57,66],["H8199","I will judge",68,80],["H0376","you every one",81,94],["H1870","after his ways",95,109]]},"33:21":{"text":"And it came to pass in the twelfth year of our captivity, in the tenth month, in the fifth day of the month, that one that had escaped out of Jerusalem came unto me, saying, The city is smitten.","words":[["H8147","And it came to pass in the twelfth",0,34],["H6240","And it came to pass in the twelfth",0,34],["H8141","year",35,39],["H1546","of our captivity",40,56],["H6224","in the tenth",58,70],["H2568","month, in the fifth",71,90],["H2320","day of the month",91,107],["H6412","that one that had escaped",109,134],["H3389","out of Jerusalem",135,151],["H0935","came",152,156],["H0559","unto me, saying",157,172],["H5892","The city",174,182],["H5221","is smitten",183,193]]},"33:22":{"text":"Now the hand of the LORD was upon me in the evening, afore he that was escaped came; and had opened my mouth, until he came to me in the morning; and my mouth was opened, and I was no more dumb.","words":[["H3027","Now the hand",0,12],["H3068","of the LORD",13,24],["H6153","was upon me in the evening",25,51],["H6440","afore",53,58],["H6412","he that was escaped",59,78],["H0935","came",79,83],["H6605","and had opened",85,99],["H6310","my mouth",100,108],["H0935","until he came",110,123],["H1242","to me in the morning",124,144],["H6310","and my mouth",146,158],["H6605","was opened",159,169],["H0481","and I was no more dumb",171,193]]},"33:23":{"text":"Then the word of the LORD came unto me, saying,","words":[["H1697","Then the word",0,13],["H3068","of the LORD",14,25],["H0559","came unto me, saying",26,46]]},"33:24":{"text":"Son of man, they that inhabit those wastes of the land of Israel speak, saying, Abraham was one, and he inherited the land: but we are many; the land is given us for inheritance.","words":[["H1121","Son",0,3],["H0120","of man",4,10],["H3427","they that inhabit",12,29],["H2723","those wastes",30,42],["H0127","of the land",43,54],["H3478","of Israel",55,64],["H0559","speak",65,70],["H0559","saying",72,78],["H0085","Abraham",80,87],["H0259","was one",88,95],["H3423","and he inherited",97,113],["H0776","the land",114,122],["H7227","but we are many",124,139],["H0776","the land",141,149],["H5414","is given",150,158],["H4181","us for inheritance",159,177]]},"33:25":{"text":"Wherefore say unto them, Thus saith the Lord GOD; Ye eat with the blood, and lift up your eyes toward your idols, and shed blood: and shall ye possess the land?","words":[["H0559","Wherefore say",0,13],["H0559","unto them, Thus saith",14,35],["H0136","the Lord",36,44],["H3069","GOD",45,48],["H0398","Ye eat",50,56],["H1818","with the blood",57,71],["H5375","and lift up",73,84],["H5869","your eyes",85,94],["H1544","toward your idols",95,112],["H8210","and shed",114,122],["H1818","blood",123,128],["H3423","and shall ye possess",130,150],["H0776","the land",151,159]]},"33:26":{"text":"Ye stand upon your sword, ye work abomination, and ye defile every one his neighbour's wife: and shall ye possess the land?","words":[["H5975","Ye stand",0,8],["H2719","upon your sword",9,24],["H6213","ye work",26,33],["H8441","abomination",34,45],["H2930","and ye defile",47,60],["H0376","every one",61,70],["H7453","his neighbour's",71,86],["H0802","wife",87,91],["H3423","and shall ye possess",93,113],["H0776","the land",114,122]]},"33:27":{"text":"Say thou thus unto them, Thus saith the Lord GOD; As I live, surely they that are in the wastes shall fall by the sword, and him that is in the open field will I give to the beasts to be devoured, and they that be in the forts and in the caves shall die of the pestilence.","words":[["H0559","Say",0,3],["H0559","thou thus unto them, Thus saith",4,35],["H0136","the Lord",36,44],["H3069","GOD",45,48],["H2416","As I live",50,59],["H2723","surely they that are in the wastes",61,95],["H5307","shall fall",96,106],["H2719","by the sword",107,119],["H6440","and him that is in the open",121,148],["H7704","field",149,154],["H5414","will I give",155,166],["H2416","to the beasts",167,180],["H0398","to be devoured",181,195],["H4679","and they that be in the forts",197,226],["H4631","and in the caves",227,243],["H4191","shall die",244,253],["H1698","of the pestilence",254,271]]},"33:28":{"text":"For I will lay the land most desolate, and the pomp of her strength shall cease; and the mountains of Israel shall be desolate, that none shall pass through.","words":[["H5414","For I will lay",0,14],["H0776","the land",15,23],["H4923","most",24,28],["H8077","desolate",29,37],["H1347","and the pomp",39,51],["H5797","of her strength",52,67],["H7673","shall cease",68,79],["H2022","and the mountains",81,98],["H3478","of Israel",99,108],["H8074","shall be desolate",109,126],["H5674","that none shall pass through",128,156]]},"33:29":{"text":"Then shall they know that I am the LORD, when I have laid the land most desolate because of all their abominations which they have committed.","words":[["H3045","Then shall they know",0,20],["H3068","that I am the LORD",21,39],["H5414","when I have laid",41,57],["H0776","the land",58,66],["H4923","most",67,71],["H8077","desolate",72,80],["H8441","because of all their abominations",81,114],["H6213","which they have committed",115,140]]},"33:30":{"text":"Also, thou son of man, the children of thy people still are talking against thee by the walls and in the doors of the houses, and speak one to another, every one to his brother, saying, Come, I pray you, and hear what is the word that cometh forth from the LORD.","words":[["H1121","Also, thou son",0,14],["H0120","of man",15,21],["H1121","the children",23,35],["H5971","of thy people",36,49],["H1696","still are talking",50,67],["H0681","against",68,75],["H7023","thee by the walls",76,93],["H6607","and in the doors",94,110],["H1004","of the houses",111,124],["H1696","and speak",126,135],["H2297","one",136,139],["H0259","to another",140,150],["H0376","every one",152,161],["H0251","to his brother",162,176],["H0559","saying",178,184],["H0935","Come",186,190],["H8085","I pray you, and hear",192,212],["H1697","what is the word",213,229],["H3318","that cometh forth",230,247],["H3068","from the LORD",248,261]]},"33:31":{"text":"And they come unto thee as the people cometh, and they sit before thee as my people, and they hear thy words, but they will not do them: for with their mouth they shew much love, but their heart goeth after their covetousness.","words":[["H0935","And they come",0,13],["H5971","unto thee as the people",14,37],["H3996","cometh",38,44],["H3427","and they sit",46,58],["H6440","before",59,65],["H5971","thee as my people",66,83],["H8085","and they hear",85,98],["H1697","thy words",99,108],["H6213","but they will not do",110,130],["H6310","them: for with their mouth",131,157],["H6213","they shew",158,167],["H5690","much love",168,177],["H3820","but their heart",179,194],["H1980","goeth",195,200],["H0310","after",201,206],["H1215","their covetousness",207,225]]},"33:32":{"text":"And, lo, thou art unto them as a very lovely song of one that hath a pleasant voice, and can play well on an instrument: for they hear thy words, but they do them not.","words":[["H5690","And, lo, thou art unto them as a very lovely",0,44],["H7892","song",45,49],["H3303","of one that hath a pleasant",50,77],["H6963","voice",78,83],["H2895","and can play well",85,102],["H5059","on an instrument",103,119],["H8085","for they hear",121,134],["H1697","thy words",135,144],["H6213","but they do",146,157]]},"33:33":{"text":"And when this cometh to pass, (lo, it will come,) then shall they know that a prophet hath been among them.","words":[["H0935","And when this cometh to pass",0,28],["H0935","(lo, it will come",30,47],["H3045",") then shall they know",48,70],["H5030","that a prophet",71,85],["H8432","hath been among",86,101]]},"34:1":{"text":"And the word of the LORD came unto me, saying,","words":[["H1697","And the word",0,12],["H3068","of the LORD",13,24],["H0559","came unto me, saying",25,45]]},"34:2":{"text":"Son of man, prophesy against the shepherds of Israel, prophesy, and say unto them, Thus saith the Lord GOD unto the shepherds; Woe be to the shepherds of Israel that do feed themselves! should not the shepherds feed the flocks?","words":[["H1121","Son",0,3],["H0120","of man",4,10],["H5012","prophesy",12,20],["H7462","against the shepherds",21,42],["H3478","of Israel",43,52],["H5012","prophesy",54,62],["H0559","and say",64,71],["H0559","unto them, Thus saith",72,93],["H0136","the Lord",94,102],["H3069","GOD",103,106],["H7462","unto the shepherds",107,125],["H1945","Woe",127,130],["H7462","be to the shepherds",131,150],["H3478","of Israel",151,160],["H7462","that do feed",161,173],["H7462","themselves! should not the shepherds",174,210],["H7462","feed",211,215],["H6629","the flocks",216,226]]},"34:3":{"text":"Ye eat the fat, and ye clothe you with the wool, ye kill them that are fed: but ye feed not the flock.","words":[["H0398","Ye eat",0,6],["H2459","the fat",7,14],["H3847","and ye clothe",16,29],["H6785","you with the wool",30,47],["H2076","ye kill",49,56],["H1277","them that are fed",57,74],["H7462","but ye feed",76,87],["H6629","not the flock",88,101]]},"34:4":{"text":"The diseased have ye not strengthened, neither have ye healed that which was sick, neither have ye bound up that which was broken, neither have ye brought again that which was driven away, neither have ye sought that which was lost; but with force and with cruelty have ye ruled them.","words":[["H2470","The diseased",0,12],["H2388","have ye not strengthened",13,37],["H7495","neither have ye healed",39,61],["H2470","that which was sick",62,81],["H2280","neither have ye bound up",83,107],["H7665","that which was broken",108,129],["H7725","neither have ye brought again",131,160],["H5080","that which was driven away",161,187],["H1245","neither have ye sought",189,211],["H0006","that which was lost",212,231],["H2394","but with force",233,247],["H6531","and with cruelty",248,264],["H7287","have ye ruled",265,278]]},"34:5":{"text":"And they were scattered, because there is no shepherd: and they became meat to all the beasts of the field, when they were scattered.","words":[["H6327","And they were scattered",0,23],["H7462","because there is no shepherd",25,53],["H0402","and they became meat",55,75],["H2416","to all the beasts",76,93],["H7704","of the field",94,106],["H6327","when they were scattered",108,132]]},"34:6":{"text":"My sheep wandered through all the mountains, and upon every high hill: yea, my flock was scattered upon all the face of the earth, and none did search or seek after them.","words":[["H6629","My sheep",0,8],["H7686","wandered",9,17],["H2022","through all the mountains",18,43],["H7311","and upon every high",45,64],["H1389","hill",65,69],["H6629","yea, my flock",71,84],["H6327","was scattered",85,98],["H6440","upon all the face",99,116],["H0776","of the earth",117,129],["H1875","and none did search",131,150],["H1245","or seek",151,158]]},"34:7":{"text":"Therefore, ye shepherds, hear the word of the LORD;","words":[["H7462","Therefore, ye shepherds",0,23],["H8085","hear",25,29],["H1697","the word",30,38],["H3068","of the LORD",39,50]]},"34:8":{"text":"As I live, saith the Lord GOD, surely because my flock became a prey, and my flock became meat to every beast of the field, because there was no shepherd, neither did my shepherds search for my flock, but the shepherds fed themselves, and fed not my flock;","words":[["H2416","As I live",0,9],["H5002","saith",11,16],["H0136","the Lord",17,25],["H3069","GOD",26,29],["H6629","surely because my flock",31,54],["H0957","became a prey",55,68],["H6629","and my flock",70,82],["H0402","became meat",83,94],["H2416","to every beast",95,109],["H7704","of the field",110,122],["H7462","because there was no shepherd",124,153],["H7462","neither did my shepherds",155,179],["H1875","search",180,186],["H6629","for my flock",187,199],["H7462","but the shepherds",201,218],["H7462","fed",219,222],["H7462","themselves, and fed",223,242],["H6629","not my flock",243,255]]},"34:9":{"text":"Therefore, O ye shepherds, hear the word of the LORD;","words":[["H7462","Therefore, O ye shepherds",0,25],["H8085","hear",27,31],["H1697","the word",32,40],["H3068","of the LORD",41,52]]},"34:10":{"text":"Thus saith the Lord GOD; Behold, I am against the shepherds; and I will require my flock at their hand, and cause them to cease from feeding the flock; neither shall the shepherds feed themselves any more; for I will deliver my flock from their mouth, that they may not be meat for them.","words":[["H0559","Thus saith",0,10],["H0136","the Lord",11,19],["H3069","GOD",20,23],["H7462","Behold, I am against the shepherds",25,59],["H1875","and I will require",61,79],["H6629","my flock",80,88],["H3027","at their hand",89,102],["H7673","and cause them to cease",104,127],["H7462","from feeding",128,140],["H6629","the flock",141,150],["H7462","neither shall the shepherds",152,179],["H7462","feed",180,184],["H5337","themselves any more; for I will deliver",185,224],["H6629","my flock",225,233],["H6310","from their mouth",234,250],["H0402","that they may not be meat",252,277]]},"34:11":{"text":"For thus saith the Lord GOD; Behold, I, even I, will both search my sheep, and seek them out.","words":[["H0559","For thus saith",0,14],["H0136","the Lord",15,23],["H3069","GOD",24,27],["H1875","Behold, I, even I, will both search",29,64],["H6629","my sheep",65,73],["H1239","and seek them out",75,92]]},"34:12":{"text":"As a shepherd seeketh out his flock in the day that he is among his sheep that are scattered; so will I seek out my sheep, and will deliver them out of all places where they have been scattered in the cloudy and dark day.","words":[["H7462","As a shepherd",0,13],["H1243","seeketh out",14,25],["H5739","his flock",26,35],["H3117","in the day",36,46],["H8432","that he is among",47,63],["H6629","his sheep",64,73],["H6567","that are scattered",74,92],["H1239","so will I seek out",94,112],["H6629","my sheep",113,121],["H5337","and will deliver",123,139],["H4725","them out of all places",140,162],["H6327","where they have been scattered",163,193],["H6051","in the cloudy",194,207],["H6205","and dark",208,216],["H3117","day",217,220]]},"34:13":{"text":"And I will bring them out from the people, and gather them from the countries, and will bring them to their own land, and feed them upon the mountains of Israel by the rivers, and in all the inhabited places of the country.","words":[["H3318","And I will bring them out",0,25],["H5971","from the people",26,41],["H6908","and gather",43,53],["H0776","them from the countries",54,77],["H0935","and will bring",79,93],["H0127","them to their own land",94,116],["H7462","and feed",118,126],["H2022","them upon the mountains",127,150],["H3478","of Israel",151,160],["H0650","by the rivers",161,174],["H4186","and in all the inhabited places",176,207],["H0776","of the country",208,222]]},"34:14":{"text":"I will feed them in a good pasture, and upon the high mountains of Israel shall their fold be: there shall they lie in a good fold, and in a fat pasture shall they feed upon the mountains of Israel.","words":[["H7462","I will feed",0,11],["H2896","them in a good",12,26],["H4829","pasture",27,34],["H4791","and upon the high",36,53],["H2022","mountains",54,63],["H3478","of Israel",64,73],["H5116","shall their fold",74,90],["H7257","be: there shall they lie",91,115],["H2896","in a good",116,125],["H5116","fold",126,130],["H8082","and in a fat",132,144],["H4829","pasture",145,152],["H7462","shall they feed",153,168],["H2022","upon the mountains",169,187],["H3478","of Israel",188,197]]},"34:15":{"text":"I will feed my flock, and I will cause them to lie down, saith the Lord GOD.","words":[["H7462","I will feed",0,11],["H6629","my flock",12,20],["H7257","and I will cause them to lie down",22,55],["H5002","saith",57,62],["H0136","the Lord",63,71],["H3069","GOD",72,75]]},"34:16":{"text":"I will seek that which was lost, and bring again that which was driven away, and will bind up that which was broken, and will strengthen that which was sick: but I will destroy the fat and the strong; I will feed them with judgment.","words":[["H1245","I will seek",0,11],["H0006","that which was lost",12,31],["H7725","and bring again",33,48],["H5080","that which was driven away",49,75],["H2280","and will bind up",77,93],["H7665","that which was broken",94,115],["H2388","and will strengthen",117,136],["H2470","that which was sick",137,156],["H8045","but I will destroy",158,176],["H8082","the fat",177,184],["H2389","and the strong",185,199],["H7462","I will feed",201,212],["H4941","them with judgment",213,231]]},"34:17":{"text":"And as for you, O my flock, thus saith the Lord GOD; Behold, I judge between cattle and cattle, between the rams and the he goats.","words":[["H0859","And as for you",0,14],["H6629","O my flock",16,26],["H0559","thus saith",28,38],["H0136","the Lord",39,47],["H3069","GOD",48,51],["H8199","Behold, I judge",53,68],["H7716","between cattle",69,83],["H7716","and cattle",84,94],["H0352","between the rams",96,112],["H6260","and the he goats",113,129]]},"34:18":{"text":"Seemeth it a small thing unto you to have eaten up the good pasture, but ye must tread down with your feet the residue of your pastures? and to have drunk of the deep waters, but ye must foul the residue with your feet?","words":[["H4592","Seemeth it a small thing",0,24],["H7462","unto you to have eaten up",25,50],["H2896","the good",51,59],["H4829","pasture",60,67],["H7429","but ye must tread down",69,91],["H7272","with your feet",92,106],["H3499","the residue",107,118],["H4829","of your pastures",119,135],["H8354","and to have drunk",137,154],["H4950","of the deep",155,166],["H4325","waters",167,173],["H7515","but ye must foul",175,191],["H3498","the residue",192,203],["H7272","with your feet",204,218]]},"34:19":{"text":"And as for my flock, they eat that which ye have trodden with your feet; and they drink that which ye have fouled with your feet.","words":[["H6629","And as for my flock",0,19],["H7462","they eat",21,29],["H4823","that which ye have trodden",30,56],["H7272","with your feet",57,71],["H8354","and they drink",73,87],["H4833","that which ye have fouled",88,113],["H7272","with your feet",114,128]]},"34:20":{"text":"Therefore thus saith the Lord GOD unto them; Behold, I, even I, will judge between the fat cattle and between the lean cattle.","words":[["H0559","Therefore thus saith",0,20],["H0136","the Lord",21,29],["H3069","GOD",30,33],["H8199","unto them; Behold, I, even I, will judge",34,74],["H1274","between the fat",75,90],["H7716","cattle",91,97],["H7330","and between the lean",98,118],["H7716","cattle",119,125]]},"34:21":{"text":"Because ye have thrust with side and with shoulder, and pushed all the diseased with your horns, till ye have scattered them abroad;","words":[["H1920","Because ye have thrust",0,22],["H6654","with side",23,32],["H3802","and with shoulder",33,50],["H5055","and pushed",52,62],["H2470","all the diseased",63,79],["H7161","with your horns",80,95],["H6327","till ye have scattered",97,119],["H2351","them abroad",120,131]]},"34:22":{"text":"Therefore will I save my flock, and they shall no more be a prey; and I will judge between cattle and cattle.","words":[["H3467","Therefore will I save",0,21],["H6629","my flock",22,30],["H0957","and they shall no more be a prey",32,64],["H8199","and I will judge",66,82],["H7716","between cattle",83,97],["H7716","and cattle",98,108]]},"34:23":{"text":"And I will set up one shepherd over them, and he shall feed them, even my servant David; he shall feed them, and he shall be their shepherd.","words":[["H6965","And I will set up",0,17],["H0259","one",18,21],["H7462","shepherd",22,30],["H7462","over them, and he shall feed",31,59],["H5650","them, even my servant",60,81],["H1732","David",82,87],["H7462","he shall feed",89,102],["H7462","them, and he shall be their shepherd",103,139]]},"34:24":{"text":"And I the LORD will be their God, and my servant David a prince among them; I the LORD have spoken it.","words":[["H3068","And I the LORD",0,14],["H0430","will be their God",15,32],["H5650","and my servant",34,48],["H1732","David",49,54],["H5387","a prince",55,63],["H8432","among",64,69],["H3068","them; I the LORD",70,86],["H1696","have spoken",87,98]]},"34:25":{"text":"And I will make with them a covenant of peace, and will cause the evil beasts to cease out of the land: and they shall dwell safely in the wilderness, and sleep in the woods.","words":[["H3772","And I will make",0,15],["H1285","with them a covenant",16,36],["H7965","of peace",37,45],["H7451","and will cause the evil",47,70],["H2416","beasts",71,77],["H7673","to cease",78,86],["H0776","out of the land",87,102],["H3427","and they shall dwell",104,124],["H0983","safely",125,131],["H4057","in the wilderness",132,149],["H3462","and sleep",151,160],["H3293","in the woods",161,173],["H3264","in the woods",161,173]]},"34:26":{"text":"And I will make them and the places round about my hill a blessing; and I will cause the shower to come down in his season; there shall be showers of blessing.","words":[["H5414","And I will make",0,15],["H5439","them and the places round about",16,47],["H1389","my hill",48,55],["H1293","a blessing",56,66],["H1653","and I will cause the shower",68,95],["H3381","to come down",96,108],["H6256","in his season",109,122],["H1653","there shall be showers",124,146],["H1293","of blessing",147,158]]},"34:27":{"text":"And the tree of the field shall yield her fruit, and the earth shall yield her increase, and they shall be safe in their land, and shall know that I am the LORD, when I have broken the bands of their yoke, and delivered them out of the hand of those that served themselves of them.","words":[["H6086","And the tree",0,12],["H7704","of the field",13,25],["H5414","shall yield",26,37],["H6529","her fruit",38,47],["H0776","and the earth",49,62],["H5414","shall yield",63,74],["H2981","her increase",75,87],["H0983","and they shall be safe",89,111],["H0127","in their land",112,125],["H3045","and shall know",127,141],["H3068","that I am the LORD",142,160],["H7665","when I have broken",162,180],["H4133","the bands",181,190],["H5923","of their yoke",191,204],["H5337","and delivered",206,219],["H3027","them out of the hand",220,240],["H5647","of those that served",241,261]]},"34:28":{"text":"And they shall no more be a prey to the heathen, neither shall the beast of the land devour them; but they shall dwell safely, and none shall make them afraid.","words":[["H0957","And they shall no more be a prey",0,32],["H1471","to the heathen",33,47],["H2416","neither shall the beast",49,72],["H0776","of the land",73,84],["H0398","devour",85,91],["H3427","them; but they shall dwell",92,118],["H0983","safely",119,125],["H2729","and none shall make them afraid",127,158]]},"34:29":{"text":"And I will raise up for them a plant of renown, and they shall be no more consumed with hunger in the land, neither bear the shame of the heathen any more.","words":[["H6965","And I will raise up",0,19],["H4302","for them a plant",20,36],["H8034","of renown",37,46],["H0622","and they shall be no more consumed",48,82],["H7458","with hunger",83,94],["H0776","in the land",95,106],["H5375","neither bear",108,120],["H3639","the shame",121,130],["H1471","of the heathen",131,145]]},"34:30":{"text":"Thus shall they know that I the LORD their God am with them, and that they, even the house of Israel, are my people, saith the Lord GOD.","words":[["H3045","Thus shall they know",0,20],["H3068","that I the LORD",21,36],["H0430","their God",37,46],["H1004","am with them, and that they, even the house",47,90],["H3478","of Israel",91,100],["H5971","are my people",102,115],["H5002","saith",117,122],["H0136","the Lord",123,131],["H3069","GOD",132,135]]},"34:31":{"text":"And ye my flock, the flock of my pasture, are men, and I am your God, saith the Lord GOD.","words":[["H0859","And ye",0,6],["H6629","my flock",7,15],["H6629","the flock",17,26],["H4830","of my pasture",27,40],["H0120","are men",42,49],["H0430","and I am your God",51,68],["H5002","saith",70,75],["H0136","the Lord",76,84],["H3069","GOD",85,88]]},"35:1":{"text":"Moreover the word of the LORD came unto me, saying,","words":[["H1697","Moreover the word",0,17],["H3068","of the LORD",18,29],["H0559","came unto me, saying",30,50]]},"35:2":{"text":"Son of man, set thy face against mount Seir, and prophesy against it,","words":[["H1121","Son",0,3],["H0120","of man",4,10],["H7760","set",12,15],["H6440","thy face",16,24],["H2022","against mount",25,38],["H8165","Seir",39,43],["H5012","and prophesy",45,57]]},"35:3":{"text":"And say unto it, Thus saith the Lord GOD; Behold, O mount Seir, I am against thee, and I will stretch out mine hand against thee, and I will make thee most desolate.","words":[["H0559","And say",0,7],["H0559","unto it, Thus saith",8,27],["H0136","the Lord",28,36],["H3069","GOD",37,40],["H2022","Behold, O mount",42,57],["H8165","Seir",58,62],["H5186","I am against thee, and I will stretch out",64,105],["H3027","mine hand",106,115],["H5414","against thee, and I will make",116,145],["H4923","thee most",146,155],["H8077","desolate",156,164]]},"35:4":{"text":"I will lay thy cities waste, and thou shalt be desolate, and thou shalt know that I am the LORD.","words":[["H7760","I will lay",0,10],["H5892","thy cities",11,21],["H2723","waste",22,27],["H8077","and thou shalt be desolate",29,55],["H3045","and thou shalt know",57,76],["H3068","that I am the LORD",77,95]]},"35:5":{"text":"Because thou hast had a perpetual hatred, and hast shed the blood of the children of Israel by the force of the sword in the time of their calamity, in the time that their iniquity had an end:","words":[["H5769","Because thou hast had a perpetual",0,33],["H0342","hatred",34,40],["H5064","and hast shed",42,55],["H1121","the blood of the children",56,81],["H3478","of Israel",82,91],["H3027","by the force",92,104],["H2719","of the sword",105,117],["H6256","in the time",118,129],["H0343","of their calamity",130,147],["H6256","in the time",149,160],["H5771","that their iniquity",161,180],["H7093","had an end",181,191]]},"35:6":{"text":"Therefore, as I live, saith the Lord GOD, I will prepare thee unto blood, and blood shall pursue thee: sith thou hast not hated blood, even blood shall pursue thee.","words":[["H2416","Therefore, as I live",0,20],["H5002","saith",22,27],["H0136","the Lord",28,36],["H3069","GOD",37,40],["H6213","I will prepare",42,56],["H1818","thee unto blood",57,72],["H1818","and blood",74,83],["H7291","shall pursue",84,96],["H0518","thee: sith",97,107],["H8130","thou hast not hated",108,127],["H1818","blood",128,133],["H1818","even blood",135,145],["H7291","shall pursue",146,158]]},"35:7":{"text":"Thus will I make mount Seir most desolate, and cut off from it him that passeth out and him that returneth.","words":[["H5414","Thus will I make",0,16],["H2022","mount",17,22],["H8165","Seir",23,27],["H8077","most",28,32],["H8077","desolate",33,41],["H3772","and cut off",43,54],["H5674","from it him that passeth out",55,83],["H7725","and him that returneth",84,106]]},"35:8":{"text":"And I will fill his mountains with his slain men: in thy hills, and in thy valleys, and in all thy rivers, shall they fall that are slain with the sword.","words":[["H4390","And I will fill",0,15],["H2022","his mountains",16,29],["H2491","with his slain",30,44],["H1389","men: in thy hills",45,62],["H1516","and in thy valleys",64,82],["H0650","and in all thy rivers",84,105],["H5307","shall they fall",107,122],["H2491","that are slain",123,137],["H2719","with the sword",138,152]]},"35:9":{"text":"I will make thee perpetual desolations, and thy cities shall not return: and ye shall know that I am the LORD.","words":[["H5414","I will make",0,11],["H5769","thee perpetual",12,26],["H8077","desolations",27,38],["H5892","and thy cities",40,54],["H7725","shall not return",55,71],["H3427","shall not return",55,71],["H3045","and ye shall know",73,90],["H3068","that I am the LORD",91,109]]},"35:10":{"text":"Because thou hast said, These two nations and these two countries shall be mine, and we will possess it; whereas the LORD was there:","words":[["H0559","Because thou hast said",0,22],["H8147","These two",24,33],["H1471","nations",34,41],["H8147","and these two",42,55],["H0776","countries",56,65],["H3423","shall be mine, and we will possess",66,100],["H3068","it; whereas the LORD",101,121]]},"35:11":{"text":"Therefore, as I live, saith the Lord GOD, I will even do according to thine anger, and according to thine envy which thou hast used out of thy hatred against them; and I will make myself known among them, when I have judged thee.","words":[["H2416","Therefore, as I live",0,20],["H5002","saith",22,27],["H0136","the Lord",28,36],["H3069","GOD",37,40],["H6213","I will even do",42,56],["H0639","according to thine anger",57,81],["H7068","and according to thine envy",83,110],["H6213","which thou hast used",111,131],["H8135","out of thy hatred",132,149],["H3045","against them; and I will make myself known",150,192],["H8199","among them, when I have judged",193,223]]},"35:12":{"text":"And thou shalt know that I am the LORD, and that I have heard all thy blasphemies which thou hast spoken against the mountains of Israel, saying, They are laid desolate, they are given us to consume.","words":[["H3045","And thou shalt know",0,19],["H3068","that I am the LORD",20,38],["H8085","and that I have heard",40,61],["H5007","all thy blasphemies",62,81],["H0559","which thou hast spoken",82,104],["H2022","against the mountains",105,126],["H3478","of Israel",127,136],["H0559","saying",138,144],["H8074","They are laid desolate",146,168],["H8077","They are laid desolate",146,168],["H5414","they are given",170,184],["H0402","us to consume",185,198]]},"35:13":{"text":"Thus with your mouth ye have boasted against me, and have multiplied your words against me: I have heard them.","words":[["H6310","Thus with your mouth",0,20],["H1431","ye have boasted",21,36],["H6280","against me, and have multiplied",37,68],["H1697","your words",69,79],["H8085","against me: I have heard",80,104]]},"35:14":{"text":"Thus saith the Lord GOD; When the whole earth rejoiceth, I will make thee desolate.","words":[["H0559","Thus saith",0,10],["H0136","the Lord",11,19],["H3069","GOD",20,23],["H0776","When the whole earth",25,45],["H8055","rejoiceth",46,55],["H6213","I will make",57,68],["H8077","thee desolate",69,82]]},"35:15":{"text":"As thou didst rejoice at the inheritance of the house of Israel, because it was desolate, so will I do unto thee: thou shalt be desolate, O mount Seir, and all Idumea, even all of it: and they shall know that I am the LORD.","words":[["H8057","As thou didst rejoice",0,21],["H5159","at the inheritance",22,40],["H1004","of the house",41,53],["H3478","of Israel",54,63],["H8074","because it was desolate",65,88],["H6213","so will I do",90,102],["H8077","unto thee: thou shalt be desolate",103,136],["H2022","O mount",138,145],["H8165","Seir",146,150],["H0123","and all Idumea",152,166],["H3045","even all of it: and they shall know",168,203],["H3068","that I am the LORD",204,222]]},"36:1":{"text":"Also, thou son of man, prophesy unto the mountains of Israel, and say, Ye mountains of Israel, hear the word of the LORD:","words":[["H1121","Also, thou son",0,14],["H0120","of man",15,21],["H5012","prophesy",23,31],["H2022","unto the mountains",32,50],["H3478","of Israel",51,60],["H0559","and say",62,69],["H2022","Ye mountains",71,83],["H3478","of Israel",84,93],["H8085","hear",95,99],["H1697","the word",100,108],["H3068","of the LORD",109,120]]},"36:2":{"text":"Thus saith the Lord GOD; Because the enemy hath said against you, Aha, even the ancient high places are ours in possession:","words":[["H0559","Thus saith",0,10],["H0136","the Lord",11,19],["H3069","GOD",20,23],["H0341","Because the enemy",25,42],["H0559","hath said",43,52],["H1889","against you, Aha",53,69],["H5769","even the ancient",71,87],["H1116","high places",88,99],["H4181","are ours in possession",100,122]]},"36:3":{"text":"Therefore prophesy and say, Thus saith the Lord GOD; Because they have made you desolate, and swallowed you up on every side, that ye might be a possession unto the residue of the heathen, and ye are taken up in the lips of talkers, and are an infamy of the people:","words":[["H5012","Therefore prophesy",0,18],["H0559","and say",19,26],["H0559","Thus saith",28,38],["H0136","the Lord",39,47],["H3069","GOD",48,51],["H8074","Because they have made you desolate",53,88],["H7602","and swallowed you up",90,110],["H5439","on every side",111,124],["H4181","that ye might be a possession",126,155],["H7611","unto the residue",156,172],["H1471","of the heathen",173,187],["H5927","and ye are taken up",189,208],["H8193","in the lips",209,220],["H3956","of talkers",221,231],["H1681","and are an infamy",233,250],["H5971","of the people",251,264]]},"36:4":{"text":"Therefore, ye mountains of Israel, hear the word of the Lord GOD; Thus saith the Lord GOD to the mountains, and to the hills, to the rivers, and to the valleys, to the desolate wastes, and to the cities that are forsaken, which became a prey and derision to the residue of the heathen that are round about;","words":[["H2022","Therefore, ye mountains",0,23],["H3478","of Israel",24,33],["H8085","hear",35,39],["H1697","the word",40,48],["H0136","of the Lord",49,60],["H3069","GOD",61,64],["H0559","Thus saith",66,76],["H0136","the Lord",77,85],["H3069","GOD",86,89],["H2022","to the mountains",90,106],["H1389","and to the hills",108,124],["H0650","to the rivers",126,139],["H1516","and to the valleys",141,159],["H8074","to the desolate",161,176],["H2723","wastes",177,183],["H5892","and to the cities",185,202],["H5800","that are forsaken",203,220],["H0957","which became a prey",222,241],["H3933","and derision",242,254],["H7611","to the residue",255,269],["H1471","of the heathen",270,284],["H5439","that are round about",285,305]]},"36:5":{"text":"Therefore thus saith the Lord GOD; Surely in the fire of my jealousy have I spoken against the residue of the heathen, and against all Idumea, which have appointed my land into their possession with the joy of all their heart, with despiteful minds, to cast it out for a prey.","words":[["H0559","Therefore thus saith",0,20],["H0136","the Lord",21,29],["H3069","GOD",30,33],["H0784","Surely in the fire",35,53],["H7068","of my jealousy",54,68],["H1696","have I spoken",69,82],["H7611","against the residue",83,102],["H1471","of the heathen",103,117],["H0123","and against all Idumea",119,141],["H5414","which have appointed",143,163],["H0776","my land",164,171],["H4181","into their possession",172,193],["H8057","with the joy",194,206],["H3824","of all their heart",207,225],["H7589","with despiteful",227,242],["H5315","minds",243,248],["H4054","to cast it out",250,264],["H0957","for a prey",265,275]]},"36:6":{"text":"Prophesy therefore concerning the land of Israel, and say unto the mountains, and to the hills, to the rivers, and to the valleys, Thus saith the Lord GOD; Behold, I have spoken in my jealousy and in my fury, because ye have borne the shame of the heathen:","words":[["H5012","Prophesy",0,8],["H0127","therefore concerning the land",9,38],["H3478","of Israel",39,48],["H0559","and say",50,57],["H2022","unto the mountains",58,76],["H1389","and to the hills",78,94],["H0650","to the rivers",96,109],["H1516","and to the valleys",111,129],["H0559","Thus saith",131,141],["H0136","the Lord",142,150],["H3069","GOD",151,154],["H1696","Behold, I have spoken",156,177],["H7068","in my jealousy",178,192],["H2534","and in my fury",193,207],["H5375","because ye have borne",209,230],["H3639","the shame",231,240],["H1471","of the heathen",241,255]]},"36:7":{"text":"Therefore thus saith the Lord GOD; I have lifted up mine hand, Surely the heathen that are about you, they shall bear their shame.","words":[["H0559","Therefore thus saith",0,20],["H0136","the Lord",21,29],["H3069","GOD",30,33],["H5375","I have lifted up",35,51],["H3027","mine hand",52,61],["H1471","Surely the heathen",63,81],["H5439","that are about",82,96],["H5375","you, they shall bear",97,117],["H3639","their shame",118,129]]},"36:8":{"text":"But ye, O mountains of Israel, ye shall shoot forth your branches, and yield your fruit to my people of Israel; for they are at hand to come.","words":[["H2022","But ye, O mountains",0,19],["H3478","of Israel",20,29],["H5414","ye shall shoot forth",31,51],["H6057","your branches",52,65],["H5375","and yield",67,76],["H6529","your fruit",77,87],["H5971","to my people",88,100],["H3478","of Israel",101,110],["H7126","for they are at hand",112,132],["H0935","to come",133,140]]},"36:9":{"text":"For, behold, I am for you, and I will turn unto you, and ye shall be tilled and sown:","words":[["H6437","For, behold, I am for you, and I will turn",0,42],["H5647","unto you, and ye shall be tilled",43,75],["H2232","and sown",76,84]]},"36:10":{"text":"And I will multiply men upon you, all the house of Israel, even all of it: and the cities shall be inhabited, and the wastes shall be builded:","words":[["H7235","And I will multiply",0,19],["H0120","men",20,23],["H1004","upon you, all the house",24,47],["H3478","of Israel",48,57],["H5892","even all of it: and the cities",59,89],["H3427","shall be inhabited",90,108],["H2723","and the wastes",110,124],["H1129","shall be builded",125,141]]},"36:11":{"text":"And I will multiply upon you man and beast; and they shall increase and bring fruit: and I will settle you after your old estates, and will do better unto you than at your beginnings: and ye shall know that I am the LORD.","words":[["H7235","And I will multiply",0,19],["H0120","upon you man",20,32],["H0929","and beast",33,42],["H7235","and they shall increase",44,67],["H6509","and bring fruit",68,83],["H3427","and I will settle",85,102],["H6927","you after your old estates",103,129],["H2895","and will do better",131,149],["H7221","unto you than at your beginnings",150,182],["H3045","and ye shall know",184,201],["H3068","that I am the LORD",202,220]]},"36:12":{"text":"Yea, I will cause men to walk upon you, even my people Israel; and they shall possess thee, and thou shalt be their inheritance, and thou shalt no more henceforth bereave them of men.","words":[["H0120","Yea, I will cause men",0,21],["H3212","to walk",22,29],["H5971","upon you, even my people",30,54],["H3478","Israel",55,61],["H3423","and they shall possess",63,85],["H5159","thee, and thou shalt be their inheritance",86,127],["H3254","and thou shalt no more",129,151],["H7921","henceforth bereave",152,170]]},"36:13":{"text":"Thus saith the Lord GOD; Because they say unto you, Thou land devourest up men, and hast bereaved thy nations;","words":[["H0559","Thus saith",0,10],["H0136","the Lord",11,19],["H3069","GOD",20,23],["H0559","Because they say",25,41],["H0398","unto you, Thou land devourest up",42,74],["H0120","men",75,78],["H7921","and hast bereaved",80,97],["H1471","thy nations",98,109]]},"36:14":{"text":"Therefore thou shalt devour men no more, neither bereave thy nations any more, saith the Lord GOD.","words":[["H0398","Therefore thou shalt devour",0,27],["H0120","men",28,31],["H7921","no more, neither bereave",32,56],["H3782","no more, neither bereave",32,56],["H1471","thy nations",57,68],["H5002","any more, saith",69,84],["H0136","the Lord",85,93],["H3069","GOD",94,97]]},"36:15":{"text":"Neither will I cause men to hear in thee the shame of the heathen any more, neither shalt thou bear the reproach of the people any more, neither shalt thou cause thy nations to fall any more, saith the Lord GOD.","words":[["H8085","Neither will I cause men to hear",0,32],["H3639","in thee the shame",33,50],["H1471","of the heathen",51,65],["H5375","any more, neither shalt thou bear",66,99],["H2781","the reproach",100,112],["H5971","of the people",113,126],["H1471","any more, neither shalt thou cause thy nations",127,173],["H3782","to fall",174,181],["H5002","any more, saith",182,197],["H0136","the Lord",198,206],["H3069","GOD",207,210]]},"36:16":{"text":"Moreover the word of the LORD came unto me, saying,","words":[["H1697","Moreover the word",0,17],["H3068","of the LORD",18,29],["H0559","came unto me, saying",30,50]]},"36:17":{"text":"Son of man, when the house of Israel dwelt in their own land, they defiled it by their own way and by their doings: their way was before me as the uncleanness of a removed woman.","words":[["H1121","Son",0,3],["H0120","of man",4,10],["H1004","when the house",12,26],["H3478","of Israel",27,36],["H3427","dwelt",37,42],["H0127","in their own land",43,60],["H2930","they defiled",62,74],["H1870","it by their own way",75,94],["H5949","and by their doings",95,114],["H1870","their way",116,125],["H6440","was before",126,136],["H2932","me as the uncleanness",137,158],["H5079","of a removed woman",159,177]]},"36:18":{"text":"Wherefore I poured my fury upon them for the blood that they had shed upon the land, and for their idols wherewith they had polluted it:","words":[["H8210","Wherefore I poured",0,18],["H2534","my fury",19,26],["H1818","upon them for the blood",27,50],["H8210","that they had shed",51,69],["H0776","upon the land",70,83],["H1544","and for their idols",85,104],["H2930","wherewith they had polluted",105,132]]},"36:19":{"text":"And I scattered them among the heathen, and they were dispersed through the countries: according to their way and according to their doings I judged them.","words":[["H6327","And I scattered",0,15],["H1471","them among the heathen",16,38],["H2219","and they were dispersed",40,63],["H0776","through the countries",64,85],["H1870","according to their way",87,109],["H5949","and according to their doings",110,139],["H8199","I judged",140,148]]},"36:20":{"text":"And when they entered unto the heathen, whither they went, they profaned my holy name, when they said to them, These are the people of the LORD, and are gone forth out of his land.","words":[["H0935","And when they entered",0,21],["H1471","unto the heathen",22,38],["H0935","whither they went",40,57],["H2490","they profaned",59,72],["H6944","my holy",73,80],["H8034","name",81,85],["H0559","when they said",87,101],["H5971","to them, These are the people",102,131],["H3068","of the LORD",132,143],["H3318","and are gone forth",145,163],["H0776","out of his land",164,179]]},"36:21":{"text":"But I had pity for mine holy name, which the house of Israel had profaned among the heathen, whither they went.","words":[["H2550","But I had pity",0,14],["H6944","for mine holy",15,28],["H8034","name",29,33],["H1004","which the house",35,50],["H3478","of Israel",51,60],["H2490","had profaned",61,73],["H1471","among the heathen",74,91],["H0935","whither they went",93,110]]},"36:22":{"text":"Therefore say unto the house of Israel, Thus saith the Lord GOD; I do not this for your sakes, O house of Israel, but for mine holy name's sake, which ye have profaned among the heathen, whither ye went.","words":[["H0559","Therefore say",0,13],["H1004","unto the house",14,28],["H3478","of Israel",29,38],["H0559","Thus saith",40,50],["H0136","the Lord",51,59],["H3069","GOD",60,63],["H6213","I do",65,69],["H1004","not this for your sakes, O house",70,102],["H3478","of Israel",103,112],["H6944","but for mine holy",114,131],["H8034","name's",132,138],["H2490","sake, which ye have profaned",139,167],["H1471","among the heathen",168,185],["H0935","whither ye went",187,202]]},"36:23":{"text":"And I will sanctify my great name, which was profaned among the heathen, which ye have profaned in the midst of them; and the heathen shall know that I am the LORD, saith the Lord GOD, when I shall be sanctified in you before their eyes.","words":[["H6942","And I will sanctify",0,19],["H1419","my great",20,28],["H8034","name",29,33],["H2490","which was profaned",35,53],["H1471","among the heathen",54,71],["H2490","which ye have profaned",73,95],["H8432","in the midst",96,108],["H1471","of them; and the heathen",109,133],["H3045","shall know",134,144],["H3068","that I am the LORD",145,163],["H5002","saith",165,170],["H0136","the Lord",171,179],["H3069","GOD",180,183],["H6942","when I shall be sanctified",185,211],["H5869","in you before their eyes",212,236]]},"36:24":{"text":"For I will take you from among the heathen, and gather you out of all countries, and will bring you into your own land.","words":[["H3947","For I will take",0,15],["H4480","you from among",16,30],["H1471","the heathen",31,42],["H6908","and gather",44,54],["H0776","you out of all countries",55,79],["H0935","and will bring",81,95],["H0127","you into your own land",96,118]]},"36:25":{"text":"Then will I sprinkle clean water upon you, and ye shall be clean: from all your filthiness, and from all your idols, will I cleanse you.","words":[["H2236","Then will I sprinkle",0,20],["H2889","clean",21,26],["H4325","water",27,32],["H2891","upon you, and ye shall be clean",33,64],["H2932","from all your filthiness",66,90],["H1544","and from all your idols",92,115],["H2891","will I cleanse",117,131]]},"36:26":{"text":"A new heart also will I give you, and a new spirit will I put within you: and I will take away the stony heart out of your flesh, and I will give you an heart of flesh.","words":[["H2319","A new",0,5],["H3820","heart",6,11],["H5414","also will I give",12,28],["H2319","you, and a new",29,43],["H7307","spirit",44,50],["H5414","will I put",51,61],["H7130","within",62,68],["H5493","you: and I will take away",69,94],["H0068","the stony",95,104],["H3820","heart",105,110],["H1320","out of your flesh",111,128],["H5414","and I will give",130,145],["H3820","you an heart",146,158],["H1320","of flesh",159,167]]},"36:27":{"text":"And I will put my spirit within you, and cause you to walk in my statutes, and ye shall keep my judgments, and do them.","words":[["H5414","And I will put",0,14],["H7307","my spirit",15,24],["H7130","within",25,31],["H6213","you, and cause",32,46],["H3212","you to walk",47,58],["H2706","in my statutes",59,73],["H8104","and ye shall keep",75,92],["H4941","my judgments",93,105],["H6213","and do",107,113]]},"36:28":{"text":"And ye shall dwell in the land that I gave to your fathers; and ye shall be my people, and I will be your God.","words":[["H3427","And ye shall dwell",0,18],["H0776","in the land",19,30],["H5414","that I gave",31,42],["H0001","to your fathers",43,58],["H5971","and ye shall be my people",60,85],["H0430","and I will be your God",87,109]]},"36:29":{"text":"I will also save you from all your uncleannesses: and I will call for the corn, and will increase it, and lay no famine upon you.","words":[["H3467","I will also save",0,16],["H2932","you from all your uncleannesses",17,48],["H7121","and I will call",50,65],["H1715","for the corn",66,78],["H7235","and will increase",80,97],["H5414","it, and lay",98,109],["H7458","no famine",110,119]]},"36:30":{"text":"And I will multiply the fruit of the tree, and the increase of the field, that ye shall receive no more reproach of famine among the heathen.","words":[["H7235","And I will multiply",0,19],["H6529","the fruit",20,29],["H6086","of the tree",30,41],["H8570","and the increase",43,59],["H7704","of the field",60,72],["H3947","that ye shall receive",74,95],["H2781","no more reproach",96,112],["H7458","of famine",113,122],["H1471","among the heathen",123,140]]},"36:31":{"text":"Then shall ye remember your own evil ways, and your doings that were not good, and shall lothe yourselves in your own sight for your iniquities and for your abominations.","words":[["H2142","Then shall ye remember",0,22],["H7451","your own evil",23,36],["H1870","ways",37,41],["H4611","and your doings",43,58],["H2896","that were not good",59,77],["H6962","and shall lothe",79,94],["H6440","yourselves in your own sight",95,123],["H5771","for your iniquities",124,143],["H8441","and for your abominations",144,169]]},"36:32":{"text":"Not for your sakes do I this, saith the Lord GOD, be it known unto you: be ashamed and confounded for your own ways, O house of Israel.","words":[["H6213","Not for your sakes do",0,21],["H5002","I this, saith",22,35],["H0136","the Lord",36,44],["H3069","GOD",45,48],["H3045","be it known",50,61],["H0954","unto you: be ashamed",62,82],["H3637","and confounded",83,97],["H1870","for your own ways",98,115],["H1004","O house",117,124],["H3478","of Israel",125,134]]},"36:33":{"text":"Thus saith the Lord GOD; In the day that I shall have cleansed you from all your iniquities I will also cause you to dwell in the cities, and the wastes shall be builded.","words":[["H0559","Thus saith",0,10],["H0136","the Lord",11,19],["H3069","GOD",20,23],["H3117","In the day",25,35],["H2891","that I shall have cleansed",36,62],["H5771","you from all your iniquities",63,91],["H3427","I will also cause you to dwell",92,122],["H5892","in the cities",123,136],["H2723","and the wastes",138,152],["H1129","shall be builded",153,169]]},"36:34":{"text":"And the desolate land shall be tilled, whereas it lay desolate in the sight of all that passed by.","words":[["H8074","And the desolate",0,16],["H0776","land",17,21],["H5647","shall be tilled",22,37],["H8077","whereas it lay desolate",39,62],["H5869","in the sight",63,75],["H5674","of all that passed by",76,97]]},"36:35":{"text":"And they shall say, This land that was desolate is become like the garden of Eden; and the waste and desolate and ruined cities are become fenced, and are inhabited.","words":[["H0559","And they shall say",0,18],["H1977","This",20,24],["H0776","land",25,29],["H8074","that was desolate",30,47],["H1588","is become like the garden",48,73],["H5731","of Eden",74,81],["H2720","and the waste",83,96],["H8074","and desolate",97,109],["H2040","and ruined",110,120],["H5892","cities",121,127],["H1219","are become fenced",128,145],["H3427","and are inhabited",147,164]]},"36:36":{"text":"Then the heathen that are left round about you shall know that I the LORD build the ruined places, and plant that that was desolate: I the LORD have spoken it, and I will do it.","words":[["H1471","Then the heathen",0,16],["H7604","that are left",17,30],["H5439","round about",31,42],["H3045","you shall know",43,57],["H3068","that I the LORD",58,73],["H1129","build",74,79],["H2040","the ruined",80,90],["H5193","places, and plant",91,108],["H8074","that that was desolate",109,131],["H3068","I the LORD",133,143],["H1696","have spoken",144,155],["H6213","it, and I will do",156,173]]},"36:37":{"text":"Thus saith the Lord GOD; I will yet for this be enquired of by the house of Israel, to do it for them; I will increase them with men like a flock.","words":[["H0559","Thus saith",0,10],["H0136","the Lord",11,19],["H3069","GOD",20,23],["H1875","I will yet for this be enquired",25,56],["H1004","of by the house",57,72],["H3478","of Israel",73,82],["H6213","to do",84,89],["H7235","it for them; I will increase",90,118],["H0120","them with men",119,132],["H6629","like a flock",133,145]]},"36:38":{"text":"As the holy flock, as the flock of Jerusalem in her solemn feasts; so shall the waste cities be filled with flocks of men: and they shall know that I am the LORD.","words":[["H6944","As the holy",0,11],["H6629","flock",12,17],["H6629","as the flock",19,31],["H3389","of Jerusalem",32,44],["H4150","in her solemn feasts",45,65],["H2720","so shall the waste",67,85],["H5892","cities",86,92],["H4392","be filled",93,102],["H6629","with flocks",103,114],["H0120","of men",115,121],["H3045","and they shall know",123,142],["H3068","that I am the LORD",143,161]]},"37:1":{"text":"The hand of the LORD was upon me, and carried me out in the spirit of the LORD, and set me down in the midst of the valley which was full of bones,","words":[["H3027","The hand",0,8],["H3068","of the LORD",9,20],["H3318","was upon me, and carried me out",21,52],["H7307","in the spirit",53,66],["H3068","of the LORD",67,78],["H5117","and set me down",80,95],["H8432","in the midst",96,108],["H1237","of the valley",109,122],["H4392","which was full",123,137],["H6106","of bones",138,146]]},"37:2":{"text":"And caused me to pass by them round about: and, behold, there were very many in the open valley; and, lo, they were very dry.","words":[["H5674","And caused me to pass",0,21],["H5439","by them round about",22,41],["H3966","and, behold, there were very",43,71],["H7227","many",72,76],["H6440","in the open",77,88],["H1237","valley",89,95],["H3966","and, lo, they were very",97,120],["H3002","dry",121,124]]},"37:3":{"text":"And he said unto me, Son of man, can these bones live? And I answered, O Lord GOD, thou knowest.","words":[["H0559","And he said",0,11],["H1121","unto me, Son",12,24],["H0120","of man",25,31],["H6106","can these bones",33,48],["H2421","live",49,53],["H0559","And I answered",55,69],["H0136","O Lord",71,77],["H3069","GOD",78,81],["H3045","thou knowest",83,95]]},"37:4":{"text":"Again he said unto me, Prophesy upon these bones, and say unto them, O ye dry bones, hear the word of the LORD.","words":[["H0559","Again he said",0,13],["H5012","unto me, Prophesy",14,31],["H6106","upon these bones",32,48],["H0559","and say",50,57],["H3002","unto them, O ye dry",58,77],["H6106","bones",78,83],["H8085","hear",85,89],["H1697","the word",90,98],["H3068","of the LORD",99,110]]},"37:5":{"text":"Thus saith the Lord GOD unto these bones; Behold, I will cause breath to enter into you, and ye shall live:","words":[["H0559","Thus saith",0,10],["H0136","the Lord",11,19],["H3069","GOD",20,23],["H6106","unto these bones",24,40],["H7307","Behold, I will cause breath",42,69],["H0935","to enter",70,78],["H2421","into you, and ye shall live",79,106]]},"37:6":{"text":"And I will lay sinews upon you, and will bring up flesh upon you, and cover you with skin, and put breath in you, and ye shall live; and ye shall know that I am the LORD.","words":[["H5414","And I will lay",0,14],["H1517","sinews",15,21],["H5927","upon you, and will bring up",22,49],["H1320","flesh",50,55],["H7159","upon you, and cover",56,75],["H5785","you with skin",76,89],["H5414","and put",91,98],["H7307","breath",99,105],["H2421","in you, and ye shall live",106,131],["H3045","and ye shall know",133,150],["H3068","that I am the LORD",151,169]]},"37:7":{"text":"So I prophesied as I was commanded: and as I prophesied, there was a noise, and behold a shaking, and the bones came together, bone to his bone.","words":[["H5012","So I prophesied",0,15],["H6680","as I was commanded",16,34],["H5012","and as I prophesied",36,55],["H6963","there was a noise",57,74],["H7494","and behold a shaking",76,96],["H6106","and the bones",98,111],["H7126","came together",112,125],["H6106","bone",127,131],["H6106","to his bone",132,143]]},"37:8":{"text":"And when I beheld, lo, the sinews and the flesh came up upon them, and the skin covered them above: but there was no breath in them.","words":[["H7200","And when I beheld",0,17],["H1517","lo, the sinews",19,33],["H1320","and the flesh",34,47],["H5927","came up",48,55],["H5785","upon them, and the skin",56,79],["H7159","covered",80,87],["H4605","them above",88,98],["H7307","but there was no breath",100,123]]},"37:9":{"text":"Then said he unto me, Prophesy unto the wind, prophesy, son of man, and say to the wind, Thus saith the Lord GOD; Come from the four winds, O breath, and breathe upon these slain, that they may live.","words":[["H0559","Then said",0,9],["H5012","he unto me, Prophesy",10,30],["H7307","unto the wind",31,44],["H5012","prophesy",46,54],["H1121","son",56,59],["H0120","of man",60,66],["H0559","and say",68,75],["H7307","to the wind",76,87],["H0559","Thus saith",89,99],["H0136","the Lord",100,108],["H3069","GOD",109,112],["H0935","Come",114,118],["H0702","from the four",119,132],["H7307","winds",133,138],["H7307","O breath",140,148],["H5301","and breathe",150,161],["H2026","upon these slain",162,178],["H2421","that they may live",180,198]]},"37:10":{"text":"So I prophesied as he commanded me, and the breath came into them, and they lived, and stood up upon their feet, an exceeding great army.","words":[["H5012","So I prophesied",0,15],["H6680","as he commanded",16,31],["H7307","me, and the breath",32,50],["H0935","came",51,55],["H2421","into them, and they lived",56,81],["H5975","and stood up",83,95],["H7272","upon their feet",96,111],["H3966","an exceeding",113,125],["H3966","an exceeding",113,125],["H1419","great",126,131],["H2428","army",132,136]]},"37:11":{"text":"Then he said unto me, Son of man, these bones are the whole house of Israel: behold, they say, Our bones are dried, and our hope is lost: we are cut off for our parts.","words":[["H0559","Then he said",0,12],["H1121","unto me, Son",13,25],["H0120","of man",26,32],["H6106","these bones",34,45],["H1004","are the whole house",46,65],["H3478","of Israel",66,75],["H0559","behold, they say",77,93],["H6106","Our bones",95,104],["H3001","are dried",105,114],["H8615","and our hope",116,128],["H0006","is lost",129,136],["H1504","we are cut off",138,152]]},"37:12":{"text":"Therefore prophesy and say unto them, Thus saith the Lord GOD; Behold, O my people, I will open your graves, and cause you to come up out of your graves, and bring you into the land of Israel.","words":[["H5012","Therefore prophesy",0,18],["H0559","and say",19,26],["H0559","unto them, Thus saith",27,48],["H0136","the Lord",49,57],["H3069","GOD",58,61],["H5971","Behold, O my people",63,82],["H6605","I will open",84,95],["H6913","your graves",96,107],["H5927","and cause you to come up",109,133],["H6913","out of your graves",134,152],["H0935","and bring",154,163],["H0127","you into the land",164,181],["H3478","of Israel",182,191]]},"37:13":{"text":"And ye shall know that I am the LORD, when I have opened your graves, O my people, and brought you up out of your graves,","words":[["H3045","And ye shall know",0,17],["H3068","that I am the LORD",18,36],["H6605","when I have opened",38,56],["H6913","your graves",57,68],["H5971","O my people",70,81],["H5927","and brought you up",83,101],["H6913","out of your graves",102,120]]},"37:14":{"text":"And shall put my spirit in you, and ye shall live, and I shall place you in your own land: then shall ye know that I the LORD have spoken it, and performed it, saith the LORD.","words":[["H5414","And shall put",0,13],["H7307","my spirit",14,23],["H2421","in you, and ye shall live",24,49],["H3240","and I shall place",51,68],["H0127","you in your own land",69,89],["H3045","then shall ye know",91,109],["H3068","that I the LORD",110,125],["H1696","have spoken",126,137],["H6213","it, and performed",138,155],["H5002","it, saith",156,165],["H3068","the LORD",166,174]]},"37:15":{"text":"The word of the LORD came again unto me, saying,","words":[["H1697","The word",0,8],["H3068","of the LORD",9,20],["H0559","came again unto me, saying",21,47]]},"37:16":{"text":"Moreover, thou son of man, take thee one stick, and write upon it, For Judah, and for the children of Israel his companions: then take another stick, and write upon it, For Joseph, the stick of Ephraim, and for all the house of Israel his companions:","words":[["H1121","Moreover, thou son",0,18],["H0120","of man",19,25],["H3947","take",27,31],["H0259","thee one",32,40],["H6086","stick",41,46],["H3789","and write",48,57],["H3063","upon it, For Judah",58,76],["H1121","and for the children",78,98],["H3478","of Israel",99,108],["H2270","his companions",109,123],["H3947","then take",125,134],["H0259","another",135,142],["H6086","stick",143,148],["H3789","and write",150,159],["H3130","upon it, For Joseph",160,179],["H6086","the stick",181,190],["H0669","of Ephraim",191,201],["H1004","and for all the house",203,224],["H3478","of Israel",225,234],["H2270","his companions",235,249]]},"37:17":{"text":"And join them one to another into one stick; and they shall become one in thine hand.","words":[["H7126","And join",0,8],["H0259","them one",9,17],["H0259","to another",18,28],["H0259","into one",29,37],["H6086","stick",38,43],["H0259","and they shall become one",45,70],["H3027","in thine hand",71,84]]},"37:18":{"text":"And when the children of thy people shall speak unto thee, saying, Wilt thou not shew us what thou meanest by these?","words":[["H1121","And when the children",0,21],["H5971","of thy people",22,35],["H0559","shall speak",36,47],["H0559","unto thee, saying",48,65],["H5046","Wilt thou not shew",67,85]]},"37:19":{"text":"Say unto them, Thus saith the Lord GOD; Behold, I will take the stick of Joseph, which is in the hand of Ephraim, and the tribes of Israel his fellows, and will put them with him, even with the stick of Judah, and make them one stick, and they shall be one in mine hand.","words":[["H1696","Say",0,3],["H0559","unto them, Thus saith",4,25],["H0136","the Lord",26,34],["H3069","GOD",35,38],["H3947","Behold, I will take",40,59],["H6086","the stick",60,69],["H3130","of Joseph",70,79],["H3027","which is in the hand",81,101],["H0669","of Ephraim",102,112],["H7626","and the tribes",114,128],["H3478","of Israel",129,138],["H2270","his fellows",139,150],["H5414","and will put",152,164],["H6086","them with him, even with the stick",165,199],["H3063","of Judah",200,208],["H6213","and make",210,218],["H0259","them one",219,227],["H6086","stick",228,233],["H0259","and they shall be one",235,256],["H3027","in mine hand",257,269]]},"37:20":{"text":"And the sticks whereon thou writest shall be in thine hand before their eyes.","words":[["H6086","And the sticks",0,14],["H3789","whereon thou writest",15,35],["H3027","shall be in thine hand",36,58],["H5869","before their eyes",59,76]]},"37:21":{"text":"And say unto them, Thus saith the Lord GOD; Behold, I will take the children of Israel from among the heathen, whither they be gone, and will gather them on every side, and bring them into their own land:","words":[["H1696","And say",0,7],["H0559","unto them, Thus saith",8,29],["H0136","the Lord",30,38],["H3069","GOD",39,42],["H3947","Behold, I will take",44,63],["H1121","the children",64,76],["H3478","of Israel",77,86],["H0996","from among",87,97],["H1471","the heathen",98,109],["H1980","whither they be gone",111,131],["H6908","and will gather",133,148],["H5439","them on every side",149,167],["H0935","and bring",169,178],["H0127","them into their own land",179,203]]},"37:22":{"text":"And I will make them one nation in the land upon the mountains of Israel; and one king shall be king to them all: and they shall be no more two nations, neither shall they be divided into two kingdoms any more at all:","words":[["H6213","And I will make",0,15],["H0259","them one",16,24],["H1471","nation",25,31],["H0776","in the land",32,43],["H2022","upon the mountains",44,62],["H3478","of Israel",63,72],["H0259","and one",74,81],["H4428","king",82,86],["H4428","shall be king",87,100],["H5750","to them all: and they shall be",101,131],["H8147","no more two",132,143],["H1471","nations",144,151],["H2673","neither shall they be divided",153,182],["H8147","into two",183,191],["H4467","kingdoms",192,200]]},"37:23":{"text":"Neither shall they defile themselves any more with their idols, nor with their detestable things, nor with any of their transgressions: but I will save them out of all their dwellingplaces, wherein they have sinned, and will cleanse them: so shall they be my people, and I will be their God.","words":[["H2930","Neither shall they defile",0,25],["H1544","themselves any more with their idols",26,62],["H8251","nor with their detestable things",64,96],["H6588","nor with any of their transgressions",98,134],["H3467","but I will save",136,151],["H4186","them out of all their dwellingplaces",152,188],["H2398","wherein they have sinned",190,214],["H2891","and will cleanse",216,232],["H5971","them: so shall they be my people",233,265],["H0430","and I will be their God",267,290]]},"37:24":{"text":"And David my servant shall be king over them; and they all shall have one shepherd: they shall also walk in my judgments, and observe my statutes, and do them.","words":[["H1732","And David",0,9],["H5650","my servant",10,20],["H4428","shall be king",21,34],["H0259","over them; and they all shall have one",35,73],["H7462","shepherd",74,82],["H3212","they shall also walk",84,104],["H4941","in my judgments",105,120],["H8104","and observe",122,133],["H2708","my statutes",134,145],["H6213","and do",147,153]]},"37:25":{"text":"And they shall dwell in the land that I have given unto Jacob my servant, wherein your fathers have dwelt; and they shall dwell therein, even they, and their children, and their children's children for ever: and my servant David shall be their prince for ever.","words":[["H3427","And they shall dwell",0,20],["H0776","in the land",21,32],["H5414","that I have given",33,50],["H3290","unto Jacob",51,61],["H5650","my servant",62,72],["H0001","wherein your fathers",74,94],["H3427","have dwelt",95,105],["H3427","and they shall dwell",107,127],["H1121","therein, even they, and their children",128,166],["H1121","and their children's",168,188],["H1121","children",189,197],["H5769","for ever",198,206],["H5650","and my servant",208,222],["H1732","David",223,228],["H5387","shall be their prince",229,250],["H5704","for",251,254],["H5769","ever",255,259]]},"37:26":{"text":"Moreover I will make a covenant of peace with them; it shall be an everlasting covenant with them: and I will place them, and multiply them, and will set my sanctuary in the midst of them for evermore.","words":[["H3772","Moreover I will make",0,20],["H1285","a covenant",21,31],["H7965","of peace",32,40],["H5769","with them; it shall be an everlasting",41,78],["H1285","covenant",79,87],["H5414","with them: and I will place",88,115],["H7235","them, and multiply",116,134],["H5414","them, and will set",135,153],["H4720","my sanctuary",154,166],["H8432","in the midst",167,179],["H5769","of them for evermore",180,200]]},"37:27":{"text":"My tabernacle also shall be with them: yea, I will be their God, and they shall be my people.","words":[["H4908","My tabernacle",0,13],["H0430","also shall be with them: yea, I will be their God",14,63],["H5971","and they shall be my people",65,92]]},"37:28":{"text":"And the heathen shall know that I the LORD do sanctify Israel, when my sanctuary shall be in the midst of them for evermore.","words":[["H1471","And the heathen",0,15],["H3045","shall know",16,26],["H3068","that I the LORD",27,42],["H6942","do sanctify",43,54],["H3478","Israel",55,61],["H4720","when my sanctuary",63,80],["H8432","shall be in the midst",81,102],["H5769","of them for evermore",103,123]]},"38:1":{"text":"And the word of the LORD came unto me, saying,","words":[["H1697","And the word",0,12],["H3068","of the LORD",13,24],["H0559","came unto me, saying",25,45]]},"38:2":{"text":"Son of man, set thy face against Gog, the land of Magog, the chief prince of Meshech and Tubal, and prophesy against him,","words":[["H1121","Son",0,3],["H0120","of man",4,10],["H7760","set",12,15],["H6440","thy face",16,24],["H1463","against Gog",25,36],["H0776","the land",38,46],["H4031","of Magog",47,55],["H7218","the chief",57,66],["H5387","prince",67,73],["H4902","of Meshech",74,84],["H8422","and Tubal",85,94],["H5012","and prophesy",96,108]]},"38:3":{"text":"And say, Thus saith the Lord GOD; Behold, I am against thee, O Gog, the chief prince of Meshech and Tubal:","words":[["H0559","And say",0,7],["H0559","Thus saith",9,19],["H0136","the Lord",20,28],["H3069","GOD",29,32],["H1463","Behold, I am against thee, O Gog",34,66],["H7218","the chief",68,77],["H5387","prince",78,84],["H4902","of Meshech",85,95],["H8422","and Tubal",96,105]]},"38:4":{"text":"And I will turn thee back, and put hooks into thy jaws, and I will bring thee forth, and all thine army, horses and horsemen, all of them clothed with all sorts of armour, even a great company with bucklers and shields, all of them handling swords:","words":[["H7725","And I will turn thee back",0,25],["H5414","and put",27,34],["H2397","hooks",35,40],["H3895","into thy jaws",41,54],["H3318","and I will bring thee forth",56,83],["H2428","and all thine army",85,103],["H5483","horses",105,111],["H6571","and horsemen",112,124],["H3847","all of them clothed",126,145],["H4358","with all sorts",146,160],["H7227","of armour, even a great",161,184],["H6951","company",185,192],["H6793","with bucklers",193,206],["H4043","and shields",207,218],["H8610","all of them handling",220,240],["H2719","swords",241,247]]},"38:5":{"text":"Persia, Ethiopia, and Libya with them; all of them with shield and helmet:","words":[["H6539","Persia",0,6],["H3568","Ethiopia",8,16],["H6316","and Libya",18,27],["H4043","with them; all of them with shield",28,62],["H3553","and helmet",63,73]]},"38:6":{"text":"Gomer, and all his bands; the house of Togarmah of the north quarters, and all his bands: and many people with thee.","words":[["H1586","Gomer",0,5],["H0102","and all his bands",7,24],["H1004","the house",26,35],["H8425","of Togarmah",36,47],["H6828","of the north",48,60],["H3411","quarters",61,69],["H0102","and all his bands",71,88],["H7227","and many",90,98],["H5971","people",99,105]]},"38:7":{"text":"Be thou prepared, and prepare for thyself, thou, and all thy company that are assembled unto thee, and be thou a guard unto them.","words":[["H3559","Be thou prepared",0,16],["H3559","and prepare",18,29],["H6951","for thyself, thou, and all thy company",30,68],["H6950","that are assembled",69,87],["H4929","unto thee, and be thou a guard",88,118]]},"38:8":{"text":"After many days thou shalt be visited: in the latter years thou shalt come into the land that is brought back from the sword, and is gathered out of many people, against the mountains of Israel, which have been always waste: but it is brought forth out of the nations, and they shall dwell safely all of them.","words":[["H7227","After many",0,10],["H3117","days",11,15],["H6485","thou shalt be visited",16,37],["H0319","in the latter",39,52],["H8141","years",53,58],["H0935","thou shalt come",59,74],["H0776","into the land",75,88],["H7725","that is brought back",89,109],["H2719","from the sword",110,124],["H6908","and is gathered",126,141],["H7227","out of many",142,153],["H5971","people",154,160],["H2022","against the mountains",162,183],["H3478","of Israel",184,193],["H8548","which have been always",195,217],["H2723","waste",218,223],["H3318","but it is brought forth",225,248],["H5971","out of the nations",249,267],["H3427","and they shall dwell",269,289],["H0983","safely",290,296]]},"38:9":{"text":"Thou shalt ascend and come like a storm, thou shalt be like a cloud to cover the land, thou, and all thy bands, and many people with thee.","words":[["H5927","Thou shalt ascend",0,17],["H0935","and come",18,26],["H7722","like a storm",27,39],["H6051","thou shalt be like a cloud",41,67],["H3680","to cover",68,76],["H0776","the land",77,85],["H0102","thou, and all thy bands",87,110],["H7227","and many",112,120],["H5971","people",121,127]]},"38:10":{"text":"Thus saith the Lord GOD; It shall also come to pass, that at the same time shall things come into thy mind, and thou shalt think an evil thought:","words":[["H0559","Thus saith",0,10],["H0136","the Lord",11,19],["H3069","GOD",20,23],["H3117","It shall also come to pass, that at the same time",25,74],["H1697","shall things",75,87],["H5927","come",88,92],["H3824","into thy mind",93,106],["H2803","and thou shalt think",108,128],["H7451","an evil",129,136],["H4284","thought",137,144]]},"38:11":{"text":"And thou shalt say, I will go up to the land of unwalled villages; I will go to them that are at rest, that dwell safely, all of them dwelling without walls, and having neither bars nor gates,","words":[["H0559","And thou shalt say",0,18],["H5927","I will go up",20,32],["H0776","to the land",33,44],["H6519","of unwalled villages",45,65],["H0935","I will go",67,76],["H8252","to them that are at rest",77,101],["H3427","that dwell",103,113],["H0983","safely",114,120],["H3427","all of them dwelling",122,142],["H2346","without walls",143,156],["H1280","and having neither bars",158,181],["H1817","nor gates",182,191]]},"38:12":{"text":"To take a spoil, and to take a prey; to turn thine hand upon the desolate places that are now inhabited, and upon the people that are gathered out of the nations, which have gotten cattle and goods, that dwell in the midst of the land.","words":[["H7997","To take",0,7],["H7998","a spoil",8,15],["H0962","and to take",17,28],["H0957","a prey",29,35],["H7725","to turn",37,44],["H3027","thine hand",45,55],["H2723","upon the desolate places",56,80],["H3427","that are now inhabited",81,103],["H5971","and upon the people",105,124],["H0622","that are gathered",125,142],["H1471","out of the nations",143,161],["H6213","which have gotten",163,180],["H4735","cattle",181,187],["H7075","and goods",188,197],["H3427","that dwell",199,209],["H2872","in the midst",210,222],["H0776","of the land",223,234]]},"38:13":{"text":"Sheba, and Dedan, and the merchants of Tarshish, with all the young lions thereof, shall say unto thee, Art thou come to take a spoil? hast thou gathered thy company to take a prey? to carry away silver and gold, to take away cattle and goods, to take a great spoil?","words":[["H7614","Sheba",0,5],["H1719","and Dedan",7,16],["H5503","and the merchants",18,35],["H8659","of Tarshish",36,47],["H3715","with all the young lions",49,73],["H0559","thereof, shall say",74,92],["H0935","unto thee, Art thou come",93,117],["H7997","to take",118,125],["H7998","a spoil",126,133],["H6950","hast thou gathered",135,153],["H6951","thy company",154,165],["H0962","to take",166,173],["H0957","a prey",174,180],["H5375","to carry away",182,195],["H3701","silver",196,202],["H2091","and gold",203,211],["H3947","to take away",213,225],["H4735","cattle",226,232],["H7075","and goods",233,242],["H7997","to take",244,251],["H1419","a great",252,259],["H7998","spoil",260,265]]},"38:14":{"text":"Therefore, son of man, prophesy and say unto Gog, Thus saith the Lord GOD; In that day when my people of Israel dwelleth safely, shalt thou not know it?","words":[["H1121","Therefore, son",0,14],["H0120","of man",15,21],["H5012","prophesy",23,31],["H0559","and say",32,39],["H1463","unto Gog",40,48],["H0559","Thus saith",50,60],["H0136","the Lord",61,69],["H3069","GOD",70,73],["H3117","In that day",75,86],["H5971","when my people",87,101],["H3478","of Israel",102,111],["H3427","dwelleth",112,120],["H0983","safely",121,127],["H3045","shalt thou not know",129,148]]},"38:15":{"text":"And thou shalt come from thy place out of the north parts, thou, and many people with thee, all of them riding upon horses, a great company, and a mighty army:","words":[["H0935","And thou shalt come",0,19],["H4725","from thy place",20,34],["H6828","out of the north",35,51],["H3411","parts",52,57],["H7227","thou, and many",59,73],["H5971","people",74,80],["H7392","with thee, all of them riding",81,110],["H5483","upon horses",111,122],["H1419","a great",124,131],["H6951","company",132,139],["H7227","and a mighty",141,153],["H2428","army",154,158]]},"38:16":{"text":"And thou shalt come up against my people of Israel, as a cloud to cover the land; it shall be in the latter days, and I will bring thee against my land, that the heathen may know me, when I shall be sanctified in thee, O Gog, before their eyes.","words":[["H5927","And thou shalt come up",0,22],["H5971","against my people",23,40],["H3478","of Israel",41,50],["H6051","as a cloud",52,62],["H3680","to cover",63,71],["H0776","the land",72,80],["H0319","it shall be in the latter",82,107],["H3117","days",108,112],["H0935","and I will bring",114,130],["H0776","thee against my land",131,151],["H1471","that the heathen",153,169],["H3045","may know",170,178],["H6942","me, when I shall be sanctified",179,209],["H1463","in thee, O Gog",210,224],["H5869","before their eyes",226,243]]},"38:17":{"text":"Thus saith the Lord GOD; Art thou he of whom I have spoken in old time by my servants the prophets of Israel, which prophesied in those days many years that I would bring thee against them?","words":[["H0559","Thus saith",0,10],["H0136","the Lord",11,19],["H3069","GOD",20,23],["H1696","Art thou he of whom I have spoken",25,58],["H6931","in old",59,65],["H3117","time",66,70],["H3027","by",71,73],["H5650","my servants",74,85],["H5030","the prophets",86,98],["H3478","of Israel",99,108],["H5012","which prophesied",110,126],["H3117","in those days",127,140],["H8141","many years",141,151],["H0935","that I would bring",152,170]]},"38:18":{"text":"And it shall come to pass at the same time when Gog shall come against the land of Israel, saith the Lord GOD, that my fury shall come up in my face.","words":[["H3117","And it shall come to pass at the same time",0,42],["H3117","when",43,47],["H1463","Gog",48,51],["H0935","shall come",52,62],["H0127","against the land",63,79],["H3478","of Israel",80,89],["H5002","saith",91,96],["H0136","the Lord",97,105],["H3069","GOD",106,109],["H2534","that my fury",111,123],["H5927","shall come up",124,137],["H0639","in my face",138,148]]},"38:19":{"text":"For in my jealousy and in the fire of my wrath have I spoken, Surely in that day there shall be a great shaking in the land of Israel;","words":[["H7068","For in my jealousy",0,18],["H0784","and in the fire",19,34],["H5678","of my wrath",35,46],["H1696","have I spoken",47,60],["H3117","Surely in that day",62,80],["H1419","there shall be a great",81,103],["H7494","shaking",104,111],["H0127","in the land",112,123],["H3478","of Israel",124,133]]},"38:20":{"text":"So that the fishes of the sea, and the fowls of the heaven, and the beasts of the field, and all creeping things that creep upon the earth, and all the men that are upon the face of the earth, shall shake at my presence, and the mountains shall be thrown down, and the steep places shall fall, and every wall shall fall to the ground.","words":[["H1709","So that the fishes",0,18],["H3220","of the sea",19,29],["H5775","and the fowls",31,44],["H8064","of the heaven",45,58],["H2416","and the beasts",60,74],["H7704","of the field",75,87],["H7431","and all creeping things",89,112],["H7430","that creep",113,123],["H0127","upon the earth",124,138],["H0120","and all the men",140,155],["H6440","that are upon the face",156,178],["H0127","of the earth",179,191],["H7493","shall shake",193,204],["H6440","at my presence",205,219],["H2022","and the mountains",221,238],["H2040","shall be thrown down",239,259],["H4095","and the steep places",261,281],["H5307","shall fall",282,292],["H2346","and every wall",294,308],["H5307","shall fall",309,319],["H0776","to the ground",320,333]]},"38:21":{"text":"And I will call for a sword against him throughout all my mountains, saith the Lord GOD: every man's sword shall be against his brother.","words":[["H7121","And I will call",0,15],["H2719","for a sword",16,27],["H2022","against him throughout all my mountains",28,67],["H5002","saith",69,74],["H0136","the Lord",75,83],["H3069","GOD",84,87],["H0376","every man's",89,100],["H2719","sword",101,106],["H0251","shall be against his brother",107,135]]},"38:22":{"text":"And I will plead against him with pestilence and with blood; and I will rain upon him, and upon his bands, and upon the many people that are with him, an overflowing rain, and great hailstones, fire, and brimstone.","words":[["H8199","And I will plead",0,16],["H1698","against him with pestilence",17,44],["H1818","and with blood",45,59],["H4305","and I will rain",61,76],["H0102","upon him, and upon his bands",77,105],["H7227","and upon the many",107,124],["H5971","people",125,131],["H7857","that are with him, an overflowing",132,165],["H1653","rain",166,170],["H0417","and great hailstones",172,192],["H0068","and great hailstones",172,192],["H0784","fire",194,198],["H1614","and brimstone",200,213]]},"38:23":{"text":"Thus will I magnify myself, and sanctify myself; and I will be known in the eyes of many nations, and they shall know that I am the LORD.","words":[["H1431","Thus will I magnify",0,19],["H6942","myself, and sanctify",20,40],["H3045","myself; and I will be known",41,68],["H5869","in the eyes",69,80],["H7227","of many",81,88],["H1471","nations",89,96],["H3045","and they shall know",98,117],["H3068","that I am the LORD",118,136]]},"39:1":{"text":"Therefore, thou son of man, prophesy against Gog, and say, Thus saith the Lord GOD; Behold, I am against thee, O Gog, the chief prince of Meshech and Tubal:","words":[["H1121","Therefore, thou son",0,19],["H0120","of man",20,26],["H5012","prophesy",28,36],["H1463","against Gog",37,48],["H0559","and say",50,57],["H0559","Thus saith",59,69],["H0136","the Lord",70,78],["H3069","GOD",79,82],["H1463","Behold, I am against thee, O Gog",84,116],["H7218","the chief",118,127],["H5387","prince",128,134],["H4902","of Meshech",135,145],["H8422","and Tubal",146,155]]},"39:2":{"text":"And I will turn thee back, and leave but the sixth part of thee, and will cause thee to come up from the north parts, and will bring thee upon the mountains of Israel:","words":[["H7725","And I will turn thee back",0,25],["H8338","and leave but the sixth part",27,55],["H5927","of thee, and will cause thee to come up",56,95],["H6828","from the north",96,110],["H3411","parts",111,116],["H0935","and will bring",118,132],["H2022","thee upon the mountains",133,156],["H3478","of Israel",157,166]]},"39:3":{"text":"And I will smite thy bow out of thy left hand, and will cause thine arrows to fall out of thy right hand.","words":[["H5221","And I will smite",0,16],["H7198","thy bow",17,24],["H8040","out of thy left",25,40],["H3027","hand",41,45],["H2671","and will cause thine arrows",47,74],["H5307","to fall",75,82],["H3225","out of thy right",83,99],["H3027","hand",100,104]]},"39:4":{"text":"Thou shalt fall upon the mountains of Israel, thou, and all thy bands, and the people that is with thee: I will give thee unto the ravenous birds of every sort, and to the beasts of the field to be devoured.","words":[["H5307","Thou shalt fall",0,15],["H2022","upon the mountains",16,34],["H3478","of Israel",35,44],["H0102","thou, and all thy bands",46,69],["H5971","and the people",71,85],["H5414","that is with thee: I will give",86,116],["H5861","thee unto the ravenous",117,139],["H6833","birds",140,145],["H3671","of every sort",146,159],["H2416","and to the beasts",161,178],["H7704","of the field",179,191],["H0402","to be devoured",192,206]]},"39:5":{"text":"Thou shalt fall upon the open field: for I have spoken it, saith the Lord GOD.","words":[["H5307","Thou shalt fall",0,15],["H6440","upon the open",16,29],["H7704","field",30,35],["H1696","for I have spoken",37,54],["H5002","it, saith",55,64],["H0136","the Lord",65,73],["H3069","GOD",74,77]]},"39:6":{"text":"And I will send a fire on Magog, and among them that dwell carelessly in the isles: and they shall know that I am the LORD.","words":[["H7971","And I will send",0,15],["H0784","a fire",16,22],["H4031","on Magog",23,31],["H3427","and among them that dwell",33,58],["H0983","carelessly",59,69],["H0339","in the isles",70,82],["H3045","and they shall know",84,103],["H3068","that I am the LORD",104,122]]},"39:7":{"text":"So will I make my holy name known in the midst of my people Israel; and I will not let them pollute my holy name any more: and the heathen shall know that I am the LORD, the Holy One in Israel.","words":[["H6944","So will I make my holy",0,22],["H8034","name",23,27],["H3045","known",28,33],["H8432","in the midst",34,46],["H5971","of my people",47,59],["H3478","Israel",60,66],["H2490","and I will not let them pollute",68,99],["H6944","my holy",100,107],["H8034","name",108,112],["H1471","any more: and the heathen",113,138],["H3045","shall know",139,149],["H3068","that I am the LORD",150,168],["H6918","the Holy One",170,182],["H3478","in Israel",183,192]]},"39:8":{"text":"Behold, it is come, and it is done, saith the Lord GOD; this is the day whereof I have spoken.","words":[["H0935","Behold, it is come",0,18],["H1961","and it is done",20,34],["H5002","saith",36,41],["H0136","the Lord",42,50],["H3069","GOD",51,54],["H3117","this is the day",56,71],["H1696","whereof I have spoken",72,93]]},"39:9":{"text":"And they that dwell in the cities of Israel shall go forth, and shall set on fire and burn the weapons, both the shields and the bucklers, the bows and the arrows, and the handstaves, and the spears, and they shall burn them with fire seven years:","words":[["H3427","And they that dwell",0,19],["H5892","in the cities",20,33],["H3478","of Israel",34,43],["H3318","shall go forth",44,58],["H1197","and shall set",60,73],["H0784","on fire",74,81],["H5400","and burn",82,90],["H5402","the weapons",91,102],["H4043","both the shields",104,120],["H6793","and the bucklers",121,137],["H7198","the bows",139,147],["H2671","and the arrows",148,162],["H3027","and the handstaves",164,182],["H4731","and the handstaves",164,182],["H7420","and the spears",184,198],["H1197","and they shall burn",200,219],["H0784","them with fire",220,234],["H7651","seven",235,240],["H8141","years",241,246]]},"39:10":{"text":"So that they shall take no wood out of the field, neither cut down any out of the forests; for they shall burn the weapons with fire: and they shall spoil those that spoiled them, and rob those that robbed them, saith the Lord GOD.","words":[["H5375","So that they shall take",0,23],["H6086","no wood",24,31],["H7704","out of the field",32,48],["H2404","neither cut down",50,66],["H3293","any out of the forests",67,89],["H1197","for they shall burn",91,110],["H5402","the weapons",111,122],["H0784","with fire",123,132],["H7997","and they shall spoil",134,154],["H7997","those that spoiled",155,173],["H0962","them, and rob",174,187],["H0962","those that robbed",188,205],["H5002","them, saith",206,217],["H0136","the Lord",218,226],["H3069","GOD",227,230]]},"39:11":{"text":"And it shall come to pass in that day, that I will give unto Gog a place there of graves in Israel, the valley of the passengers on the east of the sea: and it shall stop the noses of the passengers: and there shall they bury Gog and all his multitude: and they shall call it The valley of Hamongog.","words":[["H3117","And it shall come to pass in that day",0,37],["H5414","that I will give",39,55],["H1463","unto Gog",56,64],["H4725","a place",65,72],["H6913","there of graves",73,88],["H3478","in Israel",89,98],["H1516","the valley",100,110],["H5674","of the passengers",111,128],["H6926","on the east",129,140],["H3220","of the sea",141,151],["H2629","and it shall stop",153,170],["H5674","the noses of the passengers",171,198],["H6912","and there shall they bury",200,225],["H1463","Gog",226,229],["H1995","and all his multitude",230,251],["H7121","and they shall call",253,272],["H1516","it The valley",273,286],["H1996","of Hamongog",287,298]]},"39:12":{"text":"And seven months shall the house of Israel be burying of them, that they may cleanse the land.","words":[["H7651","And seven",0,9],["H2320","months",10,16],["H1004","shall the house",17,32],["H3478","of Israel",33,42],["H6912","be burying",43,53],["H2891","of them, that they may cleanse",54,84],["H0776","the land",85,93]]},"39:13":{"text":"Yea, all the people of the land shall bury them; and it shall be to them a renown the day that I shall be glorified, saith the Lord GOD.","words":[["H5971","Yea, all the people",0,19],["H0776","of the land",20,31],["H6912","shall bury",32,42],["H8034","them; and it shall be to them a renown",43,81],["H3117","the day",82,89],["H3513","that I shall be glorified",90,115],["H5002","saith",117,122],["H0136","the Lord",123,131],["H3069","GOD",132,135]]},"39:14":{"text":"And they shall sever out men of continual employment, passing through the land to bury with the passengers those that remain upon the face of the earth, to cleanse it: after the end of seven months shall they search.","words":[["H0914","And they shall sever out",0,24],["H0582","men",25,28],["H8548","of continual employment",29,52],["H5674","passing through",54,69],["H0776","the land",70,78],["H6912","to bury",79,86],["H5674","with the passengers",87,106],["H3498","those that remain",107,124],["H6440","upon the face",125,138],["H0776","of the earth",139,151],["H2891","to cleanse",153,163],["H7097","it: after the end",164,181],["H7651","of seven",182,190],["H2320","months",191,197],["H2713","shall they search",198,215]]},"39:15":{"text":"And the passengers that pass through the land, when any seeth a man's bone, then shall he set up a sign by it, till the buriers have buried it in the valley of Hamongog.","words":[["H5674","And the passengers",0,18],["H5674","that pass through",19,36],["H0776","the land",37,45],["H7200","when any seeth",47,61],["H0120","a man's",62,69],["H6106","bone",70,74],["H1129","then shall he set up",76,96],["H6725","a sign",97,103],["H0681","by",104,106],["H6912","it, till the buriers",107,127],["H6912","have buried",128,139],["H1516","it in the valley",140,156],["H1996","of Hamongog",157,168]]},"39:16":{"text":"And also the name of the city shall be Hamonah. Thus shall they cleanse the land.","words":[["H8034","And also the name",0,17],["H5892","of the city",18,29],["H1997","shall be Hamonah",30,46],["H2891","Thus shall they cleanse",48,71],["H0776","the land",72,80]]},"39:17":{"text":"And, thou son of man, thus saith the Lord GOD; Speak unto every feathered fowl, and to every beast of the field, Assemble yourselves, and come; gather yourselves on every side to my sacrifice that I do sacrifice for you, even a great sacrifice upon the mountains of Israel, that ye may eat flesh, and drink blood.","words":[["H1121","And, thou son",0,13],["H0120","of man",14,20],["H0559","thus saith",22,32],["H0136","the Lord",33,41],["H3069","GOD",42,45],["H0559","Speak",47,52],["H3671","unto every feathered",53,73],["H6833","fowl",74,78],["H2416","and to every beast",80,98],["H7704","of the field",99,111],["H6908","Assemble",113,121],["H0935","yourselves, and come",122,142],["H0622","gather",144,150],["H5439","yourselves on every side",151,175],["H2077","to my sacrifice",176,191],["H2076","that I do sacrifice",192,211],["H1419","for you, even a great",212,233],["H2077","sacrifice",234,243],["H2022","upon the mountains",244,262],["H3478","of Israel",263,272],["H0398","that ye may eat",274,289],["H1320","flesh",290,295],["H8354","and drink",297,306],["H1818","blood",307,312]]},"39:18":{"text":"Ye shall eat the flesh of the mighty, and drink the blood of the princes of the earth, of rams, of lambs, and of goats, of bullocks, all of them fatlings of Bashan.","words":[["H0398","Ye shall eat",0,12],["H1320","the flesh",13,22],["H1368","of the mighty",23,36],["H8354","and drink",38,47],["H1818","the blood",48,57],["H5387","of the princes",58,72],["H0776","of the earth",73,85],["H0352","of rams",87,94],["H3733","of lambs",96,104],["H6260","and of goats",106,118],["H6499","of bullocks",120,131],["H4806","all of them fatlings",133,153],["H1316","of Bashan",154,163]]},"39:19":{"text":"And ye shall eat fat till ye be full, and drink blood till ye be drunken, of my sacrifice which I have sacrificed for you.","words":[["H0398","And ye shall eat",0,16],["H2459","fat",17,20],["H7654","till ye be full",21,36],["H8354","and drink",38,47],["H1818","blood",48,53],["H7943","till ye be drunken",54,72],["H2077","of my sacrifice",74,89],["H2076","which I have sacrificed",90,113]]},"39:20":{"text":"Thus ye shall be filled at my table with horses and chariots, with mighty men, and with all men of war, saith the Lord GOD.","words":[["H7646","Thus ye shall be filled",0,23],["H7979","at my table",24,35],["H5483","with horses",36,47],["H7393","and chariots",48,60],["H1368","with mighty men",62,77],["H0376","and with all men",79,95],["H4421","of war",96,102],["H5002","saith",104,109],["H0136","the Lord",110,118],["H3069","GOD",119,122]]},"39:21":{"text":"And I will set my glory among the heathen, and all the heathen shall see my judgment that I have executed, and my hand that I have laid upon them.","words":[["H5414","And I will set",0,14],["H3519","my glory",15,23],["H1471","among the heathen",24,41],["H1471","and all the heathen",43,62],["H7200","shall see",63,72],["H4941","my judgment",73,84],["H6213","that I have executed",85,105],["H3027","and my hand",107,118],["H7760","that I have laid",119,135]]},"39:22":{"text":"So the house of Israel shall know that I am the LORD their God from that day and forward.","words":[["H1004","So the house",0,12],["H3478","of Israel",13,22],["H3045","shall know",23,33],["H3068","that I am the LORD",34,52],["H0430","their God",53,62],["H3117","from that day",63,76],["H1973","and forward",77,88]]},"39:23":{"text":"And the heathen shall know that the house of Israel went into captivity for their iniquity: because they trespassed against me, therefore hid I my face from them, and gave them into the hand of their enemies: so fell they all by the sword.","words":[["H1471","And the heathen",0,15],["H3045","shall know",16,26],["H1004","that the house",27,41],["H3478","of Israel",42,51],["H1540","went into captivity",52,71],["H5771","for their iniquity",72,90],["H4603","because they trespassed",92,115],["H5641","against me, therefore hid",116,141],["H6440","I my face",142,151],["H5414","from them, and gave",152,171],["H3027","them into the hand",172,190],["H6862","of their enemies",191,207],["H5307","so fell",209,216],["H2719","they all by the sword",217,238]]},"39:24":{"text":"According to their uncleanness and according to their transgressions have I done unto them, and hid my face from them.","words":[["H2932","According to their uncleanness",0,30],["H6588","and according to their transgressions",31,68],["H6213","have I done",69,80],["H5641","unto them, and hid",81,99],["H6440","my face",100,107]]},"39:25":{"text":"Therefore thus saith the Lord GOD; Now will I bring again the captivity of Jacob, and have mercy upon the whole house of Israel, and will be jealous for my holy name;","words":[["H0559","Therefore thus saith",0,20],["H0136","the Lord",21,29],["H3069","GOD",30,33],["H7725","Now will I bring again",35,57],["H7622","the captivity",58,71],["H7622","the captivity",58,71],["H3290","of Jacob",72,80],["H7355","and have mercy",82,96],["H1004","upon the whole house",97,117],["H3478","of Israel",118,127],["H7065","and will be jealous",129,148],["H6944","for my holy",149,160],["H8034","name",161,165]]},"39:26":{"text":"After that they have borne their shame, and all their trespasses whereby they have trespassed against me, when they dwelt safely in their land, and none made them afraid.","words":[["H5375","After that they have borne",0,26],["H3639","their shame",27,38],["H4604","and all their trespasses",40,64],["H4603","whereby they have trespassed",65,93],["H3427","against me, when they dwelt",94,121],["H0983","safely",122,128],["H0127","in their land",129,142],["H2729","and none made them afraid",144,169]]},"39:27":{"text":"When I have brought them again from the people, and gathered them out of their enemies' lands, and am sanctified in them in the sight of many nations;","words":[["H7725","When I have brought them again",0,30],["H5971","from the people",31,46],["H6908","and gathered",48,60],["H0341","them out of their enemies'",61,87],["H0776","lands",88,93],["H6942","and am sanctified",95,112],["H5869","in them in the sight",113,133],["H7227","of many",134,141],["H1471","nations",142,149]]},"39:28":{"text":"Then shall they know that I am the LORD their God, which caused them to be led into captivity among the heathen: but I have gathered them unto their own land, and have left none of them any more there.","words":[["H3045","Then shall they know",0,20],["H3068","that I am the LORD",21,39],["H0430","their God",40,49],["H1540","which caused them to be led into captivity",51,93],["H1471","among the heathen",94,111],["H3664","but I have gathered",113,132],["H0127","them unto their own land",133,157],["H3498","and have left",159,172]]},"39:29":{"text":"Neither will I hide my face any more from them: for I have poured out my spirit upon the house of Israel, saith the Lord GOD.","words":[["H5641","Neither will I hide",0,19],["H6440","my face",20,27],["H8210","any more from them: for I have poured out",28,69],["H7307","my spirit",70,79],["H1004","upon the house",80,94],["H3478","of Israel",95,104],["H5002","saith",106,111],["H0136","the Lord",112,120],["H3069","GOD",121,124]]},"40:1":{"text":"In the five and twentieth year of our captivity, in the beginning of the year, in the tenth day of the month, in the fourteenth year after that the city was smitten, in the selfsame day the hand of the LORD was upon me, and brought me thither.","words":[["H2568","In the five",0,11],["H6242","and twentieth",12,25],["H8141","year",26,30],["H1546","of our captivity",31,47],["H7218","in the beginning",49,65],["H8141","of the year",66,77],["H6218","in the tenth",79,91],["H2320","day of the month",92,108],["H0702","in the fourteenth",110,127],["H6240","in the fourteenth",110,127],["H8141","year",128,132],["H0310","after",133,138],["H5892","that the city",139,152],["H5221","was smitten",153,164],["H6106","in the selfsame",166,181],["H3117","day",182,185],["H3027","the hand",186,194],["H3068","of the LORD",195,206],["H0935","was upon me, and brought",207,231]]},"40:2":{"text":"In the visions of God brought he me into the land of Israel, and set me upon a very high mountain, by which was as the frame of a city on the south.","words":[["H4759","In the visions",0,14],["H0430","of God",15,21],["H0935","brought",22,29],["H0776","he me into the land",30,49],["H3478","of Israel",50,59],["H5117","and set",61,68],["H3966","me upon a very",69,83],["H1364","high",84,88],["H2022","mountain",89,97],["H4011","by which was as the frame",99,124],["H5892","of a city",125,134],["H5045","on the south",135,147]]},"40:3":{"text":"And he brought me thither, and, behold, there was a man, whose appearance was like the appearance of brass, with a line of flax in his hand, and a measuring reed; and he stood in the gate.","words":[["H0935","And he brought",0,14],["H0376","me thither, and, behold, there was a man",15,55],["H4758","whose appearance",57,73],["H4758","was like the appearance",74,97],["H5178","of brass",98,106],["H6616","with a line",108,119],["H6593","of flax",120,127],["H3027","in his hand",128,139],["H4060","and a measuring",141,156],["H7070","reed",157,161],["H5975","and he stood",163,175],["H8179","in the gate",176,187]]},"40:4":{"text":"And the man said unto me, Son of man, behold with thine eyes, and hear with thine ears, and set thine heart upon all that I shall shew thee; for to the intent that I might shew them unto thee art thou brought hither: declare all that thou seest to the house of Israel.","words":[["H0376","And the man",0,11],["H1696","said",12,16],["H1121","unto me, Son",17,29],["H0120","of man",30,36],["H7200","behold",38,44],["H5869","with thine eyes",45,60],["H8085","and hear",62,70],["H0241","with thine ears",71,86],["H7760","and set",88,95],["H3820","thine heart",96,107],["H7200","upon all that I shall shew",108,134],["H4616","thee; for to the intent",135,158],["H7200","that I might shew",159,176],["H0935","them unto thee art thou brought",177,208],["H5046","hither: declare",209,224],["H7200","all that thou seest",225,244],["H1004","to the house",245,257],["H3478","of Israel",258,267]]},"40:5":{"text":"And behold a wall on the outside of the house round about, and in the man's hand a measuring reed of six cubits long by the cubit and an hand breadth: so he measured the breadth of the building, one reed; and the height, one reed.","words":[["H2346","And behold a wall",0,17],["H2351","on the outside",18,32],["H1004","of the house",33,45],["H5439","round about",46,57],["H0376","and in the man's",59,75],["H3027","hand",76,80],["H4060","a measuring",81,92],["H7070","reed",93,97],["H8337","of six",98,104],["H0520","cubits",105,111],["H0520","long by the cubit",112,129],["H2948","and an hand breadth",130,149],["H4058","so he measured",151,165],["H7341","the breadth",166,177],["H1146","of the building",178,193],["H0259","one",195,198],["H7070","reed",199,203],["H6967","and the height",205,219],["H0259","one",221,224],["H7070","reed",225,229]]},"40:6":{"text":"Then came he unto the gate which looketh toward the east, and went up the stairs thereof, and measured the threshold of the gate, which was one reed broad; and the other threshold of the gate, which was one reed broad.","words":[["H0935","Then came",0,9],["H8179","he unto the gate",10,26],["H6440","which looketh",27,40],["H1870","toward",41,47],["H6921","the east",48,56],["H5927","and went up",58,69],["H4609","the stairs",70,80],["H4058","thereof, and measured",81,102],["H5592","the threshold",103,116],["H8179","of the gate",117,128],["H0259","which was one",130,143],["H7070","reed",144,148],["H7341","broad",149,154],["H0259","and the other",156,169],["H5592","threshold",170,179],["H0259","of the gate, which was one",180,206],["H7070","reed",207,211],["H7341","broad",212,217]]},"40:7":{"text":"And every little chamber was one reed long, and one reed broad; and between the little chambers were five cubits; and the threshold of the gate by the porch of the gate within was one reed.","words":[["H8372","And every little chamber",0,24],["H0259","was one",25,32],["H7070","reed",33,37],["H0753","long",38,42],["H0259","and one",44,51],["H7070","reed",52,56],["H7341","broad",57,62],["H8372","and between the little chambers",64,95],["H2568","were five",96,105],["H0520","cubits",106,112],["H5592","and the threshold",114,131],["H8179","of the gate",132,143],["H0681","by",144,146],["H0197","the porch",147,156],["H8179","of the gate",157,168],["H1004","within",169,175],["H0259","was one",176,183],["H7070","reed",184,188]]},"40:8":{"text":"He measured also the porch of the gate within, one reed.","words":[["H4058","He measured",0,11],["H0197","also the porch",12,26],["H8179","of the gate",27,38],["H1004","within",39,45],["H0259","one",47,50],["H7070","reed",51,55]]},"40:9":{"text":"Then measured he the porch of the gate, eight cubits; and the posts thereof, two cubits; and the porch of the gate was inward.","words":[["H4058","Then measured",0,13],["H0197","he the porch",14,26],["H8179","of the gate",27,38],["H8083","eight",40,45],["H0520","cubits",46,52],["H0352","and the posts",54,67],["H8147","thereof, two",68,80],["H0520","cubits",81,87],["H0197","and the porch",89,102],["H8179","of the gate",103,114],["H1004","was inward",115,125]]},"40:10":{"text":"And the little chambers of the gate eastward were three on this side, and three on that side; they three were of one measure: and the posts had one measure on this side and on that side.","words":[["H8372","And the little chambers",0,23],["H8179","of the gate",24,35],["H1870","eastward",36,44],["H6921","eastward",36,44],["H7969","were three",45,55],["H6311","on this side",56,68],["H7969","and three",70,79],["H6311","on that side",80,92],["H7969","they three",94,104],["H0259","were of one",105,116],["H4060","measure",117,124],["H0352","and the posts",126,139],["H0259","had one",140,147],["H4060","measure",148,155]]},"40:11":{"text":"And he measured the breadth of the entry of the gate, ten cubits; and the length of the gate, thirteen cubits.","words":[["H4058","And he measured",0,15],["H7341","the breadth",16,27],["H6607","of the entry",28,40],["H8179","of the gate",41,52],["H6235","ten",54,57],["H0520","cubits",58,64],["H0753","and the length",66,80],["H8179","of the gate",81,92],["H7969","thirteen",94,102],["H6240","thirteen",94,102],["H0520","cubits",103,109]]},"40:12":{"text":"The space also before the little chambers was one cubit on this side, and the space was one cubit on that side: and the little chambers were six cubits on this side, and six cubits on that side.","words":[["H1366","The space",0,9],["H6440","also before",10,21],["H8372","the little chambers",22,41],["H0259","was one",42,49],["H0520","cubit",50,55],["H1366","on this side, and the space",56,83],["H0520","was one cubit",84,97],["H8372","on that side: and the little chambers",98,135],["H8337","were six",136,144],["H0520","cubits",145,151],["H8337","on this side, and six",152,173],["H0520","cubits",174,180]]},"40:13":{"text":"He measured then the gate from the roof of one little chamber to the roof of another: the breadth was five and twenty cubits, door against door.","words":[["H4058","He measured",0,11],["H8179","then the gate",12,25],["H1406","from the roof",26,39],["H8372","of one little chamber",40,61],["H1406","to the roof",62,73],["H7341","of another: the breadth",74,97],["H2568","was five",98,106],["H6242","and twenty",107,117],["H0520","cubits",118,124],["H6607","door",126,130],["H6607","against door",131,143]]},"40:14":{"text":"He made also posts of threescore cubits, even unto the post of the court round about the gate.","words":[["H6213","He made",0,7],["H0352","also posts",8,18],["H8346","of threescore",19,32],["H0520","cubits",33,39],["H0352","even unto the post",41,59],["H2691","of the court",60,72],["H5439","round about",73,84],["H8179","the gate",85,93]]},"40:15":{"text":"And from the face of the gate of the entrance unto the face of the porch of the inner gate were fifty cubits.","words":[["H6440","And from the face",0,17],["H8179","of the gate",18,29],["H2978","of the entrance",30,45],["H6440","unto the face",46,59],["H0197","of the porch",60,72],["H6442","of the inner",73,85],["H8179","gate",86,90],["H2572","were fifty",91,101],["H0520","cubits",102,108]]},"40:16":{"text":"And there were narrow windows to the little chambers, and to their posts within the gate round about, and likewise to the arches: and windows were round about inward: and upon each post were palm trees.","words":[["H0331","And there were narrow",0,21],["H2474","windows",22,29],["H8372","to the little chambers",30,52],["H0352","and to their posts",54,72],["H6441","within",73,79],["H8179","the gate",80,88],["H5439","round about",89,100],["H0361","and likewise to the arches",102,128],["H2474","and windows",130,141],["H5439","were round about",142,158],["H6441","inward",159,165],["H0352","and upon each post",167,185],["H8561","were palm trees",186,201]]},"40:17":{"text":"Then brought he me into the outward court, and, lo, there were chambers, and a pavement made for the court round about: thirty chambers were upon the pavement.","words":[["H0935","Then brought",0,12],["H2435","he me into the outward",13,35],["H2691","court",36,41],["H3957","and, lo, there were chambers",43,71],["H7531","and a pavement",73,87],["H6213","made",88,92],["H2691","for the court",93,106],["H5439","round about",107,118],["H7970","thirty",120,126],["H3957","chambers",127,135],["H7531","were upon the pavement",136,158]]},"40:18":{"text":"And the pavement by the side of the gates over against the length of the gates was the lower pavement.","words":[["H7531","And the pavement",0,16],["H3802","by the side",17,28],["H8179","of the gates",29,41],["H5980","over against",42,54],["H0753","the length",55,65],["H8179","of the gates",66,78],["H8481","was the lower",79,92],["H7531","pavement",93,101]]},"40:19":{"text":"Then he measured the breadth from the forefront of the lower gate unto the forefront of the inner court without, an hundred cubits eastward and northward.","words":[["H4058","Then he measured",0,16],["H7341","the breadth",17,28],["H6440","from the forefront",29,47],["H8481","of the lower",48,60],["H8179","gate",61,65],["H6440","unto the forefront",66,84],["H6442","of the inner",85,97],["H2691","court",98,103],["H2351","without",104,111],["H3967","an hundred",113,123],["H0520","cubits",124,130],["H6921","eastward",131,139],["H6828","and northward",140,153]]},"40:20":{"text":"And the gate of the outward court that looked toward the north, he measured the length thereof, and the breadth thereof.","words":[["H8179","And the gate",0,12],["H2435","of the outward",13,27],["H2691","court",28,33],["H6440","that looked",34,45],["H1870","toward",46,52],["H6828","the north",53,62],["H4058","he measured",64,75],["H0753","the length",76,86],["H7341","thereof, and the breadth",87,111]]},"40:21":{"text":"And the little chambers thereof were three on this side and three on that side; and the posts thereof and the arches thereof were after the measure of the first gate: the length thereof was fifty cubits, and the breadth five and twenty cubits.","words":[["H8372","And the little chambers",0,23],["H7969","thereof were three",24,42],["H7969","on this side and three",43,65],["H0352","on that side; and the posts",66,93],["H0361","thereof and the arches",94,116],["H4060","thereof were after the measure",117,147],["H7223","of the first",148,160],["H8179","gate",161,165],["H0753","the length",167,177],["H2572","thereof was fifty",178,195],["H0520","cubits",196,202],["H7341","and the breadth",204,219],["H2568","five",220,224],["H6242","and twenty",225,235],["H0520","cubits",236,242]]},"40:22":{"text":"And their windows, and their arches, and their palm trees, were after the measure of the gate that looketh toward the east; and they went up unto it by seven steps; and the arches thereof were before them.","words":[["H2474","And their windows",0,17],["H0361","and their arches",19,35],["H8561","and their palm trees",37,57],["H4060","were after the measure",59,81],["H8179","of the gate",82,93],["H6440","that looketh",94,106],["H1870","toward",107,113],["H6921","the east",114,122],["H5927","and they went up",124,140],["H7651","unto it by seven",141,157],["H4609","steps",158,163],["H0361","and the arches",165,179],["H6440","thereof were before",180,199]]},"40:23":{"text":"And the gate of the inner court was over against the gate toward the north, and toward the east; and he measured from gate to gate an hundred cubits.","words":[["H8179","And the gate",0,12],["H6442","of the inner",13,25],["H2691","court",26,31],["H8179","was over against the gate",32,57],["H6828","toward the north",58,74],["H6921","and toward the east",76,95],["H4058","and he measured",97,112],["H8179","from gate",113,122],["H8179","to gate",123,130],["H3967","an hundred",131,141],["H0520","cubits",142,148]]},"40:24":{"text":"After that he brought me toward the south, and behold a gate toward the south: and he measured the posts thereof and the arches thereof according to these measures.","words":[["H3212","After that he brought",0,21],["H1870","me toward",22,31],["H1864","the south",32,41],["H8179","and behold a gate",43,60],["H1870","toward",61,67],["H1864","the south",68,77],["H4058","and he measured",79,94],["H0352","the posts",95,104],["H0361","thereof and the arches",105,127],["H4060","thereof according to these measures",128,163]]},"40:25":{"text":"And there were windows in it and in the arches thereof round about, like those windows: the length was fifty cubits, and the breadth five and twenty cubits.","words":[["H2474","And there were windows",0,22],["H0361","in it and in the arches",23,46],["H5439","thereof round about",47,66],["H2474","like those windows",68,86],["H0753","the length",88,98],["H2572","was fifty",99,108],["H0520","cubits",109,115],["H7341","and the breadth",117,132],["H2568","five",133,137],["H6242","and twenty",138,148],["H0520","cubits",149,155]]},"40:26":{"text":"And there were seven steps to go up to it, and the arches thereof were before them: and it had palm trees, one on this side, and another on that side, upon the posts thereof.","words":[["H7651","And there were seven",0,20],["H4609","steps",21,26],["H5930","to go up",27,35],["H0361","to it, and the arches",36,57],["H6440","thereof were before",58,77],["H8561","them: and it had palm trees",78,105],["H0259","one",107,110],["H0259","on this side, and another",111,136],["H0352","on that side, upon the posts",137,165]]},"40:27":{"text":"And there was a gate in the inner court toward the south: and he measured from gate to gate toward the south an hundred cubits.","words":[["H8179","And there was a gate",0,20],["H6442","in the inner",21,33],["H2691","court",34,39],["H1870","toward",40,46],["H1864","the south",47,56],["H4058","and he measured",58,73],["H8179","from gate",74,83],["H8179","to gate",84,91],["H1870","toward",92,98],["H1864","the south",99,108],["H3967","an hundred",109,119],["H0520","cubits",120,126]]},"40:28":{"text":"And he brought me to the inner court by the south gate: and he measured the south gate according to these measures;","words":[["H0935","And he brought",0,14],["H6442","me to the inner",15,30],["H2691","court",31,36],["H1864","by the south",37,49],["H8179","gate",50,54],["H4058","and he measured",56,71],["H1864","the south",72,81],["H8179","gate",82,86],["H4060","according to these measures",87,114]]},"40:29":{"text":"And the little chambers thereof, and the posts thereof, and the arches thereof, according to these measures: and there were windows in it and in the arches thereof round about: it was fifty cubits long, and five and twenty cubits broad.","words":[["H8372","And the little chambers",0,23],["H0352","thereof, and the posts",24,46],["H0361","thereof, and the arches",47,70],["H4060","thereof, according to these measures",71,107],["H2474","and there were windows",109,131],["H0361","in it and in the arches",132,155],["H5439","thereof round about",156,175],["H2572","it was fifty",177,189],["H0520","cubits",190,196],["H0753","long",197,201],["H2568","and five",203,211],["H6242","and twenty",212,222],["H0520","cubits",223,229],["H7341","broad",230,235]]},"40:30":{"text":"And the arches round about were five and twenty cubits long, and five cubits broad.","words":[["H0361","And the arches",0,14],["H5439","round about",15,26],["H2568","were five",27,36],["H6242","and twenty",37,47],["H0520","cubits",48,54],["H0753","long",55,59],["H2568","and five",61,69],["H0520","cubits",70,76],["H7341","broad",77,82]]},"40:31":{"text":"And the arches thereof were toward the utter court; and palm trees were upon the posts thereof: and the going up to it had eight steps.","words":[["H0361","And the arches",0,14],["H2435","thereof were toward the utter",15,44],["H2691","court",45,50],["H8561","and palm trees",52,66],["H0352","were upon the posts",67,86],["H4608","thereof: and the going up",87,112],["H8083","to it had eight",113,128],["H4609","steps",129,134]]},"40:32":{"text":"And he brought me into the inner court toward the east: and he measured the gate according to these measures.","words":[["H0935","And he brought",0,14],["H6442","me into the inner",15,32],["H2691","court",33,38],["H1870","toward",39,45],["H6921","the east",46,54],["H4058","and he measured",56,71],["H8179","the gate",72,80],["H4060","according to these measures",81,108]]},"40:33":{"text":"And the little chambers thereof, and the posts thereof, and the arches thereof, were according to these measures: and there were windows therein and in the arches thereof round about: it was fifty cubits long, and five and twenty cubits broad.","words":[["H8372","And the little chambers",0,23],["H0352","thereof, and the posts",24,46],["H0361","thereof, and the arches",47,70],["H4060","thereof, were according to these measures",71,112],["H2474","and there were windows",114,136],["H0361","therein and in the arches",137,162],["H5439","thereof round about",163,182],["H2572","it was fifty",184,196],["H0520","cubits",197,203],["H0753","long",204,208],["H2568","and five",210,218],["H6242","and twenty",219,229],["H0520","cubits",230,236],["H7341","broad",237,242]]},"40:34":{"text":"And the arches thereof were toward the outward court; and palm trees were upon the posts thereof, on this side, and on that side: and the going up to it had eight steps.","words":[["H0361","And the arches",0,14],["H2435","thereof were toward the outward",15,46],["H2691","court",47,52],["H8561","and palm trees",54,68],["H0352","were upon the posts",69,88],["H4608","thereof, on this side, and on that side: and the going up",89,146],["H8083","to it had eight",147,162],["H4609","steps",163,168]]},"40:35":{"text":"And he brought me to the north gate, and measured it according to these measures;","words":[["H0935","And he brought",0,14],["H6828","me to the north",15,30],["H8179","gate",31,35],["H4058","and measured",37,49],["H4060","it according to these measures",50,80]]},"40:36":{"text":"The little chambers thereof, the posts thereof, and the arches thereof, and the windows to it round about: the length was fifty cubits, and the breadth five and twenty cubits.","words":[["H8372","The little chambers",0,19],["H0352","thereof, the posts",20,38],["H0361","thereof, and the arches",39,62],["H2474","thereof, and the windows",63,87],["H5439","to it round about",88,105],["H0753","the length",107,117],["H2572","was fifty",118,127],["H0520","cubits",128,134],["H7341","and the breadth",136,151],["H2568","five",152,156],["H6242","and twenty",157,167],["H0520","cubits",168,174]]},"40:37":{"text":"And the posts thereof were toward the utter court; and palm trees were upon the posts thereof, on this side, and on that side: and the going up to it had eight steps.","words":[["H0352","And the posts",0,13],["H2435","thereof were toward the utter",14,43],["H2691","court",44,49],["H8561","and palm trees",51,65],["H0352","were upon the posts",66,85],["H4608","thereof, on this side, and on that side: and the going up",86,143],["H8083","to it had eight",144,159],["H4609","steps",160,165]]},"40:38":{"text":"And the chambers and the entries thereof were by the posts of the gates, where they washed the burnt offering.","words":[["H3957","And the chambers",0,16],["H6607","and the entries",17,32],["H0352","thereof were by the posts",33,58],["H8179","of the gates",59,71],["H1740","where they washed",73,90],["H5930","the burnt offering",91,109]]},"40:39":{"text":"And in the porch of the gate were two tables on this side, and two tables on that side, to slay thereon the burnt offering and the sin offering and the trespass offering.","words":[["H0197","And in the porch",0,16],["H8179","of the gate",17,28],["H8147","were two",29,37],["H7979","tables",38,44],["H7979","on this side, and two tables",45,73],["H7819","on that side, to slay",74,95],["H5930","thereon the burnt offering",96,122],["H2403","and the sin offering",123,143],["H0817","and the trespass offering",144,169]]},"40:40":{"text":"And at the side without, as one goeth up to the entry of the north gate, were two tables; and on the other side, which was at the porch of the gate, were two tables.","words":[["H3802","And at the side",0,15],["H2351","without",16,23],["H5927","as one goeth up",25,40],["H6607","to the entry",41,53],["H6828","of the north",54,66],["H8179","gate",67,71],["H8147","were two",73,81],["H7979","tables",82,88],["H0312","and on the other",90,106],["H3802","side",107,111],["H0197","which was at the porch",113,135],["H8179","of the gate",136,147],["H8147","were two",149,157],["H7979","tables",158,164]]},"40:41":{"text":"Four tables were on this side, and four tables on that side, by the side of the gate; eight tables, whereupon they slew their sacrifices.","words":[["H0702","Four",0,4],["H7979","tables",5,11],["H0702","were on this side, and four",12,39],["H7979","tables",40,46],["H3802","on that side, by the side",47,72],["H8179","of the gate",73,84],["H8083","eight",86,91],["H7979","tables",92,98],["H7819","whereupon they slew",100,119]]},"40:42":{"text":"And the four tables were of hewn stone for the burnt offering, of a cubit and an half long, and a cubit and an half broad, and one cubit high: whereupon also they laid the instruments wherewith they slew the burnt offering and the sacrifice.","words":[["H0702","And the four",0,12],["H7979","tables",13,19],["H1496","were of hewn",20,32],["H0068","stone",33,38],["H5930","for the burnt offering",39,61],["H0520","of a cubit",63,73],["H2677","and an half",74,85],["H0753","long",86,90],["H0520","and a cubit",92,103],["H2677","and an half",104,115],["H7341","broad",116,121],["H0259","and one",123,130],["H0520","cubit",131,136],["H1363","high",137,141],["H3240","whereupon also they laid",143,167],["H3627","the instruments",168,183],["H7819","wherewith they slew",184,203],["H5930","the burnt offering",204,222],["H2077","and the sacrifice",223,240]]},"40:43":{"text":"And within were hooks, an hand broad, fastened round about: and upon the tables was the flesh of the offering.","words":[["H1004","And within",0,10],["H8240","were hooks",11,21],["H0259","an",23,25],["H2948","hand",26,30],["H3559","broad, fastened",31,46],["H5439","round about",47,58],["H7979","and upon the tables",60,79],["H1320","was the flesh",80,93],["H7133","of the offering",94,109]]},"40:44":{"text":"And without the inner gate were the chambers of the singers in the inner court, which was at the side of the north gate; and their prospect was toward the south: one at the side of the east gate having the prospect toward the north.","words":[["H2351","And without",0,11],["H6442","the inner",12,21],["H8179","gate",22,26],["H3957","were the chambers",27,44],["H7891","of the singers",45,59],["H6442","in the inner",60,72],["H2691","court",73,78],["H3802","which was at the side",80,101],["H6828","of the north",102,114],["H8179","gate",115,119],["H6440","and their prospect",121,139],["H1870","was toward",140,150],["H1864","the south",151,160],["H0259","one",162,165],["H3802","at the side",166,177],["H6921","of the east",178,189],["H8179","gate",190,194],["H6440","having the prospect",195,214],["H1870","toward",215,221],["H6828","the north",222,231]]},"40:45":{"text":"And he said unto me, This chamber, whose prospect is toward the south, is for the priests, the keepers of the charge of the house.","words":[["H1696","And he said",0,11],["H2090","unto me, This",12,25],["H3957","chamber",26,33],["H6440","whose prospect",35,49],["H1870","is toward",50,59],["H1864","the south",60,69],["H3548","is for the priests",71,89],["H8104","the keepers",91,102],["H4931","of the charge",103,116],["H1004","of the house",117,129]]},"40:46":{"text":"And the chamber whose prospect is toward the north is for the priests, the keepers of the charge of the altar: these are the sons of Zadok among the sons of Levi, which come near to the LORD to minister unto him.","words":[["H3957","And the chamber",0,15],["H6440","whose prospect",16,30],["H1870","is toward",31,40],["H6828","the north",41,50],["H3548","is for the priests",51,69],["H8104","the keepers",71,82],["H4931","of the charge",83,96],["H4196","of the altar",97,109],["H1121","these are the sons",111,129],["H6659","of Zadok",130,138],["H1121","among the sons",139,153],["H3878","of Levi",154,161],["H7131","which come near",163,178],["H3068","to the LORD",179,190],["H8334","to minister",191,202]]},"40:47":{"text":"So he measured the court, an hundred cubits long, and an hundred cubits broad, foursquare; and the altar that was before the house.","words":[["H4058","So he measured",0,14],["H2691","the court",15,24],["H3967","an hundred",26,36],["H0520","cubits",37,43],["H0753","long",44,48],["H3967","and an hundred",50,64],["H0520","cubits",65,71],["H7341","broad",72,77],["H7251","foursquare",79,89],["H4196","and the altar",91,104],["H6440","that was before",105,120],["H1004","the house",121,130]]},"40:48":{"text":"And he brought me to the porch of the house, and measured each post of the porch, five cubits on this side, and five cubits on that side: and the breadth of the gate was three cubits on this side, and three cubits on that side.","words":[["H0935","And he brought",0,14],["H0197","me to the porch",15,30],["H1004","of the house",31,43],["H4058","and measured",45,57],["H0352","each post",58,67],["H0197","of the porch",68,80],["H2568","five",82,86],["H0520","cubits",87,93],["H2568","on this side, and five",94,116],["H0520","cubits",117,123],["H7341","on that side: and the breadth",124,153],["H8179","of the gate",154,165],["H7969","was three",166,175],["H0520","cubits",176,182],["H7969","on this side, and three",183,206],["H0520","cubits",207,213]]},"40:49":{"text":"The length of the porch was twenty cubits, and the breadth eleven cubits; and he brought me by the steps whereby they went up to it: and there were pillars by the posts, one on this side, and another on that side.","words":[["H0753","The length",0,10],["H0197","of the porch",11,23],["H6242","was twenty",24,34],["H0520","cubits",35,41],["H7341","and the breadth",43,58],["H6249","eleven",59,65],["H6240","eleven",59,65],["H0520","cubits",66,72],["H4609","and he brought me by the steps",74,104],["H5927","whereby they went up",105,125],["H5982","to it: and there were pillars",126,155],["H0352","by the posts",156,168],["H0259","one",170,173],["H0259","on this side, and another",174,199]]},"41:1":{"text":"Afterward he brought me to the temple, and measured the posts, six cubits broad on the one side, and six cubits broad on the other side, which was the breadth of the tabernacle.","words":[["H0935","Afterward he brought",0,20],["H1964","me to the temple",21,37],["H4058","and measured",39,51],["H0352","the posts",52,61],["H8337","six",63,66],["H0520","cubits",67,73],["H7341","broad",74,79],["H6311","on the one side",80,95],["H8337","and six",97,104],["H0520","cubits",105,111],["H7341","broad",112,117],["H6311","on the other side",118,135],["H7341","which was the breadth",137,158],["H0168","of the tabernacle",159,176]]},"41:2":{"text":"And the breadth of the door was ten cubits; and the sides of the door were five cubits on the one side, and five cubits on the other side: and he measured the length thereof, forty cubits: and the breadth, twenty cubits.","words":[["H7341","And the breadth",0,15],["H6607","of the door",16,27],["H6235","was ten",28,35],["H0520","cubits",36,42],["H3802","and the sides",44,57],["H6607","of the door",58,69],["H2568","were five",70,79],["H0520","cubits",80,86],["H2568","on the one side, and five",87,112],["H0520","cubits",113,119],["H4058","on the other side: and he measured",120,154],["H0753","the length",155,165],["H0705","thereof, forty",166,180],["H0520","cubits",181,187],["H7341","and the breadth",189,204],["H6242","twenty",206,212],["H0520","cubits",213,219]]},"41:3":{"text":"Then went he inward, and measured the post of the door, two cubits; and the door, six cubits; and the breadth of the door, seven cubits.","words":[["H0935","Then went",0,9],["H6441","he inward",10,19],["H4058","and measured",21,33],["H0352","the post",34,42],["H6607","of the door",43,54],["H8147","two",56,59],["H0520","cubits",60,66],["H6607","and the door",68,80],["H8337","six",82,85],["H0520","cubits",86,92],["H7341","and the breadth",94,109],["H6607","of the door",110,121],["H7651","seven",123,128],["H0520","cubits",129,135]]},"41:4":{"text":"So he measured the length thereof, twenty cubits; and the breadth, twenty cubits, before the temple: and he said unto me, This is the most holy place.","words":[["H4058","So he measured",0,14],["H0753","the length",15,25],["H6242","thereof, twenty",26,41],["H0520","cubits",42,48],["H7341","and the breadth",50,65],["H6242","twenty",67,73],["H0520","cubits",74,80],["H6440","before",82,88],["H1964","the temple",89,99],["H0559","and he said",101,112],["H6944","unto me, This is the most",113,138],["H6944","holy",139,143]]},"41:5":{"text":"After he measured the wall of the house, six cubits; and the breadth of every side chamber, four cubits, round about the house on every side.","words":[["H4058","After he measured",0,17],["H7023","the wall",18,26],["H1004","of the house",27,39],["H8337","six",41,44],["H0520","cubits",45,51],["H7341","and the breadth",53,68],["H6763","of every side chamber",69,90],["H0702","four",92,96],["H0520","cubits",97,103],["H5439","round about",105,116],["H1004","the house",117,126],["H5439","on every side",127,140]]},"41:6":{"text":"And the side chambers were three, one over another, and thirty in order; and they entered into the wall which was of the house for the side chambers round about, that they might have hold, but they had not hold in the wall of the house.","words":[["H6763","And the side",0,12],["H6763","chambers",13,21],["H7969","were three",22,32],["H6763","one over another",34,50],["H7970","and thirty",52,62],["H6471","in order",63,71],["H0935","and they entered",73,89],["H7023","into the wall",90,103],["H1004","which was of the house",104,126],["H6763","for the side chambers",127,148],["H5439","round about",149,160],["H0270","that they might have hold",162,187],["H0270","but they had not hold",189,210],["H7023","in the wall",211,222],["H1004","of the house",223,235]]},"41:7":{"text":"And there was an enlarging, and a winding about still upward to the side chambers: for the winding about of the house went still upward round about the house: therefore the breadth of the house was still upward, and so increased from the lowest chamber to the highest by the midst.","words":[["H7337","And there was an enlarging",0,26],["H5437","and a winding about",28,47],["H4605","still upward",48,60],["H6763","to the side chambers",61,81],["H4141","for the winding about",83,104],["H1004","of the house",105,117],["H4605","went still upward",118,135],["H5439","round about",136,147],["H1004","the house",148,157],["H7341","therefore the breadth",159,180],["H1004","of the house",181,193],["H4605","was still upward",194,210],["H5927","and so increased",212,228],["H8481","from the lowest",229,244],["H5945","chamber to the highest",245,267],["H8484","by the midst",268,280]]},"41:8":{"text":"I saw also the height of the house round about: the foundations of the side chambers were a full reed of six great cubits.","words":[["H7200","I saw",0,5],["H1363","also the height",6,21],["H1004","of the house",22,34],["H5439","round about",35,46],["H4328","the foundations",48,63],["H6763","of the side chambers",64,84],["H4393","were a full",85,96],["H7070","reed",97,101],["H8337","of six",102,108],["H0679","great",109,114],["H0520","cubits",115,121]]},"41:9":{"text":"The thickness of the wall, which was for the side chamber without, was five cubits: and that which was left was the place of the side chambers that were within.","words":[["H7341","The thickness",0,13],["H7023","of the wall",14,25],["H6763","which was for the side chamber",27,57],["H2351","without",58,65],["H2568","was five",67,75],["H0520","cubits",76,82],["H3240","and that which was left",84,107],["H1004","was the place",108,121],["H6763","of the side chambers",122,142],["H1004","that were within",143,159]]},"41:10":{"text":"And between the chambers was the wideness of twenty cubits round about the house on every side.","words":[["H3957","And between the chambers",0,24],["H7341","was the wideness",25,41],["H6242","of twenty",42,51],["H0520","cubits",52,58],["H5439","round about",59,70],["H1004","the house",71,80],["H5439","on every side",81,94]]},"41:11":{"text":"And the doors of the side chambers were toward the place that was left, one door toward the north, and another door toward the south: and the breadth of the place that was left was five cubits round about.","words":[["H6607","And the doors",0,13],["H6763","of the side chambers",14,34],["H3240","were toward the place that was left",35,70],["H0259","one",72,75],["H6607","door",76,80],["H1870","toward",81,87],["H6828","the north",88,97],["H0259","and another",99,110],["H6607","door",111,115],["H1864","toward the south",116,132],["H7341","and the breadth",134,149],["H4725","of the place",150,162],["H3240","that was left",163,176],["H2568","was five",177,185],["H0520","cubits",186,192],["H5439","round about",193,204]]},"41:12":{"text":"Now the building that was before the separate place at the end toward the west was seventy cubits broad; and the wall of the building was five cubits thick round about, and the length thereof ninety cubits.","words":[["H1146","Now the building",0,16],["H6440","that was before",17,32],["H1508","the separate place",33,51],["H6285","at the end",52,62],["H1870","toward",63,69],["H3220","the west",70,78],["H7657","was seventy",79,90],["H0520","cubits",91,97],["H7341","broad",98,103],["H7023","and the wall",105,117],["H1146","of the building",118,133],["H2568","was five",134,142],["H0520","cubits",143,149],["H7341","thick",150,155],["H5439","round about",156,167],["H0753","and the length",169,183],["H8673","thereof ninety",184,198],["H0520","cubits",199,205]]},"41:13":{"text":"So he measured the house, an hundred cubits long; and the separate place, and the building, with the walls thereof, an hundred cubits long;","words":[["H4058","So he measured",0,14],["H1004","the house",15,24],["H3967","an hundred",26,36],["H0520","cubits",37,43],["H0753","long",44,48],["H1508","and the separate place",50,72],["H1140","and the building",74,90],["H7023","with the walls",92,106],["H3967","thereof, an hundred",107,126],["H0520","cubits",127,133],["H0753","long",134,138]]},"41:14":{"text":"Also the breadth of the face of the house, and of the separate place toward the east, an hundred cubits.","words":[["H7341","Also the breadth",0,16],["H6440","of the face",17,28],["H1004","of the house",29,41],["H1508","and of the separate place",43,68],["H6921","toward the east",69,84],["H3967","an hundred",86,96],["H0520","cubits",97,103]]},"41:15":{"text":"And he measured the length of the building over against the separate place which was behind it, and the galleries thereof on the one side and on the other side, an hundred cubits, with the inner temple, and the porches of the court;","words":[["H4058","And he measured",0,15],["H0753","the length",16,26],["H1146","of the building",27,42],["H6440","over against",43,55],["H1508","the separate place",56,74],["H0310","which was behind",75,91],["H0862","it, and the galleries",92,113],["H3967","thereof on the one side and on the other side, an hundred",114,171],["H0520","cubits",172,178],["H6442","with the inner",180,194],["H1964","temple",195,201],["H0197","and the porches",203,218],["H2691","of the court",219,231]]},"41:16":{"text":"The door posts, and the narrow windows, and the galleries round about on their three stories, over against the door, cieled with wood round about, and from the ground up to the windows, and the windows were covered;","words":[["H5592","The door posts",0,14],["H0331","and the narrow",16,30],["H2474","windows",31,38],["H0862","and the galleries",40,57],["H5439","round about",58,69],["H7969","on their three stories",70,92],["H5048","over against",94,106],["H5592","the door",107,115],["H7824","cieled",117,123],["H6086","with wood",124,133],["H5439","round about",134,145],["H0776","and from the ground",147,166],["H2474","up to the windows",167,184],["H2474","and the windows",186,201],["H3680","were covered",202,214]]},"41:17":{"text":"To that above the door, even unto the inner house, and without, and by all the wall round about within and without, by measure.","words":[["H6607","To that above the door",0,22],["H6442","even unto the inner",24,43],["H1004","house",44,49],["H2351","and without",51,62],["H7023","and by all the wall",64,83],["H5439","round about",84,95],["H6442","within",96,102],["H2435","and without",103,114],["H4060","by measure",116,126]]},"41:18":{"text":"And it was made with cherubims and palm trees, so that a palm tree was between a cherub and a cherub; and every cherub had two faces;","words":[["H6213","And it was made",0,15],["H3742","with cherubims",16,30],["H8561","and palm trees",31,45],["H8561","so that a palm tree",47,66],["H3742","was between a cherub",67,87],["H3742","and a cherub",88,100],["H3742","and every cherub",102,118],["H8147","had two",119,126],["H6440","faces",127,132]]},"41:19":{"text":"So that the face of a man was toward the palm tree on the one side, and the face of a young lion toward the palm tree on the other side: it was made through all the house round about.","words":[["H6440","So that the face",0,16],["H0120","of a man",17,25],["H8561","was toward the palm tree",26,50],["H6440","on the one side, and the face",51,80],["H3715","of a young lion",81,96],["H8561","toward the palm tree",97,117],["H6213","on the other side: it was made",118,148],["H1004","through all the house",149,170],["H5439","round about",171,182]]},"41:20":{"text":"From the ground unto above the door were cherubims and palm trees made, and on the wall of the temple.","words":[["H0776","From the ground",0,15],["H6607","unto above the door",16,35],["H3742","were cherubims",36,50],["H8561","and palm trees",51,65],["H6213","made",66,70],["H7023","and on the wall",72,87],["H1964","of the temple",88,101]]},"41:21":{"text":"The posts of the temple were squared, and the face of the sanctuary; the appearance of the one as the appearance of the other.","words":[["H4201","The posts",0,9],["H1964","of the temple",10,23],["H7251","were squared",24,36],["H6440","and the face",38,50],["H6944","of the sanctuary",51,67],["H4758","the appearance",69,83],["H4758","of the one as the appearance",84,112]]},"41:22":{"text":"The altar of wood was three cubits high, and the length thereof two cubits; and the corners thereof, and the length thereof, and the walls thereof, were of wood: and he said unto me, This is the table that is before the LORD.","words":[["H4196","The altar",0,9],["H6086","of wood",10,17],["H7969","was three",18,27],["H0520","cubits",28,34],["H1364","high",35,39],["H0753","and the length",41,55],["H8147","thereof two",56,67],["H0520","cubits",68,74],["H4740","and the corners",76,91],["H0753","thereof, and the length",92,115],["H7023","thereof, and the walls",116,138],["H6086","thereof, were of wood",139,160],["H1696","and he said",162,173],["H7979","unto me, This is the table",174,200],["H6440","that is before",201,215],["H3068","the LORD",216,224]]},"41:23":{"text":"And the temple and the sanctuary had two doors.","words":[["H1964","And the temple",0,14],["H6944","and the sanctuary",15,32],["H8147","had two",33,40],["H1817","doors",41,46]]},"41:24":{"text":"And the doors had two leaves apiece, two turning leaves; two leaves for the one door, and two leaves for the other door.","words":[["H1817","And the doors",0,13],["H8147","had two",14,21],["H1817","leaves",22,28],["H8147","apiece, two",29,40],["H4142","turning",41,48],["H1817","leaves",49,55],["H8147","two",57,60],["H0259","leaves for the one",61,79],["H1817","door",80,84],["H8147","and two",86,93],["H1817","leaves",94,100],["H0312","for the other",101,114]]},"41:25":{"text":"And there were made on them, on the doors of the temple, cherubims and palm trees, like as were made upon the walls; and there were thick planks upon the face of the porch without.","words":[["H6213","And there were made",0,19],["H1817","on them, on the doors",20,41],["H1964","of the temple",42,55],["H3742","cherubims",57,66],["H8561","and palm trees",67,81],["H6213","like as were made",83,100],["H7023","upon the walls",101,115],["H5646","and there were thick",117,137],["H6086","planks",138,144],["H6440","upon the face",145,158],["H0197","of the porch",159,171],["H2351","without",172,179]]},"41:26":{"text":"And there were narrow windows and palm trees on the one side and on the other side, on the sides of the porch, and upon the side chambers of the house, and thick planks.","words":[["H0331","And there were narrow",0,21],["H2474","windows",22,29],["H8561","and palm trees",30,44],["H3802","on the one side and on the other side, on the sides",45,96],["H0197","of the porch",97,109],["H6763","and upon the side chambers",111,137],["H1004","of the house",138,150],["H5646","and thick planks",152,168]]},"42:1":{"text":"Then he brought me forth into the utter court, the way toward the north: and he brought me into the chamber that was over against the separate place, and which was before the building toward the north.","words":[["H3318","Then he brought me forth",0,24],["H2435","into the utter",25,39],["H2691","court",40,45],["H1870","the way toward",47,61],["H6828","the north",62,71],["H0935","and he brought",73,87],["H3957","me into the chamber",88,107],["H1508","that was over against the separate place",108,148],["H1146","and which was before the building",150,183],["H6828","toward the north",184,200]]},"42:2":{"text":"Before the length of an hundred cubits was the north door, and the breadth was fifty cubits.","words":[["H6440","Before",0,6],["H0753","the length",7,17],["H3967","of an hundred",18,31],["H0520","cubits",32,38],["H6828","was the north",39,52],["H6607","door",53,57],["H7341","and the breadth",59,74],["H2572","was fifty",75,84],["H0520","cubits",85,91]]},"42:3":{"text":"Over against the twenty cubits which were for the inner court, and over against the pavement which was for the utter court, was gallery against gallery in three stories.","words":[["H6242","Over against the twenty",0,23],["H6442","cubits which were for the inner",24,55],["H2691","court",56,61],["H7531","and over against the pavement",63,92],["H2435","which was for the utter",93,116],["H2691","court",117,122],["H0862","was gallery",124,135],["H6440","against",136,143],["H0862","gallery",144,151],["H7992","in three",152,160]]},"42:4":{"text":"And before the chambers was a walk of ten cubits breadth inward, a way of one cubit; and their doors toward the north.","words":[["H6440","And before",0,10],["H3957","the chambers",11,23],["H4109","was a walk",24,34],["H6235","of ten",35,41],["H0520","cubits",42,48],["H7341","breadth",49,56],["H6442","inward",57,63],["H1870","a way",65,70],["H0259","of one",71,77],["H0520","cubit",78,83],["H6607","and their doors",85,100],["H6828","toward the north",101,117]]},"42:5":{"text":"Now the upper chambers were shorter: for the galleries were higher than these, than the lower, and than the middlemost of the building.","words":[["H5945","Now the upper",0,13],["H3957","chambers",14,22],["H7114","were shorter",23,35],["H0862","for the galleries",37,54],["H0398","were higher",55,66],["H2007","than these",67,77],["H8481","than the lower",79,93],["H8484","and than the middlemost",95,118],["H1146","of the building",119,134]]},"42:6":{"text":"For they were in three stories, but had not pillars as the pillars of the courts: therefore the building was straitened more than the lowest and the middlemost from the ground.","words":[["H8027","For they were in three",0,22],["H5982","stories, but had not pillars",23,51],["H5982","as the pillars",52,66],["H2691","of the courts",67,80],["H0680","therefore the building was straitened",82,119],["H8481","more than the lowest",120,140],["H8484","and the middlemost",141,159],["H0776","from the ground",160,175]]},"42:7":{"text":"And the wall that was without over against the chambers, toward the utter court on the forepart of the chambers, the length thereof was fifty cubits.","words":[["H1447","And the wall",0,12],["H2351","that was without",13,29],["H5980","over against",30,42],["H3957","the chambers",43,55],["H1870","toward",57,63],["H2435","the utter",64,73],["H2691","court",74,79],["H6440","on the forepart",80,95],["H3957","of the chambers",96,111],["H0753","the length",113,123],["H2572","thereof was fifty",124,141],["H0520","cubits",142,148]]},"42:8":{"text":"For the length of the chambers that were in the utter court was fifty cubits: and, lo, before the temple were an hundred cubits.","words":[["H0753","For the length",0,14],["H3957","of the chambers",15,30],["H2435","that were in the utter",31,53],["H2691","court",54,59],["H2572","was fifty",60,69],["H0520","cubits",70,76],["H6440","and, lo, before",78,93],["H1964","the temple",94,104],["H3967","were an hundred",105,120],["H0520","cubits",121,127]]},"42:9":{"text":"And from under these chambers was the entry on the east side, as one goeth into them from the utter court.","words":[["H3957","And from under these chambers",0,29],["H3996","was the entry",30,43],["H0935","was the entry",30,43],["H6921","on the east side",44,60],["H0935","as one goeth",62,74],["H2007","into them",75,84],["H2435","from the utter",85,99],["H2691","court",100,105]]},"42:10":{"text":"The chambers were in the thickness of the wall of the court toward the east, over against the separate place, and over against the building.","words":[["H3957","The chambers",0,12],["H7341","were in the thickness",13,34],["H1444","of the wall",35,46],["H2691","of the court",47,59],["H1870","toward",60,66],["H6921","the east",67,75],["H6440","over against",77,89],["H1508","the separate place",90,108],["H6440","and over against",110,126],["H1146","the building",127,139]]},"42:11":{"text":"And the way before them was like the appearance of the chambers which were toward the north, as long as they, and as broad as they: and all their goings out were both according to their fashions, and according to their doors.","words":[["H1870","And the way",0,11],["H6440","before",12,18],["H4758","them was like the appearance",19,47],["H3957","of the chambers",48,63],["H1870","which were toward",64,81],["H6828","the north",82,91],["H0753","as long as",93,103],["H3651","they, and as broad as",104,125],["H7341","they, and as broad as",104,125],["H4161","they: and all their goings out",126,156],["H4941","were both according to their fashions",157,194],["H6607","and according to their doors",196,224]]},"42:12":{"text":"And according to the doors of the chambers that were toward the south was a door in the head of the way, even the way directly before the wall toward the east, as one entereth into them.","words":[["H6607","And according to the doors",0,26],["H3957","of the chambers",27,42],["H1870","that were toward",43,59],["H1864","the south",60,69],["H6607","was a door",70,80],["H7218","in the head",81,92],["H1870","of the way",93,103],["H1870","even the way",105,117],["H1903","directly",118,126],["H6440","before",127,133],["H1448","the wall",134,142],["H1870","toward",143,149],["H6921","the east",150,158],["H0935","as one entereth",160,175]]},"42:13":{"text":"Then said he unto me, The north chambers and the south chambers, which are before the separate place, they be holy chambers, where the priests that approach unto the LORD shall eat the most holy things: there shall they lay the most holy things, and the meat offering, and the sin offering, and the trespass offering; for the place is holy.","words":[["H0559","Then said",0,9],["H6828","he unto me, The north",10,31],["H3957","chambers",32,40],["H1864","and the south",41,54],["H3957","chambers",55,63],["H6440","which are before",65,81],["H1508","the separate place",82,100],["H6944","they be holy",102,114],["H3957","chambers",115,123],["H3548","where the priests",125,142],["H7138","that approach",143,156],["H3068","unto the LORD",157,170],["H0398","shall eat",171,180],["H6944","the most",181,189],["H6944","holy things",190,201],["H3240","there shall they lay",203,223],["H6944","the most",224,232],["H6944","holy things",233,244],["H4503","and the meat offering",246,267],["H2403","and the sin offering",269,289],["H0817","and the trespass offering",291,316],["H4725","for the place",318,331],["H6918","is holy",332,339]]},"42:14":{"text":"When the priests enter therein, then shall they not go out of the holy place into the utter court, but there they shall lay their garments wherein they minister; for they are holy; and shall put on other garments, and shall approach to those things which are for the people.","words":[["H3548","When the priests",0,16],["H0935","enter",17,22],["H3318","therein, then shall they not go out",23,58],["H6944","of the holy",59,70],["H2435","place into the utter",71,91],["H2691","court",92,97],["H3240","but there they shall lay",99,123],["H0899","their garments",124,138],["H8334","wherein they minister",139,160],["H6944","for they are holy",162,179],["H3847","and shall put",181,194],["H3847","and shall put",181,194],["H0312","on other",195,203],["H0899","garments",204,212],["H7126","and shall approach",214,232],["H5971","to those things which are for the people",233,273]]},"42:15":{"text":"Now when he had made an end of measuring the inner house, he brought me forth toward the gate whose prospect is toward the east, and measured it round about.","words":[["H3615","Now when he had made an end",0,27],["H4060","of measuring",28,40],["H6442","the inner",41,50],["H1004","house",51,56],["H3318","he brought me forth",58,77],["H1870","toward",78,84],["H8179","the gate",85,93],["H6440","whose prospect",94,108],["H1870","is toward",109,118],["H6921","the east",119,127],["H4058","and measured",129,141],["H5439","it round about",142,156]]},"42:16":{"text":"He measured the east side with the measuring reed, five hundred reeds, with the measuring reed round about.","words":[["H4058","He measured",0,11],["H6921","the east",12,20],["H7307","side",21,25],["H4060","with the measuring",26,44],["H7070","reed",45,49],["H2568","five",51,55],["H0520","five",51,55],["H3967","hundred",56,63],["H7070","reeds",64,69],["H4060","with the measuring",71,89],["H7070","reed",90,94],["H5439","round about",95,106]]},"42:17":{"text":"He measured the north side, five hundred reeds, with the measuring reed round about.","words":[["H4058","He measured",0,11],["H6828","the north",12,21],["H7307","side",22,26],["H2568","five",28,32],["H3967","hundred",33,40],["H7070","reeds",41,46],["H4060","with the measuring",48,66],["H7070","reed",67,71],["H5439","round about",72,83]]},"42:18":{"text":"He measured the south side, five hundred reeds, with the measuring reed.","words":[["H4058","He measured",0,11],["H1864","the south",12,21],["H7307","side",22,26],["H2568","five",28,32],["H3967","hundred",33,40],["H7070","reeds",41,46],["H4060","with the measuring",48,66],["H7070","reed",67,71]]},"42:19":{"text":"He turned about to the west side, and measured five hundred reeds with the measuring reed.","words":[["H5437","He turned about",0,15],["H3220","to the west",16,27],["H7307","side",28,32],["H4058","and measured",34,46],["H2568","five",47,51],["H3967","hundred",52,59],["H7070","reeds",60,65],["H4060","with the measuring",66,84],["H7070","reed",85,89]]},"42:20":{"text":"He measured it by the four sides: it had a wall round about, five hundred reeds long, and five hundred broad, to make a separation between the sanctuary and the profane place.","words":[["H4058","He measured",0,11],["H0702","it by the four",12,26],["H7307","sides",27,32],["H2346","it had a wall",34,47],["H5439","round about",48,59],["H2568","five",61,65],["H3967","hundred",66,73],["H0753","reeds long",74,84],["H2568","and five",86,94],["H3967","hundred",95,102],["H7341","broad",103,108],["H0914","to make a separation",110,130],["H6944","between the sanctuary",131,152],["H2455","and the profane place",153,174]]},"43:1":{"text":"Afterward he brought me to the gate, even the gate that looketh toward the east:","words":[["H3212","Afterward he brought",0,20],["H8179","me to the gate",21,35],["H8179","even the gate",37,50],["H6437","that looketh",51,63],["H1870","toward",64,70],["H6921","the east",71,79]]},"43:2":{"text":"And, behold, the glory of the God of Israel came from the way of the east: and his voice was like a noise of many waters: and the earth shined with his glory.","words":[["H3519","And, behold, the glory",0,22],["H0430","of the God",23,33],["H3478","of Israel",34,43],["H0935","came",44,48],["H1870","from the way",49,61],["H6921","of the east",62,73],["H6963","and his voice",75,88],["H6963","was like a noise",89,105],["H7227","of many",106,113],["H4325","waters",114,120],["H0776","and the earth",122,135],["H0215","shined",136,142],["H3519","with his glory",143,157]]},"43:3":{"text":"And it was according to the appearance of the vision which I saw, even according to the vision that I saw when I came to destroy the city: and the visions were like the vision that I saw by the river Chebar; and I fell upon my face.","words":[["H4758","And it was according to the appearance",0,38],["H4758","of the vision",39,52],["H7200","which I saw",53,64],["H4758","even according to the vision",66,94],["H7200","that I saw",95,105],["H0935","when I came",106,117],["H7843","to destroy",118,128],["H5892","the city",129,137],["H4759","and the visions",139,154],["H4758","were like the vision",155,175],["H7200","that I saw",176,186],["H5104","by the river",187,199],["H3529","Chebar",200,206],["H5307","and I fell",208,218],["H6440","upon my face",219,231]]},"43:4":{"text":"And the glory of the LORD came into the house by the way of the gate whose prospect is toward the east.","words":[["H3519","And the glory",0,13],["H3068","of the LORD",14,25],["H0935","came",26,30],["H1004","into the house",31,45],["H1870","by the way",46,56],["H8179","of the gate",57,68],["H6440","whose prospect",69,83],["H1870","is toward",84,93],["H6921","the east",94,102]]},"43:5":{"text":"So the spirit took me up, and brought me into the inner court; and, behold, the glory of the LORD filled the house.","words":[["H7307","So the spirit",0,13],["H5375","took me up",14,24],["H0935","and brought",26,37],["H6442","me into the inner",38,55],["H2691","court",56,61],["H3519","and, behold, the glory",63,85],["H3068","of the LORD",86,97],["H4390","filled",98,104],["H1004","the house",105,114]]},"43:6":{"text":"And I heard him speaking unto me out of the house; and the man stood by me.","words":[["H8085","And I heard",0,11],["H1696","him speaking",12,24],["H1004","unto me out of the house",25,49],["H0376","and the man",51,62],["H5975","stood",63,68],["H0681","by me",69,74]]},"43:7":{"text":"And he said unto me, Son of man, the place of my throne, and the place of the soles of my feet, where I will dwell in the midst of the children of Israel for ever, and my holy name, shall the house of Israel no more defile, neither they, nor their kings, by their whoredom, nor by the carcases of their kings in their high places.","words":[["H0559","And he said",0,11],["H1121","unto me, Son",12,24],["H0120","of man",25,31],["H4725","the place",33,42],["H3678","of my throne",43,55],["H4725","and the place",57,70],["H3709","of the soles",71,83],["H7272","of my feet",84,94],["H7931","where I will dwell",96,114],["H8432","in the midst",115,127],["H1121","of the children",128,143],["H3478","of Israel",144,153],["H5769","for ever",154,162],["H6944","and my holy",164,175],["H8034","name",176,180],["H1004","shall the house",182,197],["H3478","of Israel",198,207],["H2930","no more defile",208,222],["H4428","neither they, nor their kings",224,253],["H2184","by their whoredom",255,272],["H6297","nor by the carcases",274,293],["H4428","of their kings",294,308],["H1116","in their high places",309,329]]},"43:8":{"text":"In their setting of their threshold by my thresholds, and their post by my posts, and the wall between me and them, they have even defiled my holy name by their abominations that they have committed: wherefore I have consumed them in mine anger.","words":[["H5414","In their setting",0,16],["H5592","of their threshold",17,35],["H5592","by my thresholds",36,52],["H4201","and their post",54,68],["H0681","by",69,71],["H4201","my posts",72,80],["H7023","and the wall",82,94],["H2930","between me and them, they have even defiled",95,138],["H6944","my holy",139,146],["H8034","name",147,151],["H8441","by their abominations",152,173],["H6213","that they have committed",174,198],["H3615","wherefore I have consumed",200,225],["H0639","them in mine anger",226,244]]},"43:9":{"text":"Now let them put away their whoredom, and the carcases of their kings, far from me, and I will dwell in the midst of them for ever.","words":[["H7368","Now let them put away",0,21],["H2184","their whoredom",22,36],["H6297","and the carcases",38,54],["H4428","of their kings",55,69],["H7368","far",71,74],["H7931","from me, and I will dwell",75,100],["H8432","in the midst",101,113],["H5769","of them for ever",114,130]]},"43:10":{"text":"Thou son of man, shew the house to the house of Israel, that they may be ashamed of their iniquities: and let them measure the pattern.","words":[["H1121","Thou son",0,8],["H0120","of man",9,15],["H5046","shew",17,21],["H1004","the house",22,31],["H1004","to the house",32,44],["H3478","of Israel",45,54],["H3637","that they may be ashamed",56,80],["H5771","of their iniquities",81,100],["H4058","and let them measure",102,122],["H8508","the pattern",123,134]]},"43:11":{"text":"And if they be ashamed of all that they have done, shew them the form of the house, and the fashion thereof, and the goings out thereof, and the comings in thereof, and all the forms thereof, and all the ordinances thereof, and all the forms thereof, and all the laws thereof: and write it in their sight, that they may keep the whole form thereof, and all the ordinances thereof, and do them.","words":[["H3637","And if they be ashamed",0,22],["H6213","of all that they have done",23,49],["H3045","shew",51,55],["H6699","them the form",56,69],["H1004","of the house",70,82],["H8498","and the fashion",84,99],["H4161","thereof, and the goings out",100,127],["H4126","thereof, and the comings",128,152],["H6699","in thereof, and all the forms",153,182],["H2708","thereof, and all the ordinances",183,214],["H6699","thereof, and all the forms",215,241],["H8451","thereof, and all the laws",242,267],["H3789","thereof: and write",268,286],["H5869","it in their sight",287,304],["H8104","that they may keep",306,324],["H6699","the whole form",325,339],["H2708","thereof, and all the ordinances",340,371],["H6213","thereof, and do",372,387]]},"43:12":{"text":"This is the law of the house; Upon the top of the mountain the whole limit thereof round about shall be most holy. Behold, this is the law of the house.","words":[["H8451","This is the law",0,15],["H1004","of the house",16,28],["H7218","Upon the top",30,42],["H2022","of the mountain",43,58],["H1366","the whole limit",59,74],["H5439","thereof round about",75,94],["H6944","shall be most",95,108],["H6944","holy",109,113],["H8451","Behold, this is the law",115,138],["H1004","of the house",139,151]]},"43:13":{"text":"And these are the measures of the altar after the cubits: The cubit is a cubit and an hand breadth; even the bottom shall be a cubit, and the breadth a cubit, and the border thereof by the edge thereof round about shall be a span: and this shall be the higher place of the altar.","words":[["H4060","And these are the measures",0,26],["H4196","of the altar",27,39],["H0520","after the cubits",40,56],["H0520","The cubit",58,67],["H0520","is a cubit",68,78],["H2948","and an hand breadth",79,98],["H2436","even the bottom",100,115],["H0520","shall be a cubit",116,132],["H7341","and the breadth",134,149],["H0520","a cubit",150,157],["H1366","and the border",159,173],["H8193","thereof by the edge",174,193],["H5439","thereof round about",194,213],["H0259","shall be a",214,224],["H2239","span",225,229],["H1354","and this shall be the higher place",231,265],["H4196","of the altar",266,278]]},"43:14":{"text":"And from the bottom upon the ground even to the lower settle shall be two cubits, and the breadth one cubit; and from the lesser settle even to the greater settle shall be four cubits, and the breadth one cubit.","words":[["H2436","And from the bottom",0,19],["H0776","upon the ground",20,35],["H8481","even to the lower",36,53],["H5835","settle",54,60],["H8147","shall be two",61,73],["H0520","cubits",74,80],["H7341","and the breadth",82,97],["H0259","one",98,101],["H0520","cubit",102,107],["H6996","and from the lesser",109,128],["H5835","settle",129,135],["H1419","even to the greater",136,155],["H5835","settle",156,162],["H0702","shall be four",163,176],["H0520","cubits",177,183],["H7341","and the breadth",185,200],["H0520","one cubit",201,210]]},"43:15":{"text":"So the altar shall be four cubits; and from the altar and upward shall be four horns.","words":[["H0741","So the altar",0,12],["H2025","So the altar",0,12],["H0702","shall be four",13,26],["H0520","cubits",27,33],["H0741","and from the altar",35,53],["H4605","and upward",54,64],["H0702","shall be four",65,78],["H7161","horns",79,84]]},"43:16":{"text":"And the altar shall be twelve cubits long, twelve broad, square in the four squares thereof.","words":[["H0741","And the altar",0,13],["H8147","shall be twelve",14,29],["H6240","shall be twelve",14,29],["H0753","cubits long",30,41],["H8147","twelve",43,49],["H6240","twelve",43,49],["H7341","broad",50,55],["H7251","square",57,63],["H0702","in the four",64,75],["H7253","squares",76,83]]},"43:17":{"text":"And the settle shall be fourteen cubits long and fourteen broad in the four squares thereof; and the border about it shall be half a cubit; and the bottom thereof shall be a cubit about; and his stairs shall look toward the east.","words":[["H5835","And the settle",0,14],["H0702","shall be fourteen",15,32],["H6240","shall be fourteen",15,32],["H0753","cubits long",33,44],["H0702","and fourteen",45,57],["H6240","and fourteen",45,57],["H7341","broad",58,63],["H0702","in the four",64,75],["H7253","squares",76,83],["H1366","thereof; and the border",84,107],["H5439","about",108,113],["H2677","it shall be half",114,130],["H0520","a cubit",131,138],["H2436","and the bottom",140,154],["H0520","thereof shall be a cubit",155,179],["H5439","about",180,185],["H4609","and his stairs",187,201],["H6437","shall look",202,212],["H6921","toward the east",213,228]]},"43:18":{"text":"And he said unto me, Son of man, thus saith the Lord GOD; These are the ordinances of the altar in the day when they shall make it, to offer burnt offerings thereon, and to sprinkle blood thereon.","words":[["H0559","And he said",0,11],["H1121","unto me, Son",12,24],["H0120","of man",25,31],["H0559","thus saith",33,43],["H0136","the Lord",44,52],["H3069","GOD",53,56],["H2708","These are the ordinances",58,82],["H4196","of the altar",83,95],["H3117","in the day",96,106],["H6213","when they shall make",107,127],["H5927","it, to offer",128,140],["H5930","burnt offerings",141,156],["H2236","thereon, and to sprinkle",157,181],["H1818","blood",182,187]]},"43:19":{"text":"And thou shalt give to the priests the Levites that be of the seed of Zadok, which approach unto me, to minister unto me, saith the Lord GOD, a young bullock for a sin offering.","words":[["H5414","And thou shalt give",0,19],["H3548","to the priests",20,34],["H3881","the Levites",35,46],["H2233","that be of the seed",47,66],["H6659","of Zadok",67,75],["H7138","which approach",77,91],["H8334","unto me, to minister",92,112],["H5002","unto me, saith",113,127],["H0136","the Lord",128,136],["H3069","GOD",137,140],["H1121","a young",142,149],["H1241","a young",142,149],["H6499","bullock",150,157],["H2403","for a sin offering",158,176]]},"43:20":{"text":"And thou shalt take of the blood thereof, and put it on the four horns of it, and on the four corners of the settle, and upon the border round about: thus shalt thou cleanse and purge it.","words":[["H3947","And thou shalt take",0,19],["H1818","of the blood",20,32],["H5414","thereof, and put",33,49],["H0702","it on the four",50,64],["H7161","horns",65,70],["H0702","of it, and on the four",71,93],["H6438","corners",94,101],["H5835","of the settle",102,115],["H1366","and upon the border",117,136],["H5439","round about",137,148],["H2398","thus shalt thou cleanse",150,173],["H3722","and purge",174,183]]},"43:21":{"text":"Thou shalt take the bullock also of the sin offering, and he shall burn it in the appointed place of the house, without the sanctuary.","words":[["H3947","Thou shalt take",0,15],["H6499","the bullock",16,27],["H2403","also of the sin offering",28,52],["H8313","and he shall burn",54,71],["H4662","it in the appointed place",72,97],["H1004","of the house",98,110],["H2351","without",112,119],["H4720","the sanctuary",120,133]]},"43:22":{"text":"And on the second day thou shalt offer a kid of the goats without blemish for a sin offering; and they shall cleanse the altar, as they did cleanse it with the bullock.","words":[["H8145","And on the second",0,17],["H3117","day",18,21],["H7126","thou shalt offer",22,38],["H8163","a kid",39,44],["H5795","of the goats",45,57],["H8549","without blemish",58,73],["H2403","for a sin offering",74,92],["H2398","and they shall cleanse",94,116],["H4196","the altar",117,126],["H2398","as they did cleanse",128,147],["H6499","it with the bullock",148,167]]},"43:23":{"text":"When thou hast made an end of cleansing it, thou shalt offer a young bullock without blemish, and a ram out of the flock without blemish.","words":[["H3615","When thou hast made an end",0,26],["H2398","of cleansing",27,39],["H7126","it, thou shalt offer",40,60],["H1121","a young",61,68],["H1241","a young",61,68],["H6499","bullock",69,76],["H8549","without blemish",77,92],["H0352","and a ram",94,103],["H6629","out of the flock",104,120],["H8549","without blemish",121,136]]},"43:24":{"text":"And thou shalt offer them before the LORD, and the priests shall cast salt upon them, and they shall offer them up for a burnt offering unto the LORD.","words":[["H7126","And thou shalt offer",0,20],["H6440","them before",21,32],["H3068","the LORD",33,41],["H3548","and the priests",43,58],["H7993","shall cast",59,69],["H4417","salt",70,74],["H5927","upon them, and they shall offer them up",75,114],["H5930","for a burnt offering",115,135],["H3068","unto the LORD",136,149]]},"43:25":{"text":"Seven days shalt thou prepare every day a goat for a sin offering: they shall also prepare a young bullock, and a ram out of the flock, without blemish.","words":[["H7651","Seven",0,5],["H3117","days",6,10],["H6213","shalt thou prepare",11,29],["H3117","every day",30,39],["H8163","a goat",40,46],["H2403","for a sin offering",47,65],["H6213","they shall also prepare",67,90],["H1121","a young",91,98],["H1241","a young",91,98],["H6499","bullock",99,106],["H0352","and a ram",108,117],["H6629","out of the flock",118,134],["H8549","without blemish",136,151]]},"43:26":{"text":"Seven days shall they purge the altar and purify it; and they shall consecrate themselves.","words":[["H7651","Seven",0,5],["H3117","days",6,10],["H3722","shall they purge",11,27],["H4196","the altar",28,37],["H2891","and purify",38,48],["H4390","it; and they shall consecrate themselves",49,89],["H3027","it; and they shall consecrate themselves",49,89]]},"43:27":{"text":"And when these days are expired, it shall be, that upon the eighth day, and so forward, the priests shall make your burnt offerings upon the altar, and your peace offerings; and I will accept you, saith the Lord GOD.","words":[["H3117","And when these days",0,19],["H3615","are expired",20,31],["H8066","it shall be, that upon the eighth",33,66],["H3117","day",67,70],["H1973","and so forward",72,86],["H3548","the priests",88,99],["H6213","shall make",100,110],["H5930","your burnt offerings",111,131],["H4196","upon the altar",132,146],["H8002","and your peace offerings",148,172],["H7521","and I will accept",174,191],["H5002","you, saith",192,202],["H0136","the Lord",203,211],["H3069","GOD",212,215]]},"44:1":{"text":"Then he brought me back the way of the gate of the outward sanctuary which looketh toward the east; and it was shut.","words":[["H7725","Then he brought me back",0,23],["H1870","the way",24,31],["H8179","of the gate",32,43],["H2435","of the outward",44,58],["H4720","sanctuary",59,68],["H6437","which looketh",69,82],["H6921","toward the east",83,98],["H5462","and it was shut",100,115]]},"44:2":{"text":"Then said the LORD unto me; This gate shall be shut, it shall not be opened, and no man shall enter in by it; because the LORD, the God of Israel, hath entered in by it, therefore it shall be shut.","words":[["H0559","Then said",0,9],["H3068","the LORD",10,18],["H8179","unto me; This gate",19,37],["H5462","shall be shut",38,51],["H6605","it shall not be opened",53,75],["H0376","and no man",77,87],["H0935","shall enter",88,99],["H3068","in by it; because the LORD",100,126],["H0430","the God",128,135],["H3478","of Israel",136,145],["H0935","hath entered",147,159],["H5462","in by it, therefore it shall be shut",160,196]]},"44:3":{"text":"It is for the prince; the prince, he shall sit in it to eat bread before the LORD; he shall enter by the way of the porch of that gate, and shall go out by the way of the same.","words":[["H5387","It is for the prince",0,20],["H5387","the prince",22,32],["H3427","he shall sit",34,46],["H0398","in it to eat",47,59],["H3899","bread",60,65],["H6440","before",66,72],["H3068","the LORD",73,81],["H0935","he shall enter",83,97],["H1870","by the way",98,108],["H0197","of the porch",109,121],["H8179","of that gate",122,134],["H3318","and shall go out",136,152],["H1870","by the way",153,163]]},"44:4":{"text":"Then brought he me the way of the north gate before the house: and I looked, and, behold, the glory of the LORD filled the house of the LORD: and I fell upon my face.","words":[["H0935","Then brought",0,12],["H1870","he me the way",13,26],["H6828","of the north",27,39],["H8179","gate",40,44],["H6440","before",45,51],["H1004","the house",52,61],["H7200","and I looked",63,75],["H3519","and, behold, the glory",77,99],["H3068","of the LORD",100,111],["H4390","filled",112,118],["H1004","the house",119,128],["H3068","of the LORD",129,140],["H5307","and I fell",142,152],["H6440","upon my face",153,165]]},"44:5":{"text":"And the LORD said unto me, Son of man, mark well, and behold with thine eyes, and hear with thine ears all that I say unto thee concerning all the ordinances of the house of the LORD, and all the laws thereof; and mark well the entering in of the house, with every going forth of the sanctuary.","words":[["H3068","And the LORD",0,12],["H0559","said",13,17],["H1121","unto me, Son",18,30],["H0120","of man",31,37],["H7760","mark",39,43],["H3820","well",44,48],["H7200","and behold",50,60],["H5869","with thine eyes",61,76],["H8085","and hear",78,86],["H0241","with thine ears",87,102],["H1696","all that I say",103,117],["H2708","unto thee concerning all the ordinances",118,157],["H1004","of the house",158,170],["H3068","of the LORD",171,182],["H8451","and all the laws",184,200],["H7760","thereof; and mark",201,218],["H3820","well",219,223],["H3996","the entering in",224,239],["H1004","of the house",240,252],["H4161","with every going forth",254,276],["H4720","of the sanctuary",277,293]]},"44:6":{"text":"And thou shalt say to the rebellious, even to the house of Israel, Thus saith the Lord GOD; O ye house of Israel, let it suffice you of all your abominations,","words":[["H0559","And thou shalt say",0,18],["H4805","to the rebellious",19,36],["H1004","even to the house",38,55],["H3478","of Israel",56,65],["H0559","Thus saith",67,77],["H0136","the Lord",78,86],["H3069","GOD",87,90],["H1004","O ye house",92,102],["H3478","of Israel",103,112],["H7227","let it suffice",114,128],["H8441","you of all your abominations",129,157]]},"44:7":{"text":"In that ye have brought into my sanctuary strangers, uncircumcised in heart, and uncircumcised in flesh, to be in my sanctuary, to pollute it, even my house, when ye offer my bread, the fat and the blood, and they have broken my covenant because of all your abominations.","words":[["H0935","In that ye have brought",0,23],["H1121","into my sanctuary strangers",24,51],["H5236","into my sanctuary strangers",24,51],["H6189","uncircumcised",53,66],["H3820","in heart",67,75],["H6189","and uncircumcised",77,94],["H1320","in flesh",95,103],["H4720","to be in my sanctuary",105,126],["H2490","to pollute",128,138],["H1004","it, even my house",139,156],["H7126","when ye offer",158,171],["H3899","my bread",172,180],["H2459","the fat",182,189],["H1818","and the blood",190,203],["H6565","and they have broken",205,225],["H1285","my covenant",226,237],["H0413","because",238,245],["H8441","of all your abominations",246,270]]},"44:8":{"text":"And ye have not kept the charge of mine holy things: but ye have set keepers of my charge in my sanctuary for yourselves.","words":[["H8104","And ye have not kept",0,20],["H4931","the charge",21,31],["H6944","of mine holy things",32,51],["H7760","but ye have set",53,68],["H8104","keepers",69,76],["H4931","of my charge",77,89],["H4720","in my sanctuary",90,105]]},"44:9":{"text":"Thus saith the Lord GOD; No stranger, uncircumcised in heart, nor uncircumcised in flesh, shall enter into my sanctuary, of any stranger that is among the children of Israel.","words":[["H0559","Thus saith",0,10],["H0136","the Lord",11,19],["H3069","GOD",20,23],["H1121","No stranger",25,36],["H5236","No stranger",25,36],["H6189","uncircumcised",38,51],["H3820","in heart",52,60],["H6189","nor uncircumcised",62,79],["H1320","in flesh",80,88],["H0935","shall enter",90,101],["H4720","into my sanctuary",102,119],["H8432","of any stranger that is among",121,150],["H1121","the children",151,163],["H3478","of Israel",164,173]]},"44:10":{"text":"And the Levites that are gone away far from me, when Israel went astray, which went astray away from me after their idols; they shall even bear their iniquity.","words":[["H3881","And the Levites",0,15],["H7368","that are gone away far",16,38],["H3478","from me, when Israel",39,59],["H8582","went astray",60,71],["H8582","which went astray away",73,95],["H0310","from me after",96,109],["H1544","their idols",110,121],["H5375","they shall even bear",123,143],["H5771","their iniquity",144,158]]},"44:11":{"text":"Yet they shall be ministers in my sanctuary, having charge at the gates of the house, and ministering to the house: they shall slay the burnt offering and the sacrifice for the people, and they shall stand before them to minister unto them.","words":[["H8334","Yet they shall be ministers",0,27],["H4720","in my sanctuary",28,43],["H6486","having charge",45,58],["H8179","at the gates",59,71],["H1004","of the house",72,84],["H8334","and ministering",86,101],["H1004","to the house",102,114],["H7819","they shall slay",116,131],["H5930","the burnt offering",132,150],["H2077","and the sacrifice",151,168],["H5971","for the people",169,183],["H5975","and they shall stand",185,205],["H6440","before",206,212],["H8334","them to minister",213,229]]},"44:12":{"text":"Because they ministered unto them before their idols, and caused the house of Israel to fall into iniquity; therefore have I lifted up mine hand against them, saith the Lord GOD, and they shall bear their iniquity.","words":[["H8334","Because they ministered",0,23],["H6440","unto them before",24,40],["H1544","their idols",41,52],["H1004","and caused the house",54,74],["H3478","of Israel",75,84],["H4383","to fall",85,92],["H5771","into iniquity",93,106],["H5375","therefore have I lifted up",108,134],["H3027","mine hand",135,144],["H5002","against them, saith",145,164],["H0136","the Lord",165,173],["H3069","GOD",174,177],["H5375","and they shall bear",179,198],["H5771","their iniquity",199,213]]},"44:13":{"text":"And they shall not come near unto me, to do the office of a priest unto me, nor to come near to any of my holy things, in the most holy place: but they shall bear their shame, and their abominations which they have committed.","words":[["H5066","And they shall not come near",0,28],["H3547","unto me, to do the office of a priest",29,66],["H5066","unto me, nor to come near",67,92],["H6944","to any of my holy things",93,117],["H6944","in the most holy",119,135],["H5375","place: but they shall bear",136,162],["H3639","their shame",163,174],["H8441","and their abominations",176,198],["H6213","which they have committed",199,224]]},"44:14":{"text":"But I will make them keepers of the charge of the house, for all the service thereof, and for all that shall be done therein.","words":[["H5414","But I will make",0,15],["H8104","them keepers",16,28],["H4931","of the charge",29,42],["H1004","of the house",43,55],["H5656","for all the service",57,76],["H6213","thereof, and for all that shall be done",77,116]]},"44:15":{"text":"But the priests the Levites, the sons of Zadok, that kept the charge of my sanctuary when the children of Israel went astray from me, they shall come near to me to minister unto me, and they shall stand before me to offer unto me the fat and the blood, saith the Lord GOD:","words":[["H3548","But the priests",0,15],["H3881","the Levites",16,27],["H1121","the sons",29,37],["H6659","of Zadok",38,46],["H8104","that kept",48,57],["H4931","the charge",58,68],["H4720","of my sanctuary",69,84],["H1121","when the children",85,102],["H3478","of Israel",103,112],["H8582","went astray",113,124],["H7126","from me, they shall come near",125,154],["H8334","to me to minister",155,172],["H5975","unto me, and they shall stand",173,202],["H6440","before",203,209],["H7126","me to offer",210,221],["H2459","unto me the fat",222,237],["H1818","and the blood",238,251],["H5002","saith",253,258],["H0136","the Lord",259,267],["H3069","GOD",268,271]]},"44:16":{"text":"They shall enter into my sanctuary, and they shall come near to my table, to minister unto me, and they shall keep my charge.","words":[["H0935","They shall enter",0,16],["H4720","into my sanctuary",17,34],["H7126","and they shall come near",36,60],["H7979","to my table",61,72],["H8334","to minister",74,85],["H8104","unto me, and they shall keep",86,114],["H4931","my charge",115,124]]},"44:17":{"text":"And it shall come to pass, that when they enter in at the gates of the inner court, they shall be clothed with linen garments; and no wool shall come upon them, whiles they minister in the gates of the inner court, and within.","words":[["H0935","And it shall come to pass, that when they enter",0,47],["H8179","in at the gates",48,63],["H6442","of the inner",64,76],["H2691","court",77,82],["H3847","they shall be clothed",84,105],["H6593","with linen",106,116],["H0899","garments",117,125],["H6785","and no wool",127,138],["H5927","shall come",139,149],["H8334","upon them, whiles they minister",150,181],["H8179","in the gates",182,194],["H6442","of the inner",195,207],["H2691","court",208,213],["H1004","and within",215,225]]},"44:18":{"text":"They shall have linen bonnets upon their heads, and shall have linen breeches upon their loins; they shall not gird themselves with any thing that causeth sweat.","words":[["H6593","They shall have linen",0,21],["H6287","bonnets",22,29],["H7218","upon their heads",30,46],["H6593","and shall have linen",48,68],["H4370","breeches",69,77],["H4975","upon their loins",78,94],["H2296","they shall not gird",96,115],["H3154","themselves with any thing that causeth sweat",116,160]]},"44:19":{"text":"And when they go forth into the utter court, even into the utter court to the people, they shall put off their garments wherein they ministered, and lay them in the holy chambers, and they shall put on other garments; and they shall not sanctify the people with their garments.","words":[["H3318","And when they go forth",0,22],["H2435","into the utter",23,37],["H2691","court",38,43],["H2435","even into the utter",45,64],["H2691","court",65,70],["H5971","to the people",71,84],["H6584","they shall put off",86,104],["H0899","their garments",105,119],["H8334","wherein they ministered",120,143],["H3240","and lay",145,152],["H6944","them in the holy",153,169],["H3957","chambers",170,178],["H3847","and they shall put",180,198],["H0312","on other",199,207],["H0899","garments",208,216],["H6942","and they shall not sanctify",218,245],["H5971","the people",246,256],["H0899","with their garments",257,276]]},"44:20":{"text":"Neither shall they shave their heads, nor suffer their locks to grow long; they shall only poll their heads.","words":[["H1548","Neither shall they shave",0,24],["H7218","their heads",25,36],["H6545","nor suffer their locks",38,60],["H7971","to grow long",61,73],["H3697","they shall only",75,90],["H3697","poll",91,95],["H7218","their heads",96,107]]},"44:21":{"text":"Neither shall any priest drink wine, when they enter into the inner court.","words":[["H3548","Neither shall any priest",0,24],["H8354","drink",25,30],["H3196","wine",31,35],["H0935","when they enter",37,52],["H6442","into the inner",53,67],["H2691","court",68,73]]},"44:22":{"text":"Neither shall they take for their wives a widow, nor her that is put away: but they shall take maidens of the seed of the house of Israel, or a widow that had a priest before.","words":[["H3947","Neither shall they take",0,23],["H0802","for their wives",24,39],["H0490","a widow",40,47],["H1644","nor her that is put away",49,73],["H3947","but they shall take",75,94],["H1330","maidens",95,102],["H2233","of the seed",103,114],["H1004","of the house",115,127],["H3478","of Israel",128,137],["H0490","or a widow",139,149],["H3548","that had a priest",150,167]]},"44:23":{"text":"And they shall teach my people the difference between the holy and profane, and cause them to discern between the unclean and the clean.","words":[["H3384","And they shall teach",0,20],["H5971","my people",21,30],["H6944","the difference between the holy",31,62],["H2455","and profane",63,74],["H3045","and cause them to discern",76,101],["H2931","between the unclean",102,121],["H2889","and the clean",122,135]]},"44:24":{"text":"And in controversy they shall stand in judgment; and they shall judge it according to my judgments: and they shall keep my laws and my statutes in all mine assemblies; and they shall hallow my sabbaths.","words":[["H7379","And in controversy",0,18],["H5975","they shall stand",19,35],["H8199","in judgment",36,47],["H8199","and they shall judge",49,69],["H4941","it according to my judgments",70,98],["H8104","and they shall keep",100,119],["H8451","my laws",120,127],["H2708","and my statutes",128,143],["H4150","in all mine assemblies",144,166],["H6942","and they shall hallow",168,189],["H7676","my sabbaths",190,201]]},"44:25":{"text":"And they shall come at no dead person to defile themselves: but for father, or for mother, or for son, or for daughter, for brother, or for sister that hath had no husband, they may defile themselves.","words":[["H0935","And they shall come",0,19],["H4191","at no dead",20,30],["H0120","person",31,37],["H2930","to defile",38,47],["H0001","themselves: but for father",48,74],["H0517","or for mother",76,89],["H1121","or for son",91,101],["H1323","or for daughter",103,118],["H0251","for brother",120,131],["H0269","or for sister",133,146],["H0376","that hath had no husband",147,171],["H2930","they may defile",173,188]]},"44:26":{"text":"And after he is cleansed, they shall reckon unto him seven days.","words":[["H0310","And after",0,9],["H2893","he is cleansed",10,24],["H5608","they shall reckon",26,43],["H7651","unto him seven",44,58],["H3117","days",59,63]]},"44:27":{"text":"And in the day that he goeth into the sanctuary, unto the inner court, to minister in the sanctuary, he shall offer his sin offering, saith the Lord GOD.","words":[["H3117","And in the day",0,14],["H0935","that he goeth",15,28],["H6944","into the sanctuary",29,47],["H6442","unto the inner",49,63],["H2691","court",64,69],["H8334","to minister",71,82],["H6944","in the sanctuary",83,99],["H7126","he shall offer",101,115],["H2403","his sin offering",116,132],["H5002","saith",134,139],["H0136","the Lord",140,148],["H3069","GOD",149,152]]},"44:28":{"text":"And it shall be unto them for an inheritance: I am their inheritance: and ye shall give them no possession in Israel: I am their possession.","words":[["H5159","And it shall be unto them for an inheritance",0,44],["H5159","I am their inheritance",46,68],["H5414","and ye shall give",70,87],["H0272","them no possession",88,106],["H3478","in Israel",107,116],["H0272","I am their possession",118,139]]},"44:29":{"text":"They shall eat the meat offering, and the sin offering, and the trespass offering; and every dedicated thing in Israel shall be theirs.","words":[["H0398","They shall eat",0,14],["H4503","the meat offering",15,32],["H2403","and the sin offering",34,54],["H0817","and the trespass offering",56,81],["H2764","and every dedicated thing",83,108],["H3478","in Israel",109,118]]},"44:30":{"text":"And the first of all the firstfruits of all things, and every oblation of all, of every sort of your oblations, shall be the priest's: ye shall also give unto the priest the first of your dough, that he may cause the blessing to rest in thine house.","words":[["H7225","And the first",0,13],["H1061","of all the firstfruits",14,36],["H8641","of all things, and every oblation",37,70],["H8641","of all, of every sort of your oblations",71,110],["H3548","shall be the priest's",112,133],["H5414","ye shall also give",135,153],["H3548","unto the priest",154,169],["H7225","the first",170,179],["H6182","of your dough",180,193],["H1293","that he may cause the blessing",195,225],["H5117","to rest",226,233],["H1004","in thine house",234,248]]},"44:31":{"text":"The priests shall not eat of any thing that is dead of itself, or torn, whether it be fowl or beast.","words":[["H3548","The priests",0,11],["H0398","shall not eat",12,25],["H5038","of any thing that is dead of itself",26,61],["H2966","or torn",63,70],["H5775","whether it be fowl",72,90],["H0929","or beast",91,99]]},"45:1":{"text":"Moreover, when ye shall divide by lot the land for inheritance, ye shall offer an oblation unto the LORD, an holy portion of the land: the length shall be the length of five and twenty thousand reeds, and the breadth shall be ten thousand. This shall be holy in all the borders thereof round about.","words":[["H5307","Moreover, when ye shall divide",0,30],["H0776","by lot the land",31,46],["H5159","for inheritance",47,62],["H7311","ye shall offer",64,78],["H8641","an oblation",79,90],["H3068","unto the LORD",91,104],["H6944","an holy portion",106,121],["H0776","of the land",122,133],["H0753","the length",135,145],["H0753","shall be the length",146,165],["H2568","of five",166,173],["H6242","and twenty",174,184],["H0505","thousand",185,193],["H7341","reeds, and the breadth",194,216],["H6235","shall be ten",217,229],["H0505","thousand",230,238],["H6944","This shall be holy",240,258],["H1366","in all the borders",259,277],["H5439","thereof round about",278,297]]},"45:2":{"text":"Of this there shall be for the sanctuary five hundred in length, with five hundred in breadth, square round about; and fifty cubits round about for the suburbs thereof.","words":[["H6944","Of this there shall be for the sanctuary",0,40],["H2568","five",41,45],["H3967","hundred",46,53],["H2568","in length, with five",54,74],["H3967","hundred",75,82],["H7251","in breadth, square",83,101],["H5439","round about",102,113],["H2572","and fifty",115,124],["H0520","cubits",125,131],["H5439","round about",132,143],["H4054","for the suburbs",144,159]]},"45:3":{"text":"And of this measure shalt thou measure the length of five and twenty thousand, and the breadth of ten thousand: and in it shall be the sanctuary and the most holy place.","words":[["H4060","And of this measure",0,19],["H4058","shalt thou measure",20,38],["H0753","the length",39,49],["H2568","of five",50,57],["H6242","and twenty",58,68],["H0505","thousand",69,77],["H7341","and the breadth",79,94],["H6235","of ten",95,101],["H0505","thousand",102,110],["H4720","and in it shall be the sanctuary",112,144],["H6944","and the most",145,157],["H6944","holy",158,162]]},"45:4":{"text":"The holy portion of the land shall be for the priests the ministers of the sanctuary, which shall come near to minister unto the LORD: and it shall be a place for their houses, and an holy place for the sanctuary.","words":[["H6944","The holy",0,8],["H0776","portion of the land",9,28],["H3548","shall be for the priests",29,53],["H8334","the ministers",54,67],["H4720","of the sanctuary",68,84],["H7131","which shall come near",86,107],["H8334","to minister",108,119],["H3068","unto the LORD",120,133],["H4725","and it shall be a place",135,158],["H1004","for their houses",159,175],["H4720","and an holy place",177,194],["H4720","for the sanctuary",195,212]]},"45:5":{"text":"And the five and twenty thousand of length, and the ten thousand of breadth, shall also the Levites, the ministers of the house, have for themselves, for a possession for twenty chambers.","words":[["H2568","And the five",0,12],["H6242","and twenty",13,23],["H0505","thousand",24,32],["H0753","of length",33,42],["H6235","and the ten",44,55],["H0505","thousand",56,64],["H7341","of breadth",65,75],["H3881","shall also the Levites",77,99],["H8334","the ministers",101,114],["H1004","of the house",115,127],["H0272","have for themselves, for a possession",129,166],["H6242","for twenty",167,177],["H3957","chambers",178,186]]},"45:6":{"text":"And ye shall appoint the possession of the city five thousand broad, and five and twenty thousand long, over against the oblation of the holy portion: it shall be for the whole house of Israel.","words":[["H5414","And ye shall appoint",0,20],["H0272","the possession",21,35],["H5892","of the city",36,47],["H2568","five",48,52],["H0505","thousand",53,61],["H7341","broad",62,67],["H2568","and five",69,77],["H6242","and twenty",78,88],["H0505","thousand",89,97],["H0753","long",98,102],["H5980","over against",104,116],["H8641","the oblation",117,129],["H6944","of the holy",130,141],["H1004","portion: it shall be for the whole house",142,182],["H3478","of Israel",183,192]]},"45:7":{"text":"And a portion shall be for the prince on the one side and on the other side of the oblation of the holy portion, and of the possession of the city, before the oblation of the holy portion, and before the possession of the city, from the west side westward, and from the east side eastward: and the length shall be over against one of the portions, from the west border unto the east border.","words":[["H5387","And a portion shall be for the prince",0,37],["H8641","on the one side and on the other side of the oblation",38,91],["H6944","of the holy",92,103],["H0272","portion, and of the possession",104,134],["H5892","of the city",135,146],["H6440","before",148,154],["H8641","the oblation",155,167],["H6944","of the holy",168,179],["H6440","portion, and before",180,199],["H0272","the possession",200,214],["H5892","of the city",215,226],["H3220","from the west",228,241],["H6285","side",242,246],["H3220","westward",247,255],["H6924","and from the east",257,274],["H6285","side",275,279],["H6921","eastward",280,288],["H0753","and the length",290,304],["H5980","shall be over against",305,326],["H0259","one",327,330],["H2506","of the portions",331,346],["H3220","from the west",348,361],["H1366","border",362,368],["H6921","unto the east",369,382],["H1366","border",383,389]]},"45:8":{"text":"In the land shall be his possession in Israel: and my princes shall no more oppress my people; and the rest of the land shall they give to the house of Israel according to their tribes.","words":[["H0776","In the land",0,11],["H0272","shall be his possession",12,35],["H3478","in Israel",36,45],["H5387","and my princes",47,61],["H3238","shall no more oppress",62,83],["H5971","my people",84,93],["H0776","and the rest of the land",95,119],["H5414","shall they give",120,135],["H1004","to the house",136,148],["H3478","of Israel",149,158],["H7626","according to their tribes",159,184]]},"45:9":{"text":"Thus saith the Lord GOD; Let it suffice you, O princes of Israel: remove violence and spoil, and execute judgment and justice, take away your exactions from my people, saith the Lord GOD.","words":[["H5002","Thus saith",0,10],["H0136","the Lord",11,19],["H3069","GOD",20,23],["H7227","Let it suffice",25,39],["H5387","you, O princes",40,54],["H3478","of Israel",55,64],["H5493","remove",66,72],["H2555","violence",73,81],["H7701","and spoil",82,91],["H6213","and execute",93,104],["H4941","judgment",105,113],["H6666","and justice",114,125],["H7311","take away",127,136],["H1646","your exactions",137,151],["H5971","from my people",152,166],["H0559","saith",168,173],["H0136","the Lord",174,182],["H3069","GOD",183,186]]},"45:10":{"text":"Ye shall have just balances, and a just ephah, and a just bath.","words":[["H6664","Ye shall have just",0,18],["H3976","balances",19,27],["H6664","and a just",29,39],["H0374","ephah",40,45],["H6664","and a just",47,57],["H1324","bath",58,62]]},"45:11":{"text":"The ephah and the bath shall be of one measure, that the bath may contain the tenth part of an homer, and the ephah the tenth part of an homer: the measure thereof shall be after the homer.","words":[["H0374","The ephah",0,9],["H1324","and the bath",10,22],["H0259","shall be of one",23,38],["H8506","measure",39,46],["H1324","that the bath",48,61],["H5375","may contain",62,73],["H4643","the tenth part",74,88],["H2563","of an homer",89,100],["H0374","and the ephah",102,115],["H6224","the tenth part",116,130],["H2563","of an homer",131,142],["H4971","the measure",144,155],["H2563","thereof shall be after the homer",156,188]]},"45:12":{"text":"And the shekel shall be twenty gerahs: twenty shekels, five and twenty shekels, fifteen shekels, shall be your maneh.","words":[["H8255","And the shekel",0,14],["H6242","shall be twenty",15,30],["H1626","gerahs",31,37],["H6242","twenty",39,45],["H8255","shekels",46,53],["H2568","five",55,59],["H6242","and twenty",60,70],["H8255","shekels",71,78],["H2568","fifteen",80,87],["H6235","fifteen",80,87],["H8255","shekels",88,95],["H4488","shall be your maneh",97,116]]},"45:13":{"text":"This is the oblation that ye shall offer; the sixth part of an ephah of an homer of wheat, and ye shall give the sixth part of an ephah of an homer of barley:","words":[["H8641","This is the oblation",0,20],["H7311","that ye shall offer",21,40],["H8345","the sixth part",42,56],["H0374","of an ephah",57,68],["H2563","of an homer",69,80],["H2406","of wheat",81,89],["H8341","and ye shall give the sixth part",91,123],["H0374","of an ephah",124,135],["H2563","of an homer",136,147],["H8184","of barley",148,157]]},"45:14":{"text":"Concerning the ordinance of oil, the bath of oil, ye shall offer the tenth part of a bath out of the cor, which is an homer of ten baths; for ten baths are an homer:","words":[["H2706","Concerning the ordinance",0,24],["H8081","of oil",25,31],["H1324","the bath",33,41],["H8081","of oil",42,48],["H4643","ye shall offer the tenth part",50,79],["H1324","of a bath",80,89],["H3734","out of the cor",90,104],["H2563","which is an homer",106,123],["H6235","of ten",124,130],["H1324","baths",131,136],["H6235","for ten",138,145],["H1324","baths",146,151],["H2563","are an homer",152,164]]},"45:15":{"text":"And one lamb out of the flock, out of two hundred, out of the fat pastures of Israel; for a meat offering, and for a burnt offering, and for peace offerings, to make reconciliation for them, saith the Lord GOD.","words":[["H0259","And one",0,7],["H7716","lamb",8,12],["H6629","out of the flock",13,29],["H3967","out of two hundred",31,49],["H4945","out of the fat pastures",51,74],["H3478","of Israel",75,84],["H4503","for a meat offering",86,105],["H5930","and for a burnt offering",107,131],["H8002","and for peace offerings",133,156],["H3722","to make reconciliation",158,180],["H5002","for them, saith",181,196],["H0136","the Lord",197,205],["H3069","GOD",206,209]]},"45:16":{"text":"All the people of the land shall give this oblation for the prince in Israel.","words":[["H5971","All the people",0,14],["H0776","of the land",15,26],["H8641","shall give this oblation",27,51],["H5387","for the prince",52,66],["H3478","in Israel",67,76]]},"45:17":{"text":"And it shall be the prince's part to give burnt offerings, and meat offerings, and drink offerings, in the feasts, and in the new moons, and in the sabbaths, in all solemnities of the house of Israel: he shall prepare the sin offering, and the meat offering, and the burnt offering, and the peace offerings, to make reconciliation for the house of Israel.","words":[["H5387","And it shall be the prince's part",0,33],["H5930","to give burnt offerings",34,57],["H4503","and meat offerings",59,77],["H5262","and drink offerings",79,98],["H2282","in the feasts",100,113],["H2320","and in the new moons",115,135],["H7676","and in the sabbaths",137,156],["H4150","in all solemnities",158,176],["H1004","of the house",177,189],["H3478","of Israel",190,199],["H6213","he shall prepare",201,217],["H2403","the sin offering",218,234],["H4503","and the meat offering",236,257],["H5930","and the burnt offering",259,281],["H8002","and the peace offerings",283,306],["H3722","to make reconciliation",308,330],["H1004","for the house",331,344],["H3478","of Israel",345,354]]},"45:18":{"text":"Thus saith the Lord GOD; In the first month, in the first day of the month, thou shalt take a young bullock without blemish, and cleanse the sanctuary:","words":[["H0559","Thus saith",0,10],["H0136","the Lord",11,19],["H3069","GOD",20,23],["H7223","In the first",25,37],["H0259","month, in the first",38,57],["H2320","day of the month",58,74],["H3947","thou shalt take",76,91],["H1121","a young",92,99],["H1241","a young",92,99],["H6499","bullock",100,107],["H8549","without blemish",108,123],["H2398","and cleanse",125,136],["H4720","the sanctuary",137,150]]},"45:19":{"text":"And the priest shall take of the blood of the sin offering, and put it upon the posts of the house, and upon the four corners of the settle of the altar, and upon the posts of the gate of the inner court.","words":[["H3548","And the priest",0,14],["H3947","shall take",15,25],["H1818","of the blood",26,38],["H2403","of the sin offering",39,58],["H5414","and put",60,67],["H4201","it upon the posts",68,85],["H1004","of the house",86,98],["H0702","and upon the four",100,117],["H6438","corners",118,125],["H5835","of the settle",126,139],["H4196","of the altar",140,152],["H4201","and upon the posts",154,172],["H8179","of the gate",173,184],["H6442","of the inner",185,197],["H2691","court",198,203]]},"45:20":{"text":"And so thou shalt do the seventh day of the month for every one that erreth, and for him that is simple: so shall ye reconcile the house.","words":[["H6213","And so thou shalt do",0,20],["H7651","the seventh",21,32],["H2320","day of the month",33,49],["H0376","for every one",50,63],["H7686","that erreth",64,75],["H6612","and for him that is simple",77,103],["H3722","so shall ye reconcile",105,126],["H1004","the house",127,136]]},"45:21":{"text":"In the first month, in the fourteenth day of the month, ye shall have the passover, a feast of seven days; unleavened bread shall be eaten.","words":[["H7223","In the first",0,12],["H0702","month, in the fourteenth",13,37],["H6240","month, in the fourteenth",13,37],["H3117","day",38,41],["H2320","of the month",42,54],["H6453","ye shall have the passover",56,82],["H2282","a feast",84,91],["H7620","of seven",92,100],["H3117","days",101,105],["H4682","unleavened bread",107,123],["H0398","shall be eaten",124,138]]},"45:22":{"text":"And upon that day shall the prince prepare for himself and for all the people of the land a bullock for a sin offering.","words":[["H3117","And upon that day",0,17],["H5387","shall the prince",18,34],["H6213","prepare",35,42],["H5971","for himself and for all the people",43,77],["H0776","of the land",78,89],["H6499","a bullock",90,99],["H2403","for a sin offering",100,118]]},"45:23":{"text":"And seven days of the feast he shall prepare a burnt offering to the LORD, seven bullocks and seven rams without blemish daily the seven days; and a kid of the goats daily for a sin offering.","words":[["H7651","And seven",0,9],["H3117","days",10,14],["H2282","of the feast",15,27],["H6213","he shall prepare",28,44],["H5930","a burnt offering",45,61],["H3068","to the LORD",62,73],["H7651","seven",75,80],["H6499","bullocks",81,89],["H7651","and seven",90,99],["H0352","rams",100,104],["H8549","without blemish",105,120],["H3117","daily",121,126],["H7651","the seven",127,136],["H3117","days",137,141],["H8163","and a kid",143,152],["H5795","of the goats",153,165],["H3117","daily",166,171],["H2403","for a sin offering",172,190]]},"45:24":{"text":"And he shall prepare a meat offering of an ephah for a bullock, and an ephah for a ram, and an hin of oil for an ephah.","words":[["H6213","And he shall prepare",0,20],["H4503","a meat offering",21,36],["H0374","of an ephah",37,48],["H6499","for a bullock",49,62],["H0374","and an ephah",64,76],["H0352","for a ram",77,86],["H1969","and an hin",88,98],["H8081","of oil",99,105],["H0374","for an ephah",106,118]]},"45:25":{"text":"In the seventh month, in the fifteenth day of the month, shall he do the like in the feast of the seven days, according to the sin offering, according to the burnt offering, and according to the meat offering, and according to the oil.","words":[["H7651","In the seventh",0,14],["H2568","month, in the fifteenth",15,38],["H6240","month, in the fifteenth",15,38],["H3117","day",39,42],["H2320","of the month",43,55],["H6213","shall he do",57,68],["H2282","the like in the feast",69,90],["H7637","of the seven",91,103],["H3117","days",104,108],["H2403","according to the sin offering",110,139],["H5930","according to the burnt offering",141,172],["H4503","and according to the meat offering",174,208],["H8081","and according to the oil",210,234]]},"46:1":{"text":"Thus saith the Lord GOD; The gate of the inner court that looketh toward the east shall be shut the six working days; but on the sabbath it shall be opened, and in the day of the new moon it shall be opened.","words":[["H0559","Thus saith",0,10],["H0136","the Lord",11,19],["H3069","GOD",20,23],["H8179","The gate",25,33],["H6442","of the inner",34,46],["H2691","court",47,52],["H6437","that looketh",53,65],["H6921","toward the east",66,81],["H5462","shall be shut",82,95],["H8337","the six",96,103],["H4639","working",104,111],["H3117","days",112,116],["H7676","but on the sabbath",118,136],["H3117","but on the sabbath",118,136],["H6605","it shall be opened",137,155],["H3117","and in the day",157,171],["H2320","of the new moon",172,187],["H6605","it shall be opened",188,206]]},"46:2":{"text":"And the prince shall enter by the way of the porch of that gate without, and shall stand by the post of the gate, and the priests shall prepare his burnt offering and his peace offerings, and he shall worship at the threshold of the gate: then he shall go forth; but the gate shall not be shut until the evening.","words":[["H5387","And the prince",0,14],["H0935","shall enter",15,26],["H1870","by the way",27,37],["H0197","of the porch",38,50],["H8179","of that gate",51,63],["H2351","without",64,71],["H5975","and shall stand",73,88],["H4201","by the post",89,100],["H8179","of the gate",101,112],["H3548","and the priests",114,129],["H6213","shall prepare",130,143],["H5930","his burnt offering",144,162],["H8002","and his peace offerings",163,186],["H7812","and he shall worship",188,208],["H4670","at the threshold",209,225],["H8179","of the gate",226,237],["H3318","then he shall go forth",239,261],["H8179","but the gate",263,275],["H5462","shall not be shut",276,293],["H6153","until the evening",294,311]]},"46:3":{"text":"Likewise the people of the land shall worship at the door of this gate before the LORD in the sabbaths and in the new moons.","words":[["H5971","Likewise the people",0,19],["H0776","of the land",20,31],["H7812","shall worship",32,45],["H6607","at the door",46,57],["H8179","of this gate",58,70],["H6440","before",71,77],["H3068","the LORD",78,86],["H7676","in the sabbaths",87,102],["H2320","and in the new moons",103,123]]},"46:4":{"text":"And the burnt offering that the prince shall offer unto the LORD in the sabbath day shall be six lambs without blemish, and a ram without blemish.","words":[["H5930","And the burnt offering",0,22],["H5387","that the prince",23,38],["H7126","shall offer",39,50],["H3068","unto the LORD",51,64],["H7676","in the sabbath",65,79],["H3117","day",80,83],["H8337","shall be six",84,96],["H3532","lambs",97,102],["H8549","without blemish",103,118],["H0352","and a ram",120,129],["H8549","without blemish",130,145]]},"46:5":{"text":"And the meat offering shall be an ephah for a ram, and the meat offering for the lambs as he shall be able to give, and an hin of oil to an ephah.","words":[["H4503","And the meat offering",0,21],["H0374","shall be an ephah",22,39],["H0352","for a ram",40,49],["H4503","and the meat offering",51,72],["H3532","for the lambs",73,86],["H3027","as he shall be able",87,106],["H4991","to give",107,114],["H1969","and an hin",116,126],["H8081","of oil",127,133],["H0374","to an ephah",134,145]]},"46:6":{"text":"And in the day of the new moon it shall be a young bullock without blemish, and six lambs, and a ram: they shall be without blemish.","words":[["H3117","And in the day",0,14],["H2320","of the new moon",15,30],["H1121","it shall be a young",31,50],["H1241","it shall be a young",31,50],["H6499","bullock",51,58],["H8549","without blemish",59,74],["H8337","and six",76,83],["H3532","lambs",84,89],["H0352","and a ram",91,100],["H8549","they shall be without blemish",102,131]]},"46:7":{"text":"And he shall prepare a meat offering, an ephah for a bullock, and an ephah for a ram, and for the lambs according as his hand shall attain unto, and an hin of oil to an ephah.","words":[["H6213","And he shall prepare",0,20],["H4503","a meat offering",21,36],["H0374","an ephah",38,46],["H6499","for a bullock",47,60],["H0374","and an ephah",62,74],["H0352","for a ram",75,84],["H3532","and for the lambs",86,103],["H3027","according as his hand",104,125],["H5381","shall attain",126,138],["H1969","unto, and an hin",139,155],["H8081","of oil",156,162],["H0374","to an ephah",163,174]]},"46:8":{"text":"And when the prince shall enter, he shall go in by the way of the porch of that gate, and he shall go forth by the way thereof.","words":[["H5387","And when the prince",0,19],["H0935","shall enter",20,31],["H0935","he shall go",33,44],["H1870","in by the way",45,58],["H0197","of the porch",59,71],["H8179","of that gate",72,84],["H3318","and he shall go forth",86,107],["H1870","by the way",108,118]]},"46:9":{"text":"But when the people of the land shall come before the LORD in the solemn feasts, he that entereth in by the way of the north gate to worship shall go out by the way of the south gate; and he that entereth by the way of the south gate shall go forth by the way of the north gate: he shall not return by the way of the gate whereby he came in, but shall go forth over against it.","words":[["H5971","But when the people",0,19],["H0776","of the land",20,31],["H0935","shall come",32,42],["H6440","before",43,49],["H3068","the LORD",50,58],["H4150","in the solemn feasts",59,79],["H0935","he that entereth",81,97],["H1870","in by the way",98,111],["H6828","of the north",112,124],["H8179","gate",125,129],["H7812","to worship",130,140],["H3318","shall go out",141,153],["H1870","by the way",154,164],["H5045","of the south",165,177],["H8179","gate",178,182],["H0935","and he that entereth",184,204],["H1870","by the way",205,215],["H5045","of the south",216,228],["H8179","gate",229,233],["H3318","shall go forth",234,248],["H1870","by the way",249,259],["H6828","of the north",260,272],["H8179","gate",273,277],["H7725","he shall not return",279,298],["H1870","by the way",299,309],["H8179","of the gate",310,321],["H0935","whereby he came in",322,340],["H3318","but shall go forth",342,360],["H5226","over against",361,373]]},"46:10":{"text":"And the prince in the midst of them, when they go in, shall go in; and when they go forth, shall go forth.","words":[["H5387","And the prince",0,14],["H8432","in the midst",15,27],["H0935","of them, when they go in",28,52],["H0935","shall go in",54,65],["H3318","and when they go forth",67,89],["H3318","shall go forth",91,105]]},"46:11":{"text":"And in the feasts and in the solemnities the meat offering shall be an ephah to a bullock, and an ephah to a ram, and to the lambs as he is able to give, and an hin of oil to an ephah.","words":[["H2282","And in the feasts",0,17],["H4150","and in the solemnities",18,40],["H4503","the meat offering",41,58],["H0374","shall be an ephah",59,76],["H6499","to a bullock",77,89],["H0374","and an ephah",91,103],["H0352","to a ram",104,112],["H3532","and to the lambs",114,130],["H3027","as he is able",131,144],["H4991","to give",145,152],["H1969","and an hin",154,164],["H8081","of oil",165,171],["H0374","to an ephah",172,183]]},"46:12":{"text":"Now when the prince shall prepare a voluntary burnt offering or peace offerings voluntarily unto the LORD, one shall then open him the gate that looketh toward the east, and he shall prepare his burnt offering and his peace offerings, as he did on the sabbath day: then he shall go forth; and after his going forth one shall shut the gate.","words":[["H5387","Now when the prince",0,19],["H6213","shall prepare",20,33],["H5071","a voluntary",34,45],["H5930","burnt offering",46,60],["H8002","or peace offerings",61,79],["H5071","voluntarily",80,91],["H3068","unto the LORD",92,105],["H6605","one shall then open",107,126],["H8179","him the gate",127,139],["H6437","that looketh",140,152],["H6921","toward the east",153,168],["H6213","and he shall prepare",170,190],["H5930","his burnt offering",191,209],["H8002","and his peace offerings",210,233],["H6213","as he did",235,244],["H7676","on the sabbath",245,259],["H3117","day",260,263],["H3318","then he shall go forth",265,287],["H0310","and after",289,298],["H3318","his going forth",299,314],["H5462","one shall shut",315,329],["H8179","the gate",330,338]]},"46:13":{"text":"Thou shalt daily prepare a burnt offering unto the LORD of a lamb of the first year without blemish: thou shalt prepare it every morning.","words":[["H3117","Thou shalt daily",0,16],["H6213","prepare",17,24],["H5930","a burnt offering",25,41],["H3068","unto the LORD",42,55],["H3532","of a lamb",56,65],["H1121","of the first",66,78],["H8141","year",79,83],["H8549","without blemish",84,99],["H6213","thou shalt prepare",101,119],["H1242","it every",120,128],["H1242","morning",129,136]]},"46:14":{"text":"And thou shalt prepare a meat offering for it every morning, the sixth part of an ephah, and the third part of an hin of oil, to temper with the fine flour; a meat offering continually by a perpetual ordinance unto the LORD.","words":[["H6213","And thou shalt prepare",0,22],["H4503","a meat offering",23,38],["H1242","for it every morning",39,59],["H8345","the sixth part",61,75],["H0374","of an ephah",76,87],["H7992","and the third part",89,107],["H1969","of an hin",108,117],["H8081","of oil",118,124],["H7450","to temper with",126,140],["H5560","the fine flour",141,155],["H4503","a meat offering",157,172],["H8548","continually",173,184],["H5769","by a perpetual",185,199],["H2708","ordinance",200,209],["H3068","unto the LORD",210,223]]},"46:15":{"text":"Thus shall they prepare the lamb, and the meat offering, and the oil, every morning for a continual burnt offering.","words":[["H6213","Thus shall they prepare",0,23],["H6213","Thus shall they prepare",0,23],["H3532","the lamb",24,32],["H4503","and the meat offering",34,55],["H8081","and the oil",57,68],["H1242","every morning",70,83],["H8548","for a continual",84,99],["H5930","burnt offering",100,114]]},"46:16":{"text":"Thus saith the Lord GOD; If the prince give a gift unto any of his sons, the inheritance thereof shall be his sons'; it shall be their possession by inheritance.","words":[["H0559","Thus saith",0,10],["H0136","the Lord",11,19],["H3069","GOD",20,23],["H5387","If the prince",25,38],["H5414","give",39,43],["H4979","a gift",44,50],["H0376","unto any",51,59],["H1121","of his sons",60,71],["H5159","the inheritance",73,88],["H1121","thereof shall be his sons'",89,115],["H0272","it shall be their possession",117,145],["H5159","by inheritance",146,160]]},"46:17":{"text":"But if he give a gift of his inheritance to one of his servants, then it shall be his to the year of liberty; after it shall return to the prince: but his inheritance shall be his sons' for them.","words":[["H5414","But if he give",0,14],["H4979","a gift",15,21],["H5159","of his inheritance",22,40],["H0259","to one",41,47],["H5650","of his servants",48,63],["H8141","then it shall be his to the year",65,97],["H1865","of liberty",98,108],["H7725","after it shall return",110,131],["H5387","to the prince",132,145],["H5159","but his inheritance",147,166],["H1121","shall be his sons'",167,185]]},"46:18":{"text":"Moreover the prince shall not take of the people's inheritance by oppression, to thrust them out of their possession; but he shall give his sons inheritance out of his own possession: that my people be not scattered every man from his possession.","words":[["H5387","Moreover the prince",0,19],["H3947","shall not take",20,34],["H5971","of the people's",35,50],["H5159","inheritance",51,62],["H3238","by oppression",63,76],["H3238","to thrust",78,87],["H0272","them out of their possession",88,116],["H1121","but he shall give his sons",118,144],["H5157","inheritance",145,156],["H0272","out of his own possession",157,182],["H5971","that my people",184,198],["H6327","be not scattered",199,215],["H0376","every man",216,225],["H0272","from his possession",226,245]]},"46:19":{"text":"After he brought me through the entry, which was at the side of the gate, into the holy chambers of the priests, which looked toward the north: and, behold, there was a place on the two sides westward.","words":[["H0935","After he brought",0,16],["H3996","me through the entry",17,37],["H3802","which was at the side",39,60],["H8179","of the gate",61,72],["H6944","into the holy",74,87],["H3957","chambers",88,96],["H3548","of the priests",97,111],["H6437","which looked",113,125],["H6828","toward the north",126,142],["H4725","and, behold, there was a place",144,174],["H3411","on the two sides",175,191],["H3220","westward",192,200]]},"46:20":{"text":"Then said he unto me, This is the place where the priests shall boil the trespass offering and the sin offering, where they shall bake the meat offering; that they bear them not out into the utter court, to sanctify the people.","words":[["H0559","Then said",0,9],["H4725","he unto me, This is the place",10,39],["H3548","where the priests",40,57],["H1310","shall boil",58,68],["H0817","the trespass offering",69,90],["H2403","and the sin offering",91,111],["H0644","where they shall bake",113,134],["H4503","the meat offering",135,152],["H3318","that they bear",154,168],["H2435","them not out into the utter",169,196],["H2691","court",197,202],["H6942","to sanctify",204,215],["H5971","the people",216,226]]},"46:21":{"text":"Then he brought me forth into the utter court, and caused me to pass by the four corners of the court; and, behold, in every corner of the court there was a court.","words":[["H3318","Then he brought me forth",0,24],["H2435","into the utter",25,39],["H2691","court",40,45],["H5674","and caused me to pass by",47,71],["H0702","the four",72,80],["H4740","corners",81,88],["H2691","of the court",89,101],["H4740","and, behold, in every",103,124],["H4740","corner",125,131],["H2691","of the court",132,144],["H2691","of the court",132,144],["H2691","there was a court",145,162]]},"46:22":{"text":"In the four corners of the court there were courts joined of forty cubits long and thirty broad: these four corners were of one measure.","words":[["H0702","In the four",0,11],["H4740","corners",12,19],["H2691","of the court",20,32],["H2691","there were courts",33,50],["H7000","joined",51,57],["H0705","of forty",58,66],["H0753","cubits long",67,78],["H7970","and thirty",79,89],["H7341","broad",90,95],["H0702","these four",97,107],["H7106","corners",108,115],["H0259","were of one",116,127],["H4060","measure",128,135]]},"46:23":{"text":"And there was a row of building round about in them, round about them four, and it was made with boiling places under the rows round about.","words":[["H2905","And there was a row",0,19],["H5439","of building round about",20,43],["H5439","in them, round about",44,64],["H0702","them four",65,74],["H6213","and it was made",76,91],["H4018","with boiling places",92,111],["H2918","under the rows",112,126],["H5439","round about",127,138]]},"46:24":{"text":"Then said he unto me, These are the places of them that boil, where the ministers of the house shall boil the sacrifice of the people.","words":[["H0559","Then said",0,9],["H1004","he unto me, These are the places",10,42],["H1310","of them that boil",43,60],["H8334","where the ministers",62,81],["H1004","of the house",82,94],["H1310","shall boil",95,105],["H2077","the sacrifice",106,119],["H5971","of the people",120,133]]},"47:1":{"text":"Afterward he brought me again unto the door of the house; and, behold, waters issued out from under the threshold of the house eastward: for the forefront of the house stood toward the east, and the waters came down from under from the right side of the house, at the south side of the altar.","words":[["H7725","Afterward he brought me again",0,29],["H6607","unto the door",30,43],["H1004","of the house",44,56],["H4325","and, behold, waters",58,77],["H3318","issued out",78,88],["H4670","from under the threshold",89,113],["H1004","of the house",114,126],["H6921","eastward",127,135],["H6440","for the forefront",137,154],["H1004","of the house",155,167],["H6921","stood toward the east",168,189],["H4325","and the waters",191,205],["H3381","came down",206,215],["H3233","from under from the right",216,241],["H3802","side",242,246],["H1004","of the house",247,259],["H5045","at the south",261,273],["H4196","side of the altar",274,291]]},"47:2":{"text":"Then brought he me out of the way of the gate northward, and led me about the way without unto the utter gate by the way that looketh eastward; and, behold, there ran out waters on the right side.","words":[["H3318","Then brought he me out",0,22],["H1870","of the way",23,33],["H8179","of the gate",34,45],["H6828","northward",46,55],["H5437","and led me about",57,73],["H1870","the way",74,81],["H2351","without unto the utter",82,104],["H8179","gate",105,109],["H1870","by the way",110,120],["H6437","that looketh",121,133],["H6921","eastward",134,142],["H6379","and, behold, there ran out",144,170],["H4325","waters",171,177],["H3233","on the right",178,190],["H3802","side",191,195]]},"47:3":{"text":"And when the man that had the line in his hand went forth eastward, he measured a thousand cubits, and he brought me through the waters; the waters were to the ankles.","words":[["H0376","And when the man",0,16],["H6957","that had the line",17,34],["H3027","in his hand",35,46],["H3318","went forth",47,57],["H6921","eastward",58,66],["H4058","he measured",68,79],["H0505","a thousand",80,90],["H0520","cubits",91,97],["H5674","and he brought me through",99,124],["H4325","the waters",125,135],["H4325","the waters",137,147],["H0657","were to the ankles",148,166]]},"47:4":{"text":"Again he measured a thousand, and brought me through the waters; the waters were to the knees. Again he measured a thousand, and brought me through; the waters were to the loins.","words":[["H4058","Again he measured",0,17],["H0505","a thousand",18,28],["H5674","and brought me through",30,52],["H4325","the waters",53,63],["H4325","the waters",65,75],["H1290","were to the knees",76,93],["H4058","Again he measured",95,112],["H0505","a thousand",113,123],["H5674","and brought me through",125,147],["H4325","the waters",149,159],["H4975","were to the loins",160,177]]},"47:5":{"text":"Afterward he measured a thousand; and it was a river that I could not pass over: for the waters were risen, waters to swim in, a river that could not be passed over.","words":[["H4058","Afterward he measured",0,21],["H0505","a thousand",22,32],["H5158","and it was a river",34,52],["H3201","that I could",53,65],["H5674","not pass over",66,79],["H4325","for the waters",81,95],["H1342","were risen",96,106],["H4325","waters",108,114],["H7813","to swim in",115,125],["H5158","a river",127,134],["H5674","that could not be passed over",135,164]]},"47:6":{"text":"And he said unto me, Son of man, hast thou seen this? Then he brought me, and caused me to return to the brink of the river.","words":[["H0559","And he said",0,11],["H1121","unto me, Son",12,24],["H0120","of man",25,31],["H7200","hast thou seen",33,47],["H3212","this? Then he brought",48,69],["H7725","me, and caused me to return",70,97],["H8193","to the brink",98,110],["H5158","of the river",111,123]]},"47:7":{"text":"Now when I had returned, behold, at the bank of the river were very many trees on the one side and on the other.","words":[["H7725","Now when I had returned",0,23],["H8193","behold, at the bank",25,44],["H5158","of the river",45,57],["H3966","were very",58,67],["H7227","many",68,72],["H6086","trees",73,78]]},"47:8":{"text":"Then said he unto me, These waters issue out toward the east country, and go down into the desert, and go into the sea: which being brought forth into the sea, the waters shall be healed.","words":[["H0559","Then said",0,9],["H4325","he unto me, These waters",10,34],["H3318","issue out",35,44],["H6930","toward the east",45,60],["H1552","country",61,68],["H3381","and go down",70,81],["H6160","into the desert",82,97],["H0935","and go",99,105],["H3220","into the sea",106,118],["H3318","which being brought forth",120,145],["H3220","into the sea",146,158],["H4325","the waters",160,170],["H7495","shall be healed",171,186]]},"47:9":{"text":"And it shall come to pass, that every thing that liveth, which moveth, whithersoever the rivers shall come, shall live: and there shall be a very great multitude of fish, because these waters shall come thither: for they shall be healed; and every thing shall live whither the river cometh.","words":[["H5315","And it shall come to pass, that every thing",0,43],["H2416","that liveth",44,55],["H8317","which moveth",57,69],["H5158","whithersoever the rivers",71,95],["H0935","shall come",96,106],["H2421","shall live",108,118],["H3966","and there shall be a very",120,145],["H7227","great",146,151],["H1710","multitude of fish",152,169],["H4325","because these waters",171,191],["H0935","shall come",192,202],["H7495","thither: for they shall be healed",203,236],["H2425","and every thing shall live",238,264],["H5158","whither the river",265,282],["H0935","cometh",283,289]]},"47:10":{"text":"And it shall come to pass, that the fishers shall stand upon it from Engedi even unto Eneglaim; they shall be a place to spread forth nets; their fish shall be according to their kinds, as the fish of the great sea, exceeding many.","words":[["H1728","And it shall come to pass, that the fishers",0,43],["H5975","shall stand",44,55],["H5975","shall stand",44,55],["H5872","upon it from Engedi",56,75],["H5882","even unto Eneglaim",76,94],["H4894","they shall be a place to spread forth",96,133],["H2764","nets",134,138],["H1710","their fish",140,150],["H4327","shall be according to their kinds",151,184],["H1710","as the fish",186,197],["H1419","of the great",198,210],["H3220","sea",211,214],["H3966","exceeding",216,225],["H7227","many",226,230]]},"47:11":{"text":"But the miry places thereof and the marishes thereof shall not be healed; they shall be given to salt.","words":[["H1207","But the miry places",0,19],["H1360","thereof and the marishes",20,44],["H7495","thereof shall not be healed",45,72],["H5414","they shall be given",74,93],["H4417","to salt",94,101]]},"47:12":{"text":"And by the river upon the bank thereof, on this side and on that side, shall grow all trees for meat, whose leaf shall not fade, neither shall the fruit thereof be consumed: it shall bring forth new fruit according to his months, because their waters they issued out of the sanctuary: and the fruit thereof shall be for meat, and the leaf thereof for medicine.","words":[["H5158","And by the river",0,16],["H8193","upon the bank",17,30],["H5927","thereof, on this side and on that side, shall grow",31,81],["H6086","all trees",82,91],["H3978","for meat",92,100],["H5929","whose leaf",102,112],["H5034","shall not fade",113,127],["H6529","neither shall the fruit",129,152],["H8552","thereof be consumed",153,172],["H1069","it shall bring forth new fruit",174,204],["H2320","according to his months",205,228],["H4325","because their waters",230,250],["H3318","they issued out",251,266],["H4720","of the sanctuary",267,283],["H6529","and the fruit",285,298],["H3978","thereof shall be for meat",299,324],["H5929","and the leaf",326,338],["H8644","thereof for medicine",339,359]]},"47:13":{"text":"Thus saith the Lord GOD; This shall be the border, whereby ye shall inherit the land according to the twelve tribes of Israel: Joseph shall have two portions.","words":[["H0559","Thus saith",0,10],["H0136","the Lord",11,19],["H3069","GOD",20,23],["H1454","This",25,29],["H1366","shall be the border",30,49],["H5157","whereby ye shall inherit",51,75],["H0776","the land",76,84],["H8147","according to the twelve",85,108],["H6240","according to the twelve",85,108],["H7626","tribes",109,115],["H3478","of Israel",116,125],["H3130","Joseph",127,133],["H2256","shall have two portions",134,157]]},"47:14":{"text":"And ye shall inherit it, one as well as another: concerning the which I lifted up mine hand to give it unto your fathers: and this land shall fall unto you for inheritance.","words":[["H5157","And ye shall inherit",0,20],["H0376","it, one",21,28],["H0251","as well as another",29,47],["H5375","concerning the which I lifted up",49,81],["H3027","mine hand",82,91],["H5414","to give",92,99],["H0001","it unto your fathers",100,120],["H0776","and this land",122,135],["H5307","shall fall",136,146],["H5159","unto you for inheritance",147,171]]},"47:15":{"text":"And this shall be the border of the land toward the north side, from the great sea, the way of Hethlon, as men go to Zedad;","words":[["H1366","And this shall be the border",0,28],["H0776","of the land",29,40],["H6828","toward the north",41,57],["H6285","side",58,62],["H1419","from the great",64,78],["H3220","sea",79,82],["H1870","the way",84,91],["H2855","of Hethlon",92,102],["H0935","as men go",104,113],["H6657","to Zedad",114,122]]},"47:16":{"text":"Hamath, Berothah, Sibraim, which is between the border of Damascus and the border of Hamath; Hazarhatticon, which is by the coast of Hauran.","words":[["H2574","Hamath",0,6],["H1268","Berothah",8,16],["H5453","Sibraim",18,25],["H1366","which is between the border",27,54],["H1834","of Damascus",55,66],["H1366","and the border",67,81],["H2574","of Hamath",82,91],["H2694","Hazarhatticon",93,106],["H1366","which is by the coast",108,129],["H2362","of Hauran",130,139]]},"47:17":{"text":"And the border from the sea shall be Hazarenan, the border of Damascus, and the north northward, and the border of Hamath. And this is the north side.","words":[["H1366","And the border",0,14],["H3220","from the sea",15,27],["H2703","shall be Hazarenan",28,46],["H1366","the border",48,58],["H1834","of Damascus",59,70],["H6828","and the north",72,85],["H6828","northward",86,95],["H1366","and the border",97,111],["H2574","of Hamath",112,121],["H6828","And this is the north",123,144],["H6285","side",145,149]]},"47:18":{"text":"And the east side ye shall measure from Hauran, and from Damascus, and from Gilead, and from the land of Israel by Jordan, from the border unto the east sea. And this is the east side.","words":[["H6921","And the east",0,12],["H6285","side",13,17],["H4058","ye shall measure",18,34],["H0996","from",35,39],["H2362","Hauran",40,46],["H0996","and from",48,56],["H1834","Damascus",57,65],["H0996","and from",67,75],["H1568","Gilead",76,82],["H0996","and from",84,92],["H0776","the land",93,101],["H3478","of Israel",102,111],["H3383","by Jordan",112,121],["H1366","from the border",123,138],["H6931","unto the east",139,152],["H3220","sea",153,156],["H6921","And this is the east",158,178],["H6285","side",179,183]]},"47:19":{"text":"And the south side southward, from Tamar even to the waters of strife in Kadesh, the river to the great sea. And this is the south side southward.","words":[["H5045","And the south",0,13],["H6285","side",14,18],["H8486","southward",19,28],["H8559","from Tamar",30,40],["H4325","even to the waters",41,59],["H4808","of strife",60,69],["H4809","of strife",60,69],["H6946","in Kadesh",70,79],["H5158","the river",81,90],["H1419","to the great",91,103],["H3220","sea",104,107],["H8486","And this is the south",109,130],["H6285","side",131,135],["H5045","southward",136,145]]},"47:20":{"text":"The west side also shall be the great sea from the border, till a man come over against Hamath. This is the west side.","words":[["H3220","The west",0,8],["H6285","side",9,13],["H1419","also shall be the great",14,37],["H3220","sea",38,41],["H1366","from the border",42,57],["H0935","till a man come",59,74],["H5227","over against",75,87],["H2574","Hamath",88,94],["H3220","This is the west",96,112],["H6285","side",113,117]]},"47:21":{"text":"So shall ye divide this land unto you according to the tribes of Israel.","words":[["H2505","So shall ye divide",0,18],["H0776","this land",19,28],["H7626","unto you according to the tribes",29,61],["H3478","of Israel",62,71]]},"47:22":{"text":"And it shall come to pass, that ye shall divide it by lot for an inheritance unto you, and to the strangers that sojourn among you, which shall beget children among you: and they shall be unto you as born in the country among the children of Israel; they shall have inheritance with you among the tribes of Israel.","words":[["H5307","And it shall come to pass, that ye shall divide",0,47],["H5159","it by lot for an inheritance",48,76],["H1616","unto you, and to the strangers",77,107],["H1481","that sojourn",108,120],["H8432","among",121,126],["H3205","you, which shall beget",127,149],["H1121","children",150,158],["H8432","among",159,164],["H0249","you: and they shall be unto you as born",165,204],["H0249","in the country",205,219],["H1121","among the children",220,238],["H3478","of Israel",239,248],["H5307","they shall have",250,265],["H5159","inheritance",266,277],["H8432","with you among",278,292],["H7626","the tribes",293,303],["H3478","of Israel",304,313]]},"47:23":{"text":"And it shall come to pass, that in what tribe the stranger sojourneth, there shall ye give him his inheritance, saith the Lord GOD.","words":[["H7626","And it shall come to pass, that in what tribe",0,45],["H1616","the stranger",46,58],["H1481","sojourneth",59,69],["H5414","there shall ye give",71,90],["H5159","him his inheritance",91,110],["H5002","saith",112,117],["H0136","the Lord",118,126],["H3069","GOD",127,130]]},"48:1":{"text":"Now these are the names of the tribes. From the north end to the coast of the way of Hethlon, as one goeth to Hamath, Hazarenan, the border of Damascus northward, to the coast of Hamath; for these are his sides east and west; a portion for Dan.","words":[["H8034","Now these are the names",0,23],["H7626","of the tribes",24,37],["H6828","From the north",39,53],["H7097","end",54,57],["H3027","to the coast",58,70],["H1870","of the way",71,81],["H2855","of Hethlon",82,92],["H0935","as one goeth",94,106],["H2574","to Hamath",107,116],["H2704","Hazarenan",118,127],["H1366","the border",129,139],["H1834","of Damascus",140,151],["H6828","northward",152,161],["H3027","to the coast",163,175],["H2574","of Hamath",176,185],["H6285","for these are his sides",187,210],["H6921","east",211,215],["H3220","and west",216,224],["H0259","a",226,227],["H1835","portion for Dan",228,243]]},"48:2":{"text":"And by the border of Dan, from the east side unto the west side, a portion for Asher.","words":[["H1366","And by the border",0,17],["H1835","of Dan",18,24],["H6921","from the east",26,39],["H6285","side",40,44],["H3220","unto the west",45,58],["H6285","side",59,63],["H0259","a",65,66],["H0836","portion for Asher",67,84]]},"48:3":{"text":"And by the border of Asher, from the east side even unto the west side, a portion for Naphtali.","words":[["H1366","And by the border",0,17],["H0836","of Asher",18,26],["H6921","from the east",28,41],["H6285","side",42,46],["H3220","even unto the west",47,65],["H6285","side",66,70],["H0259","a",72,73],["H5321","portion for Naphtali",74,94]]},"48:4":{"text":"And by the border of Naphtali, from the east side unto the west side, a portion for Manasseh.","words":[["H1366","And by the border",0,17],["H5321","of Naphtali",18,29],["H6921","from the east",31,44],["H6285","side",45,49],["H3220","unto the west",50,63],["H6285","side",64,68],["H0259","a",70,71],["H4519","portion for Manasseh",72,92]]},"48:5":{"text":"And by the border of Manasseh, from the east side unto the west side, a portion for Ephraim.","words":[["H1366","And by the border",0,17],["H4519","of Manasseh",18,29],["H6921","from the east",31,44],["H6285","side",45,49],["H3220","unto the west",50,63],["H6285","side",64,68],["H0259","a",70,71],["H0669","portion for Ephraim",72,91]]},"48:6":{"text":"And by the border of Ephraim, from the east side even unto the west side, a portion for Reuben.","words":[["H1366","And by the border",0,17],["H0669","of Ephraim",18,28],["H6921","from the east",30,43],["H6285","side",44,48],["H3220","even unto the west",49,67],["H6285","side",68,72],["H0259","a",74,75],["H7205","portion for Reuben",76,94]]},"48:7":{"text":"And by the border of Reuben, from the east side unto the west side, a portion for Judah.","words":[["H1366","And by the border",0,17],["H7205","of Reuben",18,27],["H6921","from the east",29,42],["H6285","side",43,47],["H3220","unto the west",48,61],["H6285","side",62,66],["H0259","a",68,69],["H3063","portion for Judah",70,87]]},"48:8":{"text":"And by the border of Judah, from the east side unto the west side, shall be the offering which ye shall offer of five and twenty thousand reeds in breadth, and in length as one of the other parts, from the east side unto the west side: and the sanctuary shall be in the midst of it.","words":[["H1366","And by the border",0,17],["H3063","of Judah",18,26],["H6921","from the east",28,41],["H6285","side",42,46],["H3220","unto the west",47,60],["H6285","side",61,65],["H8641","shall be the offering",67,88],["H7311","which ye shall offer",89,109],["H2568","of five",110,117],["H6242","and twenty",118,128],["H0505","thousand",129,137],["H7341","reeds in breadth",138,154],["H0753","and in length",156,169],["H0259","as one",170,176],["H2506","of the other parts",177,195],["H6921","from the east",197,210],["H6285","side",211,215],["H3220","unto the west",216,229],["H6285","side",230,234],["H4720","and the sanctuary",236,253],["H8432","shall be in the midst",254,275]]},"48:9":{"text":"The oblation that ye shall offer unto the LORD shall be of five and twenty thousand in length, and of ten thousand in breadth.","words":[["H8641","The oblation",0,12],["H7311","that ye shall offer",13,32],["H3068","unto the LORD",33,46],["H2568","shall be of five",47,63],["H6242","and twenty",64,74],["H0505","thousand",75,83],["H0753","in length",84,93],["H6235","and of ten",95,105],["H0505","thousand",106,114],["H7341","in breadth",115,125]]},"48:10":{"text":"And for them, even for the priests, shall be this holy oblation; toward the north five and twenty thousand in length, and toward the west ten thousand in breadth, and toward the east ten thousand in breadth, and toward the south five and twenty thousand in length: and the sanctuary of the LORD shall be in the midst thereof.","words":[["H3548","And for them, even for the priests",0,34],["H6944","shall be this holy",36,54],["H8641","oblation",55,63],["H6828","toward the north",65,81],["H2568","five",82,86],["H6242","and twenty",87,97],["H0505","thousand",98,106],["H3220","in length, and toward the west",107,137],["H6235","ten",138,141],["H0505","thousand",142,150],["H7341","in breadth",151,161],["H6921","and toward the east",163,182],["H6235","ten",183,186],["H0505","thousand",187,195],["H7341","in breadth",196,206],["H5045","and toward the south",208,228],["H2568","five",229,233],["H6242","and twenty",234,244],["H0505","thousand",245,253],["H0753","in length",254,263],["H4720","and the sanctuary",265,282],["H3068","of the LORD",283,294],["H8432","shall be in the midst",295,316]]},"48:11":{"text":"It shall be for the priests that are sanctified of the sons of Zadok; which have kept my charge, which went not astray when the children of Israel went astray, as the Levites went astray.","words":[["H3548","It shall be for the priests",0,27],["H6942","that are sanctified",28,47],["H1121","of the sons",48,59],["H6659","of Zadok",60,68],["H8104","which have kept",70,85],["H4931","my charge",86,95],["H8582","which went not astray",97,118],["H1121","when the children",119,136],["H3478","of Israel",137,146],["H8582","went astray",147,158],["H3881","as the Levites",160,174],["H8582","went astray",175,186]]},"48:12":{"text":"And this oblation of the land that is offered shall be unto them a thing most holy by the border of the Levites.","words":[["H8642","And this oblation",0,17],["H0776","of the land",18,29],["H8641","that is offered",30,45],["H6944","shall be unto them a thing most",46,77],["H6944","holy",78,82],["H1366","by the border",83,96],["H3881","of the Levites",97,111]]},"48:13":{"text":"And over against the border of the priests the Levites shall have five and twenty thousand in length, and ten thousand in breadth: all the length shall be five and twenty thousand, and the breadth ten thousand.","words":[["H5980","And over against",0,16],["H1366","the border",17,27],["H3548","of the priests",28,42],["H3881","the Levites",43,54],["H2568","shall have five",55,70],["H6242","and twenty",71,81],["H0505","thousand",82,90],["H0753","in length",91,100],["H6235","and ten",102,109],["H0505","thousand",110,118],["H7341","in breadth",119,129],["H0753","all the length",131,145],["H2568","shall be five",146,159],["H6242","and twenty",160,170],["H0505","thousand",171,179],["H7341","and the breadth",181,196],["H6235","ten",197,200],["H0505","thousand",201,209]]},"48:14":{"text":"And they shall not sell of it, neither exchange, nor alienate the firstfruits of the land: for it is holy unto the LORD.","words":[["H4376","And they shall not sell",0,23],["H4171","of it, neither exchange",24,47],["H5674","nor alienate",49,61],["H5674","nor alienate",49,61],["H7225","the firstfruits",62,77],["H0776","of the land",78,89],["H6944","for it is holy",91,105],["H3068","unto the LORD",106,119]]},"48:15":{"text":"And the five thousand, that are left in the breadth over against the five and twenty thousand, shall be a profane place for the city, for dwelling, and for suburbs: and the city shall be in the midst thereof.","words":[["H2568","And the five",0,12],["H0505","thousand",13,21],["H3498","that are left",23,36],["H7341","in the breadth",37,51],["H6440","over against",52,64],["H2568","the five",65,73],["H6242","and twenty",74,84],["H0505","thousand",85,93],["H2455","shall be a profane",95,113],["H5892","place for the city",114,132],["H4186","for dwelling",134,146],["H4054","and for suburbs",148,163],["H5892","and the city",165,177],["H8432","shall be in the midst",178,199]]},"48:16":{"text":"And these shall be the measures thereof; the north side four thousand and five hundred, and the south side four thousand and five hundred, and on the east side four thousand and five hundred, and the west side four thousand and five hundred.","words":[["H4060","And these shall be the measures",0,31],["H6828","thereof; the north",32,50],["H6285","side",51,55],["H0702","four",56,60],["H0505","thousand",61,69],["H2568","and five",70,78],["H3967","hundred",79,86],["H5045","and the south",88,101],["H6285","side",102,106],["H0702","four",107,111],["H0505","thousand",112,120],["H2568","and five",121,129],["H3967","hundred",130,137],["H6921","and on the east",139,154],["H6285","side",155,159],["H0702","four",160,164],["H0505","thousand",165,173],["H2568","and five",174,182],["H3967","hundred",183,190],["H3220","and the west",192,204],["H6285","side",205,209],["H0702","four",210,214],["H0505","thousand",215,223],["H2568","and five",224,232],["H2568","and five",224,232],["H3967","hundred",233,240]]},"48:17":{"text":"And the suburbs of the city shall be toward the north two hundred and fifty, and toward the south two hundred and fifty, and toward the east two hundred and fifty, and toward the west two hundred and fifty.","words":[["H4054","And the suburbs",0,15],["H5892","of the city",16,27],["H6828","shall be toward the north",28,53],["H3967","two hundred",54,65],["H2572","and fifty",66,75],["H5045","and toward the south",77,97],["H3967","two hundred",98,109],["H2572","and fifty",110,119],["H6921","and toward the east",121,140],["H3967","two hundred",141,152],["H2572","and fifty",153,162],["H3220","and toward the west",164,183],["H3967","two hundred",184,195],["H2572","and fifty",196,205]]},"48:18":{"text":"And the residue in length over against the oblation of the holy portion shall be ten thousand eastward, and ten thousand westward: and it shall be over against the oblation of the holy portion; and the increase thereof shall be for food unto them that serve the city.","words":[["H3498","And the residue",0,15],["H0753","in length",16,25],["H5980","over against",26,38],["H8641","the oblation",39,51],["H6944","of the holy",52,63],["H6235","portion shall be ten",64,84],["H0505","thousand",85,93],["H6921","eastward",94,102],["H6235","and ten",104,111],["H0505","thousand",112,120],["H3220","westward",121,129],["H5980","and it shall be over against",131,159],["H8641","the oblation",160,172],["H6944","of the holy",173,184],["H8393","portion; and the increase",185,210],["H3899","thereof shall be for food",211,236],["H5647","unto them that serve",237,257],["H5892","the city",258,266]]},"48:19":{"text":"And they that serve the city shall serve it out of all the tribes of Israel.","words":[["H5647","And they that serve",0,19],["H5892","the city",20,28],["H5647","shall serve",29,40],["H7626","it out of all the tribes",41,65],["H3478","of Israel",66,75]]},"48:20":{"text":"All the oblation shall be five and twenty thousand by five and twenty thousand: ye shall offer the holy oblation foursquare, with the possession of the city.","words":[["H8641","All the oblation",0,16],["H2568","shall be five",17,30],["H6242","and twenty",31,41],["H0505","thousand",42,50],["H2568","by five",51,58],["H6242","and twenty",59,69],["H0505","thousand",70,78],["H7311","ye shall offer",80,94],["H6944","the holy",95,103],["H8641","oblation",104,112],["H7243","foursquare",113,123],["H0272","with the possession",125,144],["H5892","of the city",145,156]]},"48:21":{"text":"And the residue shall be for the prince, on the one side and on the other of the holy oblation, and of the possession of the city, over against the five and twenty thousand of the oblation toward the east border, and westward over against the five and twenty thousand toward the west border, over against the portions for the prince: and it shall be the holy oblation; and the sanctuary of the house shall be in the midst thereof.","words":[["H3498","And the residue",0,15],["H5387","shall be for the prince",16,39],["H6944","on the one side and on the other of the holy",41,85],["H8641","oblation",86,94],["H0272","and of the possession",96,117],["H5892","of the city",118,129],["H6440","over against",131,143],["H2568","the five",144,152],["H6242","and twenty",153,163],["H0505","thousand",164,172],["H8641","of the oblation",173,188],["H6921","toward the east",189,204],["H1366","border",205,211],["H3220","and westward",213,225],["H6440","over against",226,238],["H2568","the five",239,247],["H6242","and twenty",248,258],["H0505","thousand",259,267],["H3220","toward the west",268,283],["H1366","border",284,290],["H5980","over against",292,304],["H2506","the portions",305,317],["H5387","for the prince",318,332],["H6944","and it shall be the holy",334,358],["H8641","oblation",359,367],["H4720","and the sanctuary",369,386],["H1004","of the house",387,399],["H8432","shall be in the midst",400,421]]},"48:22":{"text":"Moreover from the possession of the Levites, and from the possession of the city, being in the midst of that which is the prince's, between the border of Judah and the border of Benjamin, shall be for the prince.","words":[["H0272","Moreover from the possession",0,28],["H3881","of the Levites",29,43],["H0272","and from the possession",45,68],["H5892","of the city",69,80],["H8432","being in the midst",82,100],["H5387","of that which is the prince's",101,130],["H1366","between the border",132,150],["H3063","of Judah",151,159],["H1366","and the border",160,174],["H1144","of Benjamin",175,186],["H5387","shall be for the prince",188,211]]},"48:23":{"text":"As for the rest of the tribes, from the east side unto the west side, Benjamin shall have a portion.","words":[["H3499","As for the rest",0,15],["H7626","of the tribes",16,29],["H6921","from the east",31,44],["H6285","side",45,49],["H3220","unto the west",50,63],["H6285","side",64,68],["H1144","Benjamin",70,78],["H0259","shall have a",79,91]]},"48:24":{"text":"And by the border of Benjamin, from the east side unto the west side, Simeon shall have a portion.","words":[["H1366","And by the border",0,17],["H1144","of Benjamin",18,29],["H6921","from the east",31,44],["H6285","side",45,49],["H3220","unto the west",50,63],["H6285","side",64,68],["H8095","Simeon",70,76],["H0259","shall have a",77,89]]},"48:25":{"text":"And by the border of Simeon, from the east side unto the west side, Issachar a portion.","words":[["H1366","And by the border",0,17],["H8095","of Simeon",18,27],["H6921","from the east",29,42],["H6285","side",43,47],["H3220","unto the west",48,61],["H6285","side",62,66],["H3485","Issachar",68,76],["H0259","a",77,78]]},"48:26":{"text":"And by the border of Issachar, from the east side unto the west side, Zebulun a portion.","words":[["H1366","And by the border",0,17],["H3485","of Issachar",18,29],["H6921","from the east",31,44],["H6285","side",45,49],["H3220","unto the west",50,63],["H6285","side",64,68],["H2074","Zebulun",70,77],["H0259","a",78,79]]},"48:27":{"text":"And by the border of Zebulun, from the east side unto the west side, Gad a portion.","words":[["H1366","And by the border",0,17],["H2074","of Zebulun",18,28],["H6921","from the east",30,43],["H6285","side",44,48],["H3220","unto the west",49,62],["H6285","side",63,67],["H1410","Gad",69,72],["H0259","a",73,74]]},"48:28":{"text":"And by the border of Gad, at the south side southward, the border shall be even from Tamar unto the waters of strife in Kadesh, and to the river toward the great sea.","words":[["H1366","And by the border",0,17],["H1410","of Gad",18,24],["H5045","at the south",26,38],["H6285","side",39,43],["H8486","southward",44,53],["H1366","the border",55,65],["H8559","shall be even from Tamar",66,90],["H4325","unto the waters",91,106],["H4808","of strife",107,116],["H4809","of strife",107,116],["H6946","in Kadesh",117,126],["H5158","and to the river",128,144],["H1419","toward the great",145,161],["H3220","sea",162,165]]},"48:29":{"text":"This is the land which ye shall divide by lot unto the tribes of Israel for inheritance, and these are their portions, saith the Lord GOD.","words":[["H0776","This is the land",0,16],["H5307","which ye shall divide",17,38],["H7626","by lot unto the tribes",39,61],["H3478","of Israel",62,71],["H5159","for inheritance",72,87],["H4256","and these are their portions",89,117],["H5002","saith",119,124],["H0136","the Lord",125,133],["H3069","GOD",134,137]]},"48:30":{"text":"And these are the goings out of the city on the north side, four thousand and five hundred measures.","words":[["H8444","And these are the goings out",0,28],["H5892","of the city",29,40],["H6828","on the north",41,53],["H6285","side",54,58],["H0702","four",60,64],["H0505","thousand",65,73],["H2568","and five",74,82],["H3967","hundred",83,90],["H4060","measures",91,99]]},"48:31":{"text":"And the gates of the city shall be after the names of the tribes of Israel: three gates northward; one gate of Reuben, one gate of Judah, one gate of Levi.","words":[["H8179","And the gates",0,13],["H5892","of the city",14,25],["H8034","shall be after the names",26,50],["H7626","of the tribes",51,64],["H3478","of Israel",65,74],["H7969","three",76,81],["H8179","gates",82,87],["H6828","northward",88,97],["H0259","one",99,102],["H8179","gate",103,107],["H7205","of Reuben",108,117],["H0259","one",119,122],["H8179","gate",123,127],["H3063","of Judah",128,136],["H0259","one",138,141],["H8179","gate",142,146],["H3878","of Levi",147,154]]},"48:32":{"text":"And at the east side four thousand and five hundred: and three gates; and one gate of Joseph, one gate of Benjamin, one gate of Dan.","words":[["H6921","And at the east",0,15],["H6285","side",16,20],["H0702","four",21,25],["H0505","thousand",26,34],["H2568","and five",35,43],["H3967","hundred",44,51],["H7969","and three",53,62],["H8179","gates",63,68],["H0259","and one",70,77],["H8179","gate",78,82],["H3130","of Joseph",83,92],["H0259","one",94,97],["H8179","gate",98,102],["H1144","of Benjamin",103,114],["H0259","one",116,119],["H8179","gate",120,124],["H1835","of Dan",125,131]]},"48:33":{"text":"And at the south side four thousand and five hundred measures: and three gates; one gate of Simeon, one gate of Issachar, one gate of Zebulun.","words":[["H5045","And at the south",0,16],["H6285","side",17,21],["H0702","four",22,26],["H0505","thousand",27,35],["H2568","and five",36,44],["H3967","hundred",45,52],["H4060","measures",53,61],["H7969","and three",63,72],["H8179","gates",73,78],["H0259","one",80,83],["H8179","gate",84,88],["H8095","of Simeon",89,98],["H0259","one",100,103],["H8179","gate",104,108],["H3485","of Issachar",109,120],["H0259","one",122,125],["H8179","gate",126,130],["H2074","of Zebulun",131,141]]},"48:34":{"text":"At the west side four thousand and five hundred, with their three gates; one gate of Gad, one gate of Asher, one gate of Naphtali.","words":[["H3220","At the west",0,11],["H6285","side",12,16],["H0702","four",17,21],["H0505","thousand",22,30],["H2568","and five",31,39],["H3967","hundred",40,47],["H7969","with their three",49,65],["H8179","gates",66,71],["H0259","one",73,76],["H8179","gate",77,81],["H1410","of Gad",82,88],["H0259","one",90,93],["H8179","gate",94,98],["H0836","of Asher",99,107],["H0259","one",109,112],["H8179","gate",113,117],["H5321","of Naphtali",118,129]]},"48:35":{"text":"It was round about eighteen thousand measures: and the name of the city from that day shall be, The LORD is there.","words":[["H5439","It was round about",0,18],["H8083","eighteen",19,27],["H6240","eighteen",19,27],["H0505","thousand",28,36],["H8034","measures: and the name",37,59],["H5892","of the city",60,71],["H3117","from that day",72,85],["H3074","shall be, The LORD is there",86,113]]}}};
